function readCandidateVoterMapPinCapPreference() {
  try {
    const raw = Number(
      window.localStorage?.getItem(CANDIDATE_VOTER_MAP_PIN_CAP_STORAGE_KEY),
    );
    if (Number.isFinite(raw) && raw >= 250 && raw <= 5000) {
      return Math.round(raw);
    }
  } catch {
    // Local storage can be blocked; keep a usable default.
  }
  return 1250;
}

function readCandidateVoterMapOfflineCellularPreference() {
  try {
    return (
      normalizeString(
        window.localStorage?.getItem(
          CANDIDATE_VOTER_MAP_OFFLINE_CELLULAR_STORAGE_KEY,
        ),
      ).toLowerCase() === "true"
    );
  } catch {
    return false;
  }
}

