function createCandidateDonationFlowState(seed = {}) {
  const seedFields = seed.fields && typeof seed.fields === "object" ? seed.fields : {};
  const seedCertifications =
    seed.certifications && typeof seed.certifications === "object"
      ? seed.certifications
      : {};
  return {
    open: seed.open === true,
    step: normalizeString(seed.step) || "amount",
    candidateId: normalizeString(seed.candidateId),
    candidateName: normalizeString(seed.candidateName) || "Candidate",
    unavailableReason: normalizeString(seed.unavailableReason),
    loading: seed.loading === true,
    submitting: seed.submitting === true,
    actionPendingKey: normalizeString(seed.actionPendingKey),
    error: normalizeString(seed.error),
    notice: normalizeString(seed.notice),
    eligibility: seed.eligibility || null,
    checkoutSession: seed.checkoutSession || null,
    amount: normalizeString(seed.amount),
    fields: {
      fullLegalName: normalizeString(seedFields.fullLegalName),
      addressLine1: normalizeString(seedFields.addressLine1),
      addressLine2: normalizeString(seedFields.addressLine2),
      city: normalizeString(seedFields.city),
      state: normalizeString(seedFields.state).toUpperCase(),
      postalCode: normalizeString(seedFields.postalCode),
      occupation: normalizeString(seedFields.occupation),
      employer: normalizeString(seedFields.employer),
      jobTitle: normalizeString(seedFields.jobTitle),
    },
    certifications: {
      usCitizenOrLpr: seedCertifications.usCitizenOrLpr === true,
      ownFunds: seedCertifications.ownFunds === true,
      campaignAttribution: seedCertifications.campaignAttribution === true,
    },
    submittedMessage: normalizeString(seed.submittedMessage),
  };
}

