    displayName:
      normalizeString(raw.displayName || raw.name || raw.username) ||
      "Invited user",
    avatarUrl: normalizeUrl(raw.avatarUrl || raw.profileImageUrl || raw.avatar),
    status: normalizeString(raw.status || raw.state).toLowerCase() || "pending",
    origin: normalizeString(raw.origin) || "campaign_invite",
    roleKey,
    roleLabel:
      normalizeString(raw.roleLabel || raw.role_label) ||
      candidateStaffRoleLabel(roleKey),
    roleCategory: normalizeString(raw.roleCategory || raw.role_category),
    roleEnabled: parseBoolean(raw.roleEnabled ?? raw.role_enabled, true),
