function createCandidateStaffInviteSearchState() {
  return {
    query: "",
    items: [],
    roleKey: "",
    loading: false,
    error: "",
    loaded: false,
    lastSearchQuery: "",
    selected: null,
    token: 0,
  };
}

function candidateStaffInviteSearch(resource) {
  if (!resource.inviteSearch) {
    resource.inviteSearch = createCandidateStaffInviteSearchState();
  }
  return resource.inviteSearch;
}

function candidateStaffInviteSearchEndpoint(query, limit = 8) {
  const params = new URLSearchParams({
    q: query,
    type: "users",
    surface: "comment_mentions",
    limit: String(limit),
  });
  return `/api/search/results?${params.toString()}`;
}

function normalizeCandidateStaffInviteSearchResult(raw, fallbackIndex = 0) {
  const item = normalizeSearchResultItem(raw, "users", fallbackIndex);
  if (!item) {
    return null;
  }
  const username = normalizeString(item.username).replace(/^@/u, "");
  const userId = normalizeString(item.id);
  if (!userId || !username) {
    return null;
  }
  return {
    userId,
    username,
    displayName:
      normalizeString(item.displayName || item.title || username) ||
      "Polis user",
    avatarUrl: normalizeUrl(item.avatarUrl || item.imageUrl),
    subtitle: normalizeString(item.subtitle || item.reason),
  };
}

function candidateStaffInviteStatus(user, detail, resource) {
  const userId = normalizeString(user?.userId);
  const username = normalizeString(user?.username).replace(/^@/u, "").toLowerCase();
  const staffMatch = detail.staff.some((member) => {
    const memberUsername = normalizeString(member.username).replace(/^@/u, "").toLowerCase();
    return (
      normalizeString(member.userId) === userId ||
      (username && memberUsername === username)
    );
  });
  if (staffMatch) {
    return { disabled: true, label: "Already staff" };
  }
  const invitedMatch = resource.invitations.some((invite) => {
    const inviteUsername = normalizeString(invite.username).replace(/^@/u, "").toLowerCase();
    return (
      invite.status === "pending" &&
      (normalizeString(invite.userId) === userId ||
        (username && inviteUsername === username))
    );
  });
  if (invitedMatch) {
    return { disabled: true, label: "Already invited" };
  }
  return { disabled: false, label: "Ready to invite" };
}

function candidateStaffCatalogRole(catalog, roleKey) {
  const normalized = normalizeCandidateStaffRoleKey(roleKey);
  return (
    catalog?.roles?.find((role) => role.roleKey === normalized) ||
    CANDIDATE_STAFF_FALLBACK_ROLES.map(normalizeCandidateStaffRole).find(
      (role) => role.roleKey === normalized,
    ) ||
    normalizeCandidateStaffRole({ roleKey: normalized })
  );
}

function candidateStaffAssignableRoles(catalog) {
  const roles =
    catalog?.assignableRoles?.length > 0
      ? catalog.assignableRoles
      : normalizeCandidateStaffAccessCatalog({}).assignableRoles;
  return roles.length ? roles : [normalizeCandidateStaffRole({ roleKey: "staff" })];
}

function candidateStaffRoleDefaultPermissions(catalog, roleKey) {
  return candidateStaffCatalogRole(catalog, roleKey).defaultPermissions || [];
}

