    const result = await fetchJson("/api/missions", {
      auth: true,
      method: "POST",
      body: payload,
    });
    const mission = normalizeCandidateDashboardMission(result.mission || result);
    resource.createOpen = false;
    resource.createDraft = null;
    showToast("Coalition mission created.");
