async function loadCoalitionCalendar(coalitionId, { refresh = false } = {}) {
  const normalizedCoalitionId = decodeRouteSegment(coalitionId);
  if (!normalizedCoalitionId) {
    return;
  }
  const detail = state.pages.coalitions.detail;
  const resource = coalitionCalendarWorkspace();
  if (resource.loading) {
    return;
  }
  if (resource.loaded && !refresh) {
    return;
  }
  if (refresh) {
    resource.items = [];
    resource.connections = [];
    resource.providers = [];
    resource.loaded = false;
  }
  resource.loading = true;
  resource.error = "";
  scheduleRender();

  const encodedId = encodeURIComponent(normalizedCoalitionId);
  const itemPath = `/api/coalitions/${encodedId}/calendar/items?${candidateCalendarQueryString(resource)}`;
  const [itemsResult, connectionsResult] = await Promise.allSettled([
    fetchJson(itemPath, { auth: true }),
    fetchJson(`/api/coalitions/${encodedId}/calendar/connections`, {
      auth: true,
    }),
  ]);

  if (itemsResult.status === "fulfilled") {
    resource.items = readArrayPayload(itemsResult.value, [
      "items",
      "calendar",
    ]).map(normalizeCandidateDashboardCalendarItem);
    detail.calendar = resource.items.slice(0, 6);
    resource.loaded = true;
  } else {
    resource.error = settingsErrorMessage(
      itemsResult.reason,
      "Coalition calendar could not be loaded.",
    );
  }
  if (connectionsResult.status === "fulfilled") {
    const connections = normalizeCandidateCalendarConnectionsPayload(
      connectionsResult.value,
    );
    resource.configured = connections.configured;
    resource.connections = connections.connections;
    resource.providers = connections.providers;
    if (connections.settings) {
      resource.settings = connections.settings;
    }
  }
  if (
    itemsResult.status === "rejected" &&
    connectionsResult.status === "rejected"
  ) {
    resource.error = settingsErrorMessage(
      itemsResult.reason,
      "Coalition calendar could not be loaded.",
    );
  }
  resource.loading = false;
  scheduleRender();
}

