function coalitionCalendarDraftFromForm(formData, membership) {
  if (!canManageCoalitionCalendar(membership)) {
    throw new Error("calendar_manage_required");
  }
  const startAt = Date.parse(normalizeString(formData.get("startAt")));
  const endAt = Date.parse(normalizeString(formData.get("endAt")));
  if (!Number.isFinite(startAt) || !Number.isFinite(endAt)) {
    throw new Error("Start and end time are required.");
  }
  if (endAt <= startAt) {
    throw new Error("End time must be after start time.");
  }
  const externalWriteTargets = formData
    .getAll("writeTarget")
    .map(normalizeString)
    .map((value) => {
      const [provider, ...calendarParts] = value.split(":");
      return {
        provider: normalizeString(provider),
        calendarId: normalizeString(calendarParts.join(":")),
        mode: "write",
      };
    })
    .filter((target) => target.provider && target.calendarId);
  return {
    itemType: normalizeString(formData.get("itemType")) || "busy",
    title: normalizeString(formData.get("title")) || "Busy",
    description: normalizeString(formData.get("description")) || undefined,
    locationName: normalizeString(formData.get("locationName")) || undefined,
    startAt,
    endAt,
    allDay: formData.get("allDay") === "on",
    privacy: normalizeString(formData.get("privacy")) || "details",
    status: normalizeString(formData.get("status")) || "confirmed",
    labels: splitCandidateVolunteerTags(formData.get("labels")),
    externalWriteTargets,
  };
}

async function createCoalitionCalendarItem(formData) {
  const coalitionId = currentCoalitionDetailId();
  const detail = state.pages.coalitions.detail;
  const resource = coalitionCalendarWorkspace();
  if (!coalitionId) {
    showToast("Coalition calendar unavailable.");
    return false;
  }
  resource.actionPendingKey = "create";
  resource.error = "";
  scheduleRender();
  try {
    const body = coalitionCalendarDraftFromForm(formData, detail.membership);
    const payload = await fetchJson(
      `/api/coalitions/${encodeURIComponent(coalitionId)}/calendar/items`,
      { auth: true, method: "POST", body },
    );
    const item = normalizeCandidateDashboardCalendarItem(payload.item || payload);
    resource.items = [item, ...resource.items]
      .filter((entry) => entry.calendarItemId)
      .sort((left, right) => (left.startAt || 0) - (right.startAt || 0));
    detail.calendar = resource.items.slice(0, 6);
    resource.loaded = true;
    showToast("Coalition calendar item created.");
    return true;
  } catch (error) {
    resource.error = settingsErrorMessage(
      error,
      "Coalition calendar item could not be created.",
    );
    showToast(resource.error);
    return false;
  } finally {
    resource.actionPendingKey = "";
    scheduleRender();
  }
}

function normalizeCandidateEngagementResponseMode(value) {
  const normalized = normalizeString(value).toLowerCase();
  if (normalized === "candidate" || normalized === "staff") {
    return normalized;
  }
  return "";
}

function candidateEngagementResponseModeLabel(value) {
  const mode = normalizeCandidateEngagementResponseMode(value);
  if (mode === "candidate") {
    return "Candidate";
  }
  if (mode === "staff") {
    return "Staff";
  }
  return "";
}

function candidateEngagementAvailableModesForAccess(access = null) {
  if (access?.isOwner) {
    return ["candidate"];
  }
  const permissions = candidateDashboardPermissionSet(access);
  const modes = [];
  if (permissions.has("engagement_candidate")) {
    modes.push("candidate");
  }
  if (permissions.has("engagement_staff")) {
    modes.push("staff");
  }
  return modes;
}

function normalizeCandidateEngagementKind(value) {
  const normalized = normalizeString(value).toLowerCase();
  if (normalized.includes("comment")) {
    return "post_comment";
  }
  if (normalized.includes("like")) {
    return "post_like";
  }
  return "";
}

function normalizeCandidateEngagementActor(raw = {}) {
  return {
    userId: normalizeString(raw.userId || raw.user_id || raw.id),
    username: normalizeString(raw.username || raw.handle),
    displayName: normalizeString(
      raw.displayName || raw.name || raw.userDisplayName,
    ),
    avatarUrl: normalizeUrl(
      raw.avatarUrl || raw.userAvatarUrl || raw.profileImageUrl,
    ),
  };
}

function candidateEngagementActorLabel(actor = {}) {
  return (
    normalizeString(actor.displayName) ||
    (actor.username ? `@${normalizeString(actor.username).replace(/^@/u, "")}` : "") ||
    "Someone"
  );
}

function normalizeCandidateEngagementPreview(raw = {}) {
  const post = raw.post && typeof raw.post === "object" ? raw.post : {};
  const preview = raw.preview && typeof raw.preview === "object" ? raw.preview : {};
  const source = { ...raw, ...post, ...preview };
  return {
    postThumbUrl: normalizeUrl(
      source.postThumbUrl ||
        source.thumbnailUrl ||
        source.thumbUrl ||
        source.previewImageUrl ||
        source.imageUrl ||
        source.posterUrl,
    ),
    postText: normalizeString(
      source.postText ||
        source.textPreview ||
        source.postPreview ||
        source.caption ||
        source.body ||
        source.text,
    ),
    commentText: normalizeString(source.commentText || source.comment_text),
  };
}

function normalizeCandidateEngagementComment(raw = {}, postIdFallback = "") {
  const user =
    raw.user && typeof raw.user === "object"
      ? raw.user
      : raw.author && typeof raw.author === "object"
        ? raw.author
        : raw.actor && typeof raw.actor === "object"
          ? raw.actor
          : {};
  return {
    commentId: normalizeString(raw.commentId || raw.comment_id || raw.id),
    postId: normalizeString(raw.postId || raw.post_id) || postIdFallback,
    text: normalizeString(raw.text || raw.body || raw.commentText),
    likeCount: Number(raw.likeCount ?? raw.likesCount) || 0,
    likedByMe:
      raw.likedBySelectedMode === true ||
      raw.liked_by_selected_mode === true ||
      raw.likedByCurrentUser === true ||
      raw.likedByMe === true ||
      raw.likedByResponder === true ||
      raw.likedByCandidate === true,
    createdAt:
      Number(raw.createdAt ?? raw.created_at ?? raw.receivedAt) ||
      Date.parse(raw.createdAtIso || "") ||
      null,
    replyTo: normalizeString(raw.replyTo || raw.reply_to),
    responseMode: normalizeCandidateEngagementResponseMode(raw.responseMode),
    badgeLabel: normalizeString(raw.badgeLabel || raw.badge_label),
    actor: normalizeCandidateEngagementActor({ ...user, ...raw }),
  };
}

function candidateEngagementActorsFromPayload(raw = {}, comments = []) {
  const actors = readArrayPayload(raw, ["actors", "users"])
    .map(normalizeCandidateEngagementActor)
    .filter(
      (actor) => actor.userId || actor.username || actor.displayName || actor.avatarUrl,
    );
  if (actors.length) {
    return actors;
  }
  const actorSource =
    raw.primaryActor && typeof raw.primaryActor === "object"
      ? raw.primaryActor
      : raw.primary_actor && typeof raw.primary_actor === "object"
        ? raw.primary_actor
        : raw.actor && typeof raw.actor === "object"
          ? raw.actor
          : raw.user && typeof raw.user === "object"
            ? raw.user
            : raw.primary && typeof raw.primary === "object"
              ? raw.primary
              : null;
  if (actorSource) {
    return [normalizeCandidateEngagementActor(actorSource)];
  }
  if (comments.length && comments[0].actor) {
    return [comments[0].actor];
  }
  const actor = normalizeCandidateEngagementActor(raw);
  return actor.userId || actor.username || actor.displayName || actor.avatarUrl
    ? [actor]
    : [];
}

function normalizeCandidateDashboardEngagementItem(raw = {}) {
  const kind = normalizeCandidateEngagementKind(
    raw.kind || raw.type || raw.eventType || raw.event_type,
  );
  if (!kind) {
    return null;
  }
  const target =
    raw.target && typeof raw.target === "object" ? raw.target : raw;
  const postId = normalizeString(target.postId || target.post_id || raw.postId);
  const comments = readArrayPayload(raw, ["comments"])
    .map((comment) => normalizeCandidateEngagementComment(comment, postId))
    .filter((comment) => comment.commentId || comment.text);
  const children = readArrayPayload(raw, ["children"])
    .map(normalizeCandidateDashboardEngagementItem)
    .filter(Boolean);
  const handledAt =
    Number(raw.handledAt ?? raw.handled_at ?? raw.resolvedAt) ||
    Date.parse(raw.handledAtIso || raw.resolvedAtIso || "") ||
    null;
  const receivedAt =
    Number(
      raw.receivedAt ??
        raw.received_at ??
        raw.lastEventTs ??
        raw.last_event_ts ??
        raw.createdAt,
    ) ||
    Date.parse(raw.createdAtIso || "") ||
    Math.max(0, ...comments.map((comment) => Number(comment.createdAt) || 0));
  const count =
    Number(raw.count ?? raw.totalCount ?? raw.commentsCount ?? raw.likesCount) ||
    comments.length ||
    children.length ||
    1;
  const parsedComment = normalizeCandidateEngagementComment(raw, postId);
  const primaryComment =
    parsedComment.commentId || parsedComment.text ? parsedComment : comments[0] || null;
  return {
    id:
      normalizeString(raw.id || raw.notificationId || raw.notification_id) ||
      primaryComment?.commentId ||
      `${kind}:${postId || "post"}:${receivedAt || count}`,
    kind,
    postId,
    commentId: normalizeString(target.commentId || target.comment_id),
    count: Math.max(1, count),
    additionalCount: Math.max(0, Number(raw.additionalCount) || count - 1),
    actors: candidateEngagementActorsFromPayload(raw, comments),
    preview: normalizeCandidateEngagementPreview(raw),
    comments: primaryComment && !comments.length ? [primaryComment] : comments,
    children,
    receivedAt,
    handled: raw.handled === true || raw.isHandled === true || Boolean(handledAt),
    handledAt,
    handledByDisplayName: normalizeString(
      raw.handledByDisplayName || raw.handled_by_display_name,
    ),
  };
}

function normalizeCandidateDashboardEngagementPage(raw = {}) {
  const payload = raw && typeof raw === "object" ? raw : {};
  const range = payload.range && typeof payload.range === "object" ? payload.range : {};
  const rawModes =
    payload.availableResponseModes ||
    payload.available_response_modes ||
    payload.responseModes ||
    payload.response_modes ||
    [];
  const modes = Array.isArray(rawModes)
    ? rawModes.map(normalizeCandidateEngagementResponseMode).filter(Boolean)
    : [];
  return {
    items: readArrayPayload(payload, [
      "items",
      "notifications",
      "engagement",
      "data",
    ])
      .map(normalizeCandidateDashboardEngagementItem)
      .filter(Boolean),
    availableResponseModes: Array.from(new Set(modes)),
    defaultResponseMode: normalizeCandidateEngagementResponseMode(
      payload.defaultResponseMode ||
        payload.default_response_mode ||
        payload.responseMode ||
        payload.response_mode,
    ),
    nextCursor:
      normalizeString(payload.cursor || payload.nextCursor || payload.next_cursor) ||
      null,
    rangeDays: Number(range.days ?? payload.days) || 90,
  };
}

function parseMissionTimestamp(...values) {
  for (const value of values) {
    if (value === undefined || value === null || value === "") {
      continue;
    }
    const numeric = Number(value);
    if (Number.isFinite(numeric) && numeric > 0) {
      return numeric;
    }
    const parsed = Date.parse(value);
    if (Number.isFinite(parsed)) {
      return parsed;
    }
  }
  return null;
}

function normalizeMissionScopeType(value) {
  const normalized = normalizeString(value).toLowerCase();
  if (normalized === "campaign") {
    return "candidate";
  }
  if (normalized === "candidate" || normalized === "coalition") {
    return normalized;
  }
  return "";
}

function normalizeMissionCondition(raw = {}) {
  const details = raw && typeof raw === "object" ? raw : {};
  return {
    type: normalizeString(details.type) || "condition",
    label:
      normalizeString(details.label || details.text || details.title) ||
      humanizeLabel(details.type || "condition"),
    status: normalizeString(details.status || details.progressStatus),
    target: Number(details.target || details.count || details.requiredCount) || 0,
    current: Number(details.current || details.completedCount || details.progress) || 0,
    completed: details.completed === true,
    required: details.required !== false,
    jobId: normalizeString(details.jobId || details.requiredJobId),
    metric: normalizeString(details.metric || details.metricKey || details.key),
    outreachType: normalizeString(details.outreachType || details.contactType),
    recordIds: normalizeStringList(
      details.recordIds || details.voterRecordIds || details.records,
    ),
    raw: details,
  };
}

function normalizeMissionArtifact(raw = {}) {
  return {
    artifactId: normalizeString(raw.artifactId || raw.id) || "artifact",
    jobId: normalizeString(raw.jobId),
    fileName: normalizeString(raw.fileName || raw.filename || raw.name) || "File",
    contentType: normalizeString(raw.contentType || raw.type),
    sizeBytes: Number(raw.sizeBytes || raw.size) || 0,
    createdAt: parseMissionTimestamp(raw.createdAt, raw.createdAtIso),
    raw,
  };
}

function normalizeMissionJob(raw = {}) {
  const status =
    normalizeString(raw.status || raw.state).toLowerCase() || "active";
  const priority =
    normalizeString(raw.priority).toLowerCase() || "normal";
  const targetMode = normalizeString(raw.targetMode || raw.mode).toLowerCase();
  const targetRoleLabel =
    normalizeString(raw.targetRoleLabel || raw.roleLabel || raw.targetRoleKey) ||
    "";
  const assigneeDisplayName =
    normalizeString(
      raw.assigneeDisplayName ||
        raw.assigneeName ||
        raw.userDisplayName ||
        raw.assigneeUsername,
    ) || "";
  const artifacts = readArrayPayload(raw, ["artifacts"]).map(
    normalizeMissionArtifact,
  );
  const artifactCount =
    Number(raw.artifactCount || raw.artifactsCount) || artifacts.length;
  const assigneeUserId = normalizeString(raw.assigneeUserId || raw.targetUserId);
  const dueAt = parseMissionTimestamp(raw.dueAt, raw.dueAtIso, raw.deadlineAt);
  const isClosed = [
    "completed",
    "approved",
    "failed",
    "canceled",
    "unassigned",
  ].includes(status);
  const isQueued = status === "queued";
  const isActive = ["active", "late", "needs_changes"].includes(status);
  const isSubmitted = status === "submitted";
  const isBlocked = status === "blocked";
  const isHighPriority = ["high", "urgent"].includes(priority);
  const now = Date.now();
  const isLate =
    status === "late" || (dueAt && !isClosed && dueAt < now) || false;
  const isDueSoon =
    Boolean(dueAt && !isClosed && dueAt > now && dueAt - now <= 86400000);
  return {
    missionId: normalizeString(raw.missionId),
    jobId: normalizeString(raw.jobId || raw.id) || "job",
    title: normalizeString(raw.title || raw.name) || "Mission task",
    description: normalizeString(raw.description || raw.summary),
    status,
    priority,
    targetType: normalizeString(raw.targetType || raw.type),
    targetMode,
    targetRoleKey: normalizeString(raw.targetRoleKey || raw.roleKey),
    targetRoleLabel,
    assigneeUserId,
    assigneeDisplayName,
    assigneeUsername: normalizeString(raw.assigneeUsername || raw.username),
    parentJobId: normalizeString(raw.parentJobId || raw.parentId),
    deadlineMode: normalizeString(raw.deadlineMode),
    dueAt,
    timeoutPolicy: normalizeString(raw.timeoutPolicy),
    artifactCount,
    artifacts,
    startConditions: readArrayPayload(raw, ["startConditions"]).map(
      normalizeMissionCondition,
    ),
    successConditions: readArrayPayload(raw, ["successConditions"]).map(
      normalizeMissionCondition,
    ),
    createdAt: parseMissionTimestamp(raw.createdAt, raw.createdAtIso),
    updatedAt: parseMissionTimestamp(raw.updatedAt, raw.updatedAtIso),
    claimedAt: parseMissionTimestamp(raw.claimedAt, raw.claimedAtIso),
    lastStartedAt: parseMissionTimestamp(
      raw.lastStartedAt,
      raw.lastStartedAtIso,
      raw.startedAt,
    ),
    submittedAt: parseMissionTimestamp(raw.submittedAt, raw.submittedAtIso),
    completedAt: parseMissionTimestamp(raw.completedAt, raw.completedAtIso),
    isQueued,
    isActive,
    isSubmitted,
    isBlocked,
    isClosed,
    isHighPriority,
    isLate,
    isDueSoon,
    isAttention: ["late", "blocked", "submitted", "needs_changes"].includes(
      status,
    ) || isLate,
    isClaimable:
      targetMode === "role_claim" &&
      !assigneeUserId &&
      !isQueued &&
      !isClosed,
    raw,
  };
}

function normalizeMissionEvent(raw = {}) {
  return {
    eventId: normalizeString(raw.eventId || raw.id) || "event",
    type: normalizeString(raw.type || raw.eventType) || "mission_updated",
    actorUserId: normalizeString(raw.actorUserId || raw.userId),
    createdAt: parseMissionTimestamp(raw.createdAt, raw.createdAtIso),
    details: raw.details && typeof raw.details === "object" ? raw.details : {},
    raw,
  };
}

function normalizeMission(raw = {}) {
  const jobs = readArrayPayload(raw, ["jobs", "visibleJobs", "tasks"]).map(
    normalizeMissionJob,
  );
  const assignedCount =
    Number(raw.assignedCount || raw.assignmentCount) ||
    jobs.filter((job) => job.assigneeUserId).length;
  const dueDates = jobs.map((job) => job.dueAt).filter(Boolean);
  const status =
    normalizeString(raw.status || raw.state).toLowerCase() || "active";
  const priority =
    normalizeString(raw.priority).toLowerCase() || "normal";
  return {
    missionId: normalizeString(raw.missionId || raw.id) || "mission",
    scopeType: normalizeMissionScopeType(raw.scopeType || raw.scope),
    scopeId: normalizeString(raw.scopeId || raw.candidateId || raw.coalitionId),
    scopeName: normalizeString(
      raw.scopeName ||
        raw.workspaceName ||
        raw.candidateName ||
        raw.coalitionName,
    ),
    title: normalizeString(raw.title || raw.name) || "Mission",
    description: normalizeString(raw.description || raw.summary),
    status,
    priority,
    leadUserId: normalizeString(raw.leadUserId),
    source: raw.source && typeof raw.source === "object" ? raw.source : null,
    templateId: normalizeString(raw.templateId),
    templateVersion: Number(raw.templateVersion) || null,
    jobs,
    recentEvents: readArrayPayload(raw, ["recentEvents"]).map(
      normalizeMissionEvent,
    ),
    assignedCount,
    openCount: jobs.filter((job) => !job.isClosed).length,
    attentionCount: jobs.filter((job) => job.isAttention).length,
    claimableCount: jobs.filter((job) => job.isClaimable).length,
    completedCount: jobs.filter((job) =>
      ["completed", "approved"].includes(job.status),
    ).length,
    dueAt:
      parseMissionTimestamp(raw.dueAt, raw.dueAtIso, raw.deadlineAt) ||
      (dueDates.length ? Math.min(...dueDates) : null),
    createdAt: parseMissionTimestamp(raw.createdAt, raw.createdAtIso),
    updatedAt: parseMissionTimestamp(raw.updatedAt, raw.updatedAtIso),
    raw,
  };
}

function readMissionListFilters() {
  const params = readCurrentSearchParams();
  const scopeType = normalizeMissionScopeType(params.get("scopeType"));
  const scopeId = normalizeString(params.get("scopeId"));
  const view = normalizeString(params.get("view")).toLowerCase() || "mine";
  const status = normalizeString(params.get("status")).toLowerCase();
  const q = normalizeString(params.get("q"));
  return {
    scopeType,
    scopeId,
    view: ["mine", "attention", "admin"].includes(view) ? view : "mine",
    status,
    q,
  };
}

function missionListFilterKey(filters = readMissionListFilters()) {
  return [
    filters.scopeType,
    filters.scopeId,
    filters.view,
    filters.status,
    filters.q,
  ].join("|");
}

function missionListScopeKey(filters = readMissionListFilters()) {
  return [filters.scopeType, filters.scopeId].join("|");
}

function buildMissionsRoute(filters = {}) {
  const params = new URLSearchParams();
  const scopeType = normalizeMissionScopeType(filters.scopeType);
  const scopeId = normalizeString(filters.scopeId);
  if (scopeType && scopeId) {
    params.set("scopeType", scopeType);
    params.set("scopeId", scopeId);
  }
  const view = normalizeString(filters.view);
  if (view && view !== "mine") {
    params.set("view", view);
  }
  const status = normalizeString(filters.status);
  if (status) {
    params.set("status", status);
  }
  const q = normalizeString(filters.q);
  if (q) {
    params.set("q", q);
  }
  return `/missions${params.toString() ? `?${params.toString()}` : ""}`;
}

function missionScopeLabel(scopeType, scopeId = "") {
  const type = normalizeMissionScopeType(scopeType);
  if (type === "candidate") {
    const access = findCandidateDashboardAccess(scopeId);
    return (
      normalizeString(access?.profile?.displayName) ||
      "Campaign mission hub"
    );
  }
  if (type === "coalition") {
    const item = findCoalitionListItem(scopeId);
    return normalizeString(item?.coalition?.name) || "Coalition mission hub";
  }
  return "Mission hub";
}

function missionScopeDisplayName(mission) {
  return (
    normalizeString(mission?.scopeName) ||
    missionScopeLabel(mission?.scopeType, mission?.scopeId)
  );
}

function missionScopeWorkspacePath(scopeType, scopeId = "", section = "missions") {
  const type = normalizeMissionScopeType(scopeType);
  const normalizedId = normalizeString(scopeId);
  if (type === "candidate") {
    return candidateDashboardSectionPath(normalizedId, section);
  }
  if (type === "coalition") {
    return coalitionSectionPath(normalizedId, section);
  }
  return "/missions";
}

function missionMatchesListFilters(mission, filters) {
  if (!mission) {
    return false;
  }
  const status = normalizeString(filters.status);
  if (status && status !== "all") {
    const missionFilterStatuses = new Set([
      "attention",
      "claimable",
      "new",
      "upcoming",
      "high",
      "soon",
      "queued",
      "active",
      "completed",
      "failed",
      "canceled",
    ]);
    if (missionFilterStatuses.has(status)) {
      if (!filterCandidateMissions([mission], status).length) return false;
    } else if (mission.status !== status && !mission.jobs.some((job) => job.status === status)) {
      return false;
    }
  }
  const q = normalizeString(filters.q).toLowerCase();
  if (!q) {
    return true;
  }
  return [
    mission.title,
    mission.description,
    mission.scopeType,
    mission.jobs.map((job) => `${job.title} ${job.description}`).join(" "),
  ]
    .join(" ")
    .toLowerCase()
    .includes(q);
}

function resetMissionDetail() {
  const detail = state.pages.missions.detail;
  detail.item = null;
  detail.events = [];
  detail.viewer = null;
  detail.loading = false;
  detail.error = "";
  detail.loaded = false;
  detail.actionPendingKey = "";
  detail.actionDraft = null;
}

async function loadMissionsList({ refresh = false } = {}) {
  const list = state.pages.missions.list;
  const filters = readMissionListFilters();
  const filterKey = missionListFilterKey(filters);
  const scopeKey = missionListScopeKey(filters);
  if (list.loading) {
    return;
  }
  if (list.loaded && list.filterKey === filterKey && !refresh) {
    return;
  }
  if (list.scopeKey !== scopeKey) {
    list.createOpen = false;
    list.createDraft = null;
    list.actionPendingKey = "";
  }
  if (refresh || list.filterKey !== filterKey) {
    list.items = [];
    list.nextCursor = null;
    list.loaded = false;
  }
  list.filters = filters;
  list.filterKey = filterKey;
  list.scopeKey = scopeKey;
  list.loading = true;
  list.error = "";
  scheduleRender();

  try {
    if (!filters.scopeType || !filters.scopeId) {
      await Promise.all([
        loadCandidateDashboardCampaigns({ refresh }),
        loadCoalitionsList({ refresh }),
      ]);
      list.loaded = true;
      return;
    }
    const query = new URLSearchParams({
      scopeType: filters.scopeType,
      scopeId: filters.scopeId,
      view: filters.view,
    });
    const payload = await fetchJson(`/api/missions?${query.toString()}`, {
      auth: true,
    });
    list.items = readArrayPayload(payload, ["items", "missions"]).map(
      normalizeMission,
    );
    list.loaded = true;
  } catch (error) {
    list.error =
      normalizeString(error?.message) || "Missions could not be loaded.";
  } finally {
    list.loading = false;
    scheduleRender();
  }
}

async function loadMissionDetail(missionId, { refresh = false } = {}) {
  const normalizedMissionId = decodeRouteSegment(missionId);
  if (!normalizedMissionId) {
    return;
  }
  const detail = state.pages.missions.detail;
  if (detail.loading) {
    return;
  }
  if (
    refresh ||
    normalizeString(detail.item?.missionId) !== normalizedMissionId
  ) {
    resetMissionDetail();
  }
  if (detail.loaded && !refresh) {
    return;
  }
  detail.loading = true;
  detail.error = "";
  scheduleRender();

  try {
    const encodedId = encodeURIComponent(normalizedMissionId);
    const payload = await fetchJson(`/api/missions/${encodedId}`, {
      auth: true,
    });
    detail.item = normalizeMission(payload.mission || payload);
    detail.events = readArrayPayload(payload, ["events"]).map(
      normalizeMissionEvent,
    );
    detail.viewer =
      payload.viewer && typeof payload.viewer === "object"
        ? {
            admin: payload.viewer.admin === true,
            canManage: payload.viewer.canManage === true,
            canAssign: payload.viewer.canAssign === true,
            canApprove: payload.viewer.canApprove === true,
          }
        : null;
    detail.loaded = true;
  } catch (error) {
    detail.error =
      normalizeString(error?.message) || "Mission could not be loaded.";
  } finally {
    detail.loading = false;
    scheduleRender();
  }
}

async function claimMissionJob(missionId, jobId) {
  const normalizedMissionId = normalizeString(missionId);
  const normalizedJobId = normalizeString(jobId);
  if (!normalizedMissionId || !normalizedJobId) {
    showToast("Mission job unavailable.");
    return;
  }
  const detail = state.pages.missions.detail;
  const list = state.pages.missions.list;
  const pendingKey = `${normalizedMissionId}:${normalizedJobId}:claim`;
  if (detail.actionPendingKey || list.actionPendingKey) {
    return;
  }
  detail.actionPendingKey = pendingKey;
  list.actionPendingKey = pendingKey;
  scheduleRender();

  try {
    await fetchJson(
      `/api/missions/${encodeURIComponent(normalizedMissionId)}/jobs/${encodeURIComponent(normalizedJobId)}/actions`,
      {
        auth: true,
        method: "POST",
        body: { action: "claim" },
      },
    );
    showToast("Mission task claimed.");
    await loadMissionDetail(normalizedMissionId, { refresh: true });
    const filters = readMissionListFilters();
    if (filters.scopeType && filters.scopeId) {
      await loadMissionsList({ refresh: true });
    }
  } catch (error) {
    showToast(normalizeString(error?.message) || "Could not claim task.");
  } finally {
    detail.actionPendingKey = "";
    if (list.actionPendingKey === pendingKey) {
      list.actionPendingKey = "";
    }
    scheduleRender();
  }
}

function missionDetailViewerCanManage(detail = state.pages.missions.detail) {
  const viewer = detail?.viewer || {};
  return Boolean(
    viewer.admin ||
      viewer.canManage ||
      viewer.canAssign ||
      viewer.canApprove,
  );
}

function missionJobIsMine(job = {}) {
  const currentUserId = normalizeString(state.auth?.user?.userId);
  return Boolean(
    currentUserId &&
      normalizeString(job.assigneeUserId) &&
      normalizeString(job.assigneeUserId) === currentUserId,
  );
}

function missionJobRequiresApproval(job = {}) {
  const approvalTypes = new Set([
    "required_approval",
    "manual_approval",
    "job_approved",
  ]);
  return (job.successConditions || []).some((condition) =>
    approvalTypes.has(normalizeString(condition.type).toLowerCase()),
  );
}

function missionJobMissingRequiredUpload(job = {}) {
  if (job.artifactCount > 0 || (job.artifacts || []).length) {
    return false;
  }
  return (job.successConditions || []).some((condition) =>
    ["required_upload", "artifact_uploaded"].includes(
      normalizeString(condition.type).toLowerCase(),
    ),
  );
}

function missionJobHasRequiredNote(job = {}) {
  return (job.successConditions || []).some(
    (condition) =>
      normalizeString(condition.type).toLowerCase() === "required_note",
  );
}

function missionJobFirstUnmetTrackedCondition(job = {}) {
  return (job.successConditions || []).find((condition) => {
    const type = normalizeString(condition.type).toLowerCase();
    return (
      ["campaign_quest_metric", "voter_map_batch_completed"].includes(type) &&
      normalizeString(condition.status || condition.progressStatus).toLowerCase() ===
        "ready" &&
      condition.completed !== true
    );
  });
}

function missionJobCompletionBlocker(job = {}) {
  if (missionJobMissingRequiredUpload(job)) {
    return "Upload the required file before submitting.";
  }
  const trackedCondition = missionJobFirstUnmetTrackedCondition(job);
  if (trackedCondition) {
    return `Finish tracked progress: ${missionConditionText(trackedCondition)}.`;
  }
  return "";
}

function missionJobCompletionGuidance(job = {}) {
  const messages = [];
  const blocker = missionJobCompletionBlocker(job);
  if (blocker) {
    messages.push(blocker);
  }
  if (missionJobHasRequiredNote(job)) {
    messages.push("Add a note when you submit.");
  }
  if (missionJobRequiresApproval(job)) {
    messages.push("A reviewer will approve this before it is marked complete.");
  }
  return messages;
}

