function missionJobActionPendingKey(missionId, jobId, action) {
  return `${normalizeString(missionId)}:${normalizeString(jobId)}:${normalizeString(action)}`;
}

function openMissionJobActionDraft({ missionId, jobId, action, noteRequired = false }) {
  const normalizedMissionId = normalizeString(missionId);
  const normalizedJobId = normalizeString(jobId);
  const normalizedAction = normalizeString(action).toLowerCase();
  if (!normalizedMissionId || !normalizedJobId || !normalizedAction) {
    showToast("Mission action unavailable.");
    return;
  }
  state.pages.missions.detail.actionDraft = {
    missionId: normalizedMissionId,
    jobId: normalizedJobId,
    action: normalizedAction,
    noteRequired: noteRequired === true,
  };
  scheduleRender();
}

function closeMissionJobActionDraft() {
  state.pages.missions.detail.actionDraft = null;
  scheduleRender();
}

async function runMissionJobAction({
  missionId,
  jobId,
  action,
  note = "",
  extra = null,
}) {
  const normalizedMissionId = normalizeString(missionId);
  const normalizedJobId = normalizeString(jobId);
  const normalizedAction = normalizeString(action).toLowerCase();
  if (!normalizedMissionId || !normalizedJobId || !normalizedAction) {
    showToast("Mission action unavailable.");
    return false;
  }
  const detail = state.pages.missions.detail;
  const list = state.pages.missions.list;
  const pendingKey = missionJobActionPendingKey(
    normalizedMissionId,
    normalizedJobId,
    normalizedAction,
  );
  if (detail.actionPendingKey) {
    return false;
  }
  detail.actionPendingKey = pendingKey;
  scheduleRender();
  try {
    const body = {
      action: normalizedAction,
    };
    const normalizedNote = normalizeString(note);
    if (normalizedNote) {
      body.note = normalizedNote;
    }
    if (extra && typeof extra === "object" && !Array.isArray(extra)) {
      Object.assign(body, extra);
    }
    await fetchJson(
      `/api/missions/${encodeURIComponent(normalizedMissionId)}/jobs/${encodeURIComponent(normalizedJobId)}/actions`,
      {
        auth: true,
        method: "POST",
        body,
      },
    );
    const config = missionJobActionConfig(normalizedAction);
    showToast(config.toast || "Mission task updated.");
    detail.actionDraft = null;
    await loadMissionDetail(normalizedMissionId, { refresh: true });
    const filters = readMissionListFilters();
    if (filters.scopeType && filters.scopeId) {
      await loadMissionsList({ refresh: true });
    }
    return true;
  } catch (error) {
    showToast(normalizeString(error?.message) || "Mission action failed.");
    return false;
  } finally {
    detail.actionPendingKey = "";
    if (list.actionPendingKey === pendingKey) {
      list.actionPendingKey = "";
    }
    scheduleRender();
  }
}

async function submitMissionJobAction(formData) {
  const action = normalizeString(formData.get("action")).toLowerCase();
  const note = normalizeString(formData.get("note"));
  const required = normalizeString(formData.get("noteRequired")) === "true";
  if (required && !note) {
    showToast("Add a note before continuing.");
    return false;
  }
  return runMissionJobAction({
    missionId: formData.get("missionId"),
    jobId: formData.get("jobId"),
    action,
    note,
  });
}

function missionFollowUpStartConditions(startWhen, startDelayHours) {
  if (normalizeString(startWhen).toLowerCase() !== "time_reached") {
    return [];
  }
  const hours = Math.max(1, Number(startDelayHours) || 1);
  return [
    {
      type: "time_reached",
      at: new Date(Date.now() + hours * 3600000).toISOString(),
      label: "Scheduled start",
    },
  ];
}

function missionFollowUpPayloadFromForm(formData) {
  const parentJobId = normalizeString(formData.get("parentJobId"));
  const title = normalizeString(formData.get("title"));
  const assignee = normalizeString(formData.get("assignee"));
  const targetMode = normalizeString(formData.get("targetMode")) || "user";
  const priority =
    normalizeString(formData.get("priority")).toLowerCase() || "normal";
  const presetKey =
    normalizeString(formData.get("presetKey")).toLowerCase() || "general";
  const startWhen =
    normalizeString(formData.get("startWhen")).toLowerCase() ||
    "parent_completed";
  if (!parentJobId || !title || !assignee) {
    return null;
  }
  const startConditions = missionFollowUpStartConditions(
    startWhen,
    formData.get("startDelayHours"),
  );
  return {
    parentJobId,
    startWhen,
    ...(startConditions.length ? { startConditions } : {}),
    title,
    description: normalizeString(formData.get("description")),
    priority,
    target: candidateMissionTargetPayload(targetMode, assignee),
    deadline: candidateMissionDeadlinePayload(
      formData.get("deadlineMode"),
      formData.get("dueHours"),
    ),
    timeout: candidateMissionTimeoutPayload(
      formData.get("timeoutPolicy"),
      formData.get("timeoutHours"),
    ),
    successConditions: missionPresetSuccessConditions(presetKey),
  };
}

async function createMissionFollowUpJob(formData) {
  const missionId = normalizeString(formData.get("missionId"));
  const payload = missionFollowUpPayloadFromForm(formData);
  const detail = state.pages.missions.detail;
  if (!missionId || !payload) {
    showToast("Follow-up title and owner are required.");
    return false;
  }
  const pendingKey = `${missionId}:${payload.parentJobId}:follow-up`;
  if (detail.followUpPendingKey || detail.actionPendingKey) {
    return false;
  }
  detail.followUpPendingKey = pendingKey;
  detail.error = "";
  scheduleRender();
  try {
    await fetchJson(`/api/missions/${encodeURIComponent(missionId)}/jobs`, {
      auth: true,
      method: "POST",
      body: payload,
    });
    showToast("Follow-up task added.");
    await loadMissionDetail(missionId, { refresh: true });
    const filters = readMissionListFilters();
    if (filters.scopeType && filters.scopeId) {
      await loadMissionsList({ refresh: true });
    }
    return true;
  } catch (error) {
    detail.error =
      normalizeString(error?.message) || "Follow-up task could not be added.";
    showToast(detail.error);
    return false;
  } finally {
    if (detail.followUpPendingKey === pendingKey) {
      detail.followUpPendingKey = "";
    }
    scheduleRender();
  }
}

function missionArtifactFileFromForm(formData) {
  const file = formData.get("artifactFile");
  return file && typeof file === "object" && Number(file.size) > 0
    ? file
    : null;
}

async function uploadMissionArtifact(formData) {
  const missionId = normalizeString(formData.get("missionId"));
  const jobId = normalizeString(formData.get("jobId"));
  const file = missionArtifactFileFromForm(formData);
  const detail = state.pages.missions.detail;
  if (!missionId || !jobId || !file) {
    showToast("Choose a mission file to upload.");
    return false;
  }
  const pendingKey = `${missionId}:${jobId}:artifact-upload`;
  if (detail.artifactPendingKey) {
    return false;
  }
  detail.artifactPendingKey = pendingKey;
  scheduleRender();
  try {
    const fileName = normalizeString(file.name) || "mission-file";
    const contentType = normalizeString(file.type) || "application/octet-stream";
    const payload = await fetchJson(
      `/api/missions/${encodeURIComponent(missionId)}/artifacts/upload-url`,
      {
        auth: true,
        method: "POST",
        body: {
          jobId,
          fileName,
          contentType,
          sizeBytes: Number(file.size) || 0,
        },
      },
    );
    const upload = payload.upload && typeof payload.upload === "object"
      ? payload.upload
      : payload;
    const uploadUrl = normalizeUrl(upload.uploadUrl || upload.url);
    if (!uploadUrl) {
      throw new Error("Mission upload URL was not returned.");
    }
    const response = await fetch(uploadUrl, {
      method: normalizeString(upload.method).toUpperCase() || "PUT",
      headers:
        upload.headers && typeof upload.headers === "object"
          ? upload.headers
          : { "Content-Type": contentType },
      body: file,
    });
    if (!response.ok) {
      throw new Error(`Mission file upload failed: ${response.status}`);
    }
    showToast("Mission file uploaded.");
    await loadMissionDetail(missionId, { refresh: true });
    return true;
  } catch (error) {
    showToast(normalizeString(error?.message) || "Mission file upload failed.");
    return false;
  } finally {
    if (detail.artifactPendingKey === pendingKey) {
      detail.artifactPendingKey = "";
    }
    scheduleRender();
  }
}

async function openMissionArtifact(missionId, artifactId) {
  const normalizedMissionId = normalizeString(missionId);
  const normalizedArtifactId = normalizeString(artifactId);
  const detail = state.pages.missions.detail;
  if (!normalizedMissionId || !normalizedArtifactId) {
    showToast("Mission file unavailable.");
    return;
  }
  const pendingKey = `${normalizedMissionId}:${normalizedArtifactId}:artifact-open`;
  if (detail.artifactPendingKey) {
    return;
  }
  detail.artifactPendingKey = pendingKey;
  scheduleRender();
  try {
    const payload = await fetchJson(
      `/api/missions/${encodeURIComponent(normalizedMissionId)}/artifacts/${encodeURIComponent(normalizedArtifactId)}/download-url`,
      { auth: true },
    );
    const url = normalizeUrl(payload.downloadUrl || payload.url);
    if (!url) {
      throw new Error("Mission file URL was not returned.");
    }
    window.open(url, "_blank", "noopener,noreferrer");
  } catch (error) {
    showToast(normalizeString(error?.message) || "Mission file could not be opened.");
  } finally {
    if (detail.artifactPendingKey === pendingKey) {
      detail.artifactPendingKey = "";
    }
    scheduleRender();
  }
}

async function openMissionLeadMessage(leadUserId) {
  const normalizedLeadUserId = normalizeString(leadUserId);
  if (!normalizedLeadUserId) {
    showToast("Mission lead unavailable.");
    return;
  }
  await createMessagingDmFromTarget({ recipientId: normalizedLeadUserId });
}

function candidateDashboardSectionForRoute(route = state.route) {
  const section = normalizeString(route?.routeParams?.section).toLowerCase();
  return (
    CANDIDATE_DASHBOARD_SECTION_CONFIG.some((item) => item.key === section)
      ? section
      : CANDIDATE_DASHBOARD_DEFAULT_SECTION
  );
}

function candidateDashboardSectionPath(candidateId, sectionKey = "") {
  const encodedId = encodeURIComponent(normalizeString(candidateId));
  if (!encodedId) {
    return "/candidate-dashboard";
  }
  const section = normalizeString(sectionKey);
  if (!section || section === CANDIDATE_DASHBOARD_DEFAULT_SECTION) {
    return `/candidate-dashboard/${encodedId}`;
  }
  return `/candidate-dashboard/${encodedId}/${encodeURIComponent(section)}`;
}

function isCandidateVoterMapRoute(route = state.route) {
  const routeKey = normalizeString(route?.routeKey);
  return (
    routeKey === ROUTE_KEY_CANDIDATE_VOTER_MAP ||
    routeKey === ROUTE_KEY_CANDIDATE_VOTER_MAP_SECTION
  );
}

function candidateVoterMapSectionForRoute(route = state.route) {
  if (!isCandidateVoterMapRoute(route)) {
    return "";
  }
  const section = decodeRouteSegment(route?.routeParams?.voterMapSection)
    .replace(/^\/+|\/+$/gu, "")
    .toLowerCase();
  if (!section) {
    return "menu";
  }
  if (section === "territories" || section === "territory-admin") {
    return "territories/admin";
  }
  return (
    CANDIDATE_VOTER_MAP_SECTION_CONFIG.some((item) => item.key === section)
      ? section
      : "menu"
  );
}

function candidateVoterMapRouteCandidateId() {
  const queryCandidateId = normalizeString(readCurrentSearchParams().get("candidateId"));
  if (queryCandidateId) {
    return queryCandidateId;
  }
  const selected = normalizeString(state.pages.candidateDashboard.selectedCandidateId);
  if (selected) {
    return selected;
  }
  const campaigns = state.pages.candidateDashboard.campaigns.items || [];
  if (campaigns.length === 1) {
    return normalizeString(campaigns[0].candidateId);
  }
  return "";
}

function candidateVoterMapPath(sectionKey = "", candidateId = "") {
  const normalizedSection = normalizeString(sectionKey).replace(/^\/+|\/+$/gu, "");
  const normalizedCandidateId = normalizeString(candidateId);
  const path = normalizedSection
    ? `/candidate/voter-map/${encodeURI(normalizedSection)}`
    : "/candidate/voter-map";
  if (!normalizedCandidateId) {
    return path;
  }
  const query = new URLSearchParams({ candidateId: normalizedCandidateId });
  return `${path}?${query.toString()}`;
}

function candidateMessagingServerPath(candidateId, suffix = "") {
  const encodedId = encodeURIComponent(normalizeString(candidateId));
  if (!encodedId) {
    return "/messages";
  }
  const normalizedSuffix = normalizeString(suffix);
  return `/messages/servers/campaign/${encodedId}${normalizedSuffix.startsWith("/") ? normalizedSuffix : normalizedSuffix ? `/${normalizedSuffix}` : ""}`;
}

function candidateDashboardPermissionSet(access = null) {
  return new Set(normalizeCandidateDashboardPermissions(access?.permissions));
}

function canManageCandidateMessaging(access = null) {
  if (access?.isOwner) {
    return true;
  }
  return candidateDashboardPermissionSet(access).has("messaging_manage");
}

function hasCandidateVoterMapAccess(access = null) {
  if (access?.isOwner) {
    return true;
  }
  const permissions = candidateDashboardPermissionSet(access);
  return (
    permissions.has("voter_map_manager") ||
    permissions.has("voter_map_territory")
  );
}

function canOpenCandidateVoterMap(access = null, candidate = null) {
  if (!hasCandidateVoterMapAccess(access)) {
    return false;
  }
  return candidate?.voterMapEnabled !== false;
}

function canManageCandidateStaff(access = null) {
  if (access?.isOwner) {
    return true;
  }
  return candidateDashboardPermissionSet(access).has("staff");
}

function canViewCandidateCalendarDetails(access = null) {
  if (access?.isOwner) {
    return true;
  }
  const permissions = candidateDashboardPermissionSet(access);
  return permissions.has("calendar_view_details");
}

function canCreateCandidateCalendarItems(access = null) {
  if (access?.isOwner) {
    return true;
  }
  const permissions = candidateDashboardPermissionSet(access);
  return (
    permissions.has("calendar_create_direct") ||
    permissions.has("calendar_create_draft") ||
    permissions.has("calendar_manage_promotion")
  );
}

function canApproveCandidateCalendarItems(access = null) {
  if (access?.isOwner) {
    return true;
  }
  return candidateDashboardPermissionSet(access).has("calendar_approve");
}

function canManageCandidateCalendarIntegrations(access = null) {
  if (access?.isOwner) {
    return true;
  }
  return candidateDashboardPermissionSet(access).has(
    "calendar_manage_integrations",
  );
}

function canManageCandidatePublicBooking(access = null) {
  if (access?.isOwner) {
    return true;
  }
  return candidateDashboardPermissionSet(access).has("calendar_public_booking");
}

function canOpenCandidateDashboardSection(section, access = null) {
  if (!section) {
    return false;
  }
  if (section.key === CANDIDATE_DASHBOARD_DEFAULT_SECTION) {
    return true;
  }
  if (access?.isOwner) {
    return true;
  }
  if (section.ownerOnly) {
    return false;
  }
  const permissions = candidateDashboardPermissionSet(access);
  return (section.permissions || []).some((permission) =>
    permissions.has(normalizeCandidateDashboardPermission(permission)),
  );
}

function normalizeProfile(raw = {}) {
  const links = Array.isArray(raw.links) ? raw.links : [];
  return {
    userId: normalizeString(raw.userId),
    displayName:
      normalizeString(raw.displayName || raw.username || raw.email) ||
      "Polis user",
    username: normalizeString(raw.username),
    avatarUrl: normalizeUrl(raw.avatarUrl),
    bio: normalizeString(raw.bio),
    town: normalizeString(raw.town || raw.city),
    state: normalizeString(raw.state || raw.homeStateId),
    district: normalizeString(raw.district || raw.locationDistrictId),
    followersCount: Number(raw.followersCount) || 0,
    followingCount: Number(raw.followingCount) || 0,
    friendCount: Number(raw.friendCount || raw.friendsCount) || 0,
    totalLikes: Number(raw.totalLikes) || 0,
    isFollowing: raw.isFollowing === true,
    candidateAccessStatus: normalizeString(raw.candidateAccessStatus || raw.candidate_access_status),
    links,
  };
}

function normalizeNotification(raw = {}) {
  return {
    notificationId:
      normalizeString(raw.notificationId || raw.id || raw.eventId) || "",
    title: normalizeString(raw.title || raw.headline) || "Notification",
    body: normalizeString(raw.body || raw.message || raw.description),
    createdAt: Number(raw.createdAt || raw.timestamp) || null,
    readAt: Number(raw.readAt) || null,
    route: normalizeString(raw.route || raw.path),
    raw,
  };
}

function normalizeMessagingConversation(raw = {}) {
  const participants = Array.isArray(raw.participants)
    ? raw.participants.map((participant) => ({
        userId: normalizeString(participant.userId || participant.id),
        displayName: normalizeString(
          participant.displayName || participant.name,
        ),
        username: normalizeString(participant.username || participant.handle),
        avatarUrl: normalizeUrl(participant.avatarUrl || participant.imageUrl),
        role: normalizeString(
          participant.role || participant.memberRole || participant.groupRole,
        ),
        isFriend: participant.isFriend === true || participant.friend === true,
        raw: participant,
      }))
    : [];
  const rawRoomPermissions =
    raw.roomPermissions &&
    typeof raw.roomPermissions === "object" &&
    !Array.isArray(raw.roomPermissions)
      ? raw.roomPermissions
      : {};
  const roomPermissions = Object.entries(rawRoomPermissions).reduce(
    (permissions, [key, value]) => ({
      ...permissions,
      [normalizeString(key)]: value !== false,
    }),
    {},
  );
  return {
    conversationId: normalizeString(raw.conversationId || raw.id),
    title:
      normalizeString(raw.title || raw.displayTitle || raw.label) ||
      "Conversation",
    subtitle: normalizeString(
      raw.subtitle || raw.previewText || raw.lastMessagePreview,
    ),
    kind: normalizeString(raw.kind || raw.type || "dm"),
    folder: normalizeString(raw.folder || raw.listType || "inbox"),
    isEncrypted: raw.isEncrypted === true,
    unreadCount: Number(raw.unreadCount) || 0,
    updatedAt: Number(raw.updatedAt || raw.lastMessageAt || raw.createdAt) || 0,
    participantCount: Number(raw.participantCount || raw.memberCount) || participants.length,
    lastMessagePreview:
      normalizeString(raw.lastMessagePreview || raw.previewText) ||
      (raw.isEncrypted === true ? "Encrypted message" : ""),
    avatarUrl: normalizeUrl(raw.avatarUrl || raw.imageUrl || raw.avatar),
    scopeType: normalizeString(raw.scopeType),
    scopeId: normalizeString(raw.scopeId),
    canManage: raw.canManage === true,
    canManageMembers:
      raw.canManageMembers === true ||
      raw.canManageGroup === true ||
      raw.canManage === true,
    isReadOnly: raw.isReadOnly === true || raw.readOnly === true,
    roomPermissions,
    participants,
    members: Array.isArray(raw.members) ? raw.members : participants,
    raw,
  };
}

function normalizeMessagingReaction(raw = {}) {
  const source =
    raw && typeof raw === "object" && !Array.isArray(raw)
      ? raw
      : { emoji: raw };
  const emoji =
    normalizeString(source.emoji || source.reaction || source.key) ||
    normalizeString(raw);
  const users = Array.isArray(source.users)
    ? source.users
    : Array.isArray(source.userIds)
      ? source.userIds
      : [];
  const currentUserId = normalizeString(state.auth?.user?.userId);
  return {
    emoji,
    count: Math.max(
      1,
      Number(source.count || source.total || source.reactionCount) ||
        users.length ||
        1,
    ),
    reactedByMe:
      source.reactedByMe === true ||
      source.viewerReacted === true ||
      source.me === true ||
      (currentUserId &&
        users.some((user) => normalizeString(user?.userId || user) === currentUserId)),
  };
}

function normalizeMessagingSeenByEntry(raw = {}) {
  const source =
    raw && typeof raw === "object" && !Array.isArray(raw) ? raw : {};
  const userId = normalizeString(source.userId || source.id || source.viewerId);
  const username = normalizeString(source.username || source.handle).replace(
    /^@/u,
    "",
  );
  const displayName =
    normalizeString(source.displayName || source.name || source.title) ||
    username ||
    userId;
  const seenAt =
    Number(source.seenAt || source.timestamp || source.createdAt) ||
    Date.parse(normalizeString(source.seenAtIso || source.createdAtIso)) ||
    null;
  return {
    userId,
    username,
    displayName,
    avatarUrl: normalizeUrl(
      source.avatarUrl || source.avatar || source.imageUrl || source.photoUrl,
    ),
    seenAt: Number.isFinite(seenAt) && seenAt > 0 ? seenAt : null,
    raw: source,
  };
}

function normalizeMessagingReplyPreview(raw = null) {
  if (!raw || typeof raw !== "object" || Array.isArray(raw)) {
    return null;
  }
  const sender =
    raw.sender && typeof raw.sender === "object" ? raw.sender : {};
  const messageId = normalizeString(raw.messageId || raw.id);
  if (!messageId) {
    return null;
  }
  return {
    messageId,
    senderId: normalizeString(raw.senderId || raw.senderUserId || sender.userId),
    senderDisplayName: normalizeString(
      raw.senderDisplayName ||
        raw.senderName ||
        raw.displayName ||
        sender.displayName ||
        sender.username,
    ),
    senderUsername: normalizeString(raw.senderUsername || raw.username || sender.username),
    text: normalizeString(raw.text || raw.previewText || raw.body),
    type: normalizeString(raw.type || raw.contentKind || "text"),
    isDeleted: raw.isDeleted === true || raw.deleted === true || Boolean(raw.deletedAt),
  };
}

function messagingReplyPreviewFromMessage(message) {
  if (!message?.messageId) {
    return null;
  }
  return normalizeMessagingReplyPreview({
    messageId: message.messageId,
    senderId: message.senderUserId,
    senderDisplayName: message.senderDisplayName,
    senderUsername: message.senderUsername,
    text: message.isDeleted ? "Message deleted" : message.text,
    type: message.type,
    isDeleted: message.isDeleted,
  });
}

function messagingReplySenderLabel(replyTo = null) {
  const displayName = normalizeString(replyTo?.senderDisplayName);
  if (displayName) {
    return displayName;
  }
  const username = normalizeString(replyTo?.senderUsername);
  if (username) {
    return username.startsWith("@") ? username : `@${username}`;
  }
  return "Message";
}

function messagingReplyTextLabel(replyTo = null) {
  if (replyTo?.isDeleted) {
    return "Original message deleted.";
  }
  return normalizeString(replyTo?.text) || "Message";
}

function normalizeMessagingMessage(raw = {}) {
  const sender =
    raw.sender && typeof raw.sender === "object" ? raw.sender : {};
  const createdAt = Number(raw.createdAt || raw.timestamp) || null;
  const deletedAt = Number(raw.deletedAt || raw.deleted_at) || null;
  const attachments = Array.isArray(raw.attachments)
    ? raw.attachments.map((attachment) => ({
        attachmentId: normalizeString(attachment.attachmentId || attachment.id),
        fileName:
          normalizeString(attachment.fileName || attachment.name) ||
          "Attachment",
        contentType: normalizeString(
          attachment.contentType || attachment.mimeType || attachment.mime,
        ),
        url: normalizeUrl(attachment.url || attachment.downloadUrl),
        thumbnailUrl: normalizeUrl(attachment.thumbnailUrl),
        width: Number(attachment.width) || null,
        height: Number(attachment.height) || null,
        durationMs: Number(attachment.durationMs) || null,
        size: Number(attachment.size) || null,
      }))
    : [];
  const reactions = Array.isArray(raw.reactions)
    ? raw.reactions.map(normalizeMessagingReaction).filter((reaction) => reaction.emoji)
    : [];
  const snapshot =
    raw.snapshot && typeof raw.snapshot === "object" && !Array.isArray(raw.snapshot)
      ? raw.snapshot
      : null;
  const mentions = readArrayPayload(raw, [
    "mentions",
    "textMentions",
    "text_mentions",
  ]).map((mention) => {
    const start = Math.max(0, Number(mention.start) || 0);
    const length =
      Math.max(0, Number(mention.length) || 0) ||
      Math.max(0, (Number(mention.end) || 0) - start);
    const username = normalizeString(mention.username || mention.handle);
    const end =
      Number(mention.end) ||
      (length ? start + length : username ? start + username.length + 1 : start);
    return {
      type: normalizeString(mention.type || mention.mentionType || "user").toLowerCase(),
      userId: normalizeString(mention.userId || mention.id),
      roleId: normalizeString(mention.roleId),
      username,
      displayName:
        normalizeString(mention.displayName || mention.name || mention.label) ||
        username,
      start,
      length: Math.max(0, Number(length) || Math.max(0, end - start)),
      end,
      raw: mention,
    };
  });
  const seenBy = readArrayPayload(raw, [
    "seenBy",
    "seen_by",
    "readBy",
    "read_by",
    "readReceipts",
    "receipts",
    "viewers",
  ])
    .map(normalizeMessagingSeenByEntry)
    .filter((entry) => entry.userId || entry.displayName);
  return {
    messageId: normalizeString(raw.messageId || raw.id),
    conversationId: normalizeString(raw.conversationId),
    senderUserId: normalizeString(
      raw.senderUserId || raw.senderId || raw.userId || sender.userId,
    ),
    senderDisplayName:
      normalizeString(
        raw.senderDisplayName ||
          raw.displayName ||
          raw.username ||
          sender.displayName ||
          sender.username,
      ) || "Polis user",
    senderUsername: normalizeString(raw.senderUsername || sender.username),
    senderAvatarUrl: normalizeUrl(
      raw.senderAvatarUrl || raw.avatarUrl || sender.avatarUrl,
    ),
    text:
      normalizeString(raw.text || raw.body || raw.caption || raw.previewText) ||
      (raw.isEncrypted === true ? "Encrypted message" : ""),
    type: normalizeString(raw.type || raw.contentKind || "text"),
    postId:
      normalizeString(raw.postId) ||
      normalizeString(raw.missionId ? `mission:${raw.missionId}` : ""),
    snapshot,
    createdAt,
    updatedAt: Number(raw.updatedAt || raw.editedAt) || null,
    status: normalizeString(raw.status || raw.deliveryStatus),
    isEncrypted: raw.isEncrypted === true,
    isDeleted: raw.isDeleted === true || raw.deleted === true || Boolean(deletedAt),
    deletedAt,
    isEdited: raw.isEdited === true || Boolean(raw.editedAt),
    canEdit: raw.canEdit === true,
    canEditUntil:
      Number(raw.canEditUntil || raw.can_edit_until) ||
      (createdAt ? createdAt + MESSAGING_MESSAGE_EDIT_WINDOW_MS : null),
    replyTo: normalizeMessagingReplyPreview(raw.replyTo || raw.reply_to),
    attachments,
    reactions,
    mentions,
    seenBy,
    raw,
  };
}

function normalizeMessagingRequest(raw = {}) {
  const destination =
    raw.destination && typeof raw.destination === "object"
      ? raw.destination
      : {};
  const conversation =
    raw.conversation && typeof raw.conversation === "object"
      ? raw.conversation
      : {};
  const inviter =
    raw.inviter && typeof raw.inviter === "object" ? raw.inviter : {};
  const title =
    normalizeString(
      raw.serverTitle ||
        conversation.title ||
        raw.title ||
        inviter.displayName ||
        inviter.username,
    ) || "Request";
  return {
    requestId: normalizeString(raw.requestId || raw.id),
    type: normalizeString(raw.type || "conversation_request"),
    title,
    subtitle:
      normalizeString(
        conversation.subtitle ||
          raw.subtitle ||
          raw.previewText ||
          raw.message ||
          raw.description,
      ) ||
      (normalizeString(raw.type) === "server_invite"
        ? "Open this invite in your workspace."
        : "Review this request."),
    conversationId: normalizeString(
      conversation.conversationId ||
        raw.conversationId ||
        destination.channelId,
    ),
    scopeType: normalizeString(raw.scopeType || destination.scopeType),
    scopeId: normalizeString(raw.scopeId || destination.scopeId),
    channelId: normalizeString(raw.channelId || destination.channelId),
    serverTitle: normalizeString(raw.serverTitle || raw.title),
    inviterName:
      normalizeString(inviter.displayName || inviter.username) || "Polis user",
    createdAt: Number(raw.createdAt || raw.timestamp) || null,
    raw,
  };
}

