function normalizeMessagingAutomodKeywords(value) {
  if (Array.isArray(value)) {
    return value.map((entry) => normalizeString(entry)).filter(Boolean);
  }
  const normalized = normalizeString(value);
  if (!normalized) {
    return [];
  }
  return normalized
    .split(/[\n,]/)
    .map((entry) => normalizeString(entry))
    .filter(Boolean);
}

