function normalizeCandidateDirectoryFeed(value) {
  const normalized = normalizeString(value).toLowerCase();
  return normalized === "officials" ||
    normalized === "elected_officials" ||
    normalized === "elected-officials"
    ? "officials"
    : "candidates";
}

function candidateDirectoryFeedLabel(feed) {
  return normalizeCandidateDirectoryFeed(feed) === "officials"
    ? "elected officials"
    : "candidates";
}

function candidateDirectoryFeedTitle(feed) {
  return normalizeCandidateDirectoryFeed(feed) === "officials"
    ? "Elected official directory"
    : "Candidate directory";
}

function candidateDirectoryFeedDescription(feed) {
  return normalizeCandidateDirectoryFeed(feed) === "officials"
    ? "Browse elected officials, open report cards, review votes, follow offices, and move into congressional bill context from the same web surface."
    : "Browse candidates, follow campaigns, open race profiles, filter by district or tags, and jump into Election Day context from the same web surface.";
}

function candidateDirectoryEmptyMessage(feed) {
  return normalizeCandidateDirectoryFeed(feed) === "officials"
    ? "No elected officials match these filters."
    : "No candidates match these filters.";
}

function candidateDirectoryOptionsFromParams(params = readCurrentSearchParams()) {
  const hideRaw = normalizeString(params.get("hideAutoGenerated")).toLowerCase();
  return {
    feed: normalizeCandidateDirectoryFeed(params.get("feed") || params.get("mode")),
    hideAutoGenerated: ["true", "1", "yes", "on"].includes(hideRaw),
  };
}

function buildCandidateDirectoryRoute(overrides = {}) {
  const params = readCurrentSearchParams();
  const hasOverride = (key) => Object.prototype.hasOwnProperty.call(overrides, key);
  const feed = normalizeCandidateDirectoryFeed(
    hasOverride("feed") ? overrides.feed : params.get("feed"),
  );
  const hideAutoGenerated = hasOverride("hideAutoGenerated")
    ? overrides.hideAutoGenerated === true
    : candidateDirectoryOptionsFromParams(params).hideAutoGenerated;
  return buildRouteWithQuery("/candidates", {
    feed,
    q: params.get("q"),
    level: params.get("level"),
    district: params.get("district"),
    tags: params.get("tags"),
    hideAutoGenerated: hideAutoGenerated ? "true" : "",
  });
}

async function loadCandidateList({ refresh = false } = {}) {
  const list = state.pages.candidates.list;
  if (list.loading || list.loadingMore) {
    return;
  }
  const params = readCurrentSearchParams();
  const directoryOptions = candidateDirectoryOptionsFromParams(params);
  if (refresh) {
    list.items = [];
    list.nextCursor = null;
    list.loaded = false;
  }
  list.filters = {
    ...Object.fromEntries(params.entries()),
    feed: directoryOptions.feed,
    hideAutoGenerated: directoryOptions.hideAutoGenerated,
  };
  list.loading = true;
  list.error = "";
  scheduleRender();

  try {
    const query = new URLSearchParams({
      limit: "24",
      ...(params.get("q") ? { q: params.get("q") } : {}),
      ...(params.get("level") ? { level: params.get("level") } : {}),
      ...(params.get("district") ? { district: params.get("district") } : {}),
      ...(params.get("tags") ? { tags: params.get("tags") } : {}),
      feed: directoryOptions.feed,
      ...(directoryOptions.hideAutoGenerated ? { hideAutoGenerated: "true" } : {}),
    });
    const payload = await fetchJson(`/api/candidates?${query.toString()}`, {
      auth: true,
    });
    list.items = (payload.items || []).map(normalizeCandidate);
    list.nextCursor =
      normalizeString(payload.cursor || payload.nextCursor) || null;
    list.loaded = true;
  } catch (error) {
    list.error =
      normalizeString(error?.message) || "Candidates could not be loaded.";
  } finally {
    list.loading = false;
    scheduleRender();
  }
}

/**
 * Appends the next candidate page while deduplicating repeated cursor results.
 */
async function loadMoreCandidateList() {
  const list = state.pages.candidates.list;
  if (!list.nextCursor || list.loading || list.loadingMore) {
    return;
  }

  const params = readCurrentSearchParams();
  const directoryOptions = candidateDirectoryOptionsFromParams(params);
  const previousCursor = list.nextCursor;
  list.filters = {
    ...Object.fromEntries(params.entries()),
    feed: directoryOptions.feed,
    hideAutoGenerated: directoryOptions.hideAutoGenerated,
  };
  list.loadingMore = true;
  list.error = "";
  scheduleRender();

  try {
    const query = new URLSearchParams({
      limit: "24",
      cursor: previousCursor,
      ...(params.get("q") ? { q: params.get("q") } : {}),
      ...(params.get("level") ? { level: params.get("level") } : {}),
      ...(params.get("district") ? { district: params.get("district") } : {}),
      ...(params.get("tags") ? { tags: params.get("tags") } : {}),
      feed: directoryOptions.feed,
      ...(directoryOptions.hideAutoGenerated ? { hideAutoGenerated: "true" } : {}),
    });
    const payload = await fetchJson(`/api/candidates?${query.toString()}`, {
      auth: true,
    });
    const incoming = (payload.items || []).map(normalizeCandidate);
    const seenKeys = new Set(
      list.items.map(
        (item) =>
          normalizeString(item.candidateId) ||
          normalizeString(item.officialId) ||
          normalizeString(item.entityId) ||
          normalizeString(item.username) ||
          normalizeString(item.displayName),
      ),
    );
    const nextItems = incoming.filter((item) => {
      const candidateKey =
        normalizeString(item.candidateId) ||
        normalizeString(item.officialId) ||
        normalizeString(item.entityId) ||
        normalizeString(item.username) ||
        normalizeString(item.displayName);
      if (!candidateKey || seenKeys.has(candidateKey)) {
        return false;
      }
      seenKeys.add(candidateKey);
      return true;
    });
    const nextCursor =
      normalizeString(payload.cursor || payload.nextCursor) || null;

    list.items = list.items.concat(nextItems);
    list.nextCursor =
      nextCursor === previousCursor && nextItems.length === 0
        ? null
        : nextCursor;
    list.loaded = true;
  } catch (error) {
    list.error =
      normalizeString(error?.message) || "More candidates could not be loaded.";
  } finally {
    list.loadingMore = false;
    scheduleRender();
  }
}

async function loadCandidateDetail(candidateId, { refresh = false } = {}) {
  const detail = state.pages.candidates.detail;
  const normalizedCandidateId = decodeRouteSegment(candidateId);
  if (!normalizedCandidateId) {
    return;
  }
  if (detail.loading) {
    return;
  }
  if (
    refresh ||
    normalizeString(detail.item?.candidateId) !== normalizedCandidateId
  ) {
    detail.item = null;
    detail.posts = [];
    detail.relatedEvents = [];
    detail.avatarUpload = createCandidateAvatarUploadState();
    detail.donationFlow = createCandidateDonationFlowState();
  }
  detail.loading = true;
  detail.error = "";
  scheduleRender();

  try {
    const [candidatePayload, postsPayload, eventsPayload] = await Promise.all([
      fetchJson(
        `/api/candidates/${encodeURIComponent(normalizedCandidateId)}`,
        {
          auth: true,
        },
      ),
      fetchJson(
        `/api/candidates/${encodeURIComponent(normalizedCandidateId)}/posts?limit=12`,
        { auth: true },
      ).catch(() => ({ items: [] })),
      fetchJson(
        `/api/events?hostUserId=${encodeURIComponent(normalizedCandidateId)}&limit=6`,
        { auth: true },
      ).catch(() => ({ items: [] })),
    ]);
    detail.item = normalizeCandidate(
      candidatePayload.candidate || candidatePayload,
    );
    detail.posts = (postsPayload.items || []).map(normalizeFeedItem);
    detail.relatedEvents = (eventsPayload.items || []).map(normalizeEvent);
  } catch (error) {
    detail.error =
      normalizeString(error?.message) || "Candidate page unavailable.";
  } finally {
    detail.loading = false;
    scheduleRender();
  }
}

