function petitionFieldTypeOptions() {
  return [
    ["name", "Name"],
    ["short_text", "Short text"],
    ["long_text", "Long text"],
    ["email", "Email"],
    ["phone", "Phone"],
    ["address", "Address"],
    ["signature", "E-signature"],
    ["checkbox", "Checkbox"],
    ["select", "Select"],
    ["cta_video", "Join CTA video"],
  ];
}

function normalizePetitionFieldType(value) {
  const normalized = normalizeString(value).toLowerCase();
  return petitionFieldTypeOptions().some(([key]) => key === normalized)
    ? normalized
    : "short_text";
}

function normalizePetitionFieldOption(raw = {}) {
  if (typeof raw === "string") {
    const label = normalizeString(raw);
    return label ? { value: label, label } : null;
  }
  if (!raw || typeof raw !== "object") {
    return null;
  }
  const label = normalizeString(raw.label || raw.value);
  const value = normalizeString(raw.value || label);
  return label && value ? { value, label } : null;
}

function normalizePetitionField(raw = {}, index = 0) {
  const type = normalizePetitionFieldType(raw.type);
  const base = createPetitionFieldDraft(type, index);
  const id =
    normalizeString(raw.id).replace(/[^a-zA-Z0-9_-]/g, "") || base.id;
  const optionsSource = Array.isArray(raw.options)
    ? raw.options
    : Array.isArray(raw.config?.options)
      ? raw.config.options
      : [];
  const options = optionsSource
    .map(normalizePetitionFieldOption)
    .filter(Boolean);
  const config = raw.config && typeof raw.config === "object" ? raw.config : {};
  return {
    ...base,
    id,
    type,
    label: normalizeString(raw.label) || base.label,
    required: raw.required === true,
    helpText: normalizeString(raw.helpText),
    order: Number.isFinite(Number(raw.order)) ? Number(raw.order) : index,
    options: type === "select" ? options : [],
    config:
      type === "cta_video"
        ? {
            instructions: normalizeString(
              config.instructions || raw.instructions || raw.helpText,
            ),
            consentCopy:
              normalizeString(config.consentCopy) ||
              "I understand this video response may be used as part of this CTA.",
            maxDurationSeconds: 60,
          }
        : config,
  };
}

function normalizePetitionItem(raw = {}) {
  const source = raw.petition && typeof raw.petition === "object" ? raw.petition : raw;
  const fieldsSource = Array.isArray(source.fieldSchema)
    ? source.fieldSchema
    : Array.isArray(source.fields)
      ? source.fields
      : [];
  return {
    petitionId: normalizeString(source.petitionId || source.id),
    ownerType: normalizeString(source.ownerType),
    ownerId: normalizeString(source.ownerId),
    title: normalizeString(source.title),
    bodyText: normalizeString(source.bodyText),
    status: normalizeString(source.status) || "draft",
    publicSlug: normalizeString(source.publicSlug),
    sharePath: normalizeString(source.sharePath),
    shareUrl: normalizeString(source.shareUrl),
    publishedVersion: Number(source.publishedVersion) || 0,
    fieldSchema: fieldsSource.map((field, index) =>
      normalizePetitionField(field, index),
    ),
    createdAt: normalizeString(source.createdAt),
    updatedAt: normalizeString(source.updatedAt),
    publishedAt: normalizeString(source.publishedAt),
    raw: source,
  };
}

function normalizePetitionResponse(raw = {}) {
  const source =
    raw.response && typeof raw.response === "object" ? raw.response : raw;
  return {
    petitionId: normalizeString(source.petitionId),
    responseId: normalizeString(source.responseId || source.id),
    version: Number(source.version) || 0,
    values: source.values && typeof source.values === "object" ? source.values : {},
    ctaVideos: Array.isArray(source.ctaVideos) ? source.ctaVideos : [],
    duplicateFlags: Array.isArray(source.duplicateFlags)
      ? source.duplicateFlags
      : [],
    reviewStatus: normalizeString(source.reviewStatus) || "clear",
    status: normalizeString(source.status) || "active",
    mergedIntoResponseId: normalizeString(source.mergedIntoResponseId),
    createdAt: normalizeString(source.createdAt),
    updatedAt: normalizeString(source.updatedAt),
    raw: source,
  };
}

function normalizePetitionDuplicateGroup(raw = {}) {
  return {
    key: normalizeString(raw.key),
    type: normalizeString(raw.type) || "duplicate",
    responseIds: normalizeStringList(raw.responseIds),
    count: Number(raw.count) || normalizeStringList(raw.responseIds).length,
  };
}

function petitionWorkspaceForOwner(ownerType) {
  const normalizedOwnerType = normalizeString(ownerType).toLowerCase();
  if (normalizedOwnerType === "coalition") {
    const detail = state.pages.coalitions.detail;
    if (!detail.petitionsWorkspace) {
      detail.petitionsWorkspace = createPetitionsWorkspaceState();
    }
    return detail.petitionsWorkspace;
  }
  const detail = state.pages.candidateDashboard.detail;
  if (!detail.petitionsWorkspace) {
    detail.petitionsWorkspace = createPetitionsWorkspaceState();
  }
  return detail.petitionsWorkspace;
}

function petitionOwnerBasePath(ownerType, ownerId) {
  const normalizedOwnerType = normalizeString(ownerType).toLowerCase();
  const encodedOwnerId = encodeURIComponent(normalizeString(ownerId));
  if (!encodedOwnerId) {
    return "";
  }
  if (normalizedOwnerType === "coalition") {
    return `/api/coalitions/${encodedOwnerId}/petitions`;
  }
  return `/api/candidate-dashboard/petitions?candidateId=${encodedOwnerId}`;
}

function petitionOwnerDetailPath(ownerType, ownerId, petitionId, suffix = "") {
  const normalizedOwnerType = normalizeString(ownerType).toLowerCase();
  const encodedPetitionId = encodeURIComponent(normalizeString(petitionId));
  if (!encodedPetitionId) {
    return "";
  }
  if (normalizedOwnerType === "coalition") {
    const encodedOwnerId = encodeURIComponent(normalizeString(ownerId));
    return `/api/coalitions/${encodedOwnerId}/petitions/${encodedPetitionId}${suffix}`;
  }
  const encodedOwnerId = encodeURIComponent(normalizeString(ownerId));
  return `/api/candidate-dashboard/petitions/${encodedPetitionId}${suffix}?candidateId=${encodedOwnerId}`;
}

function petitionShareUrl(petition) {
  const explicit = normalizeString(petition?.shareUrl);
  if (explicit && explicit.startsWith("http")) {
    return explicit;
  }
  const slug = normalizeString(petition?.publicSlug);
  const path = normalizeString(petition?.sharePath) || (slug ? `/petitions/${slug}` : "");
  return path ? `${window.location.origin}${path}` : "";
}

async function loadPetitionsWorkspace(ownerType, ownerId, { refresh = false } = {}) {
  const workspace = petitionWorkspaceForOwner(ownerType);
  const normalizedOwnerType = normalizeString(ownerType).toLowerCase();
  const normalizedOwnerId = normalizeString(ownerId);
  if (!normalizedOwnerId || workspace.loading) {
    return;
  }
  const ownerChanged =
    workspace.ownerType !== normalizedOwnerType ||
    workspace.ownerId !== normalizedOwnerId;
  if (ownerChanged || refresh) {
    workspace.items = [];
    workspace.selectedPetitionId = "";
    workspace.responses = [];
    workspace.duplicateGroups = [];
    workspace.loaded = false;
    workspace.draft = createPetitionDraft();
  }
  if (workspace.loaded && !refresh && !ownerChanged) {
    scheduleRender();
    return;
  }
  workspace.ownerType = normalizedOwnerType;
  workspace.ownerId = normalizedOwnerId;
  workspace.loading = true;
  workspace.error = "";
  scheduleRender();
  try {
    const payload = await fetchJson(petitionOwnerBasePath(ownerType, ownerId), {
      auth: true,
    });
    workspace.items = readArrayPayload(payload, [
      "items",
      "petitions",
      "forms",
    ]).map(normalizePetitionItem);
    workspace.loaded = true;
    if (!workspace.selectedPetitionId && workspace.items.length) {
      workspace.selectedPetitionId = workspace.items[0].petitionId;
      workspace.draft = createPetitionDraft(workspace.items[0]);
    }
  } catch (error) {
    workspace.error =
      normalizeString(error?.message) || "Petitions could not be loaded.";
  } finally {
    workspace.loading = false;
    scheduleRender();
  }
}

function currentPetitionWorkspaceItem(workspace) {
  const selectedId = normalizeString(workspace?.selectedPetitionId);
  return (
    (workspace?.items || []).find(
      (item) => normalizeString(item.petitionId) === selectedId,
    ) || null
  );
}

function upsertPetitionWorkspaceItem(workspace, item) {
  const normalized = normalizePetitionItem(item);
  if (!normalized.petitionId) {
    return normalized;
  }
  const index = workspace.items.findIndex(
    (entry) => entry.petitionId === normalized.petitionId,
  );
  if (index >= 0) {
    workspace.items[index] = normalized;
  } else {
    workspace.items = [normalized, ...workspace.items];
  }
  workspace.selectedPetitionId = normalized.petitionId;
  workspace.draft = createPetitionDraft(normalized);
  return normalized;
}

async function savePetitionDraft(ownerType, ownerId, formData, { publish = false, close = false } = {}) {
  const workspace = petitionWorkspaceForOwner(ownerType);
  const draft = buildPetitionDraftFromForm(formData, workspace.draft);
  workspace.actionPendingKey = publish ? "publish" : close ? "close" : "save";
  workspace.error = "";
  workspace.notice = "";
  scheduleRender();
  try {
    const existingId = normalizeString(draft.petitionId);
    const payload = {
      title: draft.title,
      bodyText: draft.bodyText,
      fieldSchema: draft.fieldSchema,
      publish,
      close,
      status: close ? "closed" : draft.status,
    };
    const response = await fetchJson(
      existingId
        ? petitionOwnerDetailPath(ownerType, ownerId, existingId)
        : petitionOwnerBasePath(ownerType, ownerId),
      {
        auth: true,
        method: existingId ? "PATCH" : "POST",
        body: payload,
      },
    );
    const saved = upsertPetitionWorkspaceItem(
      workspace,
      response.petition || response.item || response,
    );
    workspace.notice = publish
      ? "Petition published."
      : close
        ? "Petition closed."
        : "Petition saved.";
    showToast(workspace.notice);
    return saved;
  } catch (error) {
    workspace.error =
      normalizeString(error?.message) || "Petition could not be saved.";
    showToast(workspace.error);
    return null;
  } finally {
    workspace.actionPendingKey = "";
    scheduleRender();
  }
}

async function loadPetitionResponses(ownerType, ownerId, petitionId, { refresh = false } = {}) {
  const workspace = petitionWorkspaceForOwner(ownerType);
  const normalizedPetitionId = normalizeString(petitionId);
  if (!normalizedPetitionId || workspace.responsesLoading) {
    return;
  }
  if (
    !refresh &&
    workspace.selectedPetitionId === normalizedPetitionId &&
    workspace.responses.length
  ) {
    scheduleRender();
    return;
  }
  workspace.selectedPetitionId = normalizedPetitionId;
  workspace.responsesLoading = true;
  workspace.error = "";
  scheduleRender();
  try {
    const payload = await fetchJson(
      petitionOwnerDetailPath(
        ownerType,
        ownerId,
        normalizedPetitionId,
        "/responses",
      ),
      { auth: true },
    );
    if (payload.petition) {
      upsertPetitionWorkspaceItem(workspace, payload.petition);
      workspace.selectedPetitionId = normalizedPetitionId;
    }
    workspace.responses = readArrayPayload(payload, [
      "responses",
      "items",
    ]).map(normalizePetitionResponse);
    workspace.duplicateGroups = readArrayPayload(payload, [
      "duplicateGroups",
      "duplicates",
    ]).map(normalizePetitionDuplicateGroup);
  } catch (error) {
    workspace.error =
      normalizeString(error?.message) || "Petition responses could not be loaded.";
  } finally {
    workspace.responsesLoading = false;
    scheduleRender();
  }
}

async function mergePetitionDuplicateGroup(ownerType, ownerId, petitionId, groupKey) {
  const workspace = petitionWorkspaceForOwner(ownerType);
  const group = (workspace.duplicateGroups || []).find(
    (entry) => entry.key === normalizeString(groupKey),
  );
  const responseIds = group?.responseIds || [];
  if (responseIds.length < 2) {
    showToast("Duplicate group unavailable.");
    return;
  }
  const primaryResponseId = responseIds[0];
  const duplicateResponseIds = responseIds.slice(1);
  workspace.actionPendingKey = `merge:${group.key}`;
  scheduleRender();
  try {
    await fetchJson(
      petitionOwnerDetailPath(ownerType, ownerId, petitionId, "/responses/merge"),
      {
        auth: true,
        method: "POST",
        body: { primaryResponseId, duplicateResponseIds },
      },
    );
    showToast("Duplicate responses merged.");
    await loadPetitionResponses(ownerType, ownerId, petitionId, { refresh: true });
  } catch (error) {
    workspace.error =
      normalizeString(error?.message) || "Duplicate responses could not be merged.";
    showToast(workspace.error);
  } finally {
    workspace.actionPendingKey = "";
    scheduleRender();
  }
}

async function deletePetitionResponse(ownerType, ownerId, petitionId, responseId) {
  const workspace = petitionWorkspaceForOwner(ownerType);
  const normalizedResponseId = normalizeString(responseId);
  if (!normalizedResponseId) {
    return;
  }
  workspace.actionPendingKey = `delete:${normalizedResponseId}`;
  scheduleRender();
  try {
    await fetchJson(
      petitionOwnerDetailPath(
        ownerType,
        ownerId,
        petitionId,
        `/responses/${encodeURIComponent(normalizedResponseId)}/delete`,
      ),
      { auth: true, method: "POST", body: {} },
    );
    showToast("Response deleted.");
    await loadPetitionResponses(ownerType, ownerId, petitionId, { refresh: true });
  } catch (error) {
    workspace.error =
      normalizeString(error?.message) || "Response could not be deleted.";
    showToast(workspace.error);
  } finally {
    workspace.actionPendingKey = "";
    scheduleRender();
  }
}

async function downloadPetitionResponsesCsv(ownerType, ownerId, petitionId) {
  const workspace = petitionWorkspaceForOwner(ownerType);
  const path = petitionOwnerDetailPath(
    ownerType,
    ownerId,
    petitionId,
    "/responses/export.csv",
  );
  workspace.actionPendingKey = "csv";
  scheduleRender();
  try {
    const response = await fetch(`${getApiBaseUrl()}${path}`, {
      headers: buildAuthorizedHeaders(state.auth.session),
    });
    if (!response.ok) {
      throw new Error("csv_export_failed");
    }
    const blob = await response.blob();
    const url = window.URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.href = url;
    link.download = `petition-${normalizeString(petitionId) || "responses"}.csv`;
    document.body.appendChild(link);
    link.click();
    link.remove();
    window.URL.revokeObjectURL(url);
  } catch (error) {
    workspace.error =
      normalizeString(error?.message) || "CSV export could not be downloaded.";
    showToast(workspace.error);
  } finally {
    workspace.actionPendingKey = "";
    scheduleRender();
  }
}

async function loadPublicPetitionPage(publicSlug, { refresh = false } = {}) {
  const page = state.pages.petitions.public;
  const slug = decodeRouteSegment(publicSlug);
  if (!slug || page.loading) {
    return;
  }
  const slugChanged = page.publicSlug !== slug;
  if (slugChanged || refresh) {
    Object.assign(page, createPublicPetitionState(), { publicSlug: slug });
  }
  if (page.loaded && !refresh && !slugChanged) {
    scheduleRender();
    return;
  }
  page.loading = true;
  page.error = "";
  scheduleRender();
  try {
    const payload = await fetchJson(`/api/petitions/${encodeURIComponent(slug)}`, {
      auth: false,
    });
    page.item = normalizePetitionItem(payload.petition || payload.item || payload);
    page.loaded = true;
  } catch (error) {
    page.error =
      normalizeString(error?.message) || "Petition could not be loaded.";
  } finally {
    page.loading = false;
    scheduleRender();
  }
}

async function createPublicPetitionVideoUpload(publicSlug, fieldId, file) {
  const slug = normalizeString(publicSlug);
  const normalizedFieldId = normalizeString(fieldId);
  const mimeType = normalizeString(file?.type) || "video/mp4";
  const payload = await fetchJson(
    `/api/petitions/${encodeURIComponent(slug)}/uploads/create`,
    {
      auth: false,
      method: "POST",
      body: {
        fieldId: normalizedFieldId,
        fileName: normalizeString(file?.name) || "petition-video.mp4",
        mimeType,
      },
    },
  );
  const upload = payload.upload || payload.item || payload;
  const normalizedUpload = normalizeCreateUploadPayload(upload);
  if (!normalizedUpload.uid || !normalizedUpload.uploadUrl) {
    throw new Error("upload_url_missing");
  }
  await uploadPostComposerFile(normalizedUpload, file);
  return {
    ...upload,
    fieldId: normalizedFieldId,
    uploadId: normalizedUpload.uid,
    uid: normalizedUpload.uid,
    fileName: normalizeString(file?.name),
    mimeType,
    sizeBytes: Number(file?.size) || null,
  };
}

async function submitPublicPetitionForm(formData) {
  const page = state.pages.petitions.public;
  const petition = page.item;
  if (!petition) {
    return;
  }
  page.submitting = true;
  page.error = "";
  page.notice = "";
  scheduleRender();
  try {
    const fields = [...(petition.fieldSchema || [])];
    const values = {};
    for (const field of fields) {
      const key = `field:${field.id}`;
      if (field.type === "name") {
        values[field.id] = {
          firstName: normalizeString(formData.get(`${key}:firstName`)),
          lastName: normalizeString(formData.get(`${key}:lastName`)),
        };
      } else if (field.type === "address") {
        values[field.id] = {
          line1: normalizeString(formData.get(`${key}:line1`)),
          line2: normalizeString(formData.get(`${key}:line2`)),
          city: normalizeString(formData.get(`${key}:city`)),
          state: normalizeString(formData.get(`${key}:state`)),
          postalCode: normalizeString(formData.get(`${key}:postalCode`)),
          placeId: normalizeString(formData.get(`${key}:placeId`)),
          formattedAddress: normalizeString(formData.get(`${key}:formattedAddress`)),
          lat: normalizeString(formData.get(`${key}:lat`)),
          lng: normalizeString(formData.get(`${key}:lng`)),
        };
      } else if (field.type === "signature") {
        values[field.id] = {
          typedName: normalizeString(formData.get(key)),
        };
      } else if (field.type === "checkbox") {
        values[field.id] = formData.get(key) === "on";
      } else if (field.type === "cta_video") {
        const file = page.videoFiles[field.id] || null;
        const consentAccepted = formData.get(`${key}:consent`) === "on";
        if (!page.videoUploads[field.id] && file) {
          page.videoUploads[field.id] = await createPublicPetitionVideoUpload(
            petition.publicSlug,
            field.id,
            file,
          );
        }
        values[field.id] = {
          ...(page.videoUploads[field.id] || {}),
          consentAccepted,
        };
      } else {
        values[field.id] = normalizeString(formData.get(key));
      }
    }
    await fetchJson(
      `/api/petitions/${encodeURIComponent(petition.publicSlug)}/responses`,
      {
        auth: false,
        method: "POST",
        body: { fields: values },
      },
    );
    page.notice = "Response submitted.";
    Object.values(page.videoPreviews || {}).forEach((url) => {
      if (url) window.URL.revokeObjectURL(url);
    });
    page.values = {};
    page.videoFiles = {};
    page.videoPreviews = {};
    page.videoUploads = {};
    showToast(page.notice);
  } catch (error) {
    page.error =
      normalizeString(error?.message) || "Response could not be submitted.";
    showToast(page.error);
  } finally {
    page.submitting = false;
    scheduleRender();
  }
}

function buildPetitionDraftFromForm(formData, fallback = {}) {
  const petitionId =
    normalizeString(formData.get("petitionId")) ||
    normalizeString(fallback.petitionId);
  const fieldIds = normalizeStringList(formData.getAll("fieldId"));
  const fieldSchema = fieldIds.map((fieldId, index) => {
    const prefix = `field:${fieldId}`;
    const type = normalizePetitionFieldType(formData.get(`${prefix}:type`));
    const optionsText = normalizeString(formData.get(`${prefix}:options`));
    const options = optionsText
      .split(/\r?\n/u)
      .map((line) => normalizeString(line))
      .filter(Boolean)
      .map((line) => {
        const [valuePart, ...labelParts] = line.split("|");
        const value = normalizeString(valuePart);
        const label = normalizeString(labelParts.join("|")) || value;
        return value ? { value, label } : null;
      })
      .filter(Boolean);
    const config =
      type === "cta_video"
        ? {
            instructions: normalizeString(formData.get(`${prefix}:instructions`)),
            consentCopy:
              normalizeString(formData.get(`${prefix}:consentCopy`)) ||
              "I understand this video response may be used as part of this CTA.",
            maxDurationSeconds: 60,
          }
        : {};
    return {
      id: fieldId,
      type,
      label:
        normalizeString(formData.get(`${prefix}:label`)) ||
        createPetitionFieldDraft(type, index).label,
      required: formData.get(`${prefix}:required`) === "on",
      helpText: normalizeString(formData.get(`${prefix}:helpText`)),
      order: index,
      ...(type === "select" ? { options } : {}),
      ...(Object.keys(config).length ? { config } : {}),
    };
  });
  return {
    petitionId,
    title: normalizeString(formData.get("title")) || normalizeString(fallback.title),
    bodyText: normalizeString(formData.get("bodyText")),
    status: normalizeString(fallback.status) || "draft",
    publicSlug: normalizeString(fallback.publicSlug),
    publishedVersion: Number(fallback.publishedVersion) || 0,
    fieldSchema,
  };
}

function syncPetitionBuilderDraftFromDom(ownerType) {
  const workspace = petitionWorkspaceForOwner(ownerType);
  const form = root?.querySelector('[data-route-form="petition-builder"]');
  if (!form) {
    return workspace.draft;
  }
  const formData = new FormData(form);
  workspace.draft = buildPetitionDraftFromForm(formData, workspace.draft);
  return workspace.draft;
}

function queuePetitionAddressLookup(fieldId, query) {
  const page = state.pages.petitions.public;
  page.addressLookup.fieldId = normalizeString(fieldId);
  page.addressLookup.query = normalizeString(query);
  window.clearTimeout(petitionAddressLookupTimer);
  petitionAddressLookupTimer = window.setTimeout(() => {
    loadPetitionAddressSuggestions().catch(() => {});
  }, 280);
}

async function loadPetitionAddressSuggestions() {
  const page = state.pages.petitions.public;
  const lookup = page.addressLookup;
  const query = normalizeString(lookup.query);
  lookup.items = [];
  lookup.error = "";
  if (!query || query.length < 3) {
    lookup.loading = false;
    scheduleRender();
    return;
  }
  const requestId = lookup.requestId + 1;
  lookup.requestId = requestId;
  lookup.loading = true;
  scheduleRender();
  try {
    const payload = await fetchJson(
      `/api/geo/address/autocomplete?q=${encodeURIComponent(query)}`,
      { auth: false },
    );
    if (lookup.requestId !== requestId) {
      return;
    }
    const items = readArrayPayload(payload, [
      "items",
      "results",
      "suggestions",
      "predictions",
    ]);
    lookup.items = items.map(normalizeEventAddressSuggestion).filter(Boolean);
  } catch (error) {
    if (lookup.requestId === requestId) {
      lookup.error =
        normalizeString(error?.message) || "Address suggestions failed.";
      lookup.items = [];
    }
  } finally {
    if (lookup.requestId === requestId) {
      lookup.loading = false;
      scheduleRender();
    }
  }
}

async function selectPetitionAddressSuggestion(index) {
  const page = state.pages.petitions.public;
  const lookup = page.addressLookup;
  const suggestion = lookup.items[Number(index)];
  if (!suggestion) {
    return;
  }
  lookup.loading = true;
  lookup.error = "";
  scheduleRender();
  try {
    const payload = await fetchJson(
      `/api/geo/address/details?placeId=${encodeURIComponent(suggestion.placeId)}`,
      { auth: false },
    );
    const item = payload.item || payload.details || payload.address || payload;
    const details = normalizeEventAddressDetails(item);
    const fieldId = lookup.fieldId;
    page.values[fieldId] = {
      ...(page.values[fieldId] && typeof page.values[fieldId] === "object"
        ? page.values[fieldId]
        : {}),
      line1: normalizeString(
        details.addressLine1 || eventAddressSuggestionLabel(suggestion),
      ),
      city: normalizeString(details.city),
      state: normalizeString(details.state),
      postalCode: normalizeString(details.postalCode),
      placeId: normalizeString(details.placeId || suggestion.placeId),
      formattedAddress: normalizeString(
        details.formattedAddress || eventAddressSuggestionLabel(suggestion),
      ),
      lat: Number.isFinite(details.lat) ? String(details.lat) : "",
      lng: Number.isFinite(details.lng) ? String(details.lng) : "",
    };
    lookup.items = [];
    lookup.query = "";
  } catch (error) {
    lookup.error =
      normalizeString(error?.message) || "Address details could not be loaded.";
  } finally {
    lookup.loading = false;
    scheduleRender();
  }
}

function resetCandidateDashboardDetail(candidateId = "") {
  const detail = state.pages.candidateDashboard.detail;
  state.pages.candidateDashboard.selectedCandidateId = normalizeString(candidateId);
  detail.candidate = null;
  detail.access = null;
  detail.analytics = null;
  detail.events = [];
  detail.staff = [];
  detail.calendar = [];
  detail.missions = [];
  detail.analyticsWorkspace = createCandidateDashboardAnalyticsState();
  detail.eventsWorkspace = createCandidateDashboardEventsState();
  detail.missionsWorkspace = createCandidateDashboardMissionsState();
  detail.engagement = createCandidateDashboardEngagementState();
  detail.staffAdmin = createCandidateDashboardStaffAdminState();
  detail.calendarWorkspace = createCandidateDashboardCalendarState();
  detail.volunteers = createCandidateDashboardVolunteersState();
  detail.messagingWorkspace = createCandidateDashboardMessagingState();
  detail.petitionsWorkspace = createPetitionsWorkspaceState();
  detail.contactPrompt = createCandidateDashboardContactPromptState();
  detail.voterRegistry = createCandidateDashboardVoterRegistryState();
  detail.campaignQuest = createCandidateDashboardCampaignQuestState();
  detail.voterMap = createCandidateDashboardVoterMapState();
  detail.donations = createCandidateDashboardDonationsState();
  detail.error = "";
  detail.loaded = false;
}

async function loadCandidateDashboardCampaigns({ refresh = false } = {}) {
  const campaigns = state.pages.candidateDashboard.campaigns;
  if (campaigns.loading) {
    return;
  }
  if (campaigns.loaded && !refresh) {
    return;
  }
  if (refresh) {
    campaigns.items = [];
    campaigns.nextCursor = null;
    campaigns.loaded = false;
  }
  campaigns.loading = true;
  campaigns.error = "";
  scheduleRender();

  try {
    const [accessResult, profileResult] = await Promise.allSettled([
      fetchJson("/api/candidateDashboard/candidates", { auth: true }),
      fetchJson("/api/profile/me", { auth: true }),
    ]);
    const accessItems =
      accessResult.status === "fulfilled"
        ? readArrayPayload(accessResult.value, [
            "items",
            "candidates",
            "campaigns",
            "access",
          ]).map(normalizeCandidateDashboardAccess)
        : [];
    const profile =
      profileResult.status === "fulfilled"
        ? normalizeProfile(profileResult.value.profile || profileResult.value)
        : state.pages.profile.me;
    if (profileResult.status === "fulfilled") {
      state.pages.profile.me = profile;
    }
    campaigns.items = mergeCandidateDashboardAccessItems(accessItems, profile);
    if (accessResult.status === "rejected" && !campaigns.items.length) {
      throw accessResult.reason;
    }
    campaigns.loaded = true;
  } catch (error) {
    campaigns.error =
      normalizeString(error?.message) || "Campaign access could not be loaded.";
  } finally {
    campaigns.loading = false;
    scheduleRender();
  }
}

function findCandidateDashboardAccess(candidateId) {
  const normalizedId = normalizeString(candidateId);
  if (!normalizedId) {
    return null;
  }
  return (
    state.pages.candidateDashboard.campaigns.items.find(
      (item) => normalizeString(item.candidateId) === normalizedId,
    ) || null
  );
}

async function loadCandidateDashboardDetail(candidateId, { refresh = false } = {}) {
  const normalizedCandidateId = decodeRouteSegment(candidateId);
  if (!normalizedCandidateId) {
    return;
  }
  const detail = state.pages.candidateDashboard.detail;
  if (detail.loading) {
    return;
  }
  if (
    refresh ||
    state.pages.candidateDashboard.selectedCandidateId !== normalizedCandidateId
  ) {
    resetCandidateDashboardDetail(normalizedCandidateId);
  }
  detail.loading = true;
  detail.error = "";
  detail.access = findCandidateDashboardAccess(normalizedCandidateId);
  scheduleRender();

  const now = new Date();
  const from = new Date(now.getFullYear(), now.getMonth(), now.getDate());
  const to = new Date(from.getTime() + 1000 * 60 * 60 * 24 * 30);
  const encodedId = encodeURIComponent(normalizedCandidateId);
  const requests = {
    candidate: fetchJson(`/api/candidates/${encodedId}`, { auth: true }),
    analytics: fetchJson(`/api/candidateDashboard/${encodedId}/analytics?days=30`, {
      auth: true,
    }),
    events: fetchJson(
      `/api/candidateDashboard/${encodedId}/events?status=active&limit=4`,
      { auth: true },
    ),
    staff: fetchJson(`/api/candidateDashboard/${encodedId}/staff`, {
      auth: true,
    }),
    calendar: fetchJson(
      `/api/candidateDashboard/${encodedId}/calendar/items?from=${encodeURIComponent(from.toISOString())}&to=${encodeURIComponent(to.toISOString())}&limit=6`,
      { auth: true },
    ),
    missions: fetchJson(
      `/api/missions?scopeType=candidate&scopeId=${encodedId}&view=mine&limit=5`,
      { auth: true },
    ),
  };

  const results = await Promise.allSettled(Object.values(requests));
  const [
    candidateResult,
    analyticsResult,
    eventsResult,
    staffResult,
    calendarResult,
    missionsResult,
  ] = results;

  if (candidateResult.status === "fulfilled") {
    detail.candidate = normalizeCandidate(
      candidateResult.value.candidate || candidateResult.value,
    );
  } else if (detail.access?.profile) {
    detail.candidate = normalizeCandidate({
      candidateId: normalizedCandidateId,
      userId: detail.access.profile.userId,
      displayName: detail.access.profile.displayName,
      username: detail.access.profile.username,
      avatarUrl: detail.access.profile.avatarUrl,
    });
  }
  if (analyticsResult.status === "fulfilled") {
    detail.analytics = normalizeCandidateDashboardAnalytics(
      analyticsResult.value,
    );
  }
  if (eventsResult.status === "fulfilled") {
    detail.events = readArrayPayload(eventsResult.value, ["items", "events"]).map(
      normalizeEvent,
    );
  }
  if (staffResult.status === "fulfilled") {
    detail.staff = readArrayPayload(staffResult.value, [
      "items",
      "staff",
      "members",
    ]).map(normalizeCandidateDashboardStaffMember);
  }
  if (calendarResult.status === "fulfilled") {
    detail.calendar = readArrayPayload(calendarResult.value, [
      "items",
      "calendar",
    ]).map(normalizeCandidateDashboardCalendarItem);
  }
  if (missionsResult.status === "fulfilled") {
    detail.missions = readArrayPayload(missionsResult.value, [
      "items",
      "missions",
    ]).map(normalizeCandidateDashboardMission);
  }

  const failed = results.filter((entry) => entry.status === "rejected");
  if (!detail.candidate && failed.length === results.length) {
    detail.error =
      normalizeString(failed[0]?.reason?.message) ||
      "Campaign dashboard could not be loaded.";
  }
  detail.loaded = true;
  detail.loading = false;
  scheduleRender();
}

async function loadCandidateDashboardAnalytics(
  candidateId,
  { refresh = false } = {},
) {
  const normalizedCandidateId = decodeRouteSegment(candidateId);
  if (!normalizedCandidateId) {
    return;
  }
  const detail = state.pages.candidateDashboard.detail;
  const resource = detail.analyticsWorkspace;
  if (resource.loading) {
    return;
  }
  if (resource.loaded && !refresh) {
    return;
  }
  resource.loading = true;
  resource.error = "";
  scheduleRender();

  const encodedId = encodeURIComponent(normalizedCandidateId);
  const days = Math.max(7, Math.min(90, Number(resource.days) || 30));
  const [analyticsResult, conversionsResult] = await Promise.allSettled([
    fetchJson(`/api/candidateDashboard/${encodedId}/analytics?days=${days}`, {
      auth: true,
    }),
    fetchJson(
      `/api/candidateDashboard/${encodedId}/event-conversions?days=${days}&includeDaily=true`,
      { auth: true },
    ),
  ]);

  if (analyticsResult.status === "fulfilled") {
    resource.snapshot = normalizeCandidateDashboardAnalytics(
      analyticsResult.value,
    );
    detail.analytics = resource.snapshot;
  }
  if (conversionsResult.status === "fulfilled") {
    resource.conversions = normalizeCandidateEventConversions(
      conversionsResult.value,
    );
  }
  if (analyticsResult.status === "rejected") {
    resource.error = settingsErrorMessage(
      analyticsResult.reason,
      "Campaign analytics could not be loaded.",
    );
  }
  resource.loaded = analyticsResult.status === "fulfilled";
  resource.loading = false;
  scheduleRender();
}

async function refreshCandidateDashboardAnalytics() {
  const candidateId = currentCandidateDashboardId();
  if (!candidateId) {
    return;
  }
  await loadCandidateDashboardAnalytics(candidateId, { refresh: true });
}

async function setCandidateAnalyticsRange(days) {
  const candidateId = currentCandidateDashboardId();
  if (!candidateId) {
    return;
  }
  const resource = state.pages.candidateDashboard.detail.analyticsWorkspace;
  const nextDays = Math.max(7, Math.min(90, Number(days) || 30));
  if (resource.days === nextDays && resource.loaded) {
    return;
  }
  resource.days = nextDays;
  resource.loaded = false;
  await loadCandidateDashboardAnalytics(candidateId, { refresh: true });
}

function normalizeCandidateDashboardEventsStatus(value) {
  const normalized = normalizeString(value).toLowerCase();
  return normalized === "previous" || normalized === "archived"
    ? "previous"
    : "active";
}

function candidateDashboardEventsStatusLabel(value) {
  return normalizeCandidateDashboardEventsStatus(value) === "previous"
    ? "Previous"
    : "Active";
}

function candidateDashboardEventsVisibleItems(resource) {
  return normalizeCandidateDashboardEventsStatus(resource.status) === "previous"
    ? resource.previousItems
    : resource.activeItems;
}

function candidateDashboardEventQueryString(status, resource) {
  return new URLSearchParams({
    status: normalizeCandidateDashboardEventsStatus(status),
    limit: "30",
    ...(resource.nextCursor ? { cursor: resource.nextCursor } : {}),
  }).toString();
}

function candidateDashboardEventsMapQueryString(resource) {
  const query = new URLSearchParams();
  if (resource.filters.tags) {
    query.set("tags", resource.filters.tags);
  }
  if (resource.filters.includePast) {
    query.set("includePast", "true");
  }
  return query.toString();
}

async function loadCandidateDashboardEvents(
  candidateId,
  { refresh = false } = {},
) {
  const normalizedCandidateId = decodeRouteSegment(candidateId);
  if (!normalizedCandidateId) {
    return;
  }
  const detail = state.pages.candidateDashboard.detail;
  const resource = detail.eventsWorkspace;
  if (resource.loading) {
    return;
  }
  if (resource.loaded && !refresh) {
    return;
  }
  if (refresh) {
    resource.activeItems = [];
    resource.previousItems = [];
    resource.mapItems = [];
    resource.route = null;
    resource.loaded = false;
  }
  resource.loading = true;
  resource.mapLoading = true;
  resource.error = "";
  resource.mapError = "";
  scheduleRender();

  const encodedId = encodeURIComponent(normalizedCandidateId);
  const mapQuery = candidateDashboardEventsMapQueryString(resource);
  const [activeResult, previousResult, mapResult] = await Promise.allSettled([
    fetchJson(
      `/api/candidateDashboard/${encodedId}/events?${candidateDashboardEventQueryString("active", resource)}`,
      { auth: true },
    ),
    fetchJson(
      `/api/candidateDashboard/${encodedId}/events?${candidateDashboardEventQueryString("previous", resource)}`,
      { auth: true },
    ),
    fetchJson(
      `/api/candidateDashboard/${encodedId}/events/map${mapQuery ? `?${mapQuery}` : ""}`,
      { auth: true },
    ),
  ]);

  if (activeResult.status === "fulfilled") {
    resource.activeItems = readArrayPayload(activeResult.value, [
      "items",
      "events",
    ]).map(normalizeEvent);
    detail.events = resource.activeItems;
  }
  if (previousResult.status === "fulfilled") {
    resource.previousItems = readArrayPayload(previousResult.value, [
      "items",
      "events",
    ]).map(normalizeEvent);
  }
  if (mapResult.status === "fulfilled") {
    resource.mapItems = readArrayPayload(mapResult.value, [
      "items",
      "events",
    ]).map(normalizeEvent);
  }
  if (activeResult.status === "rejected" && previousResult.status === "rejected") {
    resource.error = settingsErrorMessage(
      activeResult.reason,
      "Campaign events could not be loaded.",
    );
  }
  if (mapResult.status === "rejected") {
    resource.mapError = settingsErrorMessage(
      mapResult.reason,
      "Campaign event map could not be loaded.",
    );
  }
  resource.loaded =
    activeResult.status === "fulfilled" ||
    previousResult.status === "fulfilled";
  resource.loading = false;
  resource.mapLoading = false;
  scheduleRender();
}

async function refreshCandidateDashboardEvents() {
  const candidateId = currentCandidateDashboardId();
  if (!candidateId) {
    return;
  }
  await loadCandidateDashboardEvents(candidateId, { refresh: true });
}

function setCandidateDashboardEventsStatus(status) {
  const resource = state.pages.candidateDashboard.detail.eventsWorkspace;
  resource.status = normalizeCandidateDashboardEventsStatus(status);
  resource.editingEventId = "";
  resource.createOpen = false;
  scheduleRender();
}

function setCandidateDashboardEventsView(view) {
  const normalized = normalizeString(view).toLowerCase();
  const resource = state.pages.candidateDashboard.detail.eventsWorkspace;
  resource.view = normalized === "map" ? "map" : "list";
  scheduleRender();
}

async function applyCandidateDashboardEventMapFilters(formData) {
  const resource = state.pages.candidateDashboard.detail.eventsWorkspace;
  resource.filters = {
    tags: normalizeString(formData.get("tags")),
    includePast: formData.get("includePast") === "on",
  };
  resource.route = null;
  await refreshCandidateDashboardEvents();
}

function candidateDashboardEventPayloadFromForm(formData) {
  return buildEventPayloadFromForm(formData);
}

async function saveCandidateDashboardEvent(formData) {
  const candidateId = currentCandidateDashboardId();
  if (!candidateId) {
    return;
  }
  const resource = state.pages.candidateDashboard.detail.eventsWorkspace;
  const eventId = normalizeString(formData.get("eventId"));
  const mode = normalizeString(formData.get("mode")) === "edit" ? "edit" : "create";
  const actionKey = mode === "edit" && eventId ? `save:${eventId}` : "create";
  resource.actionPendingKey = actionKey;
  resource.error = "";
  scheduleRender();
  try {
    const payload = candidateDashboardEventPayloadFromForm(formData);
    const response =
      mode === "edit" && eventId
        ? await fetchJson(
            `/api/candidateDashboard/${encodeURIComponent(candidateId)}/events/${encodeURIComponent(eventId)}`,
            {
              auth: true,
              method: "PATCH",
              body: payload,
            },
          )
        : await fetchJson(
            `/api/candidateDashboard/${encodeURIComponent(candidateId)}/events`,
            {
              auth: true,
              method: "POST",
              body: payload,
            },
          );
    const normalized = normalizeEvent(response.event || response);
    resource.editingEventId = "";
    resource.createOpen = false;
    showToast(mode === "edit" ? "Event updated." : "Event created.");
    await refreshCandidateDashboardEvents();
    if (normalized.eventId) {
      state.pages.events.detail.item = normalized;
    }
  } catch (error) {
    resource.error = settingsErrorMessage(error, "Event save failed.");
    showToast(resource.error);
  } finally {
    if (resource.actionPendingKey === actionKey) {
      resource.actionPendingKey = "";
    }
    scheduleRender();
  }
}

async function deleteCandidateDashboardEvent(eventId) {
  const candidateId = currentCandidateDashboardId();
  const normalizedEventId = normalizeString(eventId);
  if (!candidateId || !normalizedEventId) {
    return;
  }
  const resource = state.pages.candidateDashboard.detail.eventsWorkspace;
  const actionKey = `delete:${normalizedEventId}`;
  resource.actionPendingKey = actionKey;
  resource.error = "";
  scheduleRender();
  try {
    await fetchJson(
      `/api/candidateDashboard/${encodeURIComponent(candidateId)}/events/${encodeURIComponent(normalizedEventId)}`,
      {
        auth: true,
        method: "DELETE",
      },
    );
    showToast("Event deleted.");
    await refreshCandidateDashboardEvents();
  } catch (error) {
    resource.error = settingsErrorMessage(error, "Event delete failed.");
    showToast(resource.error);
  } finally {
    if (resource.actionPendingKey === actionKey) {
      resource.actionPendingKey = "";
    }
    scheduleRender();
  }
}

async function buildCandidateDashboardEventsRoute() {
  const candidateId = currentCandidateDashboardId();
  if (!candidateId) {
    return;
  }
  const resource = state.pages.candidateDashboard.detail.eventsWorkspace;
  const eventIds = resource.mapItems
    .map((event) => normalizeString(event.eventId))
    .filter(Boolean)
    .slice(0, 12);
  if (!eventIds.length) {
    resource.mapError = "No mapped events are available for a route.";
    scheduleRender();
    return;
  }
  resource.actionPendingKey = "route";
  resource.mapError = "";
  scheduleRender();
  try {
    resource.route = await fetchJson(
      `/api/candidateDashboard/${encodeURIComponent(candidateId)}/events/route`,
      {
        auth: true,
        method: "POST",
        body: { eventIds },
      },
    );
    showToast("Campaign event route built.");
  } catch (error) {
    resource.mapError = settingsErrorMessage(
      error,
      "Event route could not be built.",
    );
    showToast(resource.mapError);
  } finally {
    if (resource.actionPendingKey === "route") {
      resource.actionPendingKey = "";
    }
    scheduleRender();
  }
}

async function loadCandidateDashboardStaffAdmin(
  candidateId,
  { refresh = false } = {},
) {
  const normalizedCandidateId = decodeRouteSegment(candidateId);
  if (!normalizedCandidateId) {
    return;
  }
  const detail = state.pages.candidateDashboard.detail;
  const staffAdmin = detail.staffAdmin;
  if (staffAdmin.loading) {
    return;
  }
  if (staffAdmin.loaded && !refresh) {
    return;
  }
  if (refresh) {
    detail.staff = [];
    staffAdmin.invitations = [];
    staffAdmin.catalog = null;
    staffAdmin.loaded = false;
  }
  staffAdmin.loading = true;
  staffAdmin.error = "";
  scheduleRender();

  const encodedId = encodeURIComponent(normalizedCandidateId);
  const inviteStatus =
    staffAdmin.invitationStatus === "all" ? "" : staffAdmin.invitationStatus;
  const inviteQuery = new URLSearchParams();
  if (inviteStatus) {
    inviteQuery.set("status", inviteStatus);
  }
  const requests = [
    fetchJson(`/api/candidateDashboard/${encodedId}/staff`, { auth: true }),
    fetchJson(`/api/candidateDashboard/${encodedId}/staff/access/roles`, {
      auth: true,
    }),
    fetchJson(
      `/api/candidateDashboard/${encodedId}/staff/invitations${inviteQuery.toString() ? `?${inviteQuery.toString()}` : ""}`,
      { auth: true },
    ),
  ];
  const [staffResult, catalogResult, invitationsResult] =
    await Promise.allSettled(requests);

  if (staffResult.status === "fulfilled") {
    detail.staff = readArrayPayload(staffResult.value, [
      "items",
      "staff",
      "members",
    ])
      .map(normalizeCandidateDashboardStaffMember)
      .filter((member) => member.userId && member.userId !== "unknown");
  }
  if (catalogResult.status === "fulfilled") {
    staffAdmin.catalog = normalizeCandidateStaffAccessCatalog(
      catalogResult.value,
    );
  } else if (!staffAdmin.catalog) {
    staffAdmin.catalog = normalizeCandidateStaffAccessCatalog({});
  }
  if (invitationsResult.status === "fulfilled") {
    staffAdmin.invitations = readArrayPayload(invitationsResult.value, [
      "items",
      "invitations",
      "invites",
    ])
      .map(normalizeCandidateStaffInvitation)
      .filter((invite) => invite.userId && invite.userId !== "unknown");
  }

  const failed = [staffResult, catalogResult, invitationsResult].filter(
    (entry) => entry.status === "rejected",
  );
  if (failed.length === 3) {
    staffAdmin.error = settingsErrorMessage(
      failed[0].reason,
      "Campaign staff could not be loaded.",
    );
  }
  staffAdmin.loaded = failed.length < 3;
  staffAdmin.loading = false;
  scheduleRender();
}

async function loadCandidateStaffInviteSearch(query, { refresh = false } = {}) {
  const resource = state.pages.candidateDashboard.detail.staffAdmin;
  const search = candidateStaffInviteSearch(resource);
  const normalizedQuery = normalizeString(query).replace(/^@/u, "");
  search.query = normalizeString(query);
  if (normalizedQuery.length < 2) {
    search.items = [];
    search.loading = false;
    search.error = "";
    search.loaded = false;
    search.lastSearchQuery = "";
    scheduleRender();
    return;
  }
  if (
    search.loading ||
    (!refresh && search.loaded && search.lastSearchQuery === normalizedQuery)
  ) {
    return;
  }
  const token = search.token + 1;
  search.token = token;
  search.lastSearchQuery = normalizedQuery;
  search.loading = true;
  search.error = "";
  scheduleRender();
  try {
    const payload = await fetchJson(candidateStaffInviteSearchEndpoint(normalizedQuery), {
      auth: true,
    });
    if (search.token !== token) return;
    search.items = normalizeSearchResultsPayload(payload, "users").items
      .map(normalizeCandidateStaffInviteSearchResult)
      .filter((item) => item && item.userId !== currentCandidateDashboardId());
    search.loaded = true;
  } catch (error) {
    if (search.token !== token) return;
    search.error = normalizeString(error?.message) || "Staff search failed.";
    search.loaded = true;
  } finally {
    if (search.token === token) {
      search.loading = false;
      scheduleRender();
    }
  }
}

function queueCandidateStaffInviteSearch() {
  window.clearTimeout(candidateStaffInviteSearchTimer);
  const resource = state.pages.candidateDashboard.detail.staffAdmin;
  const search = candidateStaffInviteSearch(resource);
  const query = normalizeString(search.query);
  if (query.replace(/^@/u, "").length < 2) {
    loadCandidateStaffInviteSearch(query).catch(() => {});
    return;
  }
  candidateStaffInviteSearchTimer = window.setTimeout(() => {
    loadCandidateStaffInviteSearch(query).catch(() => {});
  }, 300);
}

function candidateCalendarDefaultRange() {
  const now = new Date();
  const from = new Date(now.getFullYear(), now.getMonth(), 1);
  const to = new Date(now.getFullYear(), now.getMonth() + 2, 0, 23, 59, 59);
  return { from: from.getTime(), to: to.getTime() };
}

function candidateCalendarDateInputFromQuery(value) {
  const normalized = normalizeString(value);
  if (!normalized) {
    return "";
  }
  const dateOnly = normalized.match(/^(\d{4})-(\d{2})-(\d{2})$/u);
  if (dateOnly) {
    return normalized;
  }
  const date = new Date(normalized);
  if (!Number.isFinite(date.getTime())) {
    return "";
  }
  return formatDateInputValue(date.getTime());
}

function candidateCalendarRefreshTokenFromQuery(params) {
  const explicitToken = normalizeString(
    params.get("calendarRefreshToken") || params.get("calendarRefresh"),
  );
  if (explicitToken) {
    return explicitToken;
  }
  const status = normalizeString(
    params.get("calendar_status") ||
      params.get("status") ||
      calendarReturnPathStatus(),
  ).toLowerCase();
  if (status !== "success") {
    return "";
  }
  return [
    status,
    normalizeString(params.get("provider")),
    normalizeString(params.get("connectionId")),
  ].join("|");
}

function readCandidateDashboardCalendarFocus() {
  const params = readCurrentSearchParams();
  return {
    itemId: normalizeString(params.get("calendarItemId")),
    date: candidateCalendarDateInputFromQuery(params.get("calendarDate")),
    refreshToken: candidateCalendarRefreshTokenFromQuery(params),
  };
}

function syncCandidateDashboardCalendarFocus(resource) {
  if (!resource) {
    return false;
  }
  const focus = readCandidateDashboardCalendarFocus();
  const queryKey = [
    focus.itemId,
    focus.date,
    focus.refreshToken,
  ].join("|");
  if (resource.focusQueryKey === queryKey) {
    return false;
  }
  const shouldRefreshForToken =
    Boolean(focus.refreshToken) &&
    focus.refreshToken !== resource.handledFocusRefreshToken;
  resource.focusedItemId = focus.itemId;
  resource.focusedDate = focus.date;
  resource.focusRefreshToken = focus.refreshToken;
  resource.focusQueryKey = queryKey;
  if (focus.date) {
    resource.filters = {
      ...resource.filters,
      from: focus.date,
      to: focus.date,
    };
  }
  if (focus.itemId) {
    resource.filters = {
      ...resource.filters,
      status: "",
      itemType: "",
    };
  }
  if (shouldRefreshForToken) {
    resource.handledFocusRefreshToken = focus.refreshToken;
  }
  return Boolean(focus.itemId || focus.date || shouldRefreshForToken);
}

function scrollCandidateDashboardFocusedCalendarItemSoon(resource) {
  const focusedItemId = normalizeString(resource?.focusedItemId);
  const scrollKey = normalizeString(resource?.focusQueryKey) || focusedItemId;
  if (!focusedItemId || !scrollKey || resource.focusedItemScrollKey === scrollKey) {
    return;
  }
  resource.focusedItemScrollKey = scrollKey;
  window.requestAnimationFrame(() => {
    try {
      const target = root?.querySelector("#candidate-calendar-focused-item");
      if (!target) {
        return;
      }
      target.scrollIntoView({ behavior: "smooth", block: "center" });
      target.classList.add("is-focus-pulse");
      window.setTimeout(() => {
        target.classList.remove("is-focus-pulse");
      }, 1600);
    } catch {
      // Focus scrolling is best effort after render.
    }
  });
}

function candidateCalendarDateFilterTimestamp(value, endOfDay = false) {
  const normalized = normalizeString(value);
  if (!normalized) {
    return null;
  }
  const date = new Date(`${normalized}T${endOfDay ? "23:59:59" : "00:00:00"}`);
  const timestamp = date.getTime();
  return Number.isFinite(timestamp) ? timestamp : null;
}

function candidateCalendarQueryString(resource) {
  const defaults = candidateCalendarDefaultRange();
  const from =
    candidateCalendarDateFilterTimestamp(resource.filters.from, false) ||
    defaults.from;
  const to =
    candidateCalendarDateFilterTimestamp(resource.filters.to, true) ||
    defaults.to;
  const params = new URLSearchParams();
  params.set("from", String(Math.min(from, to)));
  params.set("to", String(Math.max(from, to)));
  if (normalizeString(resource.filters.itemType)) {
    params.set("itemType", normalizeString(resource.filters.itemType));
  }
  if (normalizeString(resource.filters.status)) {
    params.set("status", normalizeString(resource.filters.status));
  }
  return params.toString();
}

async function loadCandidateDashboardCalendar(
  candidateId,
  { refresh = false } = {},
) {
  const normalizedCandidateId = decodeRouteSegment(candidateId);
  if (!normalizedCandidateId) {
    return;
  }
  const detail = state.pages.candidateDashboard.detail;
  const resource = detail.calendarWorkspace;
  const focusChanged = syncCandidateDashboardCalendarFocus(resource);
  if (resource.loading) {
    return;
  }
  if (resource.loaded && !refresh && !focusChanged) {
    return;
  }
  if (refresh || focusChanged) {
    resource.items = [];
    resource.connections = [];
    resource.providers = [];
    resource.loaded = false;
  }
  resource.loading = true;
  resource.error = "";
  scheduleRender();

  const encodedId = encodeURIComponent(normalizedCandidateId);
  const itemPath = `/api/candidateDashboard/${encodedId}/calendar/items?${candidateCalendarQueryString(resource)}`;
  const [itemsResult, connectionsResult, settingsResult] =
    await Promise.allSettled([
      fetchJson(itemPath, { auth: true }),
      fetchJson(`/api/candidateDashboard/${encodedId}/calendar/connections`, {
        auth: true,
      }),
      fetchJson(`/api/candidateDashboard/${encodedId}/calendar/settings`, {
        auth: true,
      }),
    ]);

  if (itemsResult.status === "fulfilled") {
    resource.items = readArrayPayload(itemsResult.value, [
      "items",
      "calendar",
    ]).map(normalizeCandidateDashboardCalendarItem);
    detail.calendar = resource.items.slice(0, 6);
  }
  if (connectionsResult.status === "fulfilled") {
    const connections = normalizeCandidateCalendarConnectionsPayload(
      connectionsResult.value,
    );
    resource.configured = connections.configured;
    resource.connections = connections.connections;
    resource.providers = connections.providers;
    if (connections.settings) {
      resource.settings = connections.settings;
    }
  }
  if (settingsResult.status === "fulfilled") {
    resource.settings = normalizeCandidateCalendarSettings(settingsResult.value);
  }
  const failed = [itemsResult, connectionsResult, settingsResult].filter(
    (entry) => entry.status === "rejected",
  );
  if (itemsResult.status === "rejected") {
    resource.error = settingsErrorMessage(
      itemsResult.reason,
      "Campaign calendar could not be loaded.",
    );
  } else if (failed.length === 3) {
    resource.error = settingsErrorMessage(
      failed[0].reason,
      "Campaign calendar could not be loaded.",
    );
  }
  resource.loaded = itemsResult.status === "fulfilled";
  resource.loading = false;
  scheduleRender();
  if (resource.loaded) {
    scrollCandidateDashboardFocusedCalendarItemSoon(resource);
  }
}

