function candidateCalendarDraftFromForm(formData, access) {
  const startAt = Date.parse(normalizeString(formData.get("startAt")));
  const endAt = Date.parse(normalizeString(formData.get("endAt")));
  if (!Number.isFinite(startAt) || !Number.isFinite(endAt)) {
    throw new Error("Start and end time are required.");
  }
  if (endAt <= startAt) {
    throw new Error("End time must be after start time.");
  }
  const permissions = candidateDashboardPermissionSet(access);
  const canDirect =
    access?.isOwner ||
    permissions.has("calendar_create_direct") ||
    permissions.has("calendar_manage_promotion") ||
    permissions.has("calendar_public_booking");
  const externalWriteTargets = formData
    .getAll("writeTarget")
    .map(normalizeString)
    .map((value) => {
      const [provider, ...calendarParts] = value.split(":");
      return {
        provider: normalizeString(provider),
        calendarId: normalizeString(calendarParts.join(":")),
        mode: "write",
      };
    })
    .filter((target) => target.provider && target.calendarId);
  return {
    itemType: normalizeString(formData.get("itemType")) || "busy",
    title: normalizeString(formData.get("title")) || "Busy",
    description: normalizeString(formData.get("description")) || undefined,
    locationName: normalizeString(formData.get("locationName")) || undefined,
    startAt,
    endAt,
    allDay: formData.get("allDay") === "on",
    privacy: normalizeString(formData.get("privacy")) || "details",
    status: canDirect
      ? normalizeString(formData.get("status")) || "confirmed"
      : "pending_approval",
    labels: splitCandidateVolunteerTags(formData.get("labels")),
    externalWriteTargets,
  };
}

async function createCandidateCalendarItem(formData) {
  const candidateId = currentCandidateDashboardId();
  if (!candidateId) {
    return false;
  }
  const detail = state.pages.candidateDashboard.detail;
  const resource = detail.calendarWorkspace;
  resource.actionPendingKey = "create";
  scheduleRender();
  try {
    const body = candidateCalendarDraftFromForm(formData, detail.access);
    const payload = await fetchJson(
      `/api/candidateDashboard/${encodeURIComponent(candidateId)}/calendar/items`,
      { auth: true, method: "POST", body },
    );
    const item = normalizeCandidateDashboardCalendarItem(payload.item || payload);
    resource.items = [item, ...resource.items]
      .filter((entry) => entry.calendarItemId)
      .sort((left, right) => (left.startAt || 0) - (right.startAt || 0));
    detail.calendar = resource.items.slice(0, 6);
    resource.loaded = true;
    showToast(
      item.status === "pending_approval"
        ? "Calendar draft submitted."
        : "Calendar item created.",
    );
    return true;
  } catch (error) {
    showToast(settingsErrorMessage(error, "Calendar item could not be created."));
    return false;
  } finally {
    resource.actionPendingKey = "";
    scheduleRender();
  }
}

