function candidateCalendarConnectionPayloadFromForm(formData) {
  const count = Number(formData.get("calendarCount")) || 0;
  const calendars = [];
  for (let index = 0; index < count; index += 1) {
    const calendarId = normalizeString(formData.get(`calendarId:${index}`));
    if (!calendarId) {
      continue;
    }
    calendars.push({
      calendarId,
      title:
        normalizeString(formData.get(`calendarTitle:${index}`)) || "Calendar",
      label:
        normalizeString(formData.get(`calendarLabel:${index}`)) || "external",
      importEnabled: formData.get(`importEnabled:${index}`) === "on",
      writeEnabled: formData.get(`writeEnabled:${index}`) === "on",
      defaultWrite: formData.get(`defaultWrite:${index}`) === "on",
    });
  }
  return {
    defaultPrivacy: normalizeString(formData.get("defaultPrivacy")) || "busy_only",
    calendars,
  };
}

