async function loadCoalitionInviteSearch(query, { refresh = false } = {}) {
  const resource = coalitionWorkspace();
  const search = coalitionInviteSearch(resource);
  const normalizedQuery = normalizeString(query).replace(/^@/u, "");
  search.query = normalizeString(query);
  if (normalizedQuery.length < 2) {
    search.items = [];
    search.loading = false;
    search.error = "";
    search.loaded = false;
    search.lastSearchQuery = "";
    scheduleRender();
    return;
  }
  if (
    search.loading ||
    (!refresh && search.loaded && search.lastSearchQuery === normalizedQuery)
  ) {
    return;
  }
  const token = search.token + 1;
  search.token = token;
  search.lastSearchQuery = normalizedQuery;
  search.loading = true;
  search.error = "";
  scheduleRender();
  try {
    const payload = await fetchJson(coalitionInviteSearchEndpoint(normalizedQuery), {
      auth: true,
    });
    if (search.token !== token) return;
    search.items = normalizeSearchResultsPayload(payload, "users").items
      .map(normalizeCoalitionInviteSearchResult)
      .filter(Boolean);
    search.loaded = true;
  } catch (error) {
    if (search.token !== token) return;
    search.error = normalizeString(error?.message) || "Member search failed.";
    search.loaded = true;
  } finally {
    if (search.token === token) {
      search.loading = false;
      scheduleRender();
    }
  }
}

function queueCoalitionInviteSearch() {
  window.clearTimeout(coalitionInviteSearchTimer);
  const resource = coalitionWorkspace();
  const search = coalitionInviteSearch(resource);
  const query = normalizeString(search.query);
  if (query.replace(/^@/u, "").length < 2) {
    loadCoalitionInviteSearch(query).catch(() => {});
    return;
  }
  coalitionInviteSearchTimer = window.setTimeout(() => {
    loadCoalitionInviteSearch(query).catch(() => {});
  }, 300);
}

async function inviteCoalitionMember(formData) {
  const coalitionId = currentCoalitionDetailId();
  const username = normalizeString(formData.get("username")).replace(/^@/u, "");
  const userId =
    normalizeString(formData.get("userId")) ||
    normalizeString(formData.get("directUserId"));
  const roleKey = normalizeCoalitionRole(formData.get("roleKey"));
  const catalog =
    coalitionWorkspace().catalog || normalizeCoalitionAccessCatalog({});
  const permissions = formData.has("useRoleDefaults")
    ? coalitionRoleDefaultPermissions(catalog, roleKey)
    : coalitionSelectedPermissionsFromForm(formData);
  if (!coalitionId || (!username && !userId)) {
    showToast("Select a Polis account or enter a direct user id.");
    return false;
  }
  const workspace = coalitionWorkspace();
  workspace.actionPendingKey = "invite";
  workspace.error = "";
  scheduleRender();
  try {
    await fetchJson(
      `/api/coalitions/${encodeURIComponent(coalitionId)}/invitations`,
      {
        auth: true,
        method: "POST",
        body: {
          ...(username ? { username } : {}),
          ...(userId ? { userId } : {}),
          role: roleKey,
          roleKey,
          permissions,
        },
      },
    );
    workspace.inviteSearch = createCoalitionInviteSearchState();
    showToast("Coalition invitation sent.");
    await loadCoalitionDetail(coalitionId, { refresh: true });
    return true;
  } catch (error) {
    workspace.error = settingsErrorMessage(
      error,
      "Coalition invitation could not be sent.",
    );
    showToast(workspace.error);
    return false;
  } finally {
    if (workspace.actionPendingKey === "invite") {
      workspace.actionPendingKey = "";
    }
    scheduleRender();
  }
}

