async function useCoalitionVoterMapBrowserLocation() {
  const workspace = coalitionVoterMapWorkspace();
  workspace.locationError = "";
  if (!navigator.geolocation) {
    workspace.locationError = "Browser location is not available.";
    showToast(workspace.locationError);
    scheduleRender();
    return;
  }
  workspace.actionPendingKey = "location";
  scheduleRender();
  try {
    const position = await new Promise((resolve, reject) => {
      navigator.geolocation.getCurrentPosition(resolve, reject, {
        enableHighAccuracy: true,
        maximumAge: 5 * 60 * 1000,
        timeout: 10000,
      });
    });
    const coords = position?.coords || {};
    workspace.search = {
      ...workspace.search,
      lat: Number(coords.latitude).toFixed(6),
      lng: Number(coords.longitude).toFixed(6),
    };
    showToast("Location added to district search.");
  } catch (error) {
    workspace.locationError =
      normalizeString(error?.message) || "Location permission was not granted.";
    showToast(workspace.locationError);
  } finally {
    workspace.actionPendingKey = "";
    scheduleRender();
  }
}

function coalitionVoterMapDistrictSearchPayload(formData) {
  const lat = Number(normalizeString(formData.get("lat")));
  const lng = Number(normalizeString(formData.get("lng")));
  const radiusMiles = Number(normalizeString(formData.get("radiusMiles")));
  if (!Number.isFinite(lat) || lat < -90 || lat > 90) {
    throw new Error("Enter a valid latitude.");
  }
  if (!Number.isFinite(lng) || lng < -180 || lng > 180) {
    throw new Error("Enter a valid longitude.");
  }
  if (!Number.isFinite(radiusMiles) || radiusMiles <= 0 || radiusMiles > 500) {
    throw new Error("Enter a radius from 1 to 500 miles.");
  }
  return { lat, lng, radiusMiles };
}

async function searchCoalitionFederalDistricts(formData) {
  const coalitionId = currentCoalitionDetailId();
  const workspace = coalitionVoterMapWorkspace();
  if (!coalitionId) {
    showToast("Coalition voter map unavailable.");
    return false;
  }
  let body;
  try {
    body = coalitionVoterMapDistrictSearchPayload(formData);
  } catch (error) {
    workspace.error = normalizeString(error?.message) || "Search is invalid.";
    showToast(workspace.error);
    scheduleRender();
    return false;
  }
  workspace.search = {
    lat: String(body.lat),
    lng: String(body.lng),
    radiusMiles: String(body.radiusMiles),
  };
  workspace.searching = true;
  workspace.error = "";
  scheduleRender();
  try {
    const payload = await fetchJson(
      `/api/coalitions/${encodeURIComponent(coalitionId)}/voter-map/federal-districts/search`,
      { auth: true, method: "POST", body },
    );
    workspace.result = normalizeCoalitionFederalDistrictSearch(payload);
    showToast("District search complete.");
    return true;
  } catch (error) {
    workspace.error = settingsErrorMessage(
      error,
      "District search could not be completed.",
    );
    showToast(workspace.error);
    return false;
  } finally {
    workspace.searching = false;
    scheduleRender();
  }
}

function coalitionVoterMapMapWorkspace() {
  const workspace = coalitionVoterMapWorkspace();
  if (!workspace.map) {
    workspace.map = createCoalitionVoterMapWorkspaceState().map;
  }
  if (!workspace.map.viewport) {
    workspace.map.viewport = {
      centerLat: "",
      centerLng: "",
      radiusMiles: "",
    };
  }
  if (!Object.prototype.hasOwnProperty.call(workspace.map, "viewportSource")) {
    workspace.map.viewportSource = "";
  }
  return workspace.map;
}

function coalitionVoterMapBboxUnion(bboxes = []) {
  const valid = bboxes.filter(Boolean);
  if (!valid.length) {
    return null;
  }
  return valid.reduce(
    (acc, bbox) => ({
      west: Math.min(acc.west, bbox.west),
      south: Math.min(acc.south, bbox.south),
      east: Math.max(acc.east, bbox.east),
      north: Math.max(acc.north, bbox.north),
    }),
    { ...valid[0] },
  );
}

function coalitionVoterMapScopeBbox(access = {}) {
  const normalizedAccess = access || {};
  return (
    normalizedAccess.unionBbox ||
    coalitionVoterMapBboxUnion(
      (normalizedAccess.territories || []).map((territory) => territory.bbox),
    ) ||
    COALITION_VOTER_MAP_DEFAULT_BBOX
  );
}

function coalitionVoterMapBboxCenter(bbox) {
  const normalized = normalizeCoalitionVoterMapBbox(bbox);
  if (!normalized) {
    return { lat: 39.5, lng: -98 };
  }
  return {
    lat: (normalized.south + normalized.north) / 2,
    lng: (normalized.west + normalized.east) / 2,
  };
}

function coalitionVoterMapBboxRadiusMiles(bbox) {
  const normalized = normalizeCoalitionVoterMapBbox(bbox);
  if (!normalized) {
    return 50;
  }
  const center = coalitionVoterMapBboxCenter(normalized);
  const latMiles = Math.abs(normalized.north - normalized.south) * 69;
  const lngMiles =
    Math.abs(normalized.east - normalized.west) *
    Math.max(1, Math.cos((center.lat * Math.PI) / 180) * 69);
  return Math.max(5, Math.min(2500, Math.ceil(Math.max(latMiles, lngMiles) / 2)));
}

function coalitionVoterMapViewportFromBbox(bbox) {
  const normalized =
    normalizeCoalitionVoterMapBbox(bbox) || COALITION_VOTER_MAP_DEFAULT_BBOX;
  const center = coalitionVoterMapBboxCenter(normalized);
  return {
    centerLat: center.lat.toFixed(5),
    centerLng: center.lng.toFixed(5),
    radiusMiles: String(coalitionVoterMapBboxRadiusMiles(normalized)),
  };
}

function coalitionVoterMapApplyScopeViewport(access) {
  const map = coalitionVoterMapMapWorkspace();
  const bbox = coalitionVoterMapScopeBbox(access);
  map.viewport = coalitionVoterMapViewportFromBbox(bbox);
  map.viewportSource =
    access?.unionBbox || (access?.territories || []).some((territory) => territory.bbox)
      ? "scope"
      : "fallback";
  map.bbox = bbox;
  return bbox;
}

function coalitionVoterMapEnsureViewport(access) {
  const map = coalitionVoterMapMapWorkspace();
  const viewport = map.viewport || {};
  const hasScopedBbox =
    access?.unionBbox || (access?.territories || []).some((territory) => territory.bbox);
  if (map.viewportSource === "fallback" && hasScopedBbox) {
    coalitionVoterMapApplyScopeViewport(access);
    return map;
  }
  if (
    normalizeString(viewport.centerLat) &&
    normalizeString(viewport.centerLng) &&
    normalizeString(viewport.radiusMiles)
  ) {
    return map;
  }
  coalitionVoterMapApplyScopeViewport(access);
  return map;
}

function coalitionVoterMapBboxFromViewport(viewport = {}) {
  const centerLat = Number(normalizeString(viewport.centerLat));
  const centerLng = Number(normalizeString(viewport.centerLng));
  const radiusMiles = Number(normalizeString(viewport.radiusMiles));
  if (!Number.isFinite(centerLat) || centerLat < -90 || centerLat > 90) {
    throw new Error("Enter a valid map center latitude.");
  }
  if (!Number.isFinite(centerLng) || centerLng < -180 || centerLng > 180) {
    throw new Error("Enter a valid map center longitude.");
  }
  if (
    !Number.isFinite(radiusMiles) ||
    radiusMiles <= 0 ||
    radiusMiles > 2500
  ) {
    throw new Error("Enter a map radius from 1 to 2500 miles.");
  }
  const latDelta = radiusMiles / 69;
  const lngScale = Math.max(0.2, Math.cos((centerLat * Math.PI) / 180));
  const lngDelta = radiusMiles / (69 * lngScale);
  return normalizeCoalitionVoterMapBbox({
    west: Math.max(-180, centerLng - lngDelta),
    south: Math.max(-90, centerLat - latDelta),
    east: Math.min(180, centerLng + lngDelta),
    north: Math.min(90, centerLat + latDelta),
  });
}

function coalitionVoterMapBboxToParam(bbox) {
  const normalized =
    normalizeCoalitionVoterMapBbox(bbox) || COALITION_VOTER_MAP_DEFAULT_BBOX;
  return [normalized.west, normalized.south, normalized.east, normalized.north]
    .map((value) => Number(value).toFixed(5))
    .join(",");
}

function coalitionVoterMapMapPayloadFromForm(formData) {
  return {
    centerLat: normalizeString(formData.get("centerLat")),
    centerLng: normalizeString(formData.get("centerLng")),
    radiusMiles: normalizeString(formData.get("radiusMiles")),
  };
}

async function loadCoalitionDirectoryMapMembers(
  coalitionId = currentCoalitionDetailId(),
  { refresh = false, bbox = null } = {},
) {
  const normalizedCoalitionId = normalizeString(coalitionId);
  const workspace = coalitionVoterMapWorkspace();
  const map = coalitionVoterMapEnsureViewport(
    workspace.access || state.pages.coalitions.detail.voterMapAccess,
  );
  if (!normalizedCoalitionId || (map.loading && !refresh)) {
    return false;
  }
  let queryBbox = normalizeCoalitionVoterMapBbox(bbox);
  try {
    queryBbox = queryBbox || coalitionVoterMapBboxFromViewport(map.viewport);
  } catch (error) {
    map.error = normalizeString(error?.message) || "Map viewport is invalid.";
    showToast(map.error);
    scheduleRender();
    return false;
  }
  const bboxParam = coalitionVoterMapBboxToParam(queryBbox);
  if (map.loaded && map.lastBbox === bboxParam && !refresh) {
    return true;
  }
  map.loading = true;
  map.error = "";
  map.bbox = queryBbox;
  scheduleRender();
  try {
    const payload = await fetchJson(
      `/api/coalitions/${encodeURIComponent(normalizedCoalitionId)}/directory/map/query?bbox=${encodeURIComponent(bboxParam)}`,
      { auth: true },
    );
    map.members = readArrayPayload(payload, ["items", "members"]).map(
      normalizeCoalitionDirectoryMember,
    );
    map.loaded = true;
    map.lastBbox = bboxParam;
    if (
      map.selectedMemberId &&
      !map.members.some((member) => member.memberId === map.selectedMemberId)
    ) {
      map.selectedMemberId = "";
    }
    if (!map.selectedMemberId && map.members.length) {
      map.selectedMemberId = map.members[0].memberId;
    }
    return true;
  } catch (error) {
    map.error = settingsErrorMessage(
      error,
      "Coalition directory badges could not be loaded.",
    );
    showToast(map.error);
    return false;
  } finally {
    map.loading = false;
    scheduleRender();
  }
}

async function queryCoalitionDirectoryMapMembers(formData) {
  const coalitionId = currentCoalitionDetailId();
  const map = coalitionVoterMapMapWorkspace();
  if (!coalitionId) {
    showToast("Coalition map unavailable.");
    return false;
  }
  const viewport = coalitionVoterMapMapPayloadFromForm(formData);
  let bbox;
  try {
    bbox = coalitionVoterMapBboxFromViewport(viewport);
  } catch (error) {
    map.error = normalizeString(error?.message) || "Map viewport is invalid.";
    showToast(map.error);
    scheduleRender();
    return false;
  }
  map.viewport = viewport;
  map.viewportSource = "manual";
  map.bbox = bbox;
  return loadCoalitionDirectoryMapMembers(coalitionId, {
    refresh: true,
    bbox,
  });
}

function coalitionCtaWorkspace() {
  const workspace = coalitionVoterMapWorkspace();
  if (!workspace.cta) {
    workspace.cta = createCoalitionVoterMapWorkspaceState().cta;
  }
  return workspace.cta;
}

function coalitionCtaTransportRoute(coalitionId, eventId) {
  const base = coalitionSectionPath(coalitionId, "voter-map/cta/transport");
  const normalizedEventId = normalizeString(eventId);
  return normalizedEventId
    ? `${base}?eventId=${encodeURIComponent(normalizedEventId)}`
    : base;
}

function coalitionCtaTransportRouteEventId(route = state.route) {
  const queryValue = normalizeString(
    readCurrentSearchParams().get("eventId") ||
      readCurrentSearchParams().get("ctaEventId"),
  );
  if (queryValue) {
    return queryValue;
  }
  const parts = coalitionRouteParts(route);
  if (
    parts[0] === "voter-map" &&
    parts[1] === "cta" &&
    parts[2] === "transport" &&
    parts[3]
  ) {
    return decodeRouteSegment(parts[3]);
  }
  return "";
}

function coalitionCtaCreatePayload(formData) {
  const title = normalizeString(formData.get("title")) || "Coalition CTA";
  const description = normalizeString(formData.get("description"));
  const address = normalizeString(formData.get("address"));
  const locationName = normalizeString(formData.get("locationName"));
  const radiusMiles =
    Number(normalizeString(formData.get("radiusMiles"))) || 25;
  const startAtValue = normalizeString(formData.get("startAt"));
  const endAtValue = normalizeString(formData.get("endAt"));
  const startAt = Date.parse(startAtValue);
  const endAt = Date.parse(endAtValue);
  const lat = Number(normalizeString(formData.get("lat")));
  const lng = Number(normalizeString(formData.get("lng")));
  const transportCount =
    Number(normalizeString(formData.get("transportCount"))) || 0;
  const seatsPerTransport =
    Number(normalizeString(formData.get("seatsPerTransport"))) || 0;
  if (!description) {
    throw new Error("CTA description is required.");
  }
  if (!address) {
    throw new Error("Destination address is required.");
  }
  if (!Number.isFinite(radiusMiles) || radiusMiles <= 0 || radiusMiles > 500) {
    throw new Error("Enter a radius from 1 to 500 miles.");
  }
  if (!Number.isFinite(lat) || !Number.isFinite(lng)) {
    throw new Error("Destination latitude and longitude are required.");
  }
  if (!Number.isFinite(startAt) || startAt <= 0) {
    throw new Error("Start time is required.");
  }
  const resolvedEndAt =
    Number.isFinite(endAt) && endAt > startAt ? endAt : startAt + 7200000;
  const transportationProvided = formData.has("transportationProvided");
  return {
    title,
    ctaType: normalizeString(formData.get("ctaType")) || "protest_rally",
    description,
    address,
    locationName,
    radiusMiles,
    startAtIso: new Date(startAt).toISOString(),
    endAtIso: new Date(resolvedEndAt).toISOString(),
    destination: {
      lat,
      lng,
      address,
      locationName,
    },
    bannerImageUrl: normalizeUrl(formData.get("bannerImageUrl")),
    squareImageUrl: normalizeUrl(formData.get("squareImageUrl")),
    transportationProvided,
    transportCount: transportationProvided ? transportCount : 0,
    seatsPerTransport: transportationProvided ? seatsPerTransport : 0,
    boardOutboundAt: normalizeString(formData.get("boardOutboundAt")),
    boardReturnAt: normalizeString(formData.get("boardReturnAt")),
  };
}

function coalitionCtaTransportSettingsPayload(formData) {
  return {
    autoFactor: formData.has("autoFactor"),
    ...(formData.has("closeSignupsEarly")
      ? { closeSignupsEarly: true }
      : {}),
  };
}

function coalitionCtaTransportPickupPayload(formData) {
  const groupId = normalizeString(formData.get("groupId"));
  if (!groupId) {
    throw new Error("Pickup group is missing.");
  }
  const lat = Number(normalizeString(formData.get("lat")));
  const lng = Number(normalizeString(formData.get("lng")));
  return {
    groupId,
    pickupLocation: {
      name: normalizeString(formData.get("name")),
      address: normalizeString(formData.get("address")),
      ...(Number.isFinite(lat) ? { lat } : {}),
      ...(Number.isFinite(lng) ? { lng } : {}),
    },
  };
}

async function loadCoalitionCtaEvents(coalitionId, { refresh = false } = {}) {
  const normalizedCoalitionId = decodeRouteSegment(coalitionId);
  const cta = coalitionCtaWorkspace();
  if (!normalizedCoalitionId || cta.loading) {
    return;
  }
  if (cta.loaded && !refresh) {
    return;
  }
  cta.loading = true;
  cta.error = "";
  scheduleRender();
  try {
    let payload;
    try {
      const eventsPayload = await fetchJson(
        "/api/events?status=all&includePast=true&limit=100",
        { auth: true },
      );
      const items = readArrayPayload(eventsPayload, ["items", "events"]).filter(
        (item) => {
          const hostCoalitionId = normalizeString(
            item.hostCoalitionId || item.host_coalition_id,
          );
          const eventType = normalizeString(item.eventType || item.event_type);
          const ctaType = normalizeString(item.ctaType || item.cta_type);
          return (
            hostCoalitionId === normalizedCoalitionId &&
            (eventType === "cta" || Boolean(ctaType))
          );
        },
      );
      payload = { items };
    } catch {
      payload = await fetchJson(
        `/api/coalitions/${encodeURIComponent(normalizedCoalitionId)}/cta/events`,
        { auth: true },
      );
    }
    cta.events = readArrayPayload(payload, [
      "items",
      "events",
      "ctaEvents",
    ]).map(normalizeCoalitionCtaEvent);
    cta.loaded = true;
  } catch (error) {
    cta.error = settingsErrorMessage(
      error,
      "Coalition CTA events could not be loaded.",
    );
  } finally {
    cta.loading = false;
    scheduleRender();
  }
}

async function refreshCoalitionCtaEvents() {
  const coalitionId = currentCoalitionDetailId();
  if (!coalitionId) {
    return;
  }
  await loadCoalitionCtaEvents(coalitionId, { refresh: true });
}

async function createCoalitionCtaEvent(formData) {
  const coalitionId = currentCoalitionDetailId();
  const cta = coalitionCtaWorkspace();
  if (!coalitionId) {
    showToast("Coalition CTA tools unavailable.");
    return false;
  }
  let body;
  try {
    body = coalitionCtaCreatePayload(formData);
  } catch (error) {
    cta.error = normalizeString(error?.message) || "CTA event is invalid.";
    showToast(cta.error);
    scheduleRender();
    return false;
  }
  cta.actionPendingKey = "create";
  cta.error = "";
  scheduleRender();
  try {
    const payload = await fetchJson(
      `/api/coalitions/${encodeURIComponent(coalitionId)}/cta/events`,
      { auth: true, method: "POST", body },
    );
    const created = normalizeCoalitionCtaEvent(payload.event || payload.item || payload);
    cta.events = [
      created,
      ...cta.events.filter((event) => event.eventId !== created.eventId),
    ];
    cta.loaded = true;
    showToast(
      created.invitedCount
        ? `CTA created for ${formatCount(created.invitedCount)} invited member(s).`
        : "Coalition CTA created.",
    );
    return true;
  } catch (error) {
    cta.error = settingsErrorMessage(
      error,
      "Coalition CTA could not be created.",
    );
    showToast(cta.error);
    return false;
  } finally {
    if (cta.actionPendingKey === "create") {
      cta.actionPendingKey = "";
    }
    scheduleRender();
  }
}

async function loadCoalitionCtaTransportAdmin(
  eventId,
  { refresh = false } = {},
) {
  const coalitionId = currentCoalitionDetailId();
  const normalizedEventId = normalizeString(eventId);
  const cta = coalitionCtaWorkspace();
  if (!coalitionId || !normalizedEventId || cta.transportLoading) {
    return;
  }
  if (
    cta.transportLoaded &&
    cta.selectedEventId === normalizedEventId &&
    !refresh
  ) {
    return;
  }
  cta.selectedEventId = normalizedEventId;
  cta.transportLoading = true;
  cta.transportError = "";
  scheduleRender();
  try {
    const payload = await fetchJson(
      `/api/coalitions/${encodeURIComponent(coalitionId)}/cta/events/${encodeURIComponent(normalizedEventId)}/transport`,
      { auth: true },
    );
    cta.transportAdmin = normalizeCoalitionCtaTransportAdmin(payload);
    cta.transportLoaded = true;
  } catch (error) {
    cta.transportError = settingsErrorMessage(
      error,
      "CTA transport admin data could not be loaded.",
    );
  } finally {
    cta.transportLoading = false;
    scheduleRender();
  }
}

async function refreshCoalitionCtaTransportAdmin() {
  const eventId =
    coalitionCtaWorkspace().selectedEventId ||
    coalitionCtaTransportRouteEventId();
  if (!eventId) {
    showToast("Choose a CTA event before opening transport admin.");
    return;
  }
  await loadCoalitionCtaTransportAdmin(eventId, { refresh: true });
}

async function updateCoalitionCtaTransportAdmin(formData, bodyBuilder) {
  const coalitionId = currentCoalitionDetailId();
  const cta = coalitionCtaWorkspace();
  const eventId =
    normalizeString(formData.get("eventId")) ||
    cta.selectedEventId ||
    coalitionCtaTransportRouteEventId();
  if (!coalitionId || !eventId) {
    showToast("CTA transport event unavailable.");
    return false;
  }
  let body;
  try {
    body = bodyBuilder(formData);
  } catch (error) {
    cta.transportError =
      normalizeString(error?.message) || "CTA transport update is invalid.";
    showToast(cta.transportError);
    scheduleRender();
    return false;
  }
  cta.actionPendingKey = `transport:${eventId}`;
  cta.transportError = "";
  scheduleRender();
  try {
    const payload = await fetchJson(
      `/api/coalitions/${encodeURIComponent(coalitionId)}/cta/events/${encodeURIComponent(eventId)}/transport`,
      { auth: true, method: "PATCH", body },
    );
    if (payload?.event || payload?.groups || payload?.ctaEvent) {
      cta.transportAdmin = normalizeCoalitionCtaTransportAdmin(payload);
      cta.transportLoaded = true;
    } else {
      await loadCoalitionCtaTransportAdmin(eventId, { refresh: true });
    }
    showToast("CTA transport updated.");
    return true;
  } catch (error) {
    cta.transportError = settingsErrorMessage(
      error,
      "CTA transport could not be updated.",
    );
    showToast(cta.transportError);
    return false;
  } finally {
    if (cta.actionPendingKey === `transport:${eventId}`) {
      cta.actionPendingKey = "";
    }
    scheduleRender();
  }
}

function coalitionGovernanceWorkspace() {
  const detail = state.pages.coalitions.detail;
  if (!detail.governanceWorkspace) {
    detail.governanceWorkspace = createCoalitionGovernanceWorkspaceState();
  }
  return detail.governanceWorkspace;
}

function coalitionGovernancePermissionSet(membership) {
  return new Set(membership?.permissions || []);
}

function canViewCoalitionGovernance(membership) {
  if (membership?.isAdmin) {
    return true;
  }
  const permissions = coalitionGovernancePermissionSet(membership);
  return [...COALITION_GOVERNANCE_PERMISSIONS].some((permission) =>
    permissions.has(permission),
  );
}

function canManageCoalitionConstitution(membership) {
  return (
    membership?.isAdmin ||
    coalitionGovernancePermissionSet(membership).has("constitution_manage")
  );
}

function canCreateCoalitionProposal(membership) {
  return Boolean(membership?.isActive && !membership?.isPending);
}

function canScheduleCoalitionProposal(membership) {
  if (membership?.isAdmin) {
    return true;
  }
  const permissions = coalitionGovernancePermissionSet(membership);
  return (
    permissions.has("proposal_manage") ||
    permissions.has("vote_manage") ||
    permissions.has("speaker_console")
  );
}

async function refreshCoalitionGovernance() {
  const coalitionId = currentCoalitionDetailId();
  if (!coalitionId) {
    return;
  }
  await loadCoalitionDetail(coalitionId, { refresh: true });
}

function coalitionGovernanceNumberFromForm(
  formData,
  key,
  { fallback, min, max } = {},
) {
  const raw = normalizeString(formData.get(key));
  const value = raw ? Number(raw) : fallback;
  if (!Number.isFinite(value) || value < min || value > max) {
    throw new Error(`${humanizeLabel(key)} is out of range.`);
  }
  return value;
}

function coalitionGovernanceConstitutionPayload(formData) {
  const markdown = normalizeString(formData.get("markdown"));
  if (!markdown) {
    throw new Error("Constitution text is required.");
  }
  return {
    markdown,
    rules: {
      petitionThresholdPct: coalitionGovernanceNumberFromForm(formData, "petitionThresholdPct", {
        fallback: 15,
        min: 1,
        max: 100,
      }),
      petitionWindowDays: coalitionGovernanceNumberFromForm(formData, "petitionWindowDays", {
        fallback: 14,
        min: 1,
        max: 365,
      }),
      autoScheduleWithinDays: coalitionGovernanceNumberFromForm(formData, "autoScheduleWithinDays", {
        fallback: 7,
        min: 1,
        max: 365,
      }),
      defaultDebateHours: coalitionGovernanceNumberFromForm(formData, "defaultDebateHours", {
        fallback: 48,
        min: 0,
        max: 720,
      }),
      defaultVoteHours: coalitionGovernanceNumberFromForm(formData, "defaultVoteHours", {
        fallback: 24,
        min: 1,
        max: 720,
      }),
      quorumPct: coalitionGovernanceNumberFromForm(formData, "quorumPct", {
        fallback: 20,
        min: 0,
        max: 100,
      }),
      amendmentSupermajorityPct: coalitionGovernanceNumberFromForm(
        formData,
        "amendmentSupermajorityPct",
        {
          fallback: 67,
          min: 50,
          max: 100,
        },
      ),
      rcvMethod: "IRV",
    },
  };
}

async function createCoalitionConstitution(formData) {
  const coalitionId = currentCoalitionDetailId();
  if (!coalitionId) {
    showToast("Coalition governance unavailable.");
    return false;
  }
  const workspace = coalitionGovernanceWorkspace();
  let body;
  try {
    body = coalitionGovernanceConstitutionPayload(formData);
  } catch (error) {
    workspace.error = normalizeString(error?.message) || "Constitution is invalid.";
    showToast(workspace.error);
    scheduleRender();
    return false;
  }
  workspace.actionPendingKey = "constitution:create";
  workspace.error = "";
  scheduleRender();
  try {
    await fetchJson(
      `/api/coalitions/${encodeURIComponent(coalitionId)}/constitution`,
      { auth: true, method: "POST", body },
    );
    workspace.constitutionOpen = false;
    showToast("Constitution created.");
    await loadCoalitionDetail(coalitionId, { refresh: true });
    return true;
  } catch (error) {
    workspace.error = settingsErrorMessage(
      error,
      "Constitution could not be created.",
    );
    showToast(workspace.error);
    return false;
  } finally {
    if (workspace.actionPendingKey === "constitution:create") {
      workspace.actionPendingKey = "";
    }
    scheduleRender();
  }
}

function coalitionProposalOptionsFromForm(formData, proposalType) {
  if (proposalType === "YES_NO") {
    return [];
  }
  const seen = new Set();
  const options = normalizeString(formData.get("options"))
    .split(/\r?\n/u)
    .map((entry) => entry.trim())
    .filter(Boolean)
    .filter((entry) => {
      const key = entry.toLowerCase();
      if (seen.has(key)) {
        return false;
      }
      seen.add(key);
      return true;
    });
  if (options.length < 2) {
    throw new Error("Add at least two ranked-choice options.");
  }
  return options;
}

function coalitionProposalFilesFromForm(formData) {
  return formData
    .getAll("attachments")
    .filter((file) => file && typeof file === "object" && Number(file.size) > 0);
}

async function uploadCoalitionProposalAttachments(coalitionId, files = []) {
  const attachments = [];
  for (const file of files.slice(0, 5)) {
    const fileName = normalizeString(file.name);
    const contentType = normalizeString(file.type) || "application/pdf";
    if (!fileName.toLowerCase().endsWith(".pdf")) {
      throw new Error("Only PDF attachments are supported.");
    }
    const payload = await fetchJson(
      `/api/coalitions/${encodeURIComponent(coalitionId)}/proposals/attachments/create`,
      {
        auth: true,
        method: "POST",
        body: {
          fileName,
          fileSize: Number(file.size),
          contentType,
        },
      },
    );
    const upload = payload.upload || {};
    const uploadUrl = normalizeUrl(upload.uploadUrl || upload.url);
    if (!uploadUrl) {
      throw new Error("Attachment upload URL was not returned.");
    }
    const response = await fetch(uploadUrl, {
      method: normalizeString(upload.method) || "PUT",
      headers: upload.headers || { "content-type": contentType },
      body: file,
    });
    if (!response.ok) {
      throw new Error(`Attachment upload failed: ${response.status}`);
    }
    attachments.push(
      normalizeCoalitionProposalAttachment(payload.attachment || {}),
    );
  }
  return attachments;
}

async function createCoalitionProposal(formData) {
  const coalitionId = currentCoalitionDetailId();
  if (!coalitionId) {
    showToast("Coalition governance unavailable.");
    return false;
  }
  const workspace = coalitionGovernanceWorkspace();
  const title = normalizeString(formData.get("title"));
  const proposalType =
    normalizeString(formData.get("proposalType")).toUpperCase() || "YES_NO";
  if (!title) {
    workspace.error = "Proposal title is required.";
    showToast(workspace.error);
    scheduleRender();
    return false;
  }
  if (!COALITION_PROPOSAL_TYPE_OPTIONS.some(([key]) => key === proposalType)) {
    workspace.error = "Choose a valid proposal type.";
    showToast(workspace.error);
    scheduleRender();
    return false;
  }
  let options;
  try {
    options = coalitionProposalOptionsFromForm(formData, proposalType);
  } catch (error) {
    workspace.error = normalizeString(error?.message) || "Proposal options are invalid.";
    showToast(workspace.error);
    scheduleRender();
    return false;
  }
  workspace.actionPendingKey = "proposal:create";
  workspace.error = "";
  scheduleRender();
  try {
    const files = coalitionProposalFilesFromForm(formData);
    const attachments = await uploadCoalitionProposalAttachments(
      coalitionId,
      files,
    );
    await fetchJson(
      `/api/coalitions/${encodeURIComponent(coalitionId)}/proposals`,
      {
        auth: true,
        method: "POST",
        body: {
          title,
          proposalType,
          summary: normalizeString(formData.get("summary")) || undefined,
          ...(options.length ? { options } : {}),
          ...(attachments.length
            ? {
                attachments: attachments.map((attachment) => ({
                  attachmentId: attachment.attachmentId,
                  fileName: attachment.fileName,
                  contentType: attachment.contentType,
                  size: attachment.size,
                  key: attachment.key,
                })),
              }
            : {}),
        },
      },
    );
    workspace.proposalOpen = false;
    showToast("Proposal created.");
    await loadCoalitionDetail(coalitionId, { refresh: true });
    return true;
  } catch (error) {
    workspace.error = settingsErrorMessage(
      error,
      "Proposal could not be created.",
    );
    showToast(workspace.error);
    return false;
  } finally {
    if (workspace.actionPendingKey === "proposal:create") {
      workspace.actionPendingKey = "";
    }
    scheduleRender();
  }
}

