function coalitionBallotPayloadFromForm(formData, vote) {
  if (vote.proposalType === "YES_NO") {
    const choice = normalizeString(formData.get("choice")).toLowerCase();
    if (!["yes", "no", "abstain"].includes(choice)) {
      throw new Error("Choose a ballot option.");
    }
    return { choice };
  }
  const rankings = vote.options
    .map((option) => ({
      optionId: option.optionId,
      rank: Number(normalizeString(formData.get(`rank:${option.optionId}`))),
    }))
    .filter((entry) => entry.optionId);
  const uniqueRanks = new Set(rankings.map((entry) => entry.rank));
  if (
    rankings.length !== vote.options.length ||
    uniqueRanks.size !== vote.options.length ||
    rankings.some(
      (entry) =>
        !Number.isInteger(entry.rank) ||
        entry.rank < 1 ||
        entry.rank > vote.options.length,
    )
  ) {
    throw new Error("Rank every option exactly once.");
  }
  return {
    rankings: rankings
      .sort((left, right) => left.rank - right.rank)
      .map((entry) => entry.optionId),
  };
}

