function candidateDashboardEngagementSelectedMode(resource, access) {
  const modes = resource.availableResponseModes.length
    ? resource.availableResponseModes
    : candidateEngagementAvailableModesForAccess(access);
  const requested = normalizeCandidateEngagementResponseMode(resource.responseMode);
  if (requested && modes.includes(requested)) {
    return requested;
  }
  const defaultMode = normalizeCandidateEngagementResponseMode(
    resource.defaultResponseMode,
  );
  if (defaultMode && modes.includes(defaultMode)) {
    return defaultMode;
  }
  return modes[0] || "";
}

async function loadCandidateDashboardEngagement(
  candidateId,
  { refresh = false, append = false } = {},
) {
  const normalizedCandidateId = decodeRouteSegment(candidateId);
  if (!normalizedCandidateId) {
    return;
  }
  const detail = state.pages.candidateDashboard.detail;
  const engagement = detail.engagement;
  if (append ? engagement.loadingMore : engagement.loading) {
    return;
  }
  if (!append && engagement.loaded && !refresh) {
    return;
  }
  if (append && !engagement.nextCursor) {
    return;
  }
  if (refresh && !append) {
    engagement.items = [];
    engagement.nextCursor = null;
    engagement.loaded = false;
  }
  if (append) {
    engagement.loadingMore = true;
  } else {
    engagement.loading = true;
  }
  engagement.error = "";
  scheduleRender();

  try {
    const access = detail.access || findCandidateDashboardAccess(normalizedCandidateId);
    const query = new URLSearchParams({
      limit: "20",
      days: String(engagement.rangeDays || 90),
      filter: "all",
    });
    const selectedMode = candidateDashboardEngagementSelectedMode(
      engagement,
      access,
    );
    if (selectedMode) {
      query.set("responseMode", selectedMode);
    }
    if (append && engagement.nextCursor) {
      query.set("cursor", engagement.nextCursor);
    }
    const payload = await fetchJson(
      `/api/candidateDashboard/${encodeURIComponent(normalizedCandidateId)}/engagement?${query.toString()}`,
      { auth: true },
    );
    const page = normalizeCandidateDashboardEngagementPage(payload);
    const fallbackModes = candidateEngagementAvailableModesForAccess(access);
    const nextModes = page.availableResponseModes.length
      ? page.availableResponseModes
      : fallbackModes;
    engagement.items = append
      ? engagement.items.concat(page.items)
      : page.items;
    engagement.availableResponseModes = nextModes;
    engagement.defaultResponseMode =
      page.defaultResponseMode || nextModes[0] || "";
    engagement.responseMode = candidateDashboardEngagementSelectedMode(
      engagement,
      access,
    );
    engagement.nextCursor = page.nextCursor;
    engagement.rangeDays = page.rangeDays;
    engagement.loaded = true;
  } catch (error) {
    engagement.error = settingsErrorMessage(
      error,
      "Engagement queue could not be loaded.",
    );
  } finally {
    engagement.loading = false;
    engagement.loadingMore = false;
    scheduleRender();
  }
}

function currentCandidateDashboardId() {
  if (isCandidateVoterMapRoute()) {
    return candidateVoterMapRouteCandidateId();
  }
  return (
    decodeRouteSegment(getCurrentRoute().routeParams.candidateId) ||
    normalizeString(state.pages.candidateDashboard.selectedCandidateId)
  );
}

