async function loadCandidateDashboardMessaging(
  candidateId,
  { refresh = false } = {},
) {
  const normalizedCandidateId = decodeRouteSegment(candidateId);
  if (!normalizedCandidateId) {
    return;
  }
  const detail = state.pages.candidateDashboard.detail;
  const workspace =
    detail.messagingWorkspace ||
    (detail.messagingWorkspace = createCandidateDashboardMessagingState());
  if (workspace.loading) {
    return;
  }
  if (workspace.loaded && !refresh) {
    scheduleRender();
    return;
  }
  if (refresh) {
    workspace.item = null;
    workspace.loaded = false;
  }
  workspace.loading = true;
  workspace.error = "";
  scheduleRender();
  try {
    const query = buildMessagingScopeQuery("campaign", normalizedCandidateId);
    const payload = await fetchJson(
      `/api/messaging/server-directory?${query}`,
      { auth: true },
    );
    const source =
      payload.directory && typeof payload.directory === "object"
        ? payload.directory
        : payload;
    const server = payload.server
      ? normalizeMessagingServer(payload.server)
      : {
          scopeType: "campaign",
          scopeId: normalizedCandidateId,
          title:
            detail.candidate?.displayName ||
            detail.access?.profile?.displayName ||
            source.title ||
            source.name ||
            "Campaign rooms",
          canManage: source.canManage === true,
        };
    workspace.item = {
      server,
      scopeType: "campaign",
      scopeId: normalizedCandidateId,
      categories: Array.isArray(source.categories) ? source.categories : [],
      channels: (source.channels || []).map(normalizeMessagingConversation),
      canManage: server.canManage === true || source.canManage === true,
      raw: source,
    };
    workspace.loaded = true;
  } catch (error) {
    workspace.error =
      normalizeString(error?.message) || "Campaign rooms unavailable.";
  } finally {
    workspace.loading = false;
    scheduleRender();
  }
}

