function candidateDonationDigitsOnly(value) {
  return normalizeString(value).replace(/\D+/g, "");
}

async function saveCandidateDonationFinanceSection(formData, section) {
  const candidateId = currentCandidateDashboardId();
  const normalizedSection = normalizeString(section).toLowerCase();
  if (!candidateId || !["committee", "representative"].includes(normalizedSection)) {
    showToast("Finance section unavailable.");
    return false;
  }
  const donations = state.pages.candidateDashboard.detail.donations;
  donations.actionPendingKey = `finance:${normalizedSection}`;
  donations.error = "";
  scheduleRender();
  const body =
    normalizedSection === "committee"
      ? {
          section: "committee",
          candidateId,
          legalName: normalizeString(formData.get("legalName")),
          email: normalizeString(formData.get("email")),
          phone: normalizeString(formData.get("phone")),
          website: normalizeString(formData.get("website")),
          ein: candidateDonationDigitsOnly(formData.get("ein")),
          fecCandidateId: normalizeString(formData.get("fecCandidateId")),
          fecCommitteeId: normalizeString(formData.get("fecCommitteeId")),
          addressLine1: normalizeString(formData.get("addressLine1")),
          addressLine2: normalizeString(formData.get("addressLine2")),
          city: normalizeString(formData.get("city")),
          state: normalizeString(formData.get("state")).toUpperCase(),
          postalCode: normalizeString(formData.get("postalCode")),
        }
      : {
          section: "representative",
          candidateId,
          firstName: normalizeString(formData.get("firstName")),
          lastName: normalizeString(formData.get("lastName")),
          email: normalizeString(formData.get("email")),
          phone: normalizeString(formData.get("phone")),
          role: normalizeString(formData.get("role")) || "candidate",
          dobMonth: normalizeString(formData.get("dobMonth")),
          dobDay: normalizeString(formData.get("dobDay")),
          dobYear: normalizeString(formData.get("dobYear")),
          ssnLast4: candidateDonationDigitsOnly(formData.get("ssnLast4")),
          addressLine1: normalizeString(formData.get("addressLine1")),
          addressLine2: normalizeString(formData.get("addressLine2")),
          city: normalizeString(formData.get("city")),
          state: normalizeString(formData.get("state")).toUpperCase(),
          postalCode: normalizeString(formData.get("postalCode")),
        };
  try {
    const payload = await fetchJson(
      "/api/candidate-dashboard/donations/finance/update",
      {
        auth: true,
        method: "POST",
        body,
      },
    );
    const status = normalizeCandidateDonationStatusPayload(payload, {
      financeFlow: true,
    });
    donations.status = status;
    donations.financeStatus = status;
    donations.loaded = true;
    showToast(
      normalizedSection === "committee"
        ? "Committee details saved."
        : "Representative details saved.",
    );
    return true;
  } catch (error) {
    donations.error = settingsErrorMessage(
      error,
      normalizedSection === "committee"
        ? "Committee details could not be saved."
        : "Representative details could not be saved.",
    );
    showToast(donations.error);
    return false;
  } finally {
    donations.actionPendingKey = "";
    scheduleRender();
  }
}

async function startCandidateDonationPayoutSession() {
  const candidateId = currentCandidateDashboardId();
  const donations = state.pages.candidateDashboard.detail.donations;
  if (!candidateId) {
    return;
  }
  if (
    !candidateFinanceSectionComplete(donations.status, "committee") ||
    !candidateFinanceSectionComplete(donations.status, "representative")
  ) {
    showToast("Save committee and representative details before linking payouts.");
    return;
  }
  donations.actionPendingKey = "payout";
  donations.error = "";
  scheduleRender();
  try {
    const session = normalizeCandidateDonationSession(
      await fetchJson(
        "/api/candidate-dashboard/donations/finance/payout-bank/session",
        {
          auth: true,
          method: "POST",
          body: { candidateId },
        },
      ),
    );
    donations.pendingPayoutSession = session;
    if (session.url) {
      window.open(session.url, "_blank", "noopener,noreferrer");
      showToast("Payout bank link opened. Refresh status after completion.");
    } else if (session.clientSecret) {
      if (!hasStripeBrowserConfig()) {
        showToast("Stripe bank linking needs the website publishable key.");
      } else {
        showToast("Secure Stripe bank link opened.");
        await collectAndAttachCandidateDonationPayoutSession(session);
      }
    } else {
      showToast("Stripe bank linking is unavailable on web for this session.");
    }
  } catch (error) {
    donations.error = settingsErrorMessage(
      error,
      "Payout bank link could not be started.",
    );
    showToast(donations.error);
  } finally {
    if (donations.actionPendingKey === "payout") {
      donations.actionPendingKey = "";
    }
    scheduleRender();
  }
}

async function attachCandidateDonationPayoutSession() {
  const candidateId = currentCandidateDashboardId();
  const donations = state.pages.candidateDashboard.detail.donations;
  const sessionId = normalizeString(donations.pendingPayoutSession?.sessionId);
  if (!candidateId || !sessionId) {
    showToast("No payout session is waiting to be attached.");
    return;
  }
  donations.actionPendingKey = "payout-attach";
  donations.error = "";
  scheduleRender();
  try {
    const payload = await fetchJson(
      "/api/candidate-dashboard/donations/finance/payout-bank/attach",
      {
        auth: true,
        method: "POST",
        body: { candidateId, sessionId },
      },
    );
    const status = normalizeCandidateDonationStatusPayload(payload, {
      financeFlow: true,
    });
    donations.status = status;
    donations.financeStatus = status;
    donations.pendingPayoutSession = null;
    showToast("Payout bank status updated.");
  } catch (error) {
    donations.error = settingsErrorMessage(
      error,
      "Payout bank could not be attached yet.",
    );
    showToast(donations.error);
  } finally {
    donations.actionPendingKey = "";
    scheduleRender();
  }
}

