async function toggleEventInterested(eventId, currentlyInterested) {
  const normalizedEventId = normalizeString(eventId);
  if (!normalizedEventId) {
    return;
  }
  const response = await fetchJson(
    `/api/events/${encodeURIComponent(normalizedEventId)}/interested`,
    {
      auth: true,
      method: currentlyInterested ? "DELETE" : "PUT",
      body: {},
    },
  );
  const nextInterested = response.isInterested === true;
  const nextCount = Number(response.interestedCount) || 0;
  const applyUpdate = (item) =>
    item.eventId === normalizedEventId
      ? { ...item, isInterested: nextInterested, interestedCount: nextCount }
      : item;
  state.pages.events.list.items =
    state.pages.events.list.items.map(applyUpdate);
  state.pages.events.manage.items =
    state.pages.events.manage.items.map(applyUpdate);
  if (state.pages.events.detail.item?.eventId === normalizedEventId) {
    state.pages.events.detail.item = applyUpdate(
      state.pages.events.detail.item,
    );
  }
  scheduleRender();
}

function eventTransportStatePatch(response = {}) {
  const transportState = readObjectPayload(response.transportState);
  if (!Object.keys(transportState).length) {
    return {};
  }
  return {
    transportState,
    transportRemainingSeats:
      Number(transportState.remainingSeats || transportState.remaining_seats) ||
      0,
  };
}

function applyEventAttendanceUpdate(eventId, response = {}) {
  const normalizedEventId = normalizeString(eventId);
  const nextAttending = response.isAttending === true;
  const nextCount = Number(response.attendeeCount) || 0;
  const transportPatch = eventTransportStatePatch(response);
  const applyUpdate = (item) =>
    item.eventId === normalizedEventId
      ? {
          ...item,
          ...transportPatch,
          isAttending: nextAttending,
          attendeeCount: nextCount,
        }
      : item;
  state.pages.events.list.items =
    state.pages.events.list.items.map(applyUpdate);
  state.pages.events.manage.items =
    state.pages.events.manage.items.map(applyUpdate);
  if (state.pages.events.detail.item?.eventId === normalizedEventId) {
    state.pages.events.detail.item = applyUpdate(
      state.pages.events.detail.item,
    );
  }
}

async function toggleEventAttendance(
  eventId,
  currentlyAttending,
  { transportOptIn = null } = {},
) {
  const normalizedEventId = normalizeString(eventId);
  if (!normalizedEventId) {
    return;
  }
  const body =
    currentlyAttending || transportOptIn === null
      ? {}
      : { transportOptIn: transportOptIn === true };
  const response = await fetchJson(
    `/api/events/${encodeURIComponent(normalizedEventId)}/signup`,
    {
      auth: true,
      method: currentlyAttending ? "DELETE" : "POST",
      body,
    },
  );
  applyEventAttendanceUpdate(normalizedEventId, response);
  scheduleRender();
}

async function submitEventSignupForm(formData) {
  const eventId = normalizeString(formData.get("eventId"));
  if (!eventId) {
    showToast("Event unavailable.");
    return false;
  }
  const detail = state.pages.events.detail;
  const event =
    detail.item?.eventId === eventId
      ? detail.item
      : state.pages.events.list.items.find((entry) => entry.eventId === eventId);
  if (!event) {
    showToast("Event unavailable.");
    return false;
  }
  if (eventRequiresPayment(event)) {
    navigateWithAuthGate(eventPaymentRoute(eventId));
    return false;
  }
  detail.signupSaving = true;
  detail.error = "";
  scheduleRender();
  try {
    await toggleEventAttendance(eventId, false, {
      transportOptIn: event.transportEnabled
        ? formData.get("transportOptIn") === "on"
        : null,
    });
    showToast("You're signed up for this event.");
    navigateTo(eventDetailRoute(eventId));
    return true;
  } catch (error) {
    detail.error = normalizeString(error?.message) || "Event signup failed.";
    showToast(detail.error);
    return false;
  } finally {
    detail.signupSaving = false;
    scheduleRender();
  }
}

async function loadProfilePage(userId = "", { refresh = false } = {}) {
  const profileState = state.pages.profile;
  const normalizedUserId = normalizeString(userId);
  profileState.loading = true;
  profileState.error = "";
  if (refresh) {
    profileState.current = null;
    profileState.posts = createPagedState();
  }
  scheduleRender();

  try {
    const isSelf = !normalizedUserId;
    const [profilePayload, postsPayload] = await Promise.all([
      fetchJson(
        isSelf
          ? "/api/profile/me"
          : `/api/users/${encodeURIComponent(normalizedUserId)}/profile`,
        {
          auth: true,
        },
      ),
      fetchJson(
        isSelf
          ? "/api/users/me/posts?limit=18"
          : `/api/users/${encodeURIComponent(normalizedUserId)}/posts?limit=18`,
        {
          auth: true,
        },
      ).catch(() => ({ items: [] })),
    ]);
    const normalizedProfile = normalizeProfile(
      profilePayload.profile || profilePayload,
    );
    if (isSelf) {
      profileState.me = normalizedProfile;
    }
    profileState.current = normalizedProfile;
    profileState.posts.items = (postsPayload.items || []).map(
      normalizeFeedItem,
    );
    profileState.posts.nextCursor =
      normalizeString(postsPayload.nextCursor || postsPayload.cursor) || null;
    profileState.posts.loaded = true;
  } catch (error) {
    profileState.error =
      normalizeString(error?.message) || "Profile unavailable.";
  } finally {
    profileState.loading = false;
    scheduleRender();
  }
}

