function normalizeMessagingServerSecurityPolicy(raw = {}) {
  const source =
    raw?.policy && typeof raw.policy === "object" && !Array.isArray(raw.policy)
      ? raw.policy
      : raw && typeof raw === "object" && !Array.isArray(raw)
        ? raw
        : {};
  return {
    requireMfaForAdminActions: parseBoolean(
      source.requireMfaForAdminActions,
      false,
    ),
    requireMfaForSensitiveChannels: parseBoolean(
      source.requireMfaForSensitiveChannels,
      false,
    ),
    requireTrustedDeviceForAdminActions: parseBoolean(
      source.requireTrustedDeviceForAdminActions,
      false,
    ),
    requireTrustedDeviceForSensitiveChannels: parseBoolean(
      source.requireTrustedDeviceForSensitiveChannels,
      false,
    ),
    requireE2eeForSensitiveChannels: parseBoolean(
      source.requireE2eeForSensitiveChannels,
      false,
    ),
    mfaSignalAvailable: parseBoolean(source.mfaSignalAvailable, false),
    updatedBy: normalizeString(source.updatedBy),
    updatedAt:
      Number(source.updatedAt) || Date.parse(source.updatedAtIso || "") || null,
    raw: source,
  };
}

function readMessagingServerSecurityPolicyFromSources(sources = []) {
  const policyKeys = [
    "requireMfaForAdminActions",
    "requireMfaForSensitiveChannels",
    "requireTrustedDeviceForAdminActions",
    "requireTrustedDeviceForSensitiveChannels",
    "requireE2eeForSensitiveChannels",
  ];
  for (const source of sources) {
    if (!source || typeof source !== "object" || Array.isArray(source)) {
      continue;
    }
    const candidates = [
      source.policy,
      source.securityPolicy,
      source.security,
      source.policies,
      source,
    ].filter(
      (candidate) =>
        candidate && typeof candidate === "object" && !Array.isArray(candidate),
    );
    const match = candidates.find((candidate) =>
      policyKeys.some((key) =>
        Object.prototype.hasOwnProperty.call(candidate, key),
      ),
    );
    if (match) {
      return normalizeMessagingServerSecurityPolicy(match);
    }
  }
  return normalizeMessagingServerSecurityPolicy({});
}

