async function replaceMessagingServerRoleMembers(formData) {
  const scopeType = normalizeString(formData.get("scopeType"));
  const scopeId = normalizeString(formData.get("scopeId"));
  const roleId = normalizeString(formData.get("roleId"));
  const userIds = formData
    .getAll("userIds")
    .map((entry) => normalizeString(entry))
    .filter(Boolean);
  const rolesState = state.pages.messaging.serverRoles;
  if (!roleId) {
    showToast("Role unavailable.");
    return false;
  }
  const pendingKey = `${roleId}:members`;
  rolesState.actionPendingKey = pendingKey;
  rolesState.error = "";
  scheduleRender();

  try {
    const payload = await fetchJson(
      `/api/messaging/server-roles/${encodeURIComponent(roleId)}/members`,
      {
        auth: true,
        method: "PUT",
        body: { userIds },
      },
    );
    rolesState.members = Array.isArray(payload.userIds)
      ? payload.userIds.map((entry) => normalizeString(entry)).filter(Boolean)
      : userIds;
    if (rolesState.selected?.roleId === roleId) {
      rolesState.selected = {
        ...rolesState.selected,
        memberCount: rolesState.members.length,
      };
      upsertMessagingServerRole(rolesState.selected);
    }
    showToast("Role members updated.");
    if (scopeType && scopeId) {
      loadMessagingServerMembers(scopeType, scopeId, { refresh: true }).catch(
        () => {},
      );
    }
    return true;
  } catch (error) {
    rolesState.error =
      normalizeString(error?.message) || "Role members update failed.";
    showToast(rolesState.error);
    return false;
  } finally {
    if (rolesState.actionPendingKey === pendingKey) {
      rolesState.actionPendingKey = "";
    }
    scheduleRender();
  }
}

