async function updateMessagingModerationTask(formData, action) {
  const scopeType = normalizeString(formData.get("scopeType"));
  const scopeId = normalizeString(formData.get("scopeId"));
  const taskId = normalizeString(formData.get("taskId"));
  const normalizedAction = normalizeString(action).toLowerCase();
  const resolution = normalizeString(formData.get("resolution"));
  const allowedActions = ["approve", "reject", "resolved"];
  const moderationState = state.pages.messaging.serverModeration;
  if (!scopeType || !scopeId || !taskId || !allowedActions.includes(normalizedAction)) {
    showToast("Moderation action unavailable.");
    return false;
  }
  const pendingKey = `${taskId}:${normalizedAction}`;
  moderationState.actionPendingKey = pendingKey;
  moderationState.error = "";
  scheduleRender();

  try {
    const query = buildMessagingScopeQuery(scopeType, scopeId);
    const payload = await fetchJson(
      `/api/messaging/server-moderation-queue/${encodeURIComponent(taskId)}?${query}`,
      {
        auth: true,
        method: "PATCH",
        body: {
          scopeType,
          scopeId,
          action: normalizedAction,
          ...(resolution ? { resolution } : {}),
        },
      },
    );
    const task = normalizeMessagingModerationTask(payload.task || {});
    const statusFilter = normalizeString(moderationState.status);
    moderationState.items = moderationState.items
      .map((item) => (item.taskId === task.taskId ? task : item))
      .filter((item) =>
        statusFilter && statusFilter !== "all"
          ? normalizeString(item.status).toLowerCase() === statusFilter
          : true,
      );
    showToast("Moderation task updated.");
    return true;
  } catch (error) {
    moderationState.error =
      normalizeString(error?.message) || "Moderation task update failed.";
    showToast(moderationState.error);
    return false;
  } finally {
    if (moderationState.actionPendingKey === pendingKey) {
      moderationState.actionPendingKey = "";
    }
    scheduleRender();
  }
}

