function normalizeMessagingInviteTimestamp(value) {
  const timestamp = normalizeSettingsTimestamp(value);
  if (!timestamp) {
    return null;
  }
  return timestamp > 0 && timestamp < 10000000000
    ? timestamp * 1000
    : timestamp;
}

function normalizeMessagingChannelInviteLink(raw = {}) {
  const source =
    raw && typeof raw === "object" && !Array.isArray(raw)
      ? raw
      : { token: raw };
  const inviteId = normalizeString(source.inviteId || source.id || source.linkId);
  const token = normalizeString(
    source.token || source.inviteToken || source.code || source.url,
  );
  const channelId = normalizeString(
    source.channelId || source.conversationId || source.roomId,
  );
  const createdAt = normalizeMessagingInviteTimestamp(
    source.createdAt || source.timestamp || source.created_at,
  );
  const expiresAt = normalizeMessagingInviteTimestamp(
    source.expiresAt || source.expires_at || source.expiry,
  );
  const revokedAt = normalizeMessagingInviteTimestamp(
    source.revokedAt || source.revoked_at,
  );
  const lastUsedAt = normalizeMessagingInviteTimestamp(
    source.lastUsedAt || source.last_used_at,
  );
  const maxUsesValue = Number(
    source.maxUses || source.max_uses || source.useLimit,
  );
  const maxUses =
    Number.isFinite(maxUsesValue) && maxUsesValue > 0
      ? Math.trunc(maxUsesValue)
      : null;
  const useCount = Math.max(
    0,
    Number(source.useCount || source.usedCount || source.uses) || 0,
  );
  let status = normalizeString(source.status).toLowerCase();
  if (!status) {
    if (revokedAt) {
      status = "revoked";
    } else if (expiresAt && expiresAt < Date.now()) {
      status = "expired";
    } else if (maxUses && useCount >= maxUses) {
      status = "exhausted";
    } else {
      status = "active";
    }
  }
  const title =
    normalizeString(source.title || source.label || source.name) ||
    (token
      ? "Invite token"
      : inviteId
        ? `Invite ${inviteId.slice(0, 8)}`
        : "Invite link");
  return {
    inviteId: inviteId || token,
    token,
    channelId,
    title,
    subtitle:
      normalizeString(source.subtitle || source.description || source.message) ||
      (channelId ? `Room ${channelId}` : "Room invite link"),
    status,
    createdBy: normalizeString(source.createdBy || source.created_by),
    createdAt,
    expiresAt,
    maxUses,
    useCount,
    revokedAt,
    lastUsedAt,
    raw: source,
  };
}

function normalizeMessagingChannelInviteLinkPayload(payload = {}) {
  return readArrayPayload(payload, [
    "links",
    "inviteLinks",
    "items",
    "channelInvites",
  ])
    .map(normalizeMessagingChannelInviteLink)
    .filter((link) => link.inviteId || link.token || link.title);
}

function normalizeMessagingPinnedMessage(raw = {}) {
  if (raw && typeof raw !== "object") {
    return {
      pinId: "",
      messageId: "",
      sortKey: "",
      channelId: "",
      pinnedBy: "",
      pinnedAt: null,
      text: normalizeString(raw),
      contentKind: "text",
      raw,
    };
  }
  const source = raw && typeof raw === "object" ? raw : {};
  const message =
    source.message && typeof source.message === "object" ? source.message : {};
  const pinner =
    source.pinner && typeof source.pinner === "object" ? source.pinner : {};
  const messageId = normalizeString(
    source.messageId ||
      source.message_id ||
      message.messageId ||
      message.id,
  );
  const sortKey = normalizeString(
    source.sortKey || source.sort_key || message.sortKey || message.sort_key,
  );
  const pinId =
    normalizeString(source.pinId || source.pin_id || source.id) ||
    messageId ||
    sortKey;
  const channelId = normalizeString(
    source.channelId ||
      source.channel_id ||
      source.conversationId ||
      message.conversationId,
  );
  return {
    pinId,
    messageId,
    sortKey,
    channelId,
    pinnedBy: normalizeString(
      source.pinnedBy ||
        source.pinned_by ||
        source.pinnedByUserId ||
        pinner.displayName ||
        pinner.username,
    ),
    pinnedAt: Number(source.pinnedAt || source.pinned_at || source.timestamp) || null,
    text: normalizeString(
      source.text ||
        source.body ||
        source.previewText ||
        message.text ||
        message.body ||
        message.previewText,
    ),
    contentKind: normalizeString(
      source.contentKind || source.type || message.contentKind || message.type || "text",
    ),
    raw: source,
  };
}

function normalizeMessagingChannelPinsPayload(payload = {}) {
  return readArrayPayload(payload, [
    "pins",
    "pinnedMessages",
    "items",
    "pinned",
  ])
    .map(normalizeMessagingPinnedMessage)
    .filter((pin) => pin.pinId || pin.messageId || pin.text);
}

