function normalizeMessagingServerInvite(raw = {}) {
  const source =
    raw && typeof raw === "object" && !Array.isArray(raw)
      ? raw
      : { inviteeUserId: raw };
  const inviteeUserId = normalizeString(
    source.inviteeUserId || source.userId || source.id,
  );
  const title =
    normalizeString(
      source.title ||
        source.inviteeName ||
        source.displayName ||
        source.username ||
        inviteeUserId,
    ) || "Pending invite";
  return {
    inviteId:
      normalizeString(source.inviteId || source.requestId || source.id) ||
      inviteeUserId,
    inviteeUserId,
    title,
    subtitle:
      normalizeString(source.subtitle || source.description || source.message) ||
      (inviteeUserId
        ? `Pending invite for ${inviteeUserId}`
        : "Pending community invite"),
    status: normalizeString(source.status) || "pending",
    createdAt: Number(source.createdAt || source.timestamp) || null,
    raw: source,
  };
}

function normalizeMessagingServerInvitePayload(payload = {}) {
  const inviteRows = readArrayPayload(payload, [
    "invites",
    "items",
    "pendingInvites",
    "requests",
  ]);
  if (inviteRows.length) {
    return inviteRows.map(normalizeMessagingServerInvite);
  }
  return readArrayPayload(payload, [
    "inviteeUserIds",
    "userIds",
    "pendingInviteUserIds",
  ]).map(normalizeMessagingServerInvite);
}

async function loadMessagingServerInvites(
  scopeType,
  scopeId,
  { refresh = false } = {},
) {
  const invitesState = state.pages.messaging.serverInvites;
  const normalizedScopeType = normalizeString(scopeType);
  const normalizedScopeId = normalizeString(scopeId);
  const scopeChanged =
    invitesState.scopeType !== normalizedScopeType ||
    invitesState.scopeId !== normalizedScopeId;
  if (!normalizedScopeType || !normalizedScopeId || invitesState.loading) {
    return;
  }
  if (refresh || scopeChanged) {
    invitesState.items = [];
    invitesState.loaded = false;
    invitesState.scopeType = normalizedScopeType;
    invitesState.scopeId = normalizedScopeId;
  }
  invitesState.loading = true;
  invitesState.error = "";
  scheduleRender();

  try {
    const query = buildMessagingScopeQuery(normalizedScopeType, normalizedScopeId);
    const payload = await fetchJson(`/api/messaging/server-invites?${query}`, {
      auth: true,
    });
    invitesState.items = normalizeMessagingServerInvitePayload(payload).filter(
      (invite) => invite.inviteeUserId || invite.inviteId || invite.title,
    );
    invitesState.loaded = true;
  } catch (error) {
    invitesState.error =
      normalizeString(error?.message) || "Workspace invites unavailable.";
  } finally {
    invitesState.loading = false;
    scheduleRender();
  }
}

function formNullableString(formData, key) {
  const value = normalizeString(formData.get(key));
  return value || null;
}

function upsertMessagingServerInvite(invite) {
  const settingsBundle = state.pages.messaging.serverSettings.item;
  if (!settingsBundle || !invite) {
    return;
  }
  const source =
    invite && typeof invite === "object" && !Array.isArray(invite)
      ? invite
      : { inviteeUserId: invite };
  const inviteeUserId = normalizeString(
    source.inviteeUserId || source.userId || source.id,
  );
  const inviteKey =
    normalizeString(source.inviteId || source.requestId || source.id) ||
    inviteeUserId;
  const displayInvite = {
    ...source,
    title:
      normalizeString(
        source.title ||
          source.inviteeName ||
          source.displayName ||
          source.username ||
          inviteeUserId,
      ) || "Pending invite",
    subtitle:
      normalizeString(source.subtitle || source.description || source.message) ||
      (inviteeUserId ? `Invite sent to ${inviteeUserId}` : "Workspace invite pending."),
    status: normalizeString(source.status) || "pending",
  };
  if (!settingsBundle.raw || typeof settingsBundle.raw !== "object") {
    settingsBundle.raw = {};
  }
  const existing = Array.isArray(settingsBundle.raw.invites)
    ? settingsBundle.raw.invites
    : Array.isArray(settingsBundle.invites)
      ? settingsBundle.invites
      : [];
  const nextInvites = [
    displayInvite,
    ...existing.filter((item) => {
      const itemKey =
        normalizeString(item?.inviteId || item?.requestId || item?.id) ||
        normalizeString(item?.inviteeUserId || item?.userId);
      return itemKey !== inviteKey;
    }),
  ];
  settingsBundle.raw.invites = nextInvites;
  settingsBundle.invites = nextInvites;
}

async function updateMessagingServerSettings(formData) {
  const scopeType = normalizeString(formData.get("scopeType"));
  const scopeId = normalizeString(formData.get("scopeId"));
  const section = normalizeString(formData.get("section")).toLowerCase();
  const settingsState = state.pages.messaging.serverSettings;
  const pendingKey = `settings:${section || "general"}`;
  if (!scopeType || !scopeId) {
    showToast("Workspace settings unavailable.");
    return false;
  }
  if (settingsState.actionPendingKey) {
    return false;
  }
  const body = {};
  if (section === "customization") {
    const title = normalizeString(formData.get("title"));
    if (!title) {
      showToast("Add a workspace display name.");
      return false;
    }
    body.title = title;
    body.avatarUrl = normalizeUrl(formData.get("avatarUrl"));
    body.bannerUrl = normalizeUrl(formData.get("bannerUrl"));
    body.summary = normalizeString(formData.get("summary"));
    if (scopeType === "server") {
      body.visibility = normalizeString(formData.get("visibility")) || "private";
      body.discoverable = formCheckboxValue(formData, "discoverable", false);
    }
  } else if (section === "community") {
    const communityEnabled = formCheckboxValue(
      formData,
      "communityEnabled",
      false,
    );
    const welcomeChannelId = formNullableString(
      formData,
      "communityWelcomeChannelId",
    );
    const rulesChannelId = formNullableString(
      formData,
      "communityRulesChannelId",
    );
    if (communityEnabled && (!welcomeChannelId || !rulesChannelId)) {
      showToast("Choose welcome and rules rooms before enabling community.");
      return false;
    }
    body.communityEnabled = communityEnabled;
    body.communityInvitesEnabled = formCheckboxValue(
      formData,
      "communityInvitesEnabled",
      false,
    );
    body.sendWelcomeMessage = formCheckboxValue(
      formData,
      "sendWelcomeMessage",
      false,
    );
    body.promptStickerReplies = formCheckboxValue(
      formData,
      "promptStickerReplies",
      false,
    );
    body.confirmDisableCommunity = formCheckboxValue(
      formData,
      "confirmDisableCommunity",
      false,
    );
    body.systemMessageChannelId = formNullableString(
      formData,
      "systemMessageChannelId",
    );
    body.communityWelcomeChannelId = welcomeChannelId;
    body.communityRulesChannelId = rulesChannelId;
    body.communitySupportChannelId = formNullableString(
      formData,
      "communitySupportChannelId",
    );
  } else {
    showToast("This settings form is not supported yet.");
    return false;
  }
  settingsState.actionPendingKey = pendingKey;
  settingsState.error = "";
  scheduleRender();
  try {
    const payload = await fetchJson(
      `/api/messaging/server-settings?${buildMessagingScopeQuery(scopeType, scopeId)}`,
      {
        auth: true,
        method: "PATCH",
        body,
      },
    );
    settingsState.item = normalizeMessagingServerSettingsBundle(payload);
    settingsState.loaded = true;
    await Promise.all([
      loadMessagingServers().catch(() => {}),
      loadMessagingServerDirectory(scopeType, scopeId, { refresh: true }).catch(
        () => {},
      ),
    ]);
    showToast("Workspace settings updated.");
    return true;
  } catch (error) {
    settingsState.error =
      normalizeString(error?.message) || "Workspace settings could not be updated.";
    showToast(settingsState.error);
    return false;
  } finally {
    if (settingsState.actionPendingKey === pendingKey) {
      settingsState.actionPendingKey = "";
    }
    scheduleRender();
  }
}

function messagingServerDirectoryFormPosition(formData, key = "position") {
  const value = Number(formData.get(key));
  return Number.isFinite(value) && value >= 0 ? Math.floor(value) : null;
}

async function refreshMessagingServerDirectoryManagement(scopeType, scopeId) {
  await Promise.all([
    loadMessagingServerDirectory(scopeType, scopeId, { refresh: true }).catch(
      () => {},
    ),
    loadMessagingServerSettings(scopeType, scopeId, { refresh: true }).catch(
      () => {},
    ),
    loadMessagingServers().catch(() => {}),
  ]);
}

