async function removeMessagingServerMember(scopeType, scopeId, userId) {
  const normalizedUserId = normalizeString(userId);
  if (!normalizedUserId) {
    return;
  }
  const membersState = state.pages.messaging.serverMembers;
  const pendingKey = `${normalizedUserId}:remove`;
  membersState.actionPendingKey = pendingKey;
  scheduleRender();
  try {
    await fetchJson(
      `/api/messaging/server-members/${encodeURIComponent(normalizedUserId)}?${buildMessagingScopeQuery(scopeType, scopeId)}`,
      {
        auth: true,
        method: "DELETE",
      },
    );
    await Promise.all([
      loadMessagingServerMembers(scopeType, scopeId, { refresh: true }),
      loadMessagingServerBans(scopeType, scopeId, { refresh: true }).catch(
        () => {},
      ),
    ]);
    showToast("Member removed.");
    const currentSubroute = parseMessagingSubroute();
    if (
      currentSubroute.view === "server-member" &&
      normalizeString(currentSubroute.userId) === normalizedUserId
    ) {
      navigateTo(buildMessagingServerRoute(scopeType, scopeId, "/members"));
    }
  } finally {
    if (membersState.actionPendingKey === pendingKey) {
      membersState.actionPendingKey = "";
    }
    scheduleRender();
  }
}

