async function uploadCoalitionImageFile(target = "start", file) {
  const normalizedTarget = normalizeString(target).toLowerCase() || "start";
  if (!file) {
    return;
  }
  if (!normalizeString(file.type).startsWith("image/")) {
    setCoalitionImageUploadState(normalizedTarget, {
      error: "Choose an image file.",
    });
    scheduleRender();
    return;
  }
  if (Number(file.size) <= 0) {
    setCoalitionImageUploadState(normalizedTarget, {
      error: "Selected image is empty.",
    });
    scheduleRender();
    return;
  }

  const previousUpload = coalitionImageUploadStateForTarget(normalizedTarget);
  if (previousUpload.uploadId) {
    abortCoalitionImageUpload(previousUpload.uploadId).catch(() => {});
  }
  setCoalitionImageUploadState(normalizedTarget, {
    uploading: true,
  });
  scheduleRender();

  try {
    const contentType = normalizeString(file.type) || "image/jpeg";
    const fileName = normalizeString(file.name) || "coalition-image.jpg";
    const uploadPayload = await fetchJson("/api/uploads/create", {
      auth: true,
      method: "POST",
      body: {
        type: "image",
        fileName,
        fileSize: Number(file.size) || 0,
        contentType,
      },
    });
    const upload = normalizeCreateUploadPayload(uploadPayload);
    if (!upload.uid || !upload.uploadUrl) {
      throw new Error("Upload session was incomplete.");
    }
    await uploadPostComposerFile(upload, file);
    const remoteUrl = upload.deliveryUrl || upload.publicUrl;
    if (!remoteUrl) {
      throw new Error("Upload finished without a coalition image URL.");
    }
    setCoalitionImageUploadState(normalizedTarget, {
      uploading: false,
      uploadId: upload.uid,
      remoteUrl,
      fileName,
    });
  } catch (error) {
    setCoalitionImageUploadState(normalizedTarget, {
      error: coalitionImageUploadErrorMessage(error),
    });
  } finally {
    scheduleRender();
  }
}

function postComposerErrorMessage(error) {
  if (error?.status === 401) {
    return "Please sign in to create posts.";
  }
  if (error?.status === 413) {
    return "That file is too large for upload.";
  }
  return normalizeString(error?.message) || "Post could not be published.";
}

async function submitPostComposer(formData) {
  const composer = state.pages.create;
  if (composer.pending) {
    return;
  }
  updatePostComposerField("description", formData.get("description"));
  updatePostComposerField("issueIds", formData.get("issueIds"));
  updatePostComposerField("visibility", formData.get("visibility"));
  updatePostComposerField("audienceGroupIds", formData.get("audienceGroupIds"));
  updatePostComposerField("allowComments", formData.has("allowComments"));
  updatePostComposerField("allowReuseContent", formData.has("allowReuseContent"));
  updatePostComposerField(
    "aiGeneratedContent",
    formData.has("aiGeneratedContent"),
  );
  if (!composer.file) {
    composer.error = "Choose or record media before publishing.";
    scheduleRender();
    return;
  }
  const durationError = postComposerVideoDurationError(composer);
  if (durationError) {
    composer.error = durationError;
    scheduleRender();
    return;
  }

  const file = composer.file;
  if (Number(file.size) <= 0) {
    composer.error = "Selected media is empty. Choose or record it again.";
    scheduleRender();
    return;
  }
  const mediaType = composer.mediaType === "video" ? "video" : "image";
  const contentType =
    normalizeString(file.type) ||
    (mediaType === "video" ? "video/mp4" : "image/jpeg");
  const fileName =
    normalizeString(file.name) ||
    `polis-${mediaType}.${mediaType === "video" ? "mp4" : "jpg"}`;
  composer.pending = true;
  composer.stage = "Preparing upload";
  composer.error = "";
  composer.notice = "";
  composer.createdPostId = "";
  scheduleRender();

  try {
    const uploadPayload = await fetchJson("/api/uploads/create", {
      auth: true,
      method: "POST",
      body: {
        type: mediaType,
        fileName,
        fileSize: Number(file.size) || 0,
        contentType,
        ...(mediaType === "video"
          ? { maxDurationSeconds: POST_COMPOSER_MAX_VIDEO_SECONDS }
          : {}),
      },
    });
    const upload = normalizeCreateUploadPayload(uploadPayload);
    if (!upload.uid || !upload.uploadUrl) {
      throw new Error("Upload session was incomplete.");
    }

    composer.stage = `Uploading ${mediaType}`;
    scheduleRender();
    await uploadPostComposerFile(upload, file);

    const description = normalizeString(composer.description);
    const issueIds = readPostComposerIssueIds(composer.issueIds);
    const audienceGroupIds =
      composer.visibility === "custom"
        ? readPostComposerAudienceGroupIds(composer.audienceGroupIds)
        : [];
    const postId = upload.postId || upload.uid;
    composer.stage = "Saving post details";
    scheduleRender();
    await fetchJson("/api/posts/metadata", {
      auth: true,
      method: "POST",
      body: {
        postId,
        uid: upload.uid,
        type: mediaType,
        description,
        fileName,
        fileSize: Number(file.size) || 0,
        contentType,
        allowComments: composer.allowComments,
        allowReuseContent: composer.allowReuseContent,
        aiGeneratedContent: composer.aiGeneratedContent,
      },
    });

    composer.stage = "Publishing post";
    scheduleRender();
    const createPayload = await fetchJson("/api/posts", {
      auth: true,
      method: "POST",
      body: {
        type: mediaType,
        cfUid: upload.uid,
        ...(mediaType === "image"
          ? {
              imageKey: upload.uid,
              imageUrl: upload.deliveryUrl || upload.publicUrl || undefined,
            }
          : {
              originalSize: Number(file.size) || undefined,
              masterSize: Number(file.size) || undefined,
            }),
        postId,
        description,
        visibility: composer.visibility,
        ...(composer.visibility === "custom" ? { audienceGroupIds } : {}),
        issueIds,
        allowComments: composer.allowComments,
        allowReuseContent: composer.allowReuseContent,
        aiGeneratedContent: composer.aiGeneratedContent,
      },
    });
    composer.createdPostId =
      normalizeString(
        createPayload.postId ||
          createPayload.post?.postId ||
          createPayload.item?.postId,
      ) || postId;
    composer.notice =
      mediaType === "video"
        ? "Video upload started. It will appear when processing finishes."
        : "Post published.";
    showToast(composer.notice);
  } catch (error) {
    composer.error = postComposerErrorMessage(error);
    showToast(composer.error);
  } finally {
    composer.pending = false;
    composer.stage = "";
    scheduleRender();
  }
}

