async function querySettingsBrowserPermission(permission) {
  if (permission.key === "photos") {
    return { state: "picker", supported: true };
  }
  if (permission.key === "notifications") {
    if (!("Notification" in window)) {
      return { state: "unsupported", supported: false };
    }
    return { state: normalizeString(window.Notification.permission) || "prompt", supported: true };
  }
  const permissionName =
    permission.key === "location"
      ? "geolocation"
      : permission.key === "camera"
        ? "camera"
        : permission.key === "microphone"
          ? "microphone"
          : permission.key;
  try {
    const status = await navigator.permissions?.query?.({ name: permissionName });
    return { state: normalizeString(status?.state) || "prompt", supported: true };
  } catch {
    return { state: "prompt", supported: Boolean(navigator.mediaDevices || navigator.geolocation) };
  }
}

async function loadSettingsBrowserPermissions({ refresh = false } = {}) {
  const permissions = state.pages.settings.privacySafety.permissions;
  if (permissions.loaded && !refresh) {
    return;
  }
  permissions.loading = true;
  permissions.error = "";
  scheduleRender();
  try {
    const statuses = {};
    for (const permission of SETTINGS_BROWSER_PERMISSIONS) {
      statuses[permission.key] = await querySettingsBrowserPermission(permission);
    }
    permissions.statuses = statuses;
    permissions.loaded = true;
  } catch (error) {
    permissions.error = settingsErrorMessage(
      error,
      "Browser permission status could not be read.",
    );
  } finally {
    permissions.loading = false;
    scheduleRender();
  }
}

async function requestSettingsBrowserPermission(key) {
  const permissions = state.pages.settings.privacySafety.permissions;
  const normalizedKey = normalizeString(key);
  permissions.actionPendingKey = normalizedKey;
  permissions.error = "";
  scheduleRender();
  try {
    if (normalizedKey === "notifications") {
      if (!("Notification" in window)) {
        throw new Error("Notifications are not supported by this browser.");
      }
      await window.Notification.requestPermission();
    } else if (normalizedKey === "location") {
      if (!navigator.geolocation) {
        throw new Error("Location is not supported by this browser.");
      }
      await new Promise((resolve, reject) => {
        navigator.geolocation.getCurrentPosition(resolve, reject, {
          enableHighAccuracy: false,
          maximumAge: 60000,
          timeout: 12000,
        });
      });
    } else if (normalizedKey === "camera" || normalizedKey === "microphone") {
      if (!navigator.mediaDevices?.getUserMedia) {
        throw new Error("Media capture is not supported by this browser.");
      }
      const stream = await navigator.mediaDevices.getUserMedia({
        video: normalizedKey === "camera",
        audio: normalizedKey === "microphone",
      });
      stream.getTracks().forEach((track) => track.stop());
    } else if (normalizedKey === "photos") {
      showToast("Photo access uses the browser file picker when you upload media.");
    }
    await loadSettingsBrowserPermissions({ refresh: true });
    if (normalizedKey !== "photos") {
      showToast("Permission status updated.");
    }
  } catch (error) {
    permissions.error = settingsErrorMessage(error, "Permission request failed.");
    showToast(permissions.error);
  } finally {
    permissions.actionPendingKey = "";
    scheduleRender();
  }
}

