async function runSettingsStorageAction(actionKey) {
  const storage = state.pages.settings.privacySafety.storage;
  const normalizedAction = normalizeString(actionKey);
  storage.actionPendingKey = normalizedAction;
  storage.error = "";
  storage.notice = "";
  scheduleRender();
  try {
    if (normalizedAction === "clear-search") {
      for (const key of SETTINGS_SEARCH_HISTORY_STORAGE_KEYS) {
        window.localStorage?.removeItem(key);
        window.sessionStorage?.removeItem(key);
      }
      storage.notice = "Local search history cleared.";
    } else if (normalizedAction === "clear-browser-cache") {
      if (window.caches?.keys) {
        const keys = await window.caches.keys();
        await Promise.all(
          keys
            .filter((key) => /polis|shared|feed|video/iu.test(key))
            .map((key) => window.caches.delete(key)),
        );
      }
      storage.notice = "Browser cache cleanup finished.";
    } else if (normalizedAction === "reset-feed") {
      if (
        !window.confirm(
          "Reset feed personalization? This clears recommendation state for your account.",
        )
      ) {
        return;
      }
      await fetchJson("/api/me/feed-personalization/reset", {
        auth: true,
        method: "POST",
      });
      storage.notice = "Feed personalization reset.";
    }
    if (storage.notice) {
      showToast(storage.notice);
    }
  } catch (error) {
    storage.error = settingsErrorMessage(error, "Storage action failed.");
    showToast(storage.error);
  } finally {
    storage.actionPendingKey = "";
    scheduleRender();
  }
}

