async function saveSettingsNotificationPreferences(formData) {
  const notifications = state.pages.settings.notifications;
  const categoryKeys = Object.keys(defaultNotificationPreferences().categories);
  const categories = categoryKeys.reduce((next, key) => {
    next[key] = formCheckboxValue(formData, `category:${key}`, false);
    return next;
  }, {});
  const fallback = notifications.item || defaultNotificationPreferences();
  const body = {
    notificationPreferences: {
      categories,
      quietHours: {
        enabled: formCheckboxValue(formData, "quietHoursEnabled", false),
        startMinutes: timeInputToMinutes(
          formData.get("quietStart"),
          fallback.quietHours.startMinutes,
        ),
        endMinutes: timeInputToMinutes(
          formData.get("quietEnd"),
          fallback.quietHours.endMinutes,
        ),
        timezone: normalizeString(formData.get("timezone")) || "UTC",
      },
    },
  };
  notifications.saving = true;
  notifications.error = "";
  scheduleRender();
  try {
    const payload = await fetchJson("/api/me/settings/notifications", {
      auth: true,
      method: "PUT",
      body,
    });
    notifications.item = normalizeNotificationPreferences(payload);
    notifications.loaded = true;
    showToast("Notification preferences saved.");
  } catch (error) {
    notifications.error = settingsErrorMessage(
      error,
      "Notification save failed.",
    );
    showToast(notifications.error);
  } finally {
    notifications.saving = false;
    scheduleRender();
  }
}

function settingsAccountSecurity() {
  if (!state.pages.settings.accountSecurity) {
    state.pages.settings.accountSecurity = createSettingsAccountSecurityState();
  }
  return state.pages.settings.accountSecurity;
}

function defaultSettingsSecurityIdentifier() {
  const reset = settingsAccountSecurity().reset;
  return (
    reset.identifier ||
    state.auth.user?.email ||
    state.auth.user?.username ||
    ""
  );
}

async function requestSettingsPasswordReset(formData) {
  const account = settingsAccountSecurity();
  const reset = account.reset;
  const identifier = normalizeString(formData.get("identifier"));
  if (!identifier) {
    reset.error = "Email or username is required.";
    reset.notice = "";
    scheduleRender();
    return false;
  }
  reset.identifier = identifier;
  reset.requesting = true;
  reset.error = "";
  reset.notice = "";
  scheduleRender();
  try {
    const result = await requestSharedFeedPasswordReset(state.auth.config, {
      identifier,
    });
    reset.username = result.username || identifier;
    reset.deliveryDestination = result.deliveryDestination || "";
    reset.deliveryMedium = result.deliveryMedium || "";
    reset.notice = reset.deliveryDestination
      ? `Reset code sent to ${reset.deliveryDestination}.`
      : "Reset code sent if the account can receive one.";
    showToast("Password reset code sent.");
    return true;
  } catch (error) {
    reset.error = settingsErrorMessage(
      error,
      "Password reset could not be started.",
    );
    showToast(reset.error);
    return false;
  } finally {
    reset.requesting = false;
    scheduleRender();
  }
}

async function confirmSettingsPasswordReset(formData) {
  const account = settingsAccountSecurity();
  const reset = account.reset;
  const identifier =
    normalizeString(formData.get("identifier")) ||
    reset.username ||
    reset.identifier;
  const code = normalizeString(formData.get("code"));
  const password = String(formData.get("password") || "");
  if (!identifier || !code || !password) {
    reset.error = "Email or username, code, and new password are required.";
    reset.notice = "";
    scheduleRender();
    return false;
  }
  reset.identifier = identifier;
  reset.confirming = true;
  reset.error = "";
  reset.notice = "";
  scheduleRender();
  try {
    await confirmSharedFeedPasswordReset(state.auth.config, {
      identifier,
      code,
      password,
    });
    reset.notice = "Password updated. Use the new password the next time you sign in.";
    showToast("Password updated.");
    return true;
  } catch (error) {
    reset.error = settingsErrorMessage(
      error,
      "Password reset could not be confirmed.",
    );
    showToast(reset.error);
    return false;
  } finally {
    reset.confirming = false;
    scheduleRender();
  }
}

async function startSettingsTotpSetup() {
  const account = settingsAccountSecurity();
  const totp = account.totp;
  totp.starting = true;
  totp.error = "";
  totp.notice = "";
  totp.copied = false;
  scheduleRender();
  try {
    const result = await startSharedFeedTotpSetup(
      state.auth.config,
      state.auth.session,
    );
    totp.setupUri = result.setupUri || "";
    totp.secretCode = result.secretCode || "";
    totp.setupSession = result.setupSession || "";
    totp.notice = "Authenticator setup started. Add the setup URI to your app.";
    showToast("Authenticator setup started.");
  } catch (error) {
    totp.error = settingsErrorMessage(
      error,
      "Authenticator setup could not be started.",
    );
    showToast(totp.error);
  } finally {
    totp.starting = false;
    scheduleRender();
  }
}

async function copySettingsTotpSetupUri() {
  const totp = settingsAccountSecurity().totp;
  if (!totp.setupUri) {
    totp.error = "Start setup before copying the URI.";
    scheduleRender();
    return;
  }
  if (!navigator.clipboard?.writeText) {
    totp.error = "Clipboard copy is unavailable in this browser.";
    scheduleRender();
    return;
  }
  try {
    await navigator.clipboard.writeText(totp.setupUri);
    totp.copied = true;
    totp.notice = "Setup URI copied.";
    totp.error = "";
    showToast("Setup URI copied.");
  } catch {
    totp.error = "Setup URI could not be copied.";
  } finally {
    scheduleRender();
  }
}

function openSettingsTotpSetupUri() {
  const totp = settingsAccountSecurity().totp;
  if (!totp.setupUri) {
    totp.error = "Start setup before opening the authenticator URI.";
    scheduleRender();
    return;
  }
  window.location.assign(totp.setupUri);
}

async function verifySettingsTotpSetup(formData) {
  const account = settingsAccountSecurity();
  const totp = account.totp;
  const code = normalizeString(formData.get("code"));
  if (!code) {
    totp.error = "Enter the code from your app.";
    totp.notice = "";
    scheduleRender();
    return false;
  }
  totp.verifying = true;
  totp.error = "";
  totp.notice = "";
  scheduleRender();
  try {
    await verifySharedFeedTotpSetup(state.auth.config, state.auth.session, {
      code,
      setupSession: totp.setupSession,
    });
    totp.notice = "Authenticator app verified.";
    totp.error = "";
    showToast("Authenticator app verified.");
    return true;
  } catch (error) {
    totp.error = settingsErrorMessage(
      error,
      "Authenticator setup could not be verified.",
    );
    showToast(totp.error);
    return false;
  } finally {
    totp.verifying = false;
    scheduleRender();
  }
}

async function loadCurrentRoute({ refresh = false } = {}) {
  const route = getCurrentRoute();
  state.renderError = "";
  if (!(await requireAuthForRoute(route))) {
    return;
  }

  if (getRouteSection(route) !== "messages") {
    if (state.pages.messaging.conversation.item?.conversationId) {
      messagingSocket.unsubscribeConversation(
        state.pages.messaging.conversation.item.conversationId,
      );
    }
    messagingSocket.releaseSession();
    messagingSessionRetained = false;
  }

  if (isFeedRoute(route)) {
    if (isShareRoute(route)) {
      state.mode = FEED_MODE_FOR_YOU;
    }
    state.feedContext = isShareRoute(route)
      ? {
          kind: "share",
          anchorPostId:
            normalizeString(route.routeParams.postId) ||
            normalizeString(runtimeConfig.shareContext?.postId),
        }
      : {
          kind: "app",
          anchorPostId: "",
        };
    if (
      normalizeString(route.routeKey) === ROUTE_KEY_FEED &&
      state.mode === FEED_MODE_FOLLOWING
    ) {
      await loadFollowingFeed({ refresh });
      return;
    }
    await loadInitialFeed({ refresh });
    return;
  }

  const routeKey = normalizeString(route.routeKey);
  if (routeKey !== ROUTE_KEY_ELECTION_DAY) {
    clearElectionPolling();
  }
  if (isPublicAccountRoute(route)) {
    scheduleRender();
    return;
  }
  if (routeKey === ROUTE_KEY_CREATE) {
    await loadPostComposerPage({ refresh });
    return;
  }
  if (routeKey === ROUTE_KEY_POST_ANALYTICS) {
    await loadPostAnalyticsPage(route.routeParams.postId, { refresh });
    return;
  }
  if (routeKey === ROUTE_KEY_DISCOVER) {
    await loadDiscoverPage({ refresh });
    return;
  }
  if (routeKey === ROUTE_KEY_ACHIEVEMENTS) {
    await loadAchievementsPage({ refresh });
    return;
  }
  if (routeKey === ROUTE_KEY_CTA_INVITE) {
    await loadCtaInvitePage(route.routeParams.token, { refresh });
    return;
  }
  if (routeKey === ROUTE_KEY_PUBLIC_PETITION) {
    await loadPublicPetitionPage(route.routeParams.publicSlug, { refresh });
    return;
  }
  if (routeKey === ROUTE_KEY_SEARCH) {
    await loadSearchLanding({ refresh });
    return;
  }
  if (routeKey === ROUTE_KEY_SEARCH_RESULTS) {
    await loadSearchResultsPage({ refresh });
    return;
  }
  if (routeKey === ROUTE_KEY_CANDIDATES) {
    await Promise.all([
      loadCandidateList({ refresh }),
      loadElectionContext({ refresh }).catch(() => state.pages.elections.context),
    ]);
    return;
  }
  if (routeKey === ROUTE_KEY_ELECTION_DAY) {
    await loadElectionDayPage({ refresh });
    return;
  }
  if (routeKey === ROUTE_KEY_CONGRESSIONAL_REPORT_CARD) {
    await loadCongressionalReportCard({ refresh });
    return;
  }
  if (routeKey === ROUTE_KEY_OFFICIAL_DETAIL) {
    await loadOfficialDetail(route.routeParams.officialId, { refresh });
    return;
  }
  if (routeKey === ROUTE_KEY_AUTO_CANDIDATE_DETAIL) {
    await loadAutoCandidateDetail(route.routeParams.entityId, { refresh });
    return;
  }
  if (routeKey === ROUTE_KEY_OFFICIAL_REPORT_CARD) {
    await Promise.all([
      loadOfficialDetail(route.routeParams.officialId, { refresh }),
      loadOfficialReportCard(route.routeParams.officialId, { refresh }),
    ]);
    return;
  }
  if (
    routeKey === ROUTE_KEY_CANDIDATE_DETAIL ||
    routeKey === ROUTE_KEY_CANDIDATE_EDIT
  ) {
    const candidateId = resolveCandidateEditRouteCandidateId(route);
    if (!candidateId) {
      const detail = state.pages.candidates.detail;
      detail.item = null;
      detail.posts = [];
      detail.relatedEvents = [];
      detail.loading = false;
      detail.error =
        routeKey === ROUTE_KEY_CANDIDATE_EDIT
          ? "No candidate found to edit."
          : "Candidate page unavailable.";
      scheduleRender();
      return;
    }
    const legacyOfficialId = extractOfficialIdFromCandidateRouteId(
      candidateId,
    );
    if (legacyOfficialId) {
      navigateTo(buildOfficialProfileRoute(legacyOfficialId), {
        replace: true,
      });
      return;
    }
    const legacyEntityId = extractAutoCandidateEntityId(
      candidateId,
    );
    if (legacyEntityId) {
      navigateTo(buildAutoCandidateRoute(legacyEntityId), { replace: true });
      return;
    }
    await loadCandidateDetail(candidateId, { refresh });
    return;
  }
  if (
    routeKey === ROUTE_KEY_CANDIDATE_DASHBOARD ||
    routeKey === ROUTE_KEY_CANDIDATE_DASHBOARD_DETAIL ||
    routeKey === ROUTE_KEY_CANDIDATE_DASHBOARD_SECTION
  ) {
    await loadCandidateDashboardPage({ refresh });
    return;
  }
  if (
    routeKey === ROUTE_KEY_CANDIDATE_VOTER_MAP ||
    routeKey === ROUTE_KEY_CANDIDATE_VOTER_MAP_SECTION
  ) {
    await loadCandidateVoterMapPage({ refresh });
    return;
  }
  if (
    routeKey === ROUTE_KEY_COALITIONS ||
    routeKey === ROUTE_KEY_COALITION_START ||
    routeKey === ROUTE_KEY_COALITION_JOIN ||
    routeKey === ROUTE_KEY_COALITION_DETAIL ||
    routeKey === ROUTE_KEY_COALITION_SECTION
  ) {
    await loadCoalitionsPage({ refresh });
    return;
  }
  if (routeKey === ROUTE_KEY_MISSIONS) {
    await loadMissionsList({ refresh });
    return;
  }
  if (routeKey === ROUTE_KEY_MISSION_DETAIL) {
    await loadMissionDetail(route.routeParams.missionId, { refresh });
    return;
  }
  if (routeKey === ROUTE_KEY_EVENTS) {
    await loadEventsList({ refresh });
    return;
  }
  if (
    routeKey === ROUTE_KEY_EVENT_DETAIL ||
    routeKey === ROUTE_KEY_EVENT_SIGNUP ||
    routeKey === ROUTE_KEY_EVENT_PAYMENT ||
    routeKey === ROUTE_KEY_MANAGE_EVENTS_NEW ||
    routeKey === ROUTE_KEY_MANAGE_EVENTS_EDIT
  ) {
    if (route.routeParams.eventId) {
      await loadEventDetail(route.routeParams.eventId, { refresh });
    } else {
      scheduleRender();
    }
    return;
  }
  if (routeKey === ROUTE_KEY_MANAGE_EVENTS) {
    await loadManageEvents({ refresh });
    return;
  }
  if (
    routeKey === ROUTE_KEY_PROFILE_SELF ||
    routeKey === ROUTE_KEY_PROFILE_EDIT
  ) {
    await loadProfilePage("", { refresh });
    if (routeKey === ROUTE_KEY_PROFILE_EDIT) {
      return;
    }
    return;
  }
  if (routeKey === ROUTE_KEY_PROFILE_USER) {
    await loadProfilePage(route.routeParams.userId, { refresh });
    return;
  }
  if (routeKey === ROUTE_KEY_PROFILE_CONNECTIONS) {
    await loadProfilePage("", { refresh });
    await loadProfileConnections(
      normalizeString(readCurrentSearchParams().get("kind")) || "followers",
    );
    return;
  }
  if (routeKey === ROUTE_KEY_PROFILE_NOTIFICATIONS) {
    await loadProfilePage("", { refresh });
    await loadProfileNotifications();
    return;
  }
  if (
    routeKey === ROUTE_KEY_ONBOARDING_PROFILE ||
    routeKey === ROUTE_KEY_ONBOARDING_PHOTO
  ) {
    await loadProfilePage("", { refresh });
    return;
  }
  if (
    routeKey === ROUTE_KEY_ONBOARDING_LOCATION ||
    routeKey === ROUTE_KEY_ONBOARDING_ADDRESS
  ) {
    await Promise.all([
      loadProfilePage("", { refresh }).catch(() => {}),
      loadSettingsMyProfile({ refresh }),
      loadSettingsMyDistricts({ refresh }),
    ]);
    return;
  }
  if (
    routeKey === ROUTE_KEY_SETTINGS ||
    routeKey === ROUTE_KEY_SETTINGS_SECTION
  ) {
    await loadSettingsPage({ refresh });
    return;
  }
  if (
    routeKey === ROUTE_KEY_TOPICS ||
    routeKey === ROUTE_KEY_ONBOARDING_TOPICS
  ) {
    await loadTopicsPage({ refresh });
    return;
  }
  if (routeKey === ROUTE_KEY_POLICY_QUESTIONS) {
    await loadPolicyQuestionsPage({ refresh });
    return;
  }
  if (routeKey === ROUTE_KEY_POLICY_QUESTION_DETAIL) {
    await loadPolicyQuestionDetail(route.routeParams.questionId, { refresh });
    return;
  }
  if (
    routeKey === ROUTE_KEY_ADMIN ||
    routeKey === ROUTE_KEY_ADMIN_SECTION
  ) {
    await loadAdminPage({ refresh });
    return;
  }
  if (
    routeKey === ROUTE_KEY_MESSAGES_ROOT ||
    routeKey === ROUTE_KEY_MESSAGES_WILDCARD
  ) {
    const subroute = parseMessagingSubroute(route);
    if (subroute.alias) {
      navigateTo(
        buildMessagingServerRoute(subroute.scopeType, subroute.scopeId),
        {
          replace: true,
        },
      );
      return;
    }
    await ensureMessagingInitialized({ force: refresh });
    await connectMessagingSocketForRoute();
    if (subroute.view === "inbox") {
      await Promise.all([
        loadMessagingInbox({ refresh }),
        loadMessagingRequests(),
        loadMessagingServers(),
      ]);
      return;
    }
    if (subroute.view === "requests") {
      await Promise.all([
        loadMessagingRequests(),
        loadMessagingInbox({ refresh }).catch(() => {}),
        loadMessagingServers(),
      ]);
      return;
    }
    if (subroute.view === "compose") {
      await Promise.all([
        loadMessagingInbox({ refresh }).catch(() => {}),
        loadMessagingServers(),
        loadMessagingComposeFriends({ refresh }).catch(() => {}),
      ]);
      return;
    }
    if (subroute.view === "settings") {
      await Promise.all([
        loadMessagingSettings(),
        loadMessagingInbox({ refresh }).catch(() => {}),
        loadMessagingServers(),
      ]);
      return;
    }
    if (subroute.view === "devices") {
      await Promise.all([loadMessagingDevices(), loadMessagingServers()]);
      return;
    }
    if (subroute.view === "device-link") {
      await Promise.all([
        loadMessagingDevices(),
        loadMessagingSecurity(),
        loadMessagingServers(),
      ]);
      if (subroute.linkId) {
        await loadMessagingDeviceLink(subroute.linkId);
      }
      return;
    }
    if (subroute.view === "recovery") {
      await Promise.all([loadMessagingRecovery(), loadMessagingServers()]);
      return;
    }
    if (subroute.view === "recovery-restore") {
      await Promise.all([loadMessagingRecovery(), loadMessagingServers()]);
      return;
    }
    if (subroute.view === "security") {
      await Promise.all([loadMessagingSecurity(), loadMessagingServers()]);
      return;
    }
    if (subroute.view === "server") {
      await Promise.all([
        loadMessagingInbox({ refresh }).catch(() => {}),
        loadMessagingRequests().catch(() => {}),
        loadMessagingServers(),
        loadMessagingServerDirectory(subroute.scopeType, subroute.scopeId, {
          refresh,
        }),
      ]);
      return;
    }
    if (
      subroute.view === "server-settings" ||
      subroute.view === "server-settings-section"
    ) {
      const settingsPromises = [
        loadMessagingServers(),
        loadMessagingServerDirectory(subroute.scopeType, subroute.scopeId, {
          refresh,
        }).catch(() => {}),
        loadMessagingServerSettings(subroute.scopeType, subroute.scopeId, {
          refresh,
        }),
      ];
      const settingsSectionId = messagingServerSettingsKnownSection(
        subroute.sectionId,
      );
      if (settingsSectionId === "audit-log") {
        settingsPromises.push(
          loadMessagingServerAudit(subroute.scopeType, subroute.scopeId, {
            refresh,
          }),
        );
      }
      if (settingsSectionId === "emoji" || settingsSectionId === "stickers") {
        settingsPromises.push(
          loadMessagingServerAssets(
            subroute.scopeType,
            subroute.scopeId,
            settingsSectionId === "emoji" ? "emoji" : "sticker",
            { refresh },
          ),
        );
      }
      if (settingsSectionId === "security") {
        settingsPromises.push(
          loadMessagingServerSecurityPolicy(
            subroute.scopeType,
            subroute.scopeId,
            { refresh },
          ),
        );
      }
      if (
        settingsSectionId === "community-settings" ||
        settingsSectionId === "invites"
      ) {
        settingsPromises.push(
          loadMessagingServerInvites(subroute.scopeType, subroute.scopeId, {
            refresh,
          }),
        );
      }
      await Promise.all(settingsPromises);
      return;
    }
    if (subroute.view === "server-roles") {
      await Promise.all([
        loadMessagingServers(),
        loadMessagingServerDirectory(subroute.scopeType, subroute.scopeId, {
          refresh,
        }).catch(() => {}),
        loadMessagingServerRoles(subroute.scopeType, subroute.scopeId, {
          refresh,
        }),
      ]);
      return;
    }
    if (subroute.view === "server-role") {
      await Promise.all([
        loadMessagingServers(),
        loadMessagingServerDirectory(subroute.scopeType, subroute.scopeId, {
          refresh,
        }).catch(() => {}),
        loadMessagingServerRoleDetail(
          subroute.scopeType,
          subroute.scopeId,
          subroute.roleId,
          { refresh },
        ),
      ]);
      return;
    }
    if (subroute.view === "server-members") {
      await Promise.all([
        loadMessagingServers(),
        loadMessagingServerDirectory(subroute.scopeType, subroute.scopeId, {
          refresh,
        }).catch(() => {}),
        loadMessagingServerMembers(subroute.scopeType, subroute.scopeId, {
          refresh,
        }),
      ]);
      return;
    }
    if (subroute.view === "server-member") {
      await Promise.all([
        loadMessagingServers(),
        loadMessagingServerDirectory(subroute.scopeType, subroute.scopeId, {
          refresh,
        }).catch(() => {}),
        loadMessagingServerMembers(subroute.scopeType, subroute.scopeId, {
          refresh,
        }).catch(() => {}),
        loadMessagingServerMember(
          subroute.scopeType,
          subroute.scopeId,
          subroute.userId,
          { refresh },
        ),
      ]);
      return;
    }
    if (subroute.view === "server-bans") {
      await Promise.all([
        loadMessagingServers(),
        loadMessagingServerDirectory(subroute.scopeType, subroute.scopeId, {
          refresh,
        }).catch(() => {}),
        loadMessagingServerBans(subroute.scopeType, subroute.scopeId, {
          refresh,
        }),
      ]);
      return;
    }
    if (subroute.view === "server-workflows") {
      await Promise.all([
        loadMessagingServers(),
        loadMessagingServerDirectory(subroute.scopeType, subroute.scopeId, {
          refresh,
        }).catch(() => {}),
        loadMessagingServerWorkflows(subroute.scopeType, subroute.scopeId, {
          refresh,
        }),
      ]);
      return;
    }
    if (subroute.view === "server-moderation") {
      await Promise.all([
        loadMessagingServers(),
        loadMessagingServerDirectory(subroute.scopeType, subroute.scopeId, {
          refresh,
        }).catch(() => {}),
        loadMessagingServerModerationQueue(
          subroute.scopeType,
          subroute.scopeId,
          { refresh },
        ),
        loadMessagingServerAutomodRules(subroute.scopeType, subroute.scopeId, {
          refresh,
        }),
      ]);
      return;
    }
    if (subroute.view === "conversation") {
      await Promise.all([
        loadMessagingInbox({ refresh }),
        loadMessagingRequests().catch(() => {}),
        loadMessagingServers(),
        loadMessagingConversation(subroute.conversationId, { refresh }),
      ]);
      await loadMessagingSecureBrowserContextIfNeeded();
      return;
    }
    if (subroute.view === "conversation-people") {
      await Promise.all([
        loadMessagingInbox({ refresh }),
        loadMessagingRequests().catch(() => {}),
        loadMessagingServers(),
        loadMessagingConversation(subroute.conversationId, { refresh }),
        loadMessagingConversationMembers(subroute.conversationId, {
          refresh,
        }).catch(() => {}),
        loadMessagingGroupPeopleFriends({ refresh }).catch(() => {}),
      ]);
      await loadMessagingSecureBrowserContextIfNeeded();
      return;
    }
    if (subroute.view === "server-room") {
      await Promise.all([
        loadMessagingServers(),
        loadMessagingRequests().catch(() => {}),
        loadMessagingServerDirectory(subroute.scopeType, subroute.scopeId, {
          refresh,
        }).catch(() => {}),
        loadMessagingConversation(subroute.conversationId, { refresh }),
        loadMessagingConversationMembers(subroute.conversationId, {
          refresh,
        }).catch(() => {}),
      ]);
      await loadMessagingSecureBrowserContextIfNeeded();
      return;
    }
    if (
      subroute.view === "room-settings" ||
      subroute.view === "room-settings-notifications" ||
      subroute.view === "room-settings-pins" ||
      subroute.view === "room-settings-invites" ||
      subroute.view === "room-settings-integrations" ||
      subroute.view === "room-settings-section"
    ) {
      const roomSettingsLoaders = [
        loadMessagingServers(),
        loadMessagingServerDirectory(subroute.scopeType, subroute.scopeId, {
          refresh,
        }).catch(() => {}),
        loadMessagingConversation(subroute.conversationId, { refresh }),
        loadMessagingConversationMembers(subroute.conversationId, { refresh }),
      ];
      if (subroute.view === "room-settings-invites") {
        roomSettingsLoaders.push(
          loadMessagingChannelInviteLinks(subroute.conversationId, {
            refresh,
          }),
        );
      }
      if (subroute.view === "room-settings-pins") {
        roomSettingsLoaders.push(
          loadMessagingChannelPins(subroute.conversationId, {
            refresh,
          }),
        );
      }
      await Promise.all(roomSettingsLoaders);
      return;
    }
    if (
      subroute.view === "room-permissions" ||
      subroute.view === "room-permission-role"
    ) {
      await Promise.all([
        loadMessagingServers(),
        loadMessagingServerDirectory(subroute.scopeType, subroute.scopeId, {
          refresh,
        }).catch(() => {}),
        loadMessagingConversation(subroute.conversationId, { refresh }).catch(
          () => {},
        ),
        loadMessagingPermissionTarget("channel", subroute.conversationId, {
          refresh,
        }),
      ]);
      if (subroute.roleId) {
        await loadMessagingServerRoles(subroute.scopeType, subroute.scopeId, {
          refresh,
        }).catch(() => {});
      }
      return;
    }
    if (
      subroute.view === "category-permissions" ||
      subroute.view === "category-permission-role"
    ) {
      await Promise.all([
        loadMessagingServers(),
        loadMessagingServerDirectory(subroute.scopeType, subroute.scopeId, {
          refresh,
        }).catch(() => {}),
        loadMessagingPermissionTarget("category", subroute.categoryId, {
          refresh,
        }),
      ]);
      if (subroute.roleId) {
        await loadMessagingServerRoles(subroute.scopeType, subroute.scopeId, {
          refresh,
        }).catch(() => {});
      }
      return;
    }
  }
}

async function handleShare(postId) {
  const shareUrl = getShareUrl(postId);
  try {
    if (navigator.share) {
      await navigator.share({
        title: "Polis",
        text: "Watch this Polis post",
        url: shareUrl,
      });
      return;
    }
    await navigator.clipboard.writeText(shareUrl);
    showToast("Link copied.");
  } catch {
    showToast("Sharing unavailable on this device.");
  }
}

function requestAppOpen(postId, commentId = "") {
  const targetUrl = buildAppOpenUrl(postId, commentId);
  if (!targetUrl) {
    showToast("App link unavailable.");
    return;
  }
  window.location.assign(targetUrl);
}

