function topicsCategoryKey(issue = {}) {
  return issue.categoryId || issue.categoryLabel || "other";
}

function topicsCategoryLabel(issue = {}) {
  return issue.categoryLabel || humanizeLabel(issue.categoryId) || "Other";
}

function getTopicCategoryEntries(issues = state.pages.topics.issues) {
  const byKey = new Map();
  for (const issue of issues) {
    const key = topicsCategoryKey(issue);
    if (!byKey.has(key)) {
      byKey.set(key, {
        key,
        label: topicsCategoryLabel(issue),
        count: 0,
      });
    }
    byKey.get(key).count += 1;
  }
  return Array.from(byKey.values()).sort((left, right) =>
    left.label.localeCompare(right.label),
  );
}

function getFilteredTopicIssues() {
  const topics = state.pages.topics;
  const query = normalizeString(topics.query).toLowerCase();
  const categoryId = normalizeString(topics.categoryId);
  return topics.issues.filter((issue) => {
    if (
      categoryId &&
      issue.categoryId !== categoryId &&
      issue.categoryLabel !== categoryId &&
      topicsCategoryKey(issue) !== categoryId
    ) {
      return false;
    }
    if (!query) {
      return true;
    }
    return [
      issue.label,
      issue.issueId,
      issue.categoryLabel,
      issue.categoryId,
    ]
      .join(" ")
      .toLowerCase()
      .includes(query);
  });
}

function groupTopicIssues(issues) {
  const grouped = new Map();
  for (const issue of issues) {
    const key = topicsCategoryKey(issue);
    if (!grouped.has(key)) {
      grouped.set(key, {
        key,
        label: topicsCategoryLabel(issue),
        items: [],
      });
    }
    grouped.get(key).items.push(issue);
  }
  return Array.from(grouped.values())
    .map((group) => ({
      ...group,
      items: group.items.sort((left, right) =>
        left.label.localeCompare(right.label),
      ),
    }))
    .sort((left, right) => left.label.localeCompare(right.label));
}

function renderTopicCard(issue, options) {
  const topics = state.pages.topics;
  const followed = topics.followedIds.has(issue.issueId);
  const pending = topics.actionPendingKey === `follow:${issue.issueId}`;
  const selectedCount = topics.followedIds.size;
  const canSelectMore =
    !options.selectionMode || selectedCount < options.maxSelection || followed;
  const disabled = pending || (!followed && !canSelectMore);
  return `<article class="shared-topics-card${followed ? " is-selected" : ""}">
    <div class="shared-topics-card__main">
      <span>${escapeHtml(topicsCategoryLabel(issue))}</span>
      <strong>${escapeHtml(issue.label)}</strong>
      <small>${escapeHtml(issue.issueId)}</small>
    </div>
    <button class="shared-feed-chip${followed ? "" : " shared-feed-chip--primary"}" type="button" data-action="topics-toggle" data-issue-id="${escapeHtml(issue.issueId)}" data-follow="${followed ? "false" : "true"}"${disabledAttr(disabled)}>
      ${pending ? "Saving..." : followed ? `${renderIcon("check")} Following` : "Follow"}
    </button>
  </article>`;
}

function renderTopicsSelectionFooter(options) {
  if (!options.selectionMode) {
    return "";
  }
  const topics = state.pages.topics;
  const selectedCount = topics.followedIds.size;
  const canContinue = topicsCanContinue(options);
  const busy = Boolean(topics.actionPendingKey);
  const helper = canContinue
    ? "Ready to continue"
    : `Select ${options.minSelection}-${options.maxSelection} topics to continue`;
  return `<section class="shared-topics-footer">
    <div>
      <strong>${escapeHtml(helper)}</strong>
      <span>${escapeHtml(`${selectedCount} selected`)}</span>
    </div>
    <div class="shared-topics-footer__actions">
      ${
        options.onboardingMode
          ? `<button class="shared-feed-chip" type="button" data-action="topics-skip"${disabledAttr(busy)}>Skip</button>`
          : `<button class="shared-feed-chip" type="button" data-action="navigate" data-route="/settings/preferences"${disabledAttr(busy)}>Back</button>`
      }
      <button class="shared-feed-chip shared-feed-chip--primary" type="button" data-action="topics-complete"${disabledAttr(busy || !canContinue)}>${busy && topics.actionPendingKey === "topics:complete" ? "Saving..." : "Continue"}</button>
    </div>
  </section>`;
}

