function coalitionVoterRecordsSourceCounts(resource = {}) {
  return (resource.items || []).reduce(
    (counts, item) => {
      const source = candidateVoterSourceLabel(item).toLowerCase();
      if (source.includes("polis")) {
        counts.polis += 1;
      } else if (source.includes("manual")) {
        counts.manual += 1;
      } else if (source.includes("import")) {
        counts.imported += 1;
      } else {
        counts.other += 1;
      }
      return counts;
    },
    { polis: 0, manual: 0, imported: 0, other: 0 },
  );
}

