function renderMissionListCard(mission) {
  const nextJob = missionNextJob(mission);
  const progress = missionCompletionPercent(mission);
  const returnTo = encodeURIComponent(getCurrentPathWithQuery());
  return `<article class="shared-mission-card">
    <button class="shared-mission-card__main" type="button" data-action="navigate" data-route="/missions/${escapeHtml(encodeURIComponent(mission.missionId))}?returnTo=${escapeHtml(returnTo)}">
      <span class="shared-mission-card__status">${renderIcon("mission")}</span>
      <span class="shared-mission-card__body">
        <span class="shared-card__meta">
          <span>${escapeHtml(missionScopeDisplayName(mission))}</span>
          <span>${escapeHtml(humanizeLabel(mission.priority))}</span>
        </span>
        <strong>${escapeHtml(mission.title)}</strong>
        <span>${escapeHtml(mission.description || (nextJob ? `Next: ${nextJob.title}` : "No task summary available."))}</span>
      </span>
      <span class="shared-mission-card__side">
        ${renderMissionBadge(humanizeLabel(mission.status), missionStatusTone(mission.status))}
        ${mission.dueAt ? `<small>Due ${escapeHtml(formatAbsoluteDateTime(mission.dueAt))}</small>` : "<small>No due date</small>"}
      </span>
    </button>
    <div class="shared-mission-progress" aria-label="${escapeHtml(`${progress}% complete`)}">
      <span style="width: ${Math.max(0, Math.min(100, progress))}%"></span>
    </div>
    <div class="shared-mission-card__metrics">
      <span>${escapeHtml(formatCount(mission.openCount))} open</span>
      <span>${escapeHtml(formatCount(mission.attentionCount))} needs attention</span>
      <span>${escapeHtml(formatCount(mission.claimableCount))} claimable</span>
    </div>
  </article>`;
}

function missionListCounts(items = []) {
  return {
    total: items.length,
    open: items.reduce((sum, mission) => sum + mission.openCount, 0),
    attention: items.reduce((sum, mission) => sum + mission.attentionCount, 0),
    claimable: items.reduce((sum, mission) => sum + mission.claimableCount, 0),
    dueSoon: items.reduce(
      (sum, mission) =>
        sum + (mission.jobs || []).filter((job) => job.isDueSoon).length,
      0,
    ),
    blocked: items.reduce(
      (sum, mission) =>
        sum + (mission.jobs || []).filter((job) => job.isBlocked).length,
      0,
    ),
    submitted: items.reduce(
      (sum, mission) =>
        sum + (mission.jobs || []).filter((job) => job.isSubmitted).length,
      0,
    ),
    high: items.filter(missionHasHighPriority).length,
  };
}

function missionListPriorityItems(items = []) {
  return [...items].sort((left, right) => {
    const leftJob = missionNextJob(left) || {};
    const rightJob = missionNextJob(right) || {};
    const jobRank =
      candidateMissionJobRank(leftJob) - candidateMissionJobRank(rightJob);
    if (jobRank) return jobRank;
    const leftDue = candidateMissionEarliestDue(left) || Number.MAX_SAFE_INTEGER;
    const rightDue = candidateMissionEarliestDue(right) || Number.MAX_SAFE_INTEGER;
    if (leftDue !== rightDue) return leftDue - rightDue;
    return (right.attentionCount || 0) - (left.attentionCount || 0);
  });
}

function renderMissionListQuickFocus(filters, counts) {
  const entries = [
    ["", "All", counts.total],
    ["attention", "Attention", counts.attention],
    ["claimable", "Claimable", counts.claimable],
    ["soon", "Due soon", counts.dueSoon],
    ["blocked", "Blocked", counts.blocked],
    ["submitted", "Submitted", counts.submitted],
    ["high", "High priority", counts.high],
  ];
  return `<div class="shared-missions-command__focus">
    ${entries
      .map(([status, label, count]) => {
        const active =
          normalizeString(filters.status) === status ||
          (!normalizeString(filters.status) && !status);
        return `<button class="shared-missions-focus-chip${active ? " is-active" : ""}" type="button" data-action="navigate" data-route="${escapeHtml(buildMissionsRoute({ ...filters, status }))}">
          <span>${escapeHtml(label)}</span>
          <strong>${escapeHtml(formatCount(count))}</strong>
        </button>`;
      })
      .join("")}
  </div>`;
}

