function eventStartTimestamp(event = {}) {
  return Number(event.startAt) || 0;
}

function eventEndTimestamp(event = {}) {
  return Number(event.endAt) || eventStartTimestamp(event);
}

function eventIsPast(event = {}) {
  const endAt = eventEndTimestamp(event);
  return Boolean(endAt && endAt < Date.now());
}

function eventIsSoon(event = {}) {
  const startAt = eventStartTimestamp(event);
  return Boolean(
    startAt &&
      startAt >= Date.now() &&
      startAt - Date.now() <= 48 * 60 * 60 * 1000,
  );
}

function eventDateLabel(event = {}) {
  const startAt = eventStartTimestamp(event);
  if (!startAt) {
    return "Date pending";
  }
  return new Date(startAt).toLocaleString(undefined, {
    weekday: "short",
    month: "short",
    day: "numeric",
    hour: "numeric",
    minute: "2-digit",
  });
}

function eventTimeLabel(event = {}) {
  const startAt = eventStartTimestamp(event);
  if (!startAt) {
    return "Pending";
  }
  return new Date(startAt).toLocaleTimeString(undefined, {
    hour: "numeric",
    minute: "2-digit",
  });
}

function eventLocationLabel(event = {}) {
  return (
    normalizeString(event.locationTown) ||
    normalizeString(event.locationName) ||
    normalizeString(event.address) ||
    "Location pending"
  );
}

function eventListCounts(items = []) {
  return items.reduce(
    (counts, event) => {
      counts.total += 1;
      if (!eventIsPast(event)) counts.upcoming += 1;
      if (eventIsSoon(event)) counts.soon += 1;
      if (event.isAttending) counts.going += 1;
      if (event.isInterested) counts.interested += 1;
      if (eventRequiresPayment(event)) counts.paid += 1;
      if (event.transportEnabled) counts.transport += 1;
      if (normalizeString(event.eventType).toLowerCase() === "cta") counts.cta += 1;
      return counts;
    },
    {
      total: 0,
      upcoming: 0,
      soon: 0,
      going: 0,
      interested: 0,
      paid: 0,
      transport: 0,
      cta: 0,
    },
  );
}

function eventSpotlight(items = []) {
  return (
    [...items]
      .filter((event) => !eventIsPast(event))
      .sort((a, b) => eventStartTimestamp(a) - eventStartTimestamp(b))[0] ||
    null
  );
}

function renderEventMetric(label, value, detail = "") {
  return `<div>
    <span>${escapeHtml(label)}</span>
    <strong>${escapeHtml(formatCount(value))}</strong>
    ${detail ? `<small>${escapeHtml(detail)}</small>` : ""}
  </div>`;
}

