function normalizeManageEventsStatus(value) {
  const normalized = normalizeString(value).toLowerCase();
  return normalized === "previous" || normalized === "archived"
    ? "previous"
    : "active";
}

function manageEventsStatusLabel(value) {
  return normalizeManageEventsStatus(value) === "previous"
    ? "Previous"
    : "Active";
}

function manageEventsStatusRoute(value) {
  const status = normalizeManageEventsStatus(value);
  return status === "previous"
    ? "/manage-events?status=previous"
    : "/manage-events";
}

function manageEventSummary(items = []) {
  return items.reduce(
    (summary, event) => {
      summary.total += 1;
      summary.attending += Number(event.attendeeCount) || 0;
      summary.interested += Number(event.interestedCount) || 0;
      if (event.imageUrl) summary.withCovers += 1;
      if (Number.isFinite(Number(event.lat)) && Number.isFinite(Number(event.lng))) {
        summary.mapReady += 1;
      }
      if (eventRequiresPayment(event)) summary.paid += 1;
      if (event.transportEnabled) summary.transport += 1;
      if (eventIsSoon(event)) summary.soon += 1;
      return summary;
    },
    {
      total: 0,
      attending: 0,
      interested: 0,
      withCovers: 0,
      mapReady: 0,
      paid: 0,
      transport: 0,
      soon: 0,
    },
  );
}

function renderManageEventsMetric(label, value, detail = "") {
  return `<div>
    <span>${escapeHtml(label)}</span>
    <strong>${escapeHtml(value)}</strong>
    ${detail ? `<small>${escapeHtml(detail)}</small>` : ""}
  </div>`;
}

function manageEventTimeRange(event = {}) {
  const start = eventStartTimestamp(event);
  const end = eventEndTimestamp(event);
  if (!start) {
    return "Date pending";
  }
  const startLabel = eventDateLabel(event);
  if (!end || end === start) {
    return startLabel;
  }
  return `${startLabel} - ${new Date(end).toLocaleTimeString(undefined, {
    hour: "numeric",
    minute: "2-digit",
  })}`;
}

function manageEventContactLabel(event = {}) {
  return normalizeString(
    event.raw?.socials?.email ||
      event.raw?.email ||
      event.raw?.contactEmail ||
      event.raw?.contact_email,
  );
}

function manageEventReadiness(event = {}) {
  const mapReady =
    Number.isFinite(Number(event.lat)) && Number.isFinite(Number(event.lng));
  const contact = manageEventContactLabel(event);
  return [
    ["Cover", event.imageUrl ? "Ready" : "Missing", Boolean(event.imageUrl)],
    ["Map", mapReady ? "Ready" : "Needs coordinates", mapReady],
    ["Contact", contact ? contact : "Missing", Boolean(contact)],
    ["Signup", eventRequiresPayment(event) ? "Paid checkout" : "Free RSVP", true],
  ];
}

function renderManageEventReadiness(event = {}) {
  return `<div class="shared-manage-event-card__readiness">
    ${manageEventReadiness(event)
      .map(
        ([label, value, ready]) => `<span class="${ready ? "is-ready" : "is-missing"}">
          <strong>${escapeHtml(label)}</strong>
          <em>${escapeHtml(value)}</em>
        </span>`,
      )
      .join("")}
  </div>`;
}

function renderManageEventCard(event) {
  const tags = event.tags.slice(0, 5);
  const isPrevious = eventIsPast(event);
  const statusLabel = isPrevious ? "Previous" : eventIsSoon(event) ? "Soon" : "Active";
  return `<article class="shared-manage-event-card">
    <div class="shared-manage-event-card__media">
      ${
        event.imageUrl
          ? `<img src="${escapeHtml(event.imageUrl)}" alt="${escapeHtml(event.title)}" />`
          : `<div>${renderIcon("calendar")}<span>Cover needed</span></div>`
      }
    </div>
    <div class="shared-manage-event-card__body">
      <div class="shared-card__meta">
        <span>${escapeHtml(statusLabel)}</span>
        <span>${escapeHtml(manageEventTimeRange(event))}</span>
        <span>${escapeHtml(eventCostLabel(event))}</span>
      </div>
      <h3>${escapeHtml(event.title)}</h3>
      <p>${escapeHtml(event.description || event.address || "Event details are being finalized.")}</p>
      <div class="shared-manage-event-card__facts">
        <span>${renderIcon("map")} ${escapeHtml(eventLocationLabel(event))}</span>
        <span>${renderIcon("candidate")} ${escapeHtml(event.hostDisplayName || "Host pending")}</span>
        <span>${renderIcon("calendar")} ${escapeHtml(event.transportEnabled ? eventTransportLabel(event) : "No transport")}</span>
      </div>
      <div class="shared-manage-event-card__stats">
        <span><strong>${escapeHtml(formatCount(event.attendeeCount))}</strong><small>going</small></span>
        <span><strong>${escapeHtml(formatCount(event.interestedCount))}</strong><small>interested</small></span>
        <span><strong>${escapeHtml(eventCostLabel(event))}</strong><small>cost</small></span>
      </div>
      ${renderManageEventReadiness(event)}
      ${
        tags.length
          ? `<div class="shared-event-feed-card__tags">${tags.map((tag) => `<span>${escapeHtml(tag)}</span>`).join("")}</div>`
          : ""
      }
      <div class="shared-manage-event-card__actions">
        <button class="shared-feed-chip shared-feed-chip--primary" data-action="navigate" data-route="${escapeHtml(eventDetailRoute(event))}">Open</button>
        <button class="shared-feed-chip" data-action="navigate" data-route="/manage-events/${escapeHtml(encodeURIComponent(event.eventId))}/edit">Edit</button>
        <button class="shared-feed-chip" data-action="delete-event" data-event-id="${escapeHtml(event.eventId)}">Delete</button>
      </div>
    </div>
  </article>`;
}

function renderManageEventsEmpty(status) {
  const previous = normalizeManageEventsStatus(status) === "previous";
  return `<article class="shared-manage-events-empty">
    <div>${renderIcon("calendar")}</div>
    <h2>${escapeHtml(previous ? "No previous events yet" : "No active events yet")}</h2>
    <p>${escapeHtml(
      previous
        ? "Events move here after they end. Keep the active tab focused on what still needs attendance, edits, and map details."
        : "Create the first event to publish a detail page, RSVP path, map location, contact details, and attendee tracking.",
    )}</p>
    <div class="shared-card__actions">
      <button class="shared-feed-chip shared-feed-chip--primary" type="button" data-action="navigate" data-route="/manage-events/new">Create event</button>
      <button class="shared-feed-chip" type="button" data-action="navigate" data-route="/events">Public events</button>
    </div>
  </article>`;
}

function renderManageEventsPage() {
  const manage = state.pages.events.manage;
  const status = normalizeManageEventsStatus(manage.status);
  const statusLabel = manageEventsStatusLabel(status);
  const summary = manageEventSummary(manage.items);
  return `<section class="shared-page">
    ${renderTopChrome()}
    <div class="shared-page__content">
      <div class="shared-page__header">
        <div>
          <p class="shared-page__eyebrow">Manage events</p>
          <h1>Event workspace</h1>
          <p>Publish and maintain the browser version of event discovery, detail pages, signup paths, map context, attendee counts, and paid-event handoff.</p>
        </div>
        <div class="shared-card__actions">
          <button class="shared-feed-chip shared-feed-chip--primary" data-action="navigate" data-route="/manage-events/new">Create event</button>
          <button class="shared-feed-chip" data-action="navigate" data-route="/events">Public events</button>
        </div>
      </div>
      <section class="shared-manage-events-command">
        <div class="shared-manage-events-command__main">
          <div class="shared-card__meta">
            <span>${escapeHtml(statusLabel)} events</span>
            <span>${escapeHtml(manage.loading ? "Syncing" : manage.loaded ? "Loaded" : "Ready")}</span>
          </div>
          <h2>${escapeHtml(status === "previous" ? "Review past turnout and clean up event history." : "Keep upcoming events ready for RSVPs and promotion.")}</h2>
          <p>${escapeHtml(status === "previous" ? "Previous events keep attendee, interest, cost, host, and map context available for follow-up work." : "Active events need clear public details, complete signup paths, contact information, and enough readiness signals to avoid a rough handoff from the app.")}</p>
          <div class="shared-manage-events-tabs" role="group" aria-label="Event status">
            <button class="shared-feed-chip${status === "active" ? " shared-feed-chip--primary" : ""}" data-action="manage-events-status" data-status="active">Active</button>
            <button class="shared-feed-chip${status === "previous" ? " shared-feed-chip--primary" : ""}" data-action="manage-events-status" data-status="previous">Previous</button>
          </div>
        </div>
        <div class="shared-manage-events-command__metrics">
          ${renderManageEventsMetric("Events", formatCount(summary.total), statusLabel)}
          ${renderManageEventsMetric("Going", formatCount(summary.attending), "attendees")}
          ${renderManageEventsMetric("Interested", formatCount(summary.interested), "signals")}
          ${renderManageEventsMetric("Map ready", `${formatCount(summary.mapReady)}/${formatCount(summary.total)}`, "locations")}
          ${renderManageEventsMetric("Covers", `${formatCount(summary.withCovers)}/${formatCount(summary.total)}`, "visuals")}
          ${renderManageEventsMetric("Paid", formatCount(summary.paid), "checkout")}
        </div>
      </section>
      ${
        manage.loading
          ? `<div class="shared-page__loading">Loading ${escapeHtml(statusLabel.toLowerCase())} events...</div>`
          : ""
      }
      ${manage.error ? `<div class="shared-page__error">${escapeHtml(manage.error)}</div>` : ""}
      <div class="shared-manage-events-list">
        ${
          manage.items.length
            ? manage.items.map(renderManageEventCard).join("")
            : !manage.loading
              ? renderManageEventsEmpty(status)
              : ""
        }
      </div>
    </div>
  </section>`;
}

function renderEventAddressLookup(draft, pending) {
  const lookup = state.pages.events.detail.addressLookup;
  const hasItems = lookup.items.length > 0;
  return `<div class="shared-event-address-lookup is-wide">
    <label>
      <span>Event address</span>
      <input name="address" value="${escapeHtml(draft.address)}" autocomplete="street-address" required data-event-editor-field="address"${disabledAttr(pending)} />
    </label>
    ${
      lookup.loading
        ? `<div class="shared-event-address-lookup__status">Searching addresses...</div>`
        : ""
    }
    ${
      lookup.error
        ? `<div class="shared-event-address-lookup__error">${escapeHtml(lookup.error)}</div>`
        : ""
    }
    ${
      hasItems
        ? `<div class="shared-event-address-lookup__results">
            ${lookup.items
              .map(
                (item, index) => `<button class="shared-event-address-option" type="button" data-action="event-address-select" data-index="${escapeHtml(String(index))}"${disabledAttr(pending)}>
                  <strong>${escapeHtml(item.primaryText)}</strong>
                  ${item.secondaryText ? `<span>${escapeHtml(item.secondaryText)}</span>` : ""}
                </button>`,
              )
              .join("")}
          </div>`
        : ""
    }
  </div>`;
}

function renderEventEditorReadiness(draft) {
  const checks = [
    ["Cover", normalizeString(draft.imageUrl), "Cover image is set"],
    ["Time", normalizeString(draft.startAt) && normalizeString(draft.endAt), "Start and end are set"],
    ["Map", normalizeString(draft.lat) && normalizeString(draft.lng), "Map coordinates are set"],
    ["Contact", normalizeString(draft.email), "Contact email is set"],
    ["Cost", draft.isFree || normalizeString(draft.costAmount), draft.isFree ? "Free event" : "Ticket price is set"],
  ];
  return `<div class="shared-event-editor__checks">
    ${checks
      .map(
        ([label, ready, detail]) => `<span class="${ready ? "is-ready" : "is-missing"}">
          <strong>${escapeHtml(label)}</strong>
          <em>${escapeHtml(ready ? detail : "Needs attention")}</em>
        </span>`,
      )
      .join("")}
  </div>`;
}

function refreshEventEditorPreviewFromDraft(draft) {
  const editor = root?.querySelector(".shared-event-editor");
  if (!editor || !draft) {
    return;
  }
  const cover = editor.querySelector(".shared-event-editor__cover");
  if (cover) {
    cover.classList.toggle("has-image", Boolean(normalizeString(draft.imageUrl)));
    cover.innerHTML = draft.imageUrl
      ? `<img src="${escapeHtml(draft.imageUrl)}" alt="${escapeHtml(draft.title || "Event cover")}" />`
      : `<div>${renderIcon("upload")}<strong>Cover preview</strong></div>`;
  }
  const summary = editor.querySelector(".shared-event-editor__summary");
  if (summary) {
    const eyebrow = summary.querySelector(".shared-page__eyebrow");
    const title = summary.querySelector("h2");
    const body = summary.querySelector("p:not(.shared-page__eyebrow)");
    const meta = summary.querySelector(".shared-card__meta");
    if (eyebrow) eyebrow.textContent = draft.isFree ? "Free event" : "Paid event";
    if (title) title.textContent = draft.title || "Untitled event";
    if (body) {
      body.textContent =
        draft.description || "Add the public event description.";
    }
    if (meta) {
      meta.innerHTML = `<span>${escapeHtml(draft.locationTown || "Location pending")}</span><span>${escapeHtml(draft.tags || "No tags")}</span>`;
    }
  }
  const checks = editor.querySelector(".shared-event-editor__checks");
  if (checks) {
    checks.outerHTML = renderEventEditorReadiness(draft);
  }
}

function renderEventEditorWorkspace(event = {}, mode = "create", detail) {
  const draft = eventEditorDraft(event, mode);
  const pending = detail.saving === true;
  const isEdit = mode === "edit";
  const cancelRoute =
    isEdit && draft.eventId
      ? `/events/${encodeURIComponent(draft.eventId)}`
      : "/manage-events";
  return `<div class="shared-event-editor">
    <form class="shared-form shared-event-editor__form" data-route-form="event-edit">
      <input type="hidden" name="eventId" value="${escapeHtml(draft.eventId)}" />
      <input type="hidden" name="mode" value="${escapeHtml(mode)}" />
      <div class="shared-event-editor__section is-wide">
        <span>${renderIcon("calendar")}</span>
        <div>
          <h2>${escapeHtml(isEdit ? "Event details" : "Create event")}</h2>
          <p>${escapeHtml(isEdit ? "Keep the public event page, map, and signup path in sync." : "Publish a map-ready event with signup and contact details.")}</p>
        </div>
      </div>
      <label><span>Title</span><input name="title" value="${escapeHtml(draft.title)}" required data-event-editor-field="title"${disabledAttr(pending)} /></label>
      <label><span>Cover image URL</span><input name="imageUrl" type="url" inputmode="url" value="${escapeHtml(draft.imageUrl)}" required data-event-editor-field="imageUrl"${disabledAttr(pending)} /></label>
      <label class="is-wide"><span>Description</span><textarea name="description" rows="5" required data-event-editor-field="description"${disabledAttr(pending)}>${escapeHtml(draft.description)}</textarea></label>
      <label><span>Start</span><input type="datetime-local" name="startAt" value="${escapeHtml(draft.startAt)}" required data-event-editor-field="startAt"${disabledAttr(pending)} /></label>
      <label><span>End</span><input type="datetime-local" name="endAt" value="${escapeHtml(draft.endAt)}" required data-event-editor-field="endAt"${disabledAttr(pending)} /></label>
      ${renderEventAddressLookup(draft, pending)}
      <label><span>City or town</span><input name="locationTown" value="${escapeHtml(draft.locationTown)}" autocomplete="address-level2" required data-event-editor-field="locationTown"${disabledAttr(pending)} /></label>
      <label><span>State</span><input name="locationState" value="${escapeHtml(draft.locationState)}" autocomplete="address-level1" maxlength="2" data-event-editor-field="locationState"${disabledAttr(pending)} /></label>
      <label><span>ZIP</span><input name="postalCode" value="${escapeHtml(draft.postalCode)}" autocomplete="postal-code" data-event-editor-field="postalCode"${disabledAttr(pending)} /></label>
      <label><span>Place ID</span><input name="locationPlaceId" value="${escapeHtml(draft.locationPlaceId)}" data-event-editor-field="locationPlaceId"${disabledAttr(pending)} /></label>
      <label><span>Latitude</span><input name="lat" inputmode="decimal" value="${escapeHtml(draft.lat)}" required data-event-editor-field="lat"${disabledAttr(pending)} /></label>
      <label><span>Longitude</span><input name="lng" inputmode="decimal" value="${escapeHtml(draft.lng)}" required data-event-editor-field="lng"${disabledAttr(pending)} /></label>
      <label><span>Location name</span><input name="locationName" value="${escapeHtml(draft.locationName)}" placeholder="Field office, campus, venue" data-event-editor-field="locationName"${disabledAttr(pending)} /></label>
      <label><span>Tags</span><input name="tags" value="${escapeHtml(draft.tags)}" placeholder="town hall, canvass" data-event-editor-field="tags"${disabledAttr(pending)} /></label>
      <label><span>Email</span><input name="email" type="email" autocomplete="email" value="${escapeHtml(draft.email)}" required data-event-editor-field="email"${disabledAttr(pending)} /></label>
      <label><span>Website</span><input name="website" type="url" inputmode="url" value="${escapeHtml(draft.website)}" data-event-editor-field="website"${disabledAttr(pending)} /></label>
      <label><span>Other link</span><input name="link" type="url" inputmode="url" value="${escapeHtml(draft.link)}" data-event-editor-field="link"${disabledAttr(pending)} /></label>
      <label class="shared-form__checkbox"><input type="checkbox" name="isFree" data-event-editor-field="isFree"${checkedAttr(draft.isFree)}${disabledAttr(pending)} /> Free event</label>
      <label><span>Ticket price</span><input name="costAmount" inputmode="decimal" value="${escapeHtml(draft.costAmount)}" data-event-editor-field="costAmount"${disabledAttr(pending || draft.isFree)} /></label>
      <div class="shared-card__actions is-wide">
        <button class="shared-feed-chip shared-feed-chip--primary" type="submit"${disabledAttr(pending)}>${pending ? "Saving..." : isEdit ? "Save event" : "Create event"}</button>
        <button class="shared-feed-chip" type="button" data-action="navigate" data-route="${escapeHtml(cancelRoute)}"${disabledAttr(pending)}>Cancel</button>
      </div>
    </form>
    <aside class="shared-event-editor__aside">
      <div class="shared-event-editor__cover${draft.imageUrl ? " has-image" : ""}">
        ${
          draft.imageUrl
            ? `<img src="${escapeHtml(draft.imageUrl)}" alt="${escapeHtml(draft.title || "Event cover")}" />`
            : `<div>${renderIcon("upload")}<strong>Cover preview</strong></div>`
        }
      </div>
      <div class="shared-event-editor__summary">
        <p class="shared-page__eyebrow">${escapeHtml(draft.isFree ? "Free event" : "Paid event")}</p>
        <h2>${escapeHtml(draft.title || "Untitled event")}</h2>
        <p>${escapeHtml(draft.description || "Add the public event description.")}</p>
        <div class="shared-card__meta">
          <span>${escapeHtml(draft.locationTown || "Location pending")}</span>
          <span>${escapeHtml(draft.tags || "No tags")}</span>
        </div>
      </div>
      ${renderEventEditorReadiness(draft)}
    </aside>
  </div>`;
}

function renderEventDetailsCard(event) {
  return `<article class="shared-card shared-event-detail-card">
    ${
      event.imageUrl
        ? `<img class="shared-card__image" src="${escapeHtml(event.imageUrl)}" alt="${escapeHtml(event.title)}" />`
        : `<div class="shared-card__image shared-image-fallback">${escapeHtml((event.title || "E").slice(0, 1).toUpperCase())}</div>`
    }
    <div class="shared-card__body">
      <div class="shared-card__meta">
        <span>${escapeHtml(formatAbsoluteDateTime(event.startAt))}</span>
        ${event.locationTown ? `<span>${escapeHtml(event.locationTown)}</span>` : ""}
      </div>
      <h3>${escapeHtml(event.title)}</h3>
      <p>${escapeHtml(event.description || event.address || "")}</p>
      <div class="shared-card__meta">
        <span>${escapeHtml(formatCount(event.attendeeCount))} going</span>
        <span>${escapeHtml(formatCount(event.interestedCount))} interested</span>
        <span>${escapeHtml(eventCostLabel(event))}</span>
      </div>
      <div class="shared-card__meta">
        ${event.address ? `<span>${escapeHtml(event.address)}</span>` : ""}
        ${event.locationName ? `<span>${escapeHtml(event.locationName)}</span>` : ""}
        ${event.hostDisplayName ? `<span>Hosted by ${escapeHtml(event.hostDisplayName)}</span>` : ""}
      </div>
      ${
        event.tags.length
          ? `<div class="shared-card__tags">${event.tags.map((tag) => `<span>${escapeHtml(tag)}</span>`).join("")}</div>`
          : ""
      }
    </div>
  </article>`;
}

function renderEventStats(event) {
  return `<div class="shared-event-stats">
    <span><strong>${escapeHtml(eventCostLabel(event))}</strong><em>Cost</em></span>
    <span><strong>${escapeHtml(formatCount(event.attendeeCount))}</strong><em>Going</em></span>
    <span><strong>${escapeHtml(eventTransportLabel(event))}</strong><em>Transport</em></span>
  </div>`;
}

function renderEventTransportSignupControl(event, pending) {
  if (event.transportEnabled !== true) {
    return "";
  }
  const available = eventTransportAvailable(event);
  const label = eventTransportLabel(event);
  const note =
    event.transportDisclaimer ||
    (available
      ? "Pickup details may change as signups are grouped."
      : "Transportation reservations are currently closed.");
  return `<label class="shared-event-check is-wide">
    <input type="checkbox" name="transportOptIn"${disabledAttr(pending || !available)} />
    <span>
      <strong>Reserve provided transportation</strong>
      <small>${escapeHtml(label)}. ${escapeHtml(note)}</small>
    </span>
  </label>`;
}

function renderEventAttendancePanel(event) {
  const signupRoute = eventSignupRoute(event);
  return `<article class="shared-event-panel shared-event-attendance-panel">
    <div class="shared-event-panel__header">
      <div>
        <p class="shared-page__eyebrow">Attend</p>
        <h2>${event.isAttending ? "You're going" : "Sign up for this event"}</h2>
        <p>${escapeHtml(
          event.isAttending
            ? "Your attendance is recorded for this event."
            : eventRequiresPayment(event)
              ? "This event requires payment before attendance is recorded."
              : "Reserve your spot and optional transportation from the website.",
        )}</p>
      </div>
    </div>
    ${renderEventStats(event)}
    <div class="shared-card__actions">
      ${
        event.isAttending
          ? `<button class="shared-feed-chip shared-feed-chip--primary" type="button" data-action="event-attend" data-event-id="${escapeHtml(event.eventId)}">Cancel RSVP</button>`
          : `<button class="shared-feed-chip shared-feed-chip--primary" type="button" data-action="navigate" data-route="${escapeHtml(signupRoute)}">${eventRequiresPayment(event) ? "Continue" : "Sign up"}</button>`
      }
      <button class="shared-feed-chip" type="button" data-action="event-interest" data-event-id="${escapeHtml(event.eventId)}">${event.isInterested ? "Interested" : "Interested?"}</button>
    </div>
  </article>`;
}

function renderEventSignupPanel(event) {
  const detail = state.pages.events.detail;
  const pending = detail.signupSaving === true;
  const paid = eventRequiresPayment(event);
  if (event.isAttending) {
    return `<article class="shared-event-panel shared-event-signup-panel">
      <div class="shared-event-panel__header">
        <div>
          <p class="shared-page__eyebrow">Signup</p>
          <h2>You're already signed up</h2>
          <p>Your attendance is recorded. You can return to event details or cancel the RSVP.</p>
        </div>
      </div>
      ${renderEventStats(event)}
      <div class="shared-card__actions">
        <button class="shared-feed-chip shared-feed-chip--primary" type="button" data-action="navigate" data-route="${escapeHtml(eventDetailRoute(event))}">Event details</button>
        <button class="shared-feed-chip" type="button" data-action="event-attend" data-event-id="${escapeHtml(event.eventId)}">Cancel RSVP</button>
      </div>
    </article>`;
  }
  return `<article class="shared-event-panel shared-event-signup-panel">
    <div class="shared-event-panel__header">
      <div>
        <p class="shared-page__eyebrow">Signup</p>
        <h2>${paid ? "Payment details" : "Reserve your spot"}</h2>
        <p>${paid ? "Confirm the required contribution details before continuing." : "Add the attendee details needed for this reservation."}</p>
      </div>
      <strong>${escapeHtml(eventCostLabel(event))}</strong>
    </div>
    <form class="shared-event-signup-form" data-route-form="event-signup">
      <input type="hidden" name="eventId" value="${escapeHtml(event.eventId)}" />
      <label><span>First name</span><input name="firstName" autocomplete="given-name" required${disabledAttr(pending)} /></label>
      <label><span>Last name</span><input name="lastName" autocomplete="family-name" required${disabledAttr(pending)} /></label>
      ${
        paid
          ? `<label class="is-wide"><span>Full address</span><textarea name="address" rows="3" autocomplete="street-address" required${disabledAttr(pending)}></textarea></label>
            <label class="shared-event-check is-wide">
              <input type="checkbox" name="isCitizen" required${disabledAttr(pending)} />
              <span>I am a U.S. citizen or lawful permanent resident.</span>
            </label>
            <label class="shared-event-check is-wide">
              <input type="checkbox" name="isOwnFunds" required${disabledAttr(pending)} />
              <span>This contribution is from my own funds and is not from a corporation, labor organization, or foreign national.</span>
            </label>`
          : `<label><span>ZIP code</span><input name="zip" autocomplete="postal-code" inputmode="numeric" placeholder="12345" required${disabledAttr(pending)} /></label>`
      }
      ${renderEventTransportSignupControl(event, pending)}
      <div class="shared-card__actions is-wide">
        <button class="shared-feed-chip shared-feed-chip--primary" type="submit"${disabledAttr(pending)}>${pending ? "Signing up..." : paid ? "Continue to payment" : "Sign up"}</button>
        <button class="shared-feed-chip" type="button" data-action="navigate" data-route="${escapeHtml(eventDetailRoute(event))}"${disabledAttr(pending)}>Cancel</button>
      </div>
    </form>
  </article>`;
}

function renderEventPaymentPanel(event) {
  return `<article class="shared-event-panel shared-event-payment-panel">
    <div class="shared-event-panel__header">
      <div>
        <p class="shared-page__eyebrow">Payment</p>
        <h2>Secure web payment is not available yet</h2>
        <p>Paid event signups require payment before attendance is recorded. This page keeps the web flow honest instead of marking you as going without checkout.</p>
      </div>
      <strong>${escapeHtml(eventCostLabel(event))}</strong>
    </div>
    ${renderEventStats(event)}
    <div class="shared-event-payment-note">
      <strong>No RSVP has been recorded.</strong>
      <span>Use the Polis mobile app when event payments are enabled, or check with the host for current paid-event instructions.</span>
    </div>
    <div class="shared-card__actions">
      <button class="shared-feed-chip shared-feed-chip--primary" type="button" data-action="navigate" data-route="${escapeHtml(eventSignupRoute(event))}">Back to signup</button>
      <button class="shared-feed-chip" type="button" data-action="navigate" data-route="${escapeHtml(eventDetailRoute(event))}">Event details</button>
    </div>
  </article>`;
}

function renderEventDetailAside(event, routeKey) {
  if (routeKey === ROUTE_KEY_EVENT_SIGNUP) {
    return renderEventSignupPanel(event);
  }
  if (routeKey === ROUTE_KEY_EVENT_PAYMENT) {
    return renderEventPaymentPanel(event);
  }
  return renderEventAttendancePanel(event);
}

function renderEventDetailPage() {
  const detail = state.pages.events.detail;
  const event = detail.item;
  const routeKey = getCurrentRoute().routeKey;
  const isCreateRoute = routeKey === ROUTE_KEY_MANAGE_EVENTS_NEW;
  const isEditRoute = routeKey === ROUTE_KEY_MANAGE_EVENTS_EDIT;
  const isSignupRoute = routeKey === ROUTE_KEY_EVENT_SIGNUP;
  const isPaymentRoute = routeKey === ROUTE_KEY_EVENT_PAYMENT;
  const formEvent = isCreateRoute ? {} : event || {};
  const backRoute =
    isCreateRoute
      ? "/manage-events"
      : (isEditRoute || isSignupRoute || isPaymentRoute) && formEvent.eventId
        ? eventDetailRoute(formEvent)
        : "/events";
  const backLabel = isCreateRoute
    ? "Back to manage events"
    : isSignupRoute || isPaymentRoute
      ? "Back to event"
      : "Back to events";
  if (!isCreateRoute && detail.loading && !event) {
    return `<section class="shared-page">${renderTopChrome()}<div class="shared-page__content"><div class="shared-page__loading">Loading event…</div></div></section>`;
  }
  if (!isCreateRoute && !event) {
    return `<section class="shared-page">${renderTopChrome()}<div class="shared-page__content"><div class="shared-page__error">${escapeHtml(detail.error || "Event unavailable.")}</div></div></section>`;
  }
  const editorOpen = isCreateRoute || isEditRoute;
  return `<section class="shared-page">
    ${renderTopChrome()}
    <div class="shared-page__content">
      <div class="shared-page__back-row">
        <button class="shared-feed-chip" type="button" data-action="navigate" data-route="${escapeHtml(backRoute)}">${escapeHtml(backLabel)}</button>
      </div>
      <div class="shared-page__header">
        <div>
          <p class="shared-page__eyebrow">${isCreateRoute ? "Create event" : "Event"}</p>
          <h1>${escapeHtml(isCreateRoute ? "New event" : formEvent.title || "Event")}</h1>
          <p>${escapeHtml(formEvent.description || "Manage event details, attendance, and the web detail page here.")}</p>
        </div>
        ${
          !isCreateRoute && !isEditRoute
            ? `<div class="shared-card__actions">
                <button class="shared-feed-chip shared-feed-chip--primary" data-action="event-attend" data-event-id="${escapeHtml(formEvent.eventId)}">${formEvent.isAttending ? "Going" : "RSVP"}</button>
                <button class="shared-feed-chip" data-action="event-interest" data-event-id="${escapeHtml(formEvent.eventId)}">${formEvent.isInterested ? "Interested" : "Interested?"}</button>
                ${
                  formEvent.canEdit
                    ? `<button class="shared-feed-chip" data-action="navigate" data-route="/manage-events/${escapeHtml(formEvent.eventId)}/edit">Edit</button>`
                    : ""
                }
              </div>`
            : ""
        }
      </div>
      ${detail.error ? `<div class="shared-page__error">${escapeHtml(detail.error)}</div>` : ""}
      ${
        editorOpen
          ? renderEventEditorWorkspace(
              formEvent,
              isEditRoute ? "edit" : "create",
              detail,
            )
          : `<div class="shared-card-grid shared-card-grid--detail shared-event-detail-grid">
              ${renderEventDetailsCard(formEvent)}
              ${renderEventDetailAside(formEvent, routeKey)}
            </div>`
      }
    </div>
  </section>`;
}

