function humanizeLabel(value) {
  const normalized = normalizeString(value);
  if (!normalized) {
    return "";
  }
  return normalized
    .replace(/([a-z0-9])([A-Z])/g, "$1 $2")
    .replace(/[_-]+/g, " ")
    .replace(/\s+/g, " ")
    .trim()
    .replace(/\b\w/g, (match) => match.toUpperCase());
}

function buildMessagingServerRoute(scopeType, scopeId, suffix = "") {
  const base = `/messages/servers/${encodeURIComponent(normalizeString(scopeType))}/${encodeURIComponent(normalizeString(scopeId))}`;
  return suffix ? `${base}${suffix}` : base;
}

function buildMessagingRoomRoute(
  scopeType,
  scopeId,
  conversationId,
  suffix = "",
) {
  const base = `${buildMessagingServerRoute(scopeType, scopeId)}/rooms/${encodeURIComponent(normalizeString(conversationId))}`;
  return suffix ? `${base}${suffix}` : base;
}

function buildMessagingCategoryPermissionRoute(
  scopeType,
  scopeId,
  categoryId,
  suffix = "",
) {
  const base = `${buildMessagingServerRoute(scopeType, scopeId)}/categories/${encodeURIComponent(normalizeString(categoryId))}/permissions`;
  return suffix ? `${base}${suffix}` : base;
}

const MESSAGING_PERMISSION_VALUE_KEYS = Object.freeze(["deny", "inherit", "allow"]);
const MESSAGING_PERMISSION_GROUPS = Object.freeze([
  {
    id: "general",
    title: "General access",
    permissions: [
      {
        key: "viewChannel",
        title: "View room",
        description:
          "Controls whether members can see this room or category.",
      },
    ],
  },
  {
    id: "text",
    title: "Message actions",
    permissions: [
      {
        key: "sendMessages",
        title: "Send messages",
        description: "Post messages and create updates in text rooms.",
      },
      {
        key: "attachFiles",
        title: "Attach files",
        description: "Upload files, images, and media.",
      },
      {
        key: "addReactions",
        title: "Add reactions",
        description: "React to messages with emoji.",
      },
      {
        key: "readMessageHistory",
        title: "Read history",
        description: "Review messages sent before the member opened the room.",
      },
      {
        key: "pinMessages",
        title: "Pin messages",
        description: "Pin and unpin important room messages.",
      },
      {
        key: "useMissionCommands",
        title: "Use mission commands",
        description: "Open mission assignment flows from messages.",
      },
      {
        key: "sendMissionCards",
        title: "Send mission cards",
        description: "Publish structured mission cards in this room.",
      },
      {
        key: "viewMissionCards",
        title: "View mission cards",
        description: "See mission cards posted in this room.",
      },
      {
        key: "bypassSlowmode",
        title: "Bypass slowmode",
        description: "Send messages without slowmode delay.",
      },
    ],
  },
  {
    id: "moderation",
    title: "Moderation",
    permissions: [
      {
        key: "manageMessages",
        title: "Manage messages",
        description: "Delete or moderate messages from other people.",
      },
      {
        key: "manageChannel",
        title: "Manage room",
        description: "Update this room or category access and metadata.",
      },
    ],
  },
]);
const MESSAGING_PERMISSION_DESCRIPTORS = Object.freeze(
  MESSAGING_PERMISSION_GROUPS.flatMap((group) => group.permissions),
);
const MESSAGING_PERMISSION_KEYS = Object.freeze(
  MESSAGING_PERMISSION_DESCRIPTORS.map((descriptor) => descriptor.key),
);

function normalizeMessagingPermissionValue(value, fallback = "inherit") {
  const normalized = normalizeString(value).toLowerCase();
  if (MESSAGING_PERMISSION_VALUE_KEYS.includes(normalized)) {
    return normalized;
  }
  return fallback;
}

function normalizeMessagingPermissionSet(permissions = {}) {
  const source =
    permissions && typeof permissions === "object" && !Array.isArray(permissions)
      ? permissions
      : {};
  return Object.fromEntries(
    MESSAGING_PERMISSION_KEYS.map((key) => [
      key,
      normalizeMessagingPermissionValue(source[key]),
    ]),
  );
}

function messagingPermissionAllInherited(permissions = {}) {
  const normalized = normalizeMessagingPermissionSet(permissions);
  return MESSAGING_PERMISSION_KEYS.every((key) => normalized[key] === "inherit");
}

function messagingPermissionRolesFromBundle(bundle = {}, fallbackRoles = []) {
  const roleMap = new Map();
  const addRole = (raw) => {
    const role = normalizeMessagingRole(raw || {});
    if (!role.roleId || raw?.isHidden === true) return;
    roleMap.set(role.roleId, {
      ...role,
      isHidden: raw?.isHidden === true,
    });
  };
  if (Array.isArray(bundle.roles)) {
    bundle.roles.forEach(addRole);
  }
  if (Array.isArray(fallbackRoles)) {
    fallbackRoles.forEach(addRole);
  }
  return [...roleMap.values()].sort((left, right) => {
    if (left.isEveryone !== right.isEveryone) {
      return left.isEveryone ? -1 : 1;
    }
    if (left.position !== right.position) {
      return left.position - right.position;
    }
    return left.name.localeCompare(right.name);
  });
}

function normalizeMessagingPermissionOverride(raw = {}, rolesById = new Map()) {
  const subjectId = normalizeString(raw.subjectId || raw.roleId || raw.id);
  const role = rolesById.get(subjectId) || {};
  return {
    subjectType: normalizeString(raw.subjectType) || "role",
    subjectId,
    permissions: normalizeMessagingPermissionSet(raw.permissions),
    roleName:
      normalizeString(raw.roleName || raw.subjectName || raw.name || role.name) ||
      "Role",
    roleColor:
      normalizeString(raw.roleColor || raw.color || role.color) || "#8f96a3",
    rolePosition: Number(raw.rolePosition ?? raw.position ?? role.position) || 0,
    isEveryone: raw.isEveryone === true || role.isEveryone === true,
    isManaged: raw.isManaged === true || role.isManaged === true,
    isHidden: raw.isHidden === true || role.isHidden === true,
  };
}

function messagingPermissionOverridesFromTarget(target = {}, roles = []) {
  const rolesById = new Map(roles.map((role) => [role.roleId, role]));
  return (Array.isArray(target.overrides) ? target.overrides : [])
    .map((entry) => normalizeMessagingPermissionOverride(entry, rolesById))
    .filter((entry) => entry.subjectId)
    .sort((left, right) => {
      if (left.isEveryone !== right.isEveryone) {
        return left.isEveryone ? -1 : 1;
      }
      if (left.rolePosition !== right.rolePosition) {
        return left.rolePosition - right.rolePosition;
      }
      return left.roleName.localeCompare(right.roleName);
    });
}

function findMessagingServer(scopeType, scopeId) {
  const normalizedScopeType = normalizeString(scopeType).toLowerCase();
  const normalizedScopeId = normalizeString(scopeId);
  return (
    state.pages.messaging.servers.items.find(
      (item) =>
        normalizeString(item.scopeType).toLowerCase() === normalizedScopeType &&
        normalizeString(item.scopeId) === normalizedScopeId,
    ) ||
    (normalizeString(
      state.pages.messaging.serverSettings.item?.server?.scopeType,
    ).toLowerCase() === normalizedScopeType &&
    normalizeString(
      state.pages.messaging.serverSettings.item?.server?.scopeId,
    ) === normalizedScopeId
      ? state.pages.messaging.serverSettings.item?.server
      : null)
  );
}

function renderMessagingServerCards(servers = []) {
  return servers
    .map(
      (server) => `<article class="shared-card">
        <div class="shared-card__body">
          <div class="shared-card__meta">
            <span>${escapeHtml(server.scopeBadge || "Workspace")}</span>
            <span>${escapeHtml(formatCount(server.memberCount || 0))} members</span>
          </div>
          <h3>${escapeHtml(server.title || "Workspace")}</h3>
          <p>${escapeHtml(server.scopeType || "Scope server")}</p>
          <div class="shared-card__actions">
            <button class="shared-feed-chip shared-feed-chip--primary" data-action="navigate" data-route="${escapeHtml(buildMessagingServerRoute(server.scopeType, server.scopeId))}">Open</button>
          </div>
        </div>
      </article>`,
    )
    .join("");
}

function renderMessagingConversationPanel({
  conversation,
  messages,
  sideButtons = "",
  asideTitle = "Conversations",
}) {
  const conversationComposerMarkup = !conversation
    ? ""
    : conversation.isEncrypted
      ? renderMessagingSecureHandoff({ stacked: true, conversation })
      : `<form class="shared-form shared-form--inline" data-route-form="messaging-send">
          <input type="hidden" name="conversationId" value="${escapeHtml(conversation.conversationId)}" />
          <input type="text" name="text" placeholder="Write a message" />
          <button class="shared-feed-chip shared-feed-chip--primary" type="submit"${state.pages.messaging.conversation.sending ? " disabled" : ""}>${state.pages.messaging.conversation.sending ? "Sending..." : "Send"}</button>
        </form>`;
  const typingLabel = state.pages.messaging.conversation.typingParticipants.length
    ? normalizeString(state.pages.messaging.conversation.typingParticipants[0].label)
    : "";
  const conversationMainMarkup = conversation
    ? `<div class="shared-page__header">
        <div>
          <p class="shared-page__eyebrow">${escapeHtml(conversation.kind)}</p>
          <h1>${escapeHtml(conversation.title)}</h1>
          <p>${escapeHtml(conversation.isEncrypted ? "Encrypted conversation. Use the secure browser options below to manage reply access." : conversation.subtitle || "Conversation")}</p>
        </div>
      </div>
      <div class="shared-message-list">
        ${messages
          .map(
            (message) => `<article class="shared-message${message.senderUserId === state.auth.user?.userId ? " is-self" : ""}">
              <div class="shared-message__meta">
                <span>${escapeHtml(message.senderDisplayName)}</span>
                ${
                  message.createdAt
                    ? `<span>${escapeHtml(formatAbsoluteDateTime(message.createdAt))}</span>`
                    : ""
                }
              </div>
              <p>${escapeHtml(message.text)}</p>
            </article>`,
          )
          .join("")}
      </div>
      ${typingLabel ? `<div class="shared-page__hint">${escapeHtml(`${typingLabel} is typing...`)}</div>` : ""}
      ${conversationComposerMarkup}`
    : `<div class="shared-page__empty">Conversation unavailable.</div>`;
  return `<div class="shared-page__split">
    <div class="shared-page__sidebar">
      <div class="shared-page__hint">${escapeHtml(asideTitle)}</div>
      <div class="shared-stack">${sideButtons || '<div class="shared-page__empty">No related conversations.</div>'}</div>
    </div>
    <div class="shared-page__main">
      ${conversationMainMarkup}
    </div>
  </div>`;
}
