function renderMessagingAutomodRulesPanel(subroute, automodState) {
  const rules = Array.isArray(automodState.items) ? automodState.items : [];
  const enabledCount = rules.filter((rule) => rule.enabled !== false).length;
  const watchedKeywordCount = rules.reduce(
    (count, rule) =>
      count + (Array.isArray(rule.keywords) ? rule.keywords.length : 0),
    0,
  );
  const holdOrBlockCount = rules.filter((rule) =>
    ["hold", "block"].includes(normalizeMessagingAutomodAction(rule.action)),
  ).length;
  const loading = automodState.loading && !automodState.loaded;
  const ruleList = loading
    ? '<div class="shared-page__loading">Loading keyword guardrails...</div>'
    : rules.length
      ? `<div class="shared-messaging-automod-list">${rules
          .map((rule) =>
            renderMessagingAutomodRuleCard(
              rule,
              subroute,
              automodState.actionPendingKey,
            ),
          )
          .join("")}</div>`
      : '<div class="shared-messaging-empty">No keyword guardrails configured.</div>';
  return `<section class="shared-messaging-automod-panel">
    <div class="shared-messaging-automod-panel__header">
      <div>
        <span>Guardrails</span>
        <h3>Keyword guardrails</h3>
        <p>Catch high-risk keywords before they turn into unresolved reports.</p>
      </div>
      <span>${escapeHtml(formatCount(enabledCount))} active</span>
    </div>
    <div class="shared-messaging-automod-metrics">
      <div><strong>${escapeHtml(formatCount(rules.length))}</strong><span>rules</span></div>
      <div><strong>${escapeHtml(formatCount(watchedKeywordCount))}</strong><span>keywords</span></div>
      <div><strong>${escapeHtml(formatCount(holdOrBlockCount))}</strong><span>holds or blocks</span></div>
    </div>
    ${automodState.error ? `<div class="shared-page__error">${escapeHtml(automodState.error)}</div>` : ""}
    ${ruleList}
    ${renderMessagingAutomodCreateForm(subroute, automodState)}
  </section>`;
}

function messagingWorkflowTriggerOption(trigger) {
  const normalized = normalizeMessagingWorkflowTrigger(trigger);
  return (
    MESSAGING_WORKFLOW_TRIGGER_OPTIONS.find(([key]) => key === normalized) ||
    MESSAGING_WORKFLOW_TRIGGER_OPTIONS[0]
  );
}

function messagingWorkflowActionOption(actionType) {
  const normalized = normalizeMessagingWorkflowActionType(actionType);
  return (
    MESSAGING_WORKFLOW_ACTION_OPTIONS.find(([key]) => key === normalized) ||
    MESSAGING_WORKFLOW_ACTION_OPTIONS[0]
  );
}

function messagingWorkflowActionSummary(action) {
  const [type, label, description] = messagingWorkflowActionOption(action?.type);
  if (type === "call_webhook") {
    if (action?.webhookUrl) {
      try {
        return `Send to ${new URL(action.webhookUrl).host}`;
      } catch {
        return label;
      }
    }
    return label;
  }
  if (type === "send_message") {
    return action?.channelId
      ? `Post in ${action.channelId}`
      : "Post prepared room message";
  }
  if (type === "create_moderation_task") {
    return action?.reason ? `Open review: ${action.reason}` : label;
  }
  return description || label;
}

function messagingWorkflowConditionLabel(workflow, trigger, triggerDescription) {
  if (trigger === "message_keyword") {
    return workflow.keyword
      ? `Message includes "${workflow.keyword}"`
      : "Add a keyword before enabling";
  }
  if (trigger === "schedule") {
    return workflow.schedule
      ? `Runs ${humanizeLabel(workflow.schedule).toLowerCase()}`
      : "Choose a schedule before enabling";
  }
  return triggerDescription;
}

function messagingWorkflowHealth(workflow) {
  if (workflow.enabled === false) {
    return {
      label: "Paused",
      detail: workflow.updatedAt
        ? `Updated ${formatAbsoluteDateTime(workflow.updatedAt)}`
        : "Automation is not running",
      className: "is-paused",
    };
  }
  if (workflow.lastRunAt) {
    return {
      label: "Recently ran",
      detail: formatAbsoluteDateTime(workflow.lastRunAt),
      className: "is-running",
    };
  }
  return {
    label: "Ready",
    detail: workflow.updatedAt
      ? `Updated ${formatAbsoluteDateTime(workflow.updatedAt)}`
      : "Waiting for the next matching event",
    className: "is-ready",
  };
}

function messagingWorkflowActionCountLabel(actions = []) {
  const count = Array.isArray(actions) ? actions.length : 0;
  return `${formatCount(count || 1)} action${count === 1 ? "" : "s"}`;
}

function renderMessagingWorkflowCard(workflow, subroute, pendingKey = "") {
  const workflowId = normalizeString(workflow.workflowId);
  if (!workflowId) {
    return "";
  }
  const enabled = workflow.enabled !== false;
  const [trigger, triggerLabel, triggerDescription] =
    messagingWorkflowTriggerOption(workflow.trigger);
  const pendingToggle = pendingKey === `${workflowId}:toggle`;
  const pendingDelete = pendingKey === `${workflowId}:delete`;
  const pending = pendingToggle || pendingDelete;
  const health = messagingWorkflowHealth(workflow);
  const condition = messagingWorkflowConditionLabel(
    workflow,
    trigger,
    triggerDescription,
  );
  const actionTags = (workflow.actions || []).length
    ? workflow.actions
        .map(
          (action) =>
            `<span class="shared-messaging-workflow__tag">${escapeHtml(messagingWorkflowActionSummary(action))}</span>`,
        )
        .join("")
    : '<span class="shared-messaging-workflow__tag">Notify safety team</span>';
  const meta = [
    workflow.createdAt ? `Created ${formatAbsoluteDateTime(workflow.createdAt)}` : "",
    workflow.updatedAt ? `Updated ${formatAbsoluteDateTime(workflow.updatedAt)}` : "",
    workflow.createdBy ? `By ${workflow.createdBy}` : "",
  ].filter(Boolean);
  return `<article class="shared-messaging-workflow${enabled ? "" : " is-disabled"}" data-workflow-id="${escapeHtml(workflowId)}">
    <div class="shared-messaging-workflow__top">
      <span class="shared-messaging-workflow__trigger is-${escapeHtml(trigger)}">${escapeHtml(triggerLabel)}</span>
      <div>
        <strong>${escapeHtml(workflow.name || "Automation")}</strong>
        <small>${escapeHtml(condition)}</small>
      </div>
      <span class="shared-messaging-workflow__status ${escapeHtml(health.className)}">${escapeHtml(health.label)}</span>
    </div>
    <div class="shared-messaging-workflow__map" aria-label="Automation summary">
      <div>
        <small>Starts</small>
        <strong>${escapeHtml(triggerLabel)}</strong>
        <span>${escapeHtml(condition)}</span>
      </div>
      <div>
        <small>Then</small>
        <strong>${escapeHtml(messagingWorkflowActionCountLabel(workflow.actions))}</strong>
        <span>${escapeHtml((workflow.actions || []).map(messagingWorkflowActionSummary).join(" | ") || "Notify safety team")}</span>
      </div>
      <div>
        <small>Status</small>
        <strong>${escapeHtml(health.label)}</strong>
        <span>${escapeHtml(health.detail)}</span>
      </div>
    </div>
    <div class="shared-messaging-workflow__tags" aria-label="Automation actions">${actionTags}</div>
    ${meta.length ? `<div class="shared-messaging-workflow__meta">${meta.map((entry) => `<span>${escapeHtml(entry)}</span>`).join("")}</div>` : ""}
    <div class="shared-messaging-workflow__actions">
      <button class="shared-feed-chip" type="button" data-action="messaging-workflow-toggle" data-scope-type="${escapeHtml(subroute.scopeType)}" data-scope-id="${escapeHtml(subroute.scopeId)}" data-workflow-id="${escapeHtml(workflowId)}" data-enabled="${enabled ? "false" : "true"}"${disabledAttr(pending)}>${pendingToggle ? "Saving..." : enabled ? "Pause" : "Resume"}</button>
      <button class="shared-feed-chip shared-messaging-workflow__delete" type="button" data-action="messaging-workflow-delete" data-scope-type="${escapeHtml(subroute.scopeType)}" data-scope-id="${escapeHtml(subroute.scopeId)}" data-workflow-id="${escapeHtml(workflowId)}"${disabledAttr(pending)}>${pendingDelete ? "Removing..." : "Remove"}</button>
    </div>
  </article>`;
}

