function renderMessagingModerationFilters(subroute, activeStatus) {
  const statuses = [
    ["open", "Open"],
    ["approved", "Allowed"],
    ["rejected", "Blocked"],
    ["resolved", "Resolved"],
    ["all", "All"],
  ];
  const baseRoute = buildMessagingServerRoute(
    subroute.scopeType,
    subroute.scopeId,
    "/moderation",
  );
  return `<div class="shared-messaging-moderation-filters" aria-label="Moderation status filters">${statuses
    .map(([status, label]) => {
      const route =
        status === "open"
          ? baseRoute
          : `${baseRoute}?status=${encodeURIComponent(status)}`;
      return `<button class="shared-feed-chip${status === activeStatus ? " shared-feed-chip--primary" : ""}" type="button" data-action="navigate" data-route="${escapeHtml(route)}">${escapeHtml(label)}</button>`;
    })
    .join("")}</div>`;
}

function messagingModerationStatusTone(status) {
  const normalized = normalizeString(status).toLowerCase() || "open";
  if (["approved", "resolved"].includes(normalized)) return "cleared";
  if (normalized === "rejected") return "blocked";
  return "review";
}

function messagingModerationTaskAgeLabel(task) {
  if (task.createdAt) {
    return formatRelativeTime(task.createdAt);
  }
  return "No timestamp";
}

function messagingModerationTaskPriority(task) {
  const status = normalizeString(task.status).toLowerCase() || "open";
  if (status !== "open") {
    return {
      key: messagingModerationStatusTone(status),
      label: messagingModerationStatusLabel(status),
      detail: task.reviewedAt
        ? `Reviewed ${formatRelativeTime(task.reviewedAt)}`
        : "Decision recorded",
    };
  }
  const source = normalizeString(task.source).toLowerCase();
  const reason = normalizeString(task.reason).toLowerCase();
  const preview = normalizeString(task.text).toLowerCase();
  if (
    /(threat|unsafe|violence|self[-\s]?harm|hate|extrem|harass|abuse)/u.test(
      `${source} ${reason} ${preview}`,
    )
  ) {
    return {
      key: "urgent",
      label: "Urgent review",
      detail: "Safety-sensitive report",
    };
  }
  if (task.reportId || /report/u.test(source)) {
    return {
      key: "reported",
      label: "Reported",
      detail: "Member-submitted report",
    };
  }
  if (task.ruleId || /(auto|keyword|hold|block)/u.test(source)) {
    return {
      key: "held",
      label: "Held by guardrail",
      detail: "Keyword guardrail match",
    };
  }
  return {
    key: "review",
    label: "Needs decision",
    detail: "Open review item",
  };
}

function renderMessagingModerationSummary(tasks, activeStatus, automodState = {}) {
  const counts = tasks.reduce(
    (acc, task) => {
      const status = normalizeString(task.status).toLowerCase() || "open";
      acc.total += 1;
      acc[status] = (acc[status] || 0) + 1;
      return acc;
    },
    { total: 0 },
  );
  const rules = Array.isArray(automodState.items) ? automodState.items : [];
  const activeRules = rules.filter((rule) => rule.enabled !== false).length;
  const metrics = [
    [
      "Queue",
      formatCount(tasks.length),
      messagingModerationStatusLabel(activeStatus),
    ],
    ["Open", formatCount(counts.open || 0), "Needs review"],
    [
      "Reported",
      formatCount(tasks.filter((task) => task.reportId).length),
      "Member escalations",
    ],
    ["Guardrails", formatCount(activeRules), "Active guardrails"],
  ];
  return `<div class="shared-messaging-moderation-summary">${metrics
    .map(
      ([label, value, detail]) =>
        `<div><strong>${escapeHtml(value)}</strong><span>${escapeHtml(label)}</span><small>${escapeHtml(detail)}</small></div>`,
    )
    .join("")}</div>`;
}

function renderMessagingModerationHero(tasks, activeStatus, automodState) {
  const openCount = tasks.filter(
    (task) => (normalizeString(task.status).toLowerCase() || "open") === "open",
  ).length;
  const urgentCount = tasks.filter(
    (task) => messagingModerationTaskPriority(task).key === "urgent",
  ).length;
  const activeRules = Array.isArray(automodState.items)
    ? automodState.items.filter((rule) => rule.enabled !== false).length
    : 0;
  return `<section class="shared-messaging-moderation-hero">
    <div>
      <span>Moderation center</span>
      <h3>Review queue</h3>
      <p>Resolve held messages, member reports, and keyword guardrail catches without leaving the workspace.</p>
    </div>
    <div class="shared-messaging-moderation-hero__signals">
      <div><strong>${escapeHtml(formatCount(openCount))}</strong><span>open</span></div>
      <div><strong>${escapeHtml(formatCount(urgentCount))}</strong><span>urgent</span></div>
      <div><strong>${escapeHtml(formatCount(activeRules))}</strong><span>rules</span></div>
    </div>
  </section>
  ${renderMessagingModerationSummary(tasks, activeStatus, automodState)}`;
}

function renderMessagingModerationTaskCard(task, subroute, pendingKey = "") {
  const taskId = normalizeString(task.taskId);
  if (!taskId) {
    return "";
  }
  const status = normalizeString(task.status).toLowerCase() || "open";
  const source = humanizeLabel(task.source || "manual");
  const reason = humanizeLabel(task.reason || "review");
  const createdLabel = task.createdAt ? formatAbsoluteDateTime(task.createdAt) : "";
  const reviewedLabel = task.reviewedAt
    ? formatAbsoluteDateTime(task.reviewedAt)
    : "";
  const isOpen = status === "open";
  const priority = messagingModerationTaskPriority(task);
  const statusTone = messagingModerationStatusTone(status);
  const channelRoute = task.channelId
    ? `/messages/conversations/${encodeURIComponent(task.channelId)}`
    : "";
  const pending = pendingKey.startsWith(`${taskId}:`);
  const resolutionPlaceholder =
    "Write the audit note before approving, rejecting, or resolving.";
  const reviewMarkup = isOpen
    ? `<form class="shared-messaging-moderation-task__review" data-messaging-moderation-task-form>
      <input type="hidden" name="scopeType" value="${escapeHtml(subroute.scopeType)}" />
      <input type="hidden" name="scopeId" value="${escapeHtml(subroute.scopeId)}" />
      <input type="hidden" name="taskId" value="${escapeHtml(taskId)}" />
      <label>
        <span>Moderator note</span>
        <textarea name="resolution" rows="2" placeholder="${escapeHtml(resolutionPlaceholder)}"${disabledAttr(pending)}></textarea>
      </label>
      <div class="shared-messaging-moderation-task__actions">
        ${channelRoute ? `<button class="shared-feed-chip" type="button" data-action="navigate" data-route="${escapeHtml(channelRoute)}">Open thread</button>` : ""}
        <button class="shared-feed-chip" type="button" data-action="messaging-moderation-task-update" data-review-action="resolved"${disabledAttr(pending)}>${pendingKey === `${taskId}:resolved` ? "Resolving..." : "Mark resolved"}</button>
        <button class="shared-feed-chip shared-messaging-moderation-task__reject" type="button" data-action="messaging-moderation-task-update" data-review-action="reject"${disabledAttr(pending)}>${pendingKey === `${taskId}:reject` ? "Blocking..." : "Block"}</button>
        <button class="shared-feed-chip shared-feed-chip--primary" type="button" data-action="messaging-moderation-task-update" data-review-action="approve"${disabledAttr(pending)}>${pendingKey === `${taskId}:approve` ? "Allowing..." : "Allow"}</button>
      </div>
    </form>`
    : `<div class="shared-messaging-moderation-task__review">
      <div class="shared-messaging-moderation-task__resolution">
        <span>Resolution</span>
        <strong>${escapeHtml(task.resolution || "No resolution note.")}</strong>
      </div>
      ${
        channelRoute
          ? `<div class="shared-messaging-moderation-task__actions"><button class="shared-feed-chip" type="button" data-action="navigate" data-route="${escapeHtml(channelRoute)}">Open thread</button></div>`
          : ""
      }
    </div>`;
  const subject = task.actorId || task.createdBy || "Unknown member";
  const taskMeta = [
    task.channelId ? `Room ${task.channelId}` : "",
    task.messageId ? `Message ${task.messageId}` : "",
    task.reportId ? `Report ${task.reportId}` : "",
    task.ruleId ? `Rule ${task.ruleId}` : "",
    task.createdBy ? `Opened by ${task.createdBy}` : "",
    reviewedLabel ? `Reviewed ${reviewedLabel}` : "",
  ].filter(Boolean);
  return `<article class="shared-messaging-moderation-task is-${escapeHtml(priority.key)}" data-task-id="${escapeHtml(taskId)}">
    <div class="shared-messaging-moderation-task__top">
      <div class="shared-messaging-moderation-task__badges">
        <span class="shared-messaging-moderation-task__status is-${escapeHtml(status)}">${escapeHtml(messagingModerationStatusLabel(status))}</span>
        <span class="shared-messaging-moderation-task__priority is-${escapeHtml(priority.key)}">${escapeHtml(priority.label)}</span>
      </div>
      <div>
        <strong>${escapeHtml(reason)}</strong>
        <small>${escapeHtml([source, createdLabel].filter(Boolean).join(" - "))}</small>
      </div>
    </div>
    <div class="shared-messaging-moderation-task__message">
      <span>Message preview</span>
      <p>${escapeHtml(task.text || "No message preview is available for this moderation task.")}</p>
    </div>
    <div class="shared-messaging-moderation-task__map">
      <div>
        <small>Source</small>
        <strong>${escapeHtml(source)}</strong>
        <span>${escapeHtml(priority.detail)}</span>
      </div>
      <div>
        <small>Queued</small>
        <strong>${escapeHtml(messagingModerationTaskAgeLabel(task))}</strong>
        <span>${escapeHtml(createdLabel || "Timestamp unavailable")}</span>
      </div>
      <div>
        <small>Subject</small>
        <strong>${escapeHtml(subject)}</strong>
        <span>${escapeHtml(statusTone === "review" ? "Needs a moderator decision" : "Decision recorded")}</span>
      </div>
    </div>
    <div class="shared-messaging-moderation-task__meta">
      ${taskMeta.map((entry) => `<span>${escapeHtml(entry)}</span>`).join("")}
    </div>
    ${reviewMarkup}
  </article>`;
}

function renderMessagingModerationPanel(subroute, moderationState, automodState) {
  const activeStatus = normalizeString(moderationState.status) || "open";
  const moderationTasks = Array.isArray(moderationState.items)
    ? moderationState.items
    : [];
  const filters = renderMessagingModerationFilters(subroute, activeStatus);
  const taskList =
    moderationState.loading && !moderationState.loaded
      ? '<div class="shared-page__loading">Loading moderation queue...</div>'
      : `<div class="shared-messaging-moderation-list">${
          moderationTasks.length
            ? moderationTasks
                .map((task) =>
                  renderMessagingModerationTaskCard(
                    task,
                    subroute,
                    moderationState.actionPendingKey,
                  ),
                )
                .join("")
            : `<div class="shared-messaging-empty">No ${escapeHtml(messagingModerationStatusLabel(activeStatus).toLowerCase())} moderation tasks.</div>`
        }</div>`;
  return `<section class="shared-messaging-moderation-panel">
    ${renderMessagingModerationHero(moderationTasks, activeStatus, automodState)}
    ${renderMessagingAutomodRulesPanel(subroute, automodState)}
    <section class="shared-messaging-moderation-queue">
      <div class="shared-messaging-moderation-queue__header">
        <div>
          <span>Decision lane</span>
          <h3>${escapeHtml(messagingModerationStatusLabel(activeStatus))}</h3>
          <p>Open the thread when context matters, add an audit note, then approve, reject, or resolve.</p>
        </div>
        ${filters}
      </div>
      ${moderationState.error ? `<div class="shared-page__error">${escapeHtml(moderationState.error)}</div>` : ""}
      ${taskList}
    </section>
  </section>`;
}

function renderMessagingWorkspaceSettingsNav(activeView = "settings") {
  const items = [
    ["settings", "Privacy", "Message privacy and availability", "/messages/settings"],
    ["devices", "Devices", "Trusted browsers and phones", "/messages/devices"],
    ["device-link", "Device link", "Connect another device", "/messages/devices/link"],
    ["recovery", "Recovery", "Backup access keys", "/messages/recovery"],
    ["security", "Security activity", "Recent sign-ins and changes", "/messages/security-activity"],
  ];
  return `<div class="shared-messaging-list">${items
    .map(
      ([key, label, subtitle, route]) =>
        `<button class="shared-messaging-row${key === activeView ? " is-active" : ""}" data-action="navigate" data-route="${escapeHtml(route)}">
          <span class="shared-messaging-row__body"><strong>${escapeHtml(label)}</strong><span>${escapeHtml(subtitle)}</span></span>
        </button>`,
    )
    .join("")}</div>`;
}

function messagingMinuteLabel(value) {
  const minutes = normalizeMinuteValue(value, 0);
  const hour = Math.floor(minutes / 60);
  const minute = minutes % 60;
  const period = hour >= 12 ? "PM" : "AM";
  const displayHour = hour % 12 || 12;
  return `${displayHour}:${String(minute).padStart(2, "0")} ${period}`;
}

function renderMessagingAccountMetric({ icon, label, value, description }) {
  return `<div class="shared-messaging-account-metric">
    <span>${renderIcon(icon)}</span>
    <strong>${escapeHtml(value)}</strong>
    <small>${escapeHtml(label)}</small>
    <em>${escapeHtml(description)}</em>
  </div>`;
}

function renderMessagingAccountChoiceGroup({
  name,
  label,
  options,
  selected,
  disabled = false,
}) {
  return `<fieldset class="shared-messaging-account-choice-group">
    <legend>${escapeHtml(label)}</legend>
    <div class="shared-messaging-account-choice-grid">
      ${options
        .map(([value, optionLabel, description]) => {
          const isSelected = selected === value;
          return `<label class="shared-messaging-account-choice${isSelected ? " is-selected" : ""}">
            <input type="radio" name="${escapeHtml(name)}" value="${escapeHtml(value)}"${checkedAttr(isSelected)}${disabledAttr(disabled)} />
            <span>
              <strong>${escapeHtml(optionLabel)}</strong>
              <small>${escapeHtml(description)}</small>
            </span>
          </label>`;
        })
        .join("")}
    </div>
  </fieldset>`;
}

function renderMessagingAccountToggle({
  name,
  label,
  description,
  checked,
  disabled = false,
}) {
  return `<label class="shared-messaging-account-toggle">
    <input type="checkbox" name="${escapeHtml(name)}" value="true"${checkedAttr(checked)}${disabledAttr(disabled)} />
    <span>
      <strong>${escapeHtml(label)}</strong>
      <small>${escapeHtml(description)}</small>
    </span>
  </label>`;
}

