function renderMessagingWorkspaceChannelRows(directory, subroute, activeConversationId) {
  const channels = Array.isArray(directory?.channels) ? directory.channels : [];
  return renderMessagingWorkspaceRows(
    channels,
    activeConversationId,
    (channel) =>
      buildMessagingRoomRoute(
        subroute.scopeType,
        subroute.scopeId,
        channel.conversationId,
      ),
    "No rooms are available for this workspace yet.",
    {
      body: "Rooms will appear here when this workspace publishes channels you can access.",
      actions: "",
      icon: "team",
      className: "shared-messaging-empty-state--compact shared-messaging-empty-state--sidebar",
    },
  );
}

function findMessagingDirectoryCategory(directory, categoryId) {
  const normalizedCategoryId = normalizeString(categoryId);
  if (!normalizedCategoryId) {
    return null;
  }
  const categories = Array.isArray(directory?.categories)
    ? directory.categories
    : [];
  return (
    categories.find(
      (category) =>
        normalizeString(category.categoryId || category.id) ===
        normalizedCategoryId,
    ) || null
  );
}

function findMessagingDirectoryChannel(directory, conversationId) {
  const normalizedConversationId = normalizeString(conversationId);
  if (!normalizedConversationId) {
    return null;
  }
  const channels = Array.isArray(directory?.channels)
    ? directory.channels
    : [];
  return (
    channels.find((channel) => {
      const raw = channel?.raw || {};
      return [
        channel?.conversationId,
        raw.conversationId,
        raw.channelId,
        raw.id,
      ]
        .map(normalizeString)
        .some((value) => value === normalizedConversationId);
    }) || null
  );
}

const MESSAGING_DIRECTORY_ROOM_TYPE_OPTIONS = [
  {
    value: "public_within_scope",
    label: "Public room",
    description: "Visible to members who can access this workspace.",
  },
  {
    value: "announcement_only",
    label: "Announcement room",
    description: "Only workspace managers can post new messages.",
  },
];

function messagingDirectoryCategoryId(category = {}) {
  return normalizeString(
    category.categoryId || category.id || category.conversationId,
  );
}

function messagingDirectoryCategoryTitle(category = {}) {
  return (
    normalizeString(category.title || category.name || category.label) ||
    messagingDirectoryCategoryId(category) ||
    "Category"
  );
}

function messagingDirectoryChannelCategoryId(channel = {}) {
  const raw = channel?.raw || {};
  return normalizeString(
    channel.categoryId ||
      raw.categoryId ||
      raw.category_id ||
      raw.category?.categoryId ||
      raw.category?.id,
  );
}

function messagingDirectoryChannelPosition(channel = {}, fallback = 0) {
  const raw = channel?.raw || {};
  const value = Number(channel.position ?? raw.position ?? raw.sortOrder);
  return Number.isFinite(value) && value >= 0 ? Math.floor(value) : fallback;
}

function messagingDirectoryChannelRoomType(channel = {}) {
  const raw = channel?.raw || {};
  return (
    normalizeString(
      channel.roomType ||
        raw.roomType ||
        raw.settings?.roomType ||
        raw.postingPolicy?.roomType,
    ).toLowerCase() || "public_within_scope"
  );
}

function messagingDirectoryRoomTypeLabel(roomType) {
  const normalized = normalizeString(roomType).toLowerCase();
  return (
    MESSAGING_DIRECTORY_ROOM_TYPE_OPTIONS.find(
      (option) => option.value === normalized,
    )?.label ||
    humanizeLabel(normalized) ||
    "Room"
  );
}

function messagingDirectoryChannelLabel(channel = {}) {
  return (
    normalizeString(channel.title || channel.displayTitle || channel.label) ||
    normalizeString(channel.raw?.title || channel.raw?.displayTitle) ||
    "Room"
  );
}

function messagingDirectoryIsChannelMuted(channel = {}) {
  const raw = channel?.raw || {};
  const notificationLevel = normalizeString(
    channel.notificationLevel ||
      raw.notificationLevel ||
      raw.preferences?.notificationLevel ||
      raw.notifications?.level,
  ).toLowerCase();
  const mutedUntil =
    Number(raw.mutedUntil || raw.muteUntil || raw.notifications?.mutedUntil) ||
    0;
  return (
    parseBoolean(channel.isMuted ?? raw.isMuted ?? raw.muted, false) ||
    mutedUntil > Date.now() ||
    ["mute", "muted", "off", "none", "disabled"].includes(notificationLevel)
  );
}

function messagingDirectoryCategoryChannels(directory, categoryId) {
  const normalizedCategoryId = normalizeString(categoryId);
  const channels = Array.isArray(directory?.channels) ? directory.channels : [];
  return channels.filter(
    (channel) =>
      messagingDirectoryChannelCategoryId(channel) === normalizedCategoryId,
  );
}

function messagingDirectoryUncategorizedChannels(directory) {
  const channels = Array.isArray(directory?.channels) ? directory.channels : [];
  return channels.filter((channel) => !messagingDirectoryChannelCategoryId(channel));
}

function mergeMessagingRoomConversation(conversation, directory, subroute) {
  const conversationId = normalizeString(
    subroute?.conversationId || conversation?.conversationId,
  );
  const directoryChannel = findMessagingDirectoryChannel(
    directory,
    conversationId,
  );
  if (!directoryChannel && conversation) {
    return conversation;
  }
  const base =
    conversation ||
    normalizeMessagingConversation({
      conversationId,
      kind: "room",
      scopeType: subroute?.scopeType,
      scopeId: subroute?.scopeId,
    });
  if (!directoryChannel) {
    return base;
  }
  const baseTitle = normalizeString(base.title);
  const channelTitle = normalizeString(directoryChannel.title);
  const baseSubtitle = normalizeString(base.subtitle);
  const channelSubtitle =
    normalizeString(directoryChannel.subtitle) ||
    normalizeString(directoryChannel.lastMessagePreview);
  const raw = {
    ...(directoryChannel.raw || {}),
    ...(base.raw || {}),
  };
  raw.categoryId =
    normalizeString(base.raw?.categoryId) ||
    normalizeString(directoryChannel.raw?.categoryId) ||
    normalizeString(directoryChannel.raw?.category?.categoryId) ||
    normalizeString(directoryChannel.raw?.category?.id);
  raw.directoryChannel = directoryChannel;
  return {
    ...base,
    title:
      baseTitle && !["Conversation", "Room"].includes(baseTitle)
        ? baseTitle
        : channelTitle || baseTitle || "Room",
    subtitle: baseSubtitle || channelSubtitle,
    kind: "room",
    unreadCount: Math.max(
      Number(base.unreadCount) || 0,
      Number(directoryChannel.unreadCount) || 0,
    ),
    updatedAt:
      Number(base.updatedAt) ||
      Number(directoryChannel.updatedAt) ||
      Number(directoryChannel.raw?.updatedAt) ||
      0,
    participantCount:
      Number(base.participantCount) ||
      Number(directoryChannel.participantCount) ||
      Number(directoryChannel.raw?.memberCount) ||
      0,
    lastMessagePreview:
      normalizeString(base.lastMessagePreview) ||
      normalizeString(directoryChannel.lastMessagePreview),
    avatarUrl: base.avatarUrl || directoryChannel.avatarUrl,
    scopeType:
      normalizeString(base.scopeType) || normalizeString(subroute?.scopeType),
    scopeId: normalizeString(base.scopeId) || normalizeString(subroute?.scopeId),
    canManage: base.canManage === true || directoryChannel.canManage === true,
    raw,
  };
}

function readMessagingLooseList(source = {}, keys = []) {
  for (const key of keys) {
    const value = source?.[key];
    if (Array.isArray(value)) {
      return value;
    }
  }
  return [];
}

function normalizeMessagingAutomationListEntry(item, index = 0) {
  const source = item && typeof item === "object" ? item : { title: item };
  const triggerValue = normalizeString(
    source.trigger || source.triggerType || source.event || source.eventType,
  );
  const normalizedTrigger = triggerValue
    .toLowerCase()
    .replace(/[^a-z0-9]+/gu, "_")
    .replace(/^_+|_+$/gu, "");
  const triggerOption = MESSAGING_WORKFLOW_TRIGGER_OPTIONS.find(
    ([key]) => key === normalizedTrigger,
  );
  const triggerLabel = triggerOption?.[1] || humanizeLabel(triggerValue);
  const actionRows = Array.isArray(source.actions)
    ? source.actions.filter((action) => normalizeString(action?.type))
    : [];
  const actionSummary = actionRows.length
    ? actionRows
        .map((action) =>
          messagingWorkflowActionSummary(normalizeMessagingWorkflowAction(action)),
        )
        .join(" | ")
    : normalizeString(
        source.actionLabel ||
          source.action ||
          source.actionType ||
          source.destination ||
          source.webhookUrl ||
          source.url,
      );
  const lastRunAt = normalizeMessagingInviteTimestamp(
    source.lastRunAt || source.lastRunAtIso || source.updatedAt,
  );
  const title =
    normalizeString(source.title || source.name || source.label) ||
    (triggerLabel ? `${triggerLabel} automation` : "") ||
    `Connected automation ${index + 1}`;
  const subtitle =
    normalizeString(source.subtitle || source.description || source.summary) ||
    [
      triggerLabel ? `Starts with ${triggerLabel.toLowerCase()}` : "",
      actionSummary ? `then ${actionSummary.toLowerCase()}` : "",
    ]
      .filter(Boolean)
      .join(", ") ||
    "Ready for workspace handoffs.";
  const status =
    source.enabled === false
      ? "Paused"
      : messagingServerSettingsDisplayValue(
          source.status || source.state,
          actionSummary || source.webhookUrl || source.url
            ? "Connected"
            : "Ready",
        );
  return {
    ...source,
    title,
    subtitle,
    status,
    meta: lastRunAt ? `Last run ${formatAbsoluteDateTime(lastRunAt)}` : status,
  };
}

function renderMessagingLooseCardList(
  items = [],
  emptyLabel,
  fallbackTitle,
  options = {},
) {
  if (!items.length) {
    return `<div class="shared-messaging-empty">${escapeHtml(emptyLabel)}</div>`;
  }
  const icon = normalizeString(options.icon) || "messages";
  const mapEntry =
    typeof options.mapEntry === "function" ? options.mapEntry : (entry) => entry;
  return `<div class="shared-messaging-card-list">${items
    .map((item, index) => {
      const rawEntry = item && typeof item === "object" ? item : { title: item };
      const entry = mapEntry(rawEntry, index) || rawEntry;
      const title =
        normalizeString(
          entry.title ||
            entry.name ||
            entry.label ||
            entry.message ||
            entry.text ||
            entry.code,
        ) || `${fallbackTitle} ${index + 1}`;
      const subtitle =
        normalizeString(
          entry.subtitle ||
            entry.description ||
            entry.previewText ||
            entry.url ||
            entry.status ||
            entry.channelName,
        ) || "No additional metadata.";
      const meta = normalizeString(
        entry.meta ||
          entry.status ||
          entry.type ||
          (entry.createdAt ? formatAbsoluteDateTime(entry.createdAt) : ""),
      );
      return `<article class="shared-messaging-request">
        ${renderMessagingWorkspaceAvatar({ label: title, icon })}
        <div>
          <p>${escapeHtml(meta || fallbackTitle)}</p>
          <h3>${escapeHtml(title)}</h3>
          <span>${escapeHtml(subtitle)}</span>
        </div>
      </article>`;
    })
    .join("")}</div>`;
}

function messagingRoomSettingsConfig(subroute) {
  switch (subroute.view) {
    case "room-settings-notifications":
      return {
        title: "Notification settings",
        subtitle: "Alert behavior, mute state, and inherited workspace defaults.",
      };
    case "room-settings-pins":
      return {
        title: "Pinned messages",
        subtitle: "Pinned references and saved messages for this room.",
      };
    case "room-settings-invites":
      return {
        title: "Invite links",
        subtitle: "Room invite policy, active links, and workspace invite access.",
      };
    case "room-settings-integrations":
      return {
        title: "Room automations",
        subtitle: "Room-specific handoffs and external posting rules.",
      };
    case "room-settings-section":
      return {
        title: humanizeLabel(subroute.sectionId) || "Room settings",
        subtitle: "Room area.",
      };
    default:
      return {
        title: "Room settings",
        subtitle: "Members, notifications, pins, invites, and integrations.",
      };
  }
}

function renderMessagingRoomSettingsNav(subroute) {
  const items = [
    ["room-settings", "Overview", "Members and room details", "/settings"],
    [
      "room-settings-notifications",
      "Notifications",
      "Room alert defaults",
      "/settings/notifications",
    ],
    [
      "room-permissions",
      "Access",
      "Who can enter",
      "/settings/permissions",
    ],
    [
      "room-settings-pins",
      "Pinned messages",
      "Saved references",
      "/settings/pinned-messages",
    ],
    [
      "room-settings-invites",
      "Invites",
      "Links and access",
      "/settings/invites",
    ],
    [
      "room-settings-integrations",
      "Automations",
      "Room handoffs",
      "/settings/integrations",
    ],
  ];
  return `<div class="shared-messaging-list shared-messaging-room-settings-nav">${items
    .map(([key, title, subtitle, suffix]) => {
      const active =
        key === subroute.view ||
        (key === "room-permissions" &&
          subroute.view === "room-permission-role");
      return `<button class="shared-messaging-row${active ? " is-active" : ""}" data-action="navigate" data-route="${escapeHtml(buildMessagingRoomRoute(subroute.scopeType, subroute.scopeId, subroute.conversationId, suffix))}">
        <span class="shared-messaging-row__body"><strong>${escapeHtml(title)}</strong><span>${escapeHtml(subtitle)}</span></span>
      </button>`;
    })
    .join("")}</div>`;
}

function messagingRoomSettingValue(value, fallback = "Not set") {
  const normalized = normalizeString(value);
  return normalized ? humanizeLabel(normalized) || normalized : fallback;
}

function messagingRoomTimestampLabel(value, fallback = "Not scheduled") {
  if (value === null || value === undefined || value === "" || value === 0) {
    return fallback;
  }
  const numeric = Number(value);
  const parsed = Number.isFinite(numeric) && numeric > 0
    ? numeric
    : Date.parse(normalizeString(value));
  return Number.isFinite(parsed) ? formatAbsoluteDateTime(parsed) : fallback;
}

function messagingRoomNotificationLevel(raw = {}) {
  const rawLevel = normalizeString(
    raw.notificationLevel ||
      raw.viewerNotificationLevel ||
      raw.viewer_notification_level ||
      raw.personalNotificationLevel ||
      raw.personal_notification_level ||
      raw.notifications?.level ||
      raw.defaultNotificationLevel,
  ).toLowerCase();
  if (["inherit", "inherited", "server_default", "server-default", "default"].includes(rawLevel)) {
    return "inherit";
  }
  if (["mute", "muted", "off", "none", "disabled"].includes(rawLevel)) {
    return "mute";
  }
  if (["mentions_only", "mentions-only", "mention"].includes(rawLevel)) {
    return "mentions";
  }
  return rawLevel || "inherit";
}

function messagingRoomNotificationLabel(level) {
  switch (normalizeString(level).toLowerCase()) {
    case "all":
      return "All activity";
    case "mentions":
      return "Mentions only";
    case "mute":
      return "Muted";
    case "inherit":
    default:
      return "Workspace default";
  }
}

const MESSAGING_ROOM_SLOWMODE_OPTIONS = [0, 10, 30, 60, 120, 300];
const MESSAGING_ROOM_HIDE_AFTER_OPTIONS = [1, 24, 72, 168];

function messagingRoomIsAdvancedRoomType(roomType) {
  return ["private_invite_only", "staff_only", "volunteer", "ops"].includes(
    normalizeString(roomType).toLowerCase(),
  );
}

function normalizeMessagingRoomSlowmode(value) {
  const numeric = Number(value);
  if (!Number.isFinite(numeric)) {
    return 0;
  }
  return MESSAGING_ROOM_SLOWMODE_OPTIONS.includes(numeric) ? numeric : 0;
}

function normalizeMessagingRoomHideAfterHours(value) {
  const numeric = Number(value);
  if (!Number.isFinite(numeric)) {
    return 72;
  }
  return MESSAGING_ROOM_HIDE_AFTER_OPTIONS.includes(numeric) ? numeric : 72;
}

function messagingRoomSlowmodeLabel(seconds) {
  const normalized = normalizeMessagingRoomSlowmode(seconds);
  if (normalized <= 0) {
    return "Off";
  }
  if (normalized < 60) {
    return `${normalized} seconds`;
  }
  const minutes = normalized / 60;
  return minutes === 1 ? "1 minute" : `${minutes} minutes`;
}

function messagingRoomHideAfterLabel(hours) {
  switch (normalizeMessagingRoomHideAfterHours(hours)) {
    case 1:
      return "1 hour";
    case 24:
      return "24 hours";
    case 168:
      return "1 week";
    case 72:
    default:
      return "3 days";
  }
}

function messagingRoomSettingsModel(conversation, raw = {}) {
  const settings =
    raw.settings && typeof raw.settings === "object" ? raw.settings : {};
  const roomType =
    normalizeString(settings.roomType || raw.roomType).toLowerCase() ||
    "public_within_scope";
  const announcementOnly =
    settings.announcementOnly === true ||
    raw.announcementOnly === true ||
    roomType === "announcement_only";
  return {
    title: normalizeString(conversation?.title || raw.title) || "Room",
    topic: normalizeString(settings.topic || raw.topic || raw.description),
    categoryId: normalizeString(
      raw.categoryId || raw.category?.categoryId || raw.category?.id,
    ),
    roomType,
    announcementOnly,
    slowmodeSeconds: normalizeMessagingRoomSlowmode(
      Number(settings.slowmodeSeconds ?? raw.slowmodeSeconds),
    ),
    hideAfterInactivityHours: normalizeMessagingRoomHideAfterHours(
      Number(settings.hideAfterInactivityHours ?? raw.hideAfterInactivityHours),
    ),
  };
}

function renderMessagingRoomHero({
  subroute,
  conversation,
  categoryLabel,
  roomMembers,
}) {
  const raw = conversation?.raw || {};
  const memberCount =
    Number(raw.memberCount || conversation?.participantCount) ||
    (roomMembers.items || []).length;
  const title = conversation?.title || "Room";
  const subtitle =
    conversation?.subtitle ||
    raw.topic ||
    raw.description ||
    "Room operations and member access.";
  const chips = [
    messagingRoomSettingValue(conversation?.kind, "Room"),
    categoryLabel ? `Category: ${categoryLabel}` : "",
    conversation?.isEncrypted ? "Encrypted" : "",
    conversation?.canManage || raw.canManage ? "Manage access" : "",
  ].filter(Boolean);
  return `<section class="shared-messaging-room-hero">
    ${renderMessagingWorkspaceAvatar({
      label: title,
      imageUrl: conversation?.avatarUrl,
      icon: "messages",
      className: "shared-messaging-avatar--server-card",
    })}
    <div class="shared-messaging-room-hero__main">
      <p>${escapeHtml(messagingRoomSettingValue(subroute.scopeType, "Workspace room"))}</p>
      <h3>${escapeHtml(title)}</h3>
      <span>${escapeHtml(subtitle)}</span>
      <div class="shared-messaging-room-chip-cloud">${chips
        .map((chip) => `<span>${escapeHtml(chip)}</span>`)
        .join("")}</div>
    </div>
    <div class="shared-messaging-room-hero__metric">
      <strong>${escapeHtml(formatCount(memberCount))}</strong>
      <span>members</span>
    </div>
  </section>`;
}

function renderMessagingRoomSection({
  title,
  subtitle = "",
  badge = "",
  actions = "",
  body = "",
  className = "",
}) {
  return `<section class="shared-messaging-room-section${className ? ` ${escapeHtml(className)}` : ""}">
    <div class="shared-messaging-room-section__header">
      <div>
        <h3>${escapeHtml(title)}</h3>
        ${subtitle ? `<p>${escapeHtml(subtitle)}</p>` : ""}
      </div>
      ${badge ? `<span>${escapeHtml(badge)}</span>` : ""}
    </div>
    ${body}
    ${actions ? `<div class="shared-messaging-room-section__actions">${actions}</div>` : ""}
  </section>`;
}

function renderMessagingRoomModeCards(activeLevel = "server_default") {
  const normalizedActive = normalizeString(activeLevel).toLowerCase();
  const modes = [
    ["inherit", "Workspace default", "Use the workspace-level preference."],
    ["all", "All activity", "Receive notifications for every message."],
    ["mentions", "Mentions only", "Notify when you or a role is mentioned."],
    ["mute", "Muted", "Silence notifications for this channel."],
  ];
  return `<div class="shared-messaging-room-mode-grid">${modes
    .map(([key, label, copy]) => {
      const active = normalizedActive === key;
      return `<article class="shared-messaging-room-mode${active ? " is-active" : ""}">
        <strong>${escapeHtml(label)}</strong>
        <span>${escapeHtml(copy)}</span>
      </article>`;
    })
    .join("")}</div>`;
}

function renderMessagingRoomNotificationForm(subroute, notificationLevel) {
  const saving = state.pages.messaging.conversation.preferencePending;
  const options = [
    [
      "inherit",
      "Inherit server default",
      "Use the notification level configured for this workspace.",
    ],
    ["all", "All activity", "Receive notifications for every message."],
    ["mentions", "Mentions only", "Notify only when you are mentioned."],
    ["mute", "Muted", "Silence notifications for this channel."],
  ];
  return `<form class="shared-messaging-room-notification-form" data-route-form="messaging-room-notifications-update">
    <input type="hidden" name="conversationId" value="${escapeHtml(subroute.conversationId)}" />
    <div class="shared-messaging-room-notification-options">${options
      .map(([value, label, copy]) => {
        const selected = notificationLevel === value;
        return `<label class="shared-messaging-room-notification-option${selected ? " is-selected" : ""}">
          <input type="radio" name="notificationLevel" value="${escapeHtml(value)}"${checkedAttr(selected)}${disabledAttr(saving)} />
          <span>
            <strong>${escapeHtml(label)}</strong>
            <em>${escapeHtml(copy)}</em>
          </span>
        </label>`;
      })
      .join("")}</div>
    <div class="shared-messaging-room-notification-form__footer">
      <button class="shared-feed-chip shared-feed-chip--primary" type="submit"${disabledAttr(saving)}>${saving ? "Saving..." : "Save notification setting"}</button>
    </div>
  </form>`;
}

function renderMessagingRoomSettingsForm({
  subroute,
  conversation,
  directory,
  categoryLabel,
}) {
  const raw = conversation?.raw || {};
  const model = messagingRoomSettingsModel(conversation, raw);
  const saving = state.pages.messaging.conversation.settingsPending;
  const canManage = conversation?.canManage || raw.canManage;
  const disabled = saving || !canManage;
  const categories = Array.isArray(directory?.categories)
    ? directory.categories
    : [];
  const advancedRoomType = messagingRoomIsAdvancedRoomType(model.roomType);
  const categoryOptions = [
    `<option value=""${selectedAttr(!model.categoryId)}>Uncategorized</option>`,
    ...categories.map((category) => {
      const categoryId = normalizeString(
        category.categoryId || category.id || category.conversationId,
      );
      const label =
        normalizeString(category.name || category.title || category.label) ||
        categoryId ||
        "Category";
      return `<option value="${escapeHtml(categoryId)}"${selectedAttr(categoryId === model.categoryId)}>${escapeHtml(label)}</option>`;
    }),
  ].join("");
  return renderMessagingRoomSection({
    title: "Channel identity",
    subtitle:
      "Update the room name, topic, category, announcement mode, slowmode, and default visibility behavior.",
    badge: canManage ? "Editable" : "Read only",
    body: `
      <form class="shared-messaging-room-settings-form" data-route-form="messaging-room-settings-update">
        <input type="hidden" name="conversationId" value="${escapeHtml(subroute.conversationId)}" />
        <input type="hidden" name="scopeType" value="${escapeHtml(subroute.scopeType)}" />
        <input type="hidden" name="scopeId" value="${escapeHtml(subroute.scopeId)}" />
        <input type="hidden" name="currentRoomType" value="${escapeHtml(model.roomType)}" />
        <div class="shared-messaging-room-settings-form__grid">
          <label class="is-wide">
            <span>Channel name</span>
            <input name="title" value="${escapeHtml(model.title)}" maxlength="120" required${disabledAttr(disabled)} />
          </label>
          <label>
            <span>Category</span>
            <select name="categoryId"${disabledAttr(disabled)}>${categoryOptions}</select>
          </label>
          <label>
            <span>Slowmode cooldown</span>
            <select name="slowmodeSeconds"${disabledAttr(disabled)}>
              ${MESSAGING_ROOM_SLOWMODE_OPTIONS.map(
                (option) =>
                  `<option value="${escapeHtml(String(option))}"${selectedAttr(option === model.slowmodeSeconds)}>${escapeHtml(messagingRoomSlowmodeLabel(option))}</option>`,
              ).join("")}
            </select>
          </label>
          <label>
            <span>Hide after inactivity</span>
            <select name="hideAfterInactivityHours"${disabledAttr(disabled)}>
              ${MESSAGING_ROOM_HIDE_AFTER_OPTIONS.map(
                (option) =>
                  `<option value="${escapeHtml(String(option))}"${selectedAttr(option === model.hideAfterInactivityHours)}>${escapeHtml(messagingRoomHideAfterLabel(option))}</option>`,
              ).join("")}
            </select>
          </label>
          <label class="is-wide">
            <span>Channel topic</span>
            <textarea name="topic" maxlength="1024" rows="4"${disabledAttr(disabled)}>${escapeHtml(model.topic)}</textarea>
          </label>
        </div>
        <label class="shared-messaging-room-toggle${advancedRoomType ? " is-disabled" : ""}">
          <input type="checkbox" name="announcementOnly"${checkedAttr(model.announcementOnly)}${disabledAttr(disabled || advancedRoomType)} />
          <span>
            <strong>Announcement channel</strong>
            <em>${escapeHtml(advancedRoomType ? `${humanizeLabel(model.roomType) || "Advanced"} access is managed in channel permissions.` : "Posts from this channel can be distributed like announcements.")}</em>
          </span>
        </label>
        <div class="shared-messaging-room-settings-summary">
          <div><strong>Room type</strong><span>${escapeHtml(humanizeLabel(model.roomType) || "Public")}</span></div>
          <div><strong>Current category</strong><span>${escapeHtml(categoryLabel || "Uncategorized")}</span></div>
          <div><strong>Slowmode</strong><span>${escapeHtml(messagingRoomSlowmodeLabel(model.slowmodeSeconds))}</span></div>
          <div><strong>Auto-hide</strong><span>${escapeHtml(messagingRoomHideAfterLabel(model.hideAfterInactivityHours))}</span></div>
        </div>
        ${!canManage ? '<div class="shared-page__hint">You can review these settings, but this account cannot edit the room.</div>' : ""}
        <div class="shared-messaging-room-settings-form__footer">
          <button class="shared-feed-chip shared-feed-chip--primary" type="submit"${disabledAttr(disabled)}>${saving ? "Saving..." : "Save room settings"}</button>
        </div>
      </form>`,
  });
}

function renderMessagingRoomDangerSection(subroute, conversation) {
  const raw = conversation?.raw || {};
  const roomTitle = normalizeString(conversation?.title || raw.title) || "Room";
  const canManage = conversation?.canManage || raw.canManage;
  const pending = state.pages.messaging.conversation.deletePending;
  return renderMessagingRoomSection({
    title: "Delete channel",
    subtitle:
      "Remove this channel and its message history for everyone in the server.",
    badge: "Permanent",
    className: "shared-messaging-room-section--danger",
    body: `
      <div class="shared-messaging-room-danger">
        <div class="shared-messaging-room-danger__copy">
          <strong>${escapeHtml(roomTitle)}</strong>
          <span>${escapeHtml(canManage ? "This cannot be undone. Type the channel name to confirm before deleting." : "You can review this channel, but this account cannot delete it.")}</span>
        </div>
        <form class="shared-messaging-room-danger-form" data-route-form="messaging-room-delete">
          <input type="hidden" name="conversationId" value="${escapeHtml(subroute.conversationId)}" />
          <input type="hidden" name="scopeType" value="${escapeHtml(subroute.scopeType)}" />
          <input type="hidden" name="scopeId" value="${escapeHtml(subroute.scopeId)}" />
          <input type="hidden" name="roomTitle" value="${escapeHtml(roomTitle)}" />
          <label>
            <span>Type channel name</span>
            <input name="confirmTitle" placeholder="${escapeHtml(roomTitle)}"${disabledAttr(pending || !canManage)} autocomplete="off" />
          </label>
          <button class="shared-feed-chip shared-messaging-room-danger-button" type="submit"${disabledAttr(pending || !canManage)}>${pending ? "Deleting..." : "Delete channel"}</button>
        </form>
      </div>`,
  });
}

function renderMessagingRoomMemberCard(member, subroute, pendingKey = "") {
  const userId = normalizeString(member.userId);
  const removePending = pendingKey === `remove:${userId}`;
  const roleLabels = member.roles.map(messagingMemberRoleLabel).filter(Boolean);
  const meta = roleLabels.join(", ") || member.username || userId || "Room member";
  const sourceTags = member.sourceTags
    .map((tag) => normalizeString(tag))
    .filter(Boolean)
    .slice(0, 3);
  return `<article class="shared-messaging-room-member${removePending ? " is-pending" : ""}">
    ${renderMessagingWorkspaceAvatar({
      label: member.effectiveName,
      imageUrl: member.avatarUrl,
    })}
    <div class="shared-messaging-room-member__main">
      <strong>${escapeHtml(member.effectiveName)}</strong>
      <span>${escapeHtml(meta)}</span>
      <div class="shared-messaging-room-chip-cloud">${
        sourceTags.length
          ? sourceTags.map((tag) => `<span>${escapeHtml(humanizeLabel(tag) || tag)}</span>`).join("")
          : `<span>${escapeHtml(member.joinedAt ? `Joined ${formatAbsoluteDateTime(member.joinedAt)}` : "Direct room access")}</span>`
      }</div>
    </div>
    <button class="shared-feed-chip" type="button" data-action="messaging-room-member-remove" data-conversation-id="${escapeHtml(subroute.conversationId)}" data-user-id="${escapeHtml(userId)}"${disabledAttr(!userId || Boolean(pendingKey))}>${removePending ? "Removing..." : "Remove"}</button>
  </article>`;
}

function renderMessagingRoomMemberSection(subroute, roomMembers) {
  const members = roomMembers.items || [];
  const pendingKey = normalizeString(roomMembers.actionPendingKey);
  const adding = pendingKey === "add";
  const busy = Boolean(pendingKey);
  return renderMessagingRoomSection({
    title: "Room members",
    subtitle:
      "Add a person by username or user ID, then remove temporary room access without leaving the room.",
    badge: `${formatCount(members.length)} listed`,
    body: `${roomMembers.error ? `<div class="shared-page__error">${escapeHtml(roomMembers.error)}</div>` : ""}
    <form class="shared-messaging-room-member-form" data-route-form="messaging-room-member-add">
      <input type="hidden" name="conversationId" value="${escapeHtml(subroute.conversationId)}" />
      <label><span>Username</span><input name="username" placeholder="@username"${disabledAttr(busy)} /></label>
      <label><span>User ID</span><input name="userId" placeholder="user_..."${disabledAttr(busy)} /></label>
      <button class="shared-feed-chip shared-feed-chip--primary" type="submit"${disabledAttr(busy)}>${adding ? "Adding..." : "Add member"}</button>
    </form>
    <div class="shared-messaging-room-member-list">${
      members.length
        ? members
            .map((member) => renderMessagingRoomMemberCard(member, subroute, pendingKey))
            .join("")
        : '<div class="shared-messaging-empty">No room members found.</div>'
    }</div>`,
  });
}

function mergeMessagingRoomInviteRows(embeddedInvites = [], roomInviteLinks) {
  const loadedInvites =
    Array.isArray(roomInviteLinks?.items) && roomInviteLinks.items.length
      ? roomInviteLinks.items
      : [];
  const rows = [
    ...loadedInvites.map(normalizeMessagingChannelInviteLink),
    ...embeddedInvites.map(normalizeMessagingChannelInviteLink),
  ];
  const seen = new Set();
  return rows.filter((link) => {
    const key =
      normalizeString(link.inviteId || link.token) ||
      `${normalizeString(link.title)}:${normalizeString(link.createdAt)}`;
    if (!key || seen.has(key)) {
      return false;
    }
    seen.add(key);
    return true;
  });
}

function messagingRoomInviteStatusLabel(link) {
  const status = normalizeString(link.status).toLowerCase() || "active";
  if (status === "active") {
    return "Active";
  }
  return humanizeLabel(status) || "Inactive";
}

function renderMessagingRoomInviteLinkCard(link, subroute, pendingKey = "") {
  const inviteId = normalizeString(link.inviteId);
  const status = normalizeString(link.status).toLowerCase() || "active";
  const isClosed = ["revoked", "expired", "exhausted"].includes(status);
  const revokePending = pendingKey === `revoke:${inviteId}`;
  const usesLabel = link.maxUses
    ? `${formatCount(link.useCount)} / ${formatCount(link.maxUses)} uses`
    : `${formatCount(link.useCount)} uses`;
  const expiresLabel = link.expiresAt
    ? `Expires ${formatAbsoluteDateTime(link.expiresAt)}`
    : "Never expires";
  const createdLabel = link.createdAt
    ? `Created ${formatAbsoluteDateTime(link.createdAt)}`
    : "Creation time unavailable";
  return `<article class="shared-messaging-room-invite${isClosed ? " is-muted" : ""}${revokePending ? " is-pending" : ""}">
    <div class="shared-messaging-room-invite__main">
      <p>${escapeHtml(messagingRoomInviteStatusLabel(link))} | ${escapeHtml(createdLabel)}</p>
      <h3>${escapeHtml(link.title || "Invite link")}</h3>
      <span>${escapeHtml(link.token || inviteId || "Token hidden after creation")}</span>
      <div class="shared-messaging-room-chip-cloud">
        <span>${escapeHtml(usesLabel)}</span>
        <span>${escapeHtml(expiresLabel)}</span>
        ${
          link.lastUsedAt
            ? `<span>${escapeHtml(`Last used ${formatAbsoluteDateTime(link.lastUsedAt)}`)}</span>`
            : ""
        }
      </div>
    </div>
    ${
      !isClosed && inviteId
        ? `<button class="shared-feed-chip" type="button" data-action="messaging-room-invite-link-revoke" data-conversation-id="${escapeHtml(subroute.conversationId)}" data-invite-id="${escapeHtml(inviteId)}"${disabledAttr(Boolean(pendingKey))}>${revokePending ? "Revoking..." : "Revoke"}</button>`
        : `<span class="shared-messaging-room-invite__status">${escapeHtml(messagingRoomInviteStatusLabel(link))}</span>`
    }
  </article>`;
}

function renderMessagingRoomInviteLinkSection({
  subroute,
  conversation,
  raw,
  embeddedInvites,
  roomInviteLinks,
}) {
  const links = mergeMessagingRoomInviteRows(embeddedInvites, roomInviteLinks);
  const activeCount = links.filter(
    (link) => normalizeString(link.status).toLowerCase() === "active",
  ).length;
  const pendingKey = normalizeString(roomInviteLinks?.actionPendingKey);
  const creating = pendingKey === "create";
  const busy = Boolean(pendingKey);
  const latestToken = normalizeString(roomInviteLinks?.latestToken);
  const inviteCount =
    Number(raw.inviteCount || raw.pendingInviteCount || raw.activeInviteCount) ||
    activeCount ||
    links.length;
  return renderMessagingRoomSection({
    title: "Invite access",
    subtitle:
      "Create room-specific invite links, cap usage, and revoke stale access without leaving the room.",
    badge: `${formatCount(inviteCount)} active`,
    actions: `<button class="shared-feed-chip shared-feed-chip--primary" type="button" data-action="navigate" data-route="${escapeHtml(buildMessagingServerRoute(subroute.scopeType, subroute.scopeId, "/settings/invites"))}">Workspace invites</button>`,
    body: `
      <div class="shared-messaging-settings-grid">
        <div><strong>Invite access</strong><span>${escapeHtml(raw.invitesEnabled === false ? "Off" : "Workspace policy")}</span></div>
        <div><strong>Active links</strong><span>${escapeHtml(formatCount(inviteCount))}</span></div>
        <div><strong>Room</strong><span>${escapeHtml(conversation?.title || "Room")}</span></div>
      </div>
      ${roomInviteLinks?.loading ? '<div class="shared-page__loading">Loading room invite links...</div>' : ""}
      ${roomInviteLinks?.error ? `<div class="shared-page__error">${escapeHtml(roomInviteLinks.error)}</div>` : ""}
      <form class="shared-messaging-room-invite-form" data-route-form="messaging-room-invite-link-create">
        <input type="hidden" name="conversationId" value="${escapeHtml(subroute.conversationId)}" />
        <label><span>Expiry</span><select name="expiresIn"${disabledAttr(busy)}>
          <option value="1h">1 hour</option>
          <option value="24h">24 hours</option>
          <option value="7d"${selectedAttr(true)}>7 days</option>
          <option value="30d">30 days</option>
          <option value="never">Never</option>
        </select></label>
        <label><span>Max uses</span><input type="number" min="1" max="500" step="1" name="maxUses" placeholder="Unlimited"${disabledAttr(busy)} /></label>
        <button class="shared-feed-chip shared-feed-chip--primary" type="submit"${disabledAttr(busy)}>${creating ? "Creating..." : "Create link"}</button>
      </form>
      ${
        latestToken
          ? `<div class="shared-messaging-room-invite-token">
            <span>New invite token</span>
            <code>${escapeHtml(latestToken)}</code>
          </div>`
          : ""
      }
      <div class="shared-messaging-room-invite-list">${
        links.length
          ? links
              .map((link) =>
                renderMessagingRoomInviteLinkCard(link, subroute, pendingKey),
              )
              .join("")
          : `<div class="shared-messaging-empty">${escapeHtml(roomInviteLinks?.loading ? "Loading invite links..." : "No room invite links are available yet.")}</div>`
      }</div>`,
  });
}

function mergeMessagingRoomPinRows(embeddedPins = [], roomPins) {
  const loadedPins =
    Array.isArray(roomPins?.items) && roomPins.items.length
      ? roomPins.items
      : [];
  const rows = [
    ...loadedPins.map(normalizeMessagingPinnedMessage),
    ...embeddedPins.map(normalizeMessagingPinnedMessage),
  ];
  const seen = new Set();
  return rows.filter((pin) => {
    const key =
      messagingPinIdentity(pin) ||
      `${normalizeString(pin.text)}:${normalizeString(pin.pinnedAt)}`;
    if (!key || seen.has(key)) {
      return false;
    }
    seen.add(key);
    return true;
  });
}

function messagingPinnedMessageIds(pins = []) {
  const ids = new Set();
  pins.forEach((pin) => {
    const messageId = normalizeString(pin.messageId);
    const sortKey = normalizeString(pin.sortKey);
    if (messageId) {
      ids.add(messageId);
    }
    if (sortKey) {
      ids.add(sortKey);
    }
  });
  return ids;
}

function collectMessagingRoomPinCandidates(messages = [], pins = []) {
  const pinnedIds = messagingPinnedMessageIds(pins);
  return (Array.isArray(messages) ? messages : [])
    .filter((message) => {
      const messageId = normalizeString(message?.messageId);
      const status = normalizeString(message?.status).toLowerCase();
      return messageId && !message?.isDeleted && status !== "pending";
    })
    .slice(0, 10)
    .map((message) => ({
      message,
      isPinned: pinnedIds.has(normalizeString(message.messageId)),
    }));
}

function messagingRoomPinnedMessageText(pin) {
  return (
    normalizeString(pin?.text) ||
    normalizeString(pin?.messageId) ||
    normalizeString(pin?.sortKey) ||
    "Pinned message"
  );
}

function renderMessagingRoomPinCard(pin, subroute, pendingKey = "") {
  const pinId = normalizeString(pin.pinId);
  const unpinPending = pendingKey === `unpin:${pinId}`;
  const pinnedAt = pin.pinnedAt
    ? `Pinned ${formatAbsoluteDateTime(pin.pinnedAt)}`
    : "Pinned message";
  const pinnerLabel = normalizeString(pin.pinnedBy);
  const contentKind = normalizeString(pin.contentKind) || "message";
  const messageId = normalizeString(pin.messageId || pin.sortKey);
  return `<article class="shared-messaging-room-pin${unpinPending ? " is-pending" : ""}">
    <div class="shared-messaging-room-pin__main">
      <p>${escapeHtml(pinnedAt)}${pinnerLabel ? ` | ${escapeHtml(pinnerLabel)}` : ""}</p>
      <h3>${escapeHtml(messagingRoomPinnedMessageText(pin))}</h3>
      <div class="shared-messaging-room-chip-cloud">
        <span>${escapeHtml(humanizeLabel(contentKind) || contentKind)}</span>
        ${messageId ? `<span>${escapeHtml(messageId)}</span>` : ""}
      </div>
    </div>
    <button class="shared-feed-chip" type="button" data-action="messaging-room-unpin-message" data-conversation-id="${escapeHtml(subroute.conversationId)}" data-pin-id="${escapeHtml(pinId)}"${disabledAttr(!pinId || Boolean(pendingKey))}>${unpinPending ? "Unpinning..." : "Unpin"}</button>
  </article>`;
}

function renderMessagingRoomRecentPinRow(candidate, subroute, pendingKey = "") {
  const message = candidate.message || {};
  const messageId = normalizeString(message.messageId);
  const pinPending = pendingKey === `pin:${messageId}`;
  const senderLabel =
    normalizeString(message.senderDisplayName || message.senderUsername) ||
    "Polis user";
  const timeLabel = message.createdAt
    ? formatAbsoluteDateTime(message.createdAt)
    : "Time unavailable";
  const messageText =
    normalizeString(message.text) ||
    humanizeLabel(message.type) ||
    "Message content unavailable";
  return `<article class="shared-messaging-room-recent-message${candidate.isPinned ? " is-pinned" : ""}${pinPending ? " is-pending" : ""}">
    <div class="shared-messaging-room-recent-message__main">
      <p>${escapeHtml(senderLabel)} | ${escapeHtml(timeLabel)}</p>
      <strong>${escapeHtml(messageText)}</strong>
    </div>
    <button class="shared-feed-chip${candidate.isPinned ? "" : " shared-feed-chip--primary"}" type="button" data-action="messaging-room-pin-message" data-conversation-id="${escapeHtml(subroute.conversationId)}" data-message-id="${escapeHtml(messageId)}"${disabledAttr(candidate.isPinned || !messageId || Boolean(pendingKey))}>${candidate.isPinned ? "Pinned" : pinPending ? "Pinning..." : "Pin"}</button>
  </article>`;
}

function renderMessagingRoomPinnedMessagesSection({
  subroute,
  conversation,
  raw,
  embeddedPins,
  roomPins,
  roomMessages,
}) {
  const pins = mergeMessagingRoomPinRows(embeddedPins, roomPins);
  const candidates = collectMessagingRoomPinCandidates(roomMessages, pins);
  const pendingKey = normalizeString(roomPins?.actionPendingKey);
  const pinnedCount =
    Number(raw.pinnedMessageCount || raw.pinCount) || pins.length;
  return renderMessagingRoomSection({
    title: "Pinned references",
    subtitle:
      "Keep important room messages easy to find, and promote recent conversation items directly from this screen.",
    badge: `${formatCount(pinnedCount)} pinned`,
    body: `
      <div class="shared-messaging-settings-grid">
        <div><strong>Pinned messages</strong><span>${escapeHtml(formatCount(pinnedCount))}</span></div>
        <div><strong>Recent candidates</strong><span>${escapeHtml(formatCount(candidates.length))}</span></div>
        <div><strong>Pin policy</strong><span>${escapeHtml(raw.canPinMessages === false ? "Restricted" : "Available to permitted roles")}</span></div>
      </div>
      ${roomPins?.loading ? '<div class="shared-page__loading">Loading pinned messages...</div>' : ""}
      ${roomPins?.error ? `<div class="shared-page__error">${escapeHtml(roomPins.error)}</div>` : ""}
      <div class="shared-messaging-room-pin-group">
        <div class="shared-messaging-room-pin-group__header">
          <strong>Current pins</strong>
          <span>${escapeHtml(formatCount(pins.length))}</span>
        </div>
        <div class="shared-messaging-room-pin-list">${
          pins.length
            ? pins
                .map((pin) => renderMessagingRoomPinCard(pin, subroute, pendingKey))
                .join("")
            : `<div class="shared-messaging-empty">${escapeHtml(roomPins?.loading ? "Loading pinned messages..." : "No pinned messages are available for this room yet.")}</div>`
        }</div>
      </div>
      <div class="shared-messaging-room-pin-group">
        <div class="shared-messaging-room-pin-group__header">
          <strong>Recent messages</strong>
          <span>${escapeHtml(formatCount(candidates.length))}</span>
        </div>
        <div class="shared-messaging-room-recent-list">${
          candidates.length
            ? candidates
                .map((candidate) =>
                  renderMessagingRoomRecentPinRow(candidate, subroute, pendingKey),
                )
                .join("")
            : `<div class="shared-messaging-empty">${escapeHtml(conversation?.loading ? "Loading room messages..." : "No recent messages are available to pin yet.")}</div>`
        }</div>
      </div>`,
  });
}

function messagingServerSettingsValue(value, fallback = "Not set") {
  const normalized = normalizeString(value);
  return normalized ? humanizeLabel(normalized) || normalized : fallback;
}

function messagingServerNotificationLevel(serverSettings) {
  const overview =
    serverSettings?.overview && typeof serverSettings.overview === "object"
      ? serverSettings.overview
      : {};
  const raw = serverSettings?.raw || {};
  const rawLevel = normalizeString(
    overview.defaultNotificationLevel ||
      overview.notificationLevel ||
      raw.defaultNotificationLevel ||
      raw.notificationLevel ||
      raw.preferences?.notificationLevel,
  ).toLowerCase();
  if (["mention", "mentions_only", "mentions-only"].includes(rawLevel)) {
    return "mentions";
  }
  if (["muted", "mute", "off", "disabled"].includes(rawLevel)) {
    return "none";
  }
  if (["all_messages", "all-messages", "everything"].includes(rawLevel)) {
    return "all";
  }
  return rawLevel || "mentions";
}

function messagingServerSettingsGroups(serverSettings) {
  const sections =
    serverSettings?.sections && typeof serverSettings.sections === "object"
      ? serverSettings.sections
      : {};
  const groups = [
    {
      key: "settings",
      title: "Workspace defaults",
      subtitle: "Room alerts, profile, assets, and workspace-level controls.",
    },
    {
      key: "community",
      title: "Member entry",
      subtitle: "Invites, discovery, welcomes, rules, and join behavior.",
    },
    {
      key: "userManagement",
      title: "People and safety",
      subtitle: "Access groups, people, reports, blocked access, and review tools.",
    },
  ];
  return groups
    .map((group) => ({
      ...group,
      items: Array.isArray(sections[group.key])
        ? sections[group.key]
            .map((item) =>
              item && typeof item === "object"
                ? {
                    id: normalizeString(
                      item.id || item.key || item.sectionId || item.type,
                    ),
                    title:
                      normalizeString(item.title || item.label || item.name) ||
                      "Section",
                    description: normalizeString(
                      item.description || item.subtitle || item.summary,
                    ),
                    status: normalizeString(item.status || item.state),
                    available: item.available !== false,
                    raw: item,
                  }
                : null,
            )
            .filter((item) => item?.id)
        : [],
    }))
    .filter((group) => group.items.length);
}

function messagingServerSettingsItemPresentation(item = {}) {
  const normalizedId = normalizeString(item.id).toLowerCase().replace(/_/g, "-");
  const display = {
    overview: {
      title: "Overview",
      description: "Workspace health, room coverage, and available web controls.",
    },
    "server-details": {
      title: "Workspace profile",
      description: "Identity, scope, access, member count, and stable references.",
    },
    customization: {
      title: "Profile and branding",
      description: "Name, summary, icon, banner, and member-facing presentation.",
    },
    moderation: {
      title: "Safety review",
      description: "Reports, held messages, guardrails, and active restrictions.",
    },
    channels: {
      title: "Rooms",
      description: "Room structure, categories, access, and entry points.",
    },
    "community-settings": {
      title: "Member entry",
      description: "Discovery, joins, invites, welcomes, rules, and support rooms.",
    },
    "audit-log": {
      title: "Activity history",
      description: "Admin changes, access updates, safety actions, and workspace events.",
    },
    integrations: {
      title: "Connected automations",
      description: "External handoffs, connected destinations, and automation links.",
    },
    emoji: {
      title: "Custom emoji",
      description: "Emoji available in rooms and conversations.",
    },
    stickers: {
      title: "Sticker packs",
      description: "Reusable sticker assets available in the workspace.",
    },
    security: {
      title: "Safety policy",
      description: "Trusted-device, encrypted-room, invite, and abuse-prevention rules.",
    },
    invites: {
      title: "Invite links",
      description: "Reusable links, pending joins, approval, and access handoffs.",
    },
  }[normalizedId];
  return {
    title:
      display?.title ||
      normalizeString(item.title || item.label || item.name) ||
      humanizeLabel(item.id) ||
      "Workspace area",
    description:
      display?.description ||
      normalizeString(item.description || item.subtitle || item.summary),
  };
}

function findMessagingServerSettingsSection(serverSettings, sectionId) {
  const normalizedSectionId = normalizeString(sectionId);
  if (!normalizedSectionId) {
    return null;
  }
  for (const group of messagingServerSettingsGroups(serverSettings)) {
    const match = group.items.find(
      (item) => normalizeString(item.id) === normalizedSectionId,
    );
    if (match) {
      return { ...match, group };
    }
  }
  return null;
}

function renderMessagingServerSettingsHero({
  subroute,
  serverSettings,
  currentServer,
  directory,
}) {
  const server = serverSettings?.server || currentServer || {};
  const overview =
    serverSettings?.overview && typeof serverSettings.overview === "object"
      ? serverSettings.overview
      : {};
  const channels = Array.isArray(directory?.channels) ? directory.channels : [];
  const categories = Array.isArray(directory?.categories)
    ? directory.categories
    : [];
  const canManage = server.canManage === true || currentServer?.canManage === true;
  const memberCount =
    Number(server.memberCount || currentServer?.memberCount) || 0;
  const defaultLevel = messagingServerNotificationLevel(serverSettings);
  const chips = [
    server.scopeBadge || messagingServerSettingsValue(subroute.scopeType, "Workspace"),
    canManage ? "Management enabled" : "View only",
    `${formatCount(channels.length)} rooms`,
    `${formatCount(categories.length)} categories`,
    `Default: ${messagingServerSettingsValue(defaultLevel)}`,
  ].filter(Boolean);
  const subtitle =
    normalizeString(
      overview.description ||
        server.description ||
        server.raw?.description ||
        currentServer?.raw?.description,
    ) || "Workspace preferences, member entry, and administration access.";
  return `<section class="shared-messaging-server-settings-hero">
    ${renderMessagingWorkspaceAvatar({
      label: server.title || currentServer?.title || "Workspace settings",
      imageUrl: server.avatarUrl || currentServer?.avatarUrl,
      icon: "dashboard",
      className: "shared-messaging-avatar--server-card",
    })}
    <div class="shared-messaging-server-settings-hero__main">
      <p>${escapeHtml(messagingServerSettingsValue(subroute.scopeType, "Workspace"))}</p>
      <h3>${escapeHtml(server.title || currentServer?.title || "Workspace settings")}</h3>
      <span>${escapeHtml(subtitle)}</span>
      <div class="shared-messaging-server-settings-chip-cloud">${chips
        .map((chip) => `<span>${escapeHtml(chip)}</span>`)
        .join("")}</div>
    </div>
    <div class="shared-messaging-server-settings-hero__metric">
      <strong>${escapeHtml(formatCount(memberCount))}</strong>
      <span>members</span>
    </div>
  </section>`;
}

function renderMessagingServerSettingsSection({
  title,
  subtitle = "",
  badge = "",
  actions = "",
  body = "",
  className = "",
}) {
  return `<section class="shared-messaging-server-settings-section${className ? ` ${escapeHtml(className)}` : ""}">
    <div class="shared-messaging-server-settings-section__header">
      <div>
        <h3>${escapeHtml(title)}</h3>
        ${subtitle ? `<p>${escapeHtml(subtitle)}</p>` : ""}
      </div>
      ${badge ? `<span>${escapeHtml(badge)}</span>` : ""}
    </div>
    ${body}
    ${actions ? `<div class="shared-messaging-server-settings-section__actions">${actions}</div>` : ""}
  </section>`;
}

function renderMessagingServerNotificationForm(
  subroute,
  serverSettings,
  settingsState,
) {
  const activeLevel = messagingServerNotificationLevel(serverSettings);
  const saving = settingsState?.saving === true;
  const modes = [
    ["all", "All messages", "Alert members for every workspace room message."],
    [
      "mentions",
      "Mentions only",
      "Alert members when they or their roles are mentioned.",
    ],
    ["none", "None", "Suppress default workspace room alerts."],
  ];
  return renderMessagingServerSettingsSection({
    title: "Default notifications",
    subtitle:
      "Set the baseline alert behavior members inherit unless a room overrides it.",
    badge: messagingServerSettingsValue(activeLevel),
    body: `<form class="shared-messaging-server-settings-form" data-route-form="messaging-server-settings-preferences">
      <input type="hidden" name="scopeType" value="${escapeHtml(subroute.scopeType)}" />
      <input type="hidden" name="scopeId" value="${escapeHtml(subroute.scopeId)}" />
      <div class="shared-messaging-server-notification-grid">
        ${modes
          .map(([key, label, copy]) => {
            const selected = activeLevel === key;
            return `<label class="shared-messaging-server-notification${selected ? " is-active" : ""}">
              <input type="radio" name="notificationLevel" value="${escapeHtml(key)}"${checkedAttr(selected)}${disabledAttr(saving)} />
              <span>
                <strong>${escapeHtml(label)}</strong>
                <small>${escapeHtml(copy)}</small>
              </span>
            </label>`;
          })
          .join("")}
      </div>
      <div class="shared-messaging-server-settings-form__footer">
        <span>${escapeHtml(saving ? "Saving preference..." : "Changes apply to new workspace room defaults.")}</span>
        <button class="shared-feed-chip shared-feed-chip--primary" type="submit"${disabledAttr(saving)}>${saving ? "Saving..." : "Save default"}</button>
      </div>
    </form>`,
  });
}

function findMessagingServerSettingsItem(serverSettings, sectionIds = []) {
  const wanted = new Set(
    sectionIds
      .map((sectionId) =>
        normalizeString(sectionId).toLowerCase().replace(/_/g, "-"),
      )
      .filter(Boolean),
  );
  if (!wanted.size) {
    return null;
  }
  for (const group of messagingServerSettingsGroups(serverSettings)) {
    const match = group.items.find((item) =>
      wanted.has(normalizeString(item.id).toLowerCase().replace(/_/g, "-")),
    );
    if (match) {
      return { ...match, group };
    }
  }
  return null;
}

function messagingServerSettingsActionRoute(
  subroute,
  serverSettings,
  sectionIds = [],
  fallbackSuffix = "",
) {
  const section = findMessagingServerSettingsItem(serverSettings, sectionIds);
  if (section?.id) {
    return buildMessagingServerRoute(
      subroute.scopeType,
      subroute.scopeId,
      `/settings/${encodeURIComponent(section.id)}`,
    );
  }
  return buildMessagingServerRoute(
    subroute.scopeType,
    subroute.scopeId,
    fallbackSuffix,
  );
}

function renderMessagingServerCommandCard({
  icon,
  title,
  detail,
  copy,
  route,
  action,
  status,
  tone = "",
}) {
  return `<button class="shared-messaging-command-card${tone ? ` is-${escapeHtml(tone)}` : ""}" type="button" data-action="navigate" data-route="${escapeHtml(route)}">
    <span class="shared-messaging-command-card__icon" aria-hidden="true">${renderIcon(icon)}</span>
    <span class="shared-messaging-command-card__body">
      <span>${escapeHtml(detail)}</span>
      <strong>${escapeHtml(title)}</strong>
      <small>${escapeHtml(copy)}</small>
    </span>
    <span class="shared-messaging-command-card__footer">
      <em>${escapeHtml(status)}</em>
      <b>${escapeHtml(action)}</b>
    </span>
  </button>`;
}

function renderMessagingServerReadinessItem({ label, value, copy, tone = "" }) {
  return `<div class="shared-messaging-readiness-item${tone ? ` is-${escapeHtml(tone)}` : ""}">
    <span>${escapeHtml(label)}</span>
    <strong>${escapeHtml(value)}</strong>
    <small>${escapeHtml(copy)}</small>
  </div>`;
}

function renderMessagingServerSettingsOverview({
  subroute,
  serverSettings,
  currentServer,
  directory,
}) {
  const capabilities =
    serverSettings?.capabilities && typeof serverSettings.capabilities === "object"
      ? serverSettings.capabilities
      : {};
  const channels = Array.isArray(directory?.channels) ? directory.channels : [];
  const categories = Array.isArray(directory?.categories)
    ? directory.categories
    : [];
  const groups = messagingServerSettingsGroups(serverSettings);
  const canManage =
    currentServer?.canManage === true ||
    serverSettings?.server?.canManage === true ||
    capabilities.canManageServer === true ||
    capabilities.canManage === true;
  const availableSettings = groups.reduce(
    (count, group) => count + group.items.filter((item) => item.available).length,
    0,
  );
  const unavailableSettings = groups.reduce(
    (count, group) => count + group.items.filter((item) => !item.available).length,
    0,
  );
  const roomCount = channels.length;
  const categoryCount = categories.length;
  const notificationLevel = messagingServerNotificationLevel(serverSettings);
  const communitySection = findMessagingServerSettingsItem(serverSettings, [
    "community-settings",
    "community",
  ]);
  const moderationSection = findMessagingServerSettingsItem(serverSettings, [
    "moderation",
    "audit-log",
  ]);
  const automationSection = findMessagingServerSettingsItem(serverSettings, [
    "integrations",
    "workflows",
  ]);
  const securitySection = findMessagingServerSettingsItem(serverSettings, [
    "security",
  ]);
  const commandCards = [
    {
      icon: "messages",
      title: "Room directory",
      detail: `${formatCount(roomCount)} room${roomCount === 1 ? "" : "s"}`,
      copy: "Open campaign and coalition rooms, categories, and room setup.",
      route: buildMessagingServerRoute(subroute.scopeType, subroute.scopeId),
      action: roomCount ? "Open rooms" : "Set up rooms",
      status: categoryCount
        ? `${formatCount(categoryCount)} categories`
        : "No categories",
      tone: roomCount ? "ready" : "attention",
    },
    {
      icon: "team",
      title: "People and access",
      detail: canManage ? "Admin view" : "Member view",
      copy: "Review members, role groups, and who can enter each workspace area.",
      route: buildMessagingServerRoute(subroute.scopeType, subroute.scopeId, "/roles"),
      action: "Open access",
      status: canManage ? "Ready" : "Limited",
      tone: canManage ? "ready" : "muted",
    },
    {
      icon: "shield",
      title: "Moderation",
      detail: moderationSection?.available ? "Queue connected" : "Review tools",
      copy: "Handle reports, held messages, rules, and active restrictions.",
      route: buildMessagingServerRoute(
        subroute.scopeType,
        subroute.scopeId,
        "/moderation",
      ),
      action: "Review queue",
      status: moderationSection?.available ? "Ready" : "Setup",
      tone: moderationSection?.available ? "ready" : "attention",
    },
    {
      icon: "settings",
      title: "Automations",
      detail: automationSection?.available ? "Ready to run" : "Setup needed",
      copy: "Connect keyword, schedule, report, and webhook handoffs.",
      route: buildMessagingServerRoute(
        subroute.scopeType,
        subroute.scopeId,
        "/workflows",
      ),
      action: "Open automations",
      status: automationSection?.available ? "Ready" : "Setup",
      tone: automationSection?.available ? "ready" : "attention",
    },
    {
      icon: "candidate",
      title: "Community entry",
      detail: communitySection?.available ? "Onboarding controls" : "Needs setup",
      copy: "Tune welcomes, rules, support rooms, invites, and join behavior.",
      route: messagingServerSettingsActionRoute(
        subroute,
        serverSettings,
        ["community-settings", "community"],
        "/settings/community-settings",
      ),
      action: "Open community",
      status: communitySection?.available ? "Ready" : "Setup",
      tone: communitySection?.available ? "ready" : "attention",
    },
    {
      icon: "lock",
      title: "Safety policy",
      detail: securitySection?.available ? "Protected actions" : "Policy setup",
      copy: "Review trusted-device, encryption, and sensitive-room rules.",
      route: messagingServerSettingsActionRoute(
        subroute,
        serverSettings,
        ["security"],
        "/settings/security",
      ),
      action: "Open safety",
      status: securitySection?.available ? "Ready" : "Setup",
      tone: securitySection?.available ? "ready" : "attention",
    },
  ];
  const readinessItems = [
    {
      label: "Rooms",
      value: formatCount(roomCount),
      copy: roomCount
        ? `${formatCount(categoryCount)} categor${categoryCount === 1 ? "y" : "ies"} available`
        : "Create rooms before launching the workspace",
      tone: roomCount ? "ready" : "attention",
    },
    {
      label: "Controls",
      value: formatCount(availableSettings),
      copy: unavailableSettings
        ? `${formatCount(unavailableSettings)} area${unavailableSettings === 1 ? "" : "s"} still unavailable`
        : "All exposed workspace areas are available",
      tone: availableSettings ? "ready" : "attention",
    },
    {
      label: "Default alerts",
      value: messagingServerSettingsValue(notificationLevel),
      copy:
        notificationLevel === "all"
          ? "Consider mentions for campaign and coalition rooms"
          : "Low-friction default for most members",
      tone: notificationLevel === "all" ? "attention" : "ready",
    },
    {
      label: "Access level",
      value: canManage ? "Admin" : "Member",
      copy: canManage
        ? "You can change workspace controls from the website"
        : "You can review the areas available to your role",
      tone: canManage ? "ready" : "muted",
    },
  ];
  return renderMessagingServerSettingsSection({
    title: "Messaging command center",
    subtitle:
      "A web-ready overview of rooms, access, moderation, automations, and member defaults.",
    badge: canManage ? "Admin tools" : "Member view",
    body: `<div class="shared-messaging-readiness-strip">
      ${readinessItems.map(renderMessagingServerReadinessItem).join("")}
    </div>
    <div class="shared-messaging-command-grid">
      ${commandCards.map(renderMessagingServerCommandCard).join("")}
    </div>`,
  });
}

function renderMessagingServerSettingsGroups(subroute, serverSettings, sectionId) {
  const groups = messagingServerSettingsGroups(serverSettings);
  if (!groups.length) {
    return renderMessagingServerSettingsSection({
      title: "Workspace areas",
      subtitle: "This workspace has not exposed website-manageable settings yet.",
      badge: "None",
      body: '<div class="shared-messaging-empty">No workspace areas are available from the app API.</div>',
    });
  }
  const selectedSection = normalizeString(sectionId);
  return `<div class="shared-messaging-server-settings-groups">${groups
    .map(
      (group) => `<section class="shared-messaging-server-settings-group">
        <div class="shared-messaging-server-settings-group__header">
          <div>
            <h3>${escapeHtml(group.title)}</h3>
            <p>${escapeHtml(group.subtitle)}</p>
          </div>
          <span>${escapeHtml(formatCount(group.items.length))}</span>
        </div>
        <div class="shared-messaging-server-settings-list">${group.items
          .map((item) => {
            const active = selectedSection === normalizeString(item.id);
            const display = messagingServerSettingsItemPresentation(item);
            const route = buildMessagingServerRoute(
              subroute.scopeType,
              subroute.scopeId,
              `/settings/${encodeURIComponent(item.id)}`,
            );
            return `<button class="shared-messaging-server-settings-item${active ? " is-active" : ""}${item.available ? "" : " is-disabled"}" type="button"${item.available ? ` data-action="navigate" data-route="${escapeHtml(route)}"` : " disabled"}>
              <span>
                <strong>${escapeHtml(display.title)}</strong>
                <small>${escapeHtml(display.description || (item.available ? "Open this workspace area." : "Not available for this workspace."))}</small>
              </span>
              <em>${escapeHtml(item.available ? messagingServerSettingsValue(item.status, active ? "Open" : "Ready") : "Unavailable")}</em>
            </button>`;
          })
          .join("")}</div>
      </section>`,
    )
    .join("")}</div>`;
}

function messagingServerSettingsSectionActionRoute(subroute, sectionId) {
  const normalized = normalizeString(sectionId).toLowerCase();
  if (normalized === "channels") {
    return buildMessagingServerRoute(subroute.scopeType, subroute.scopeId);
  }
  if (normalized === "integrations") {
    return buildMessagingServerRoute(
      subroute.scopeType,
      subroute.scopeId,
      "/workflows",
    );
  }
  if (normalized === "invites") {
    return buildMessagingServerRoute(subroute.scopeType, subroute.scopeId, "/members");
  }
  if (normalized.includes("role") || normalized.includes("permission")) {
    return buildMessagingServerRoute(subroute.scopeType, subroute.scopeId, "/roles");
  }
  if (
    normalized.includes("member") ||
    normalized.includes("user") ||
    normalized.includes("roster")
  ) {
    return buildMessagingServerRoute(subroute.scopeType, subroute.scopeId, "/members");
  }
  if (
    normalized.includes("moderation") ||
    normalized.includes("report") ||
    normalized.includes("automod")
  ) {
    return buildMessagingServerRoute(
      subroute.scopeType,
      subroute.scopeId,
      "/moderation",
    );
  }
  if (normalized.includes("workflow") || normalized.includes("automation")) {
    return buildMessagingServerRoute(
      subroute.scopeType,
      subroute.scopeId,
      "/workflows",
    );
  }
  return "";
}

