function messagingServerSettingsKnownSection(sectionId) {
  const normalized = normalizeString(sectionId)
    .toLowerCase()
    .replace(/_/g, "-");
  return MESSAGING_SERVER_SETTINGS_SECTION_META[normalized] ? normalized : "";
}

function messagingServerSettingsSectionSources(serverSettings, section) {
  const raw = serverSettings?.raw || {};
  const sectionRaw = section?.raw || {};
  const sectionId = normalizeString(section?.id).toLowerCase().replace(/_/g, "-");
  const camelId = sectionId.replace(/-([a-z])/g, (_, letter) =>
    letter.toUpperCase(),
  );
  return [
    sectionRaw,
    sectionRaw.data,
    sectionRaw.settings,
    sectionRaw.items,
    serverSettings?.overview,
    serverSettings?.[sectionId],
    serverSettings?.[camelId],
    serverSettings?.server,
    serverSettings?.server?.raw,
    raw?.overview,
    raw?.server,
    raw?.[sectionId],
    raw?.[camelId],
    raw?.settings?.[sectionId],
    raw?.settings?.[camelId],
    raw?.sections?.[sectionId],
    raw?.sections?.[camelId],
    raw?.serverSettings?.[sectionId],
    raw?.serverSettings?.[camelId],
  ].filter(Boolean);
}

function readMessagingServerSettingsList(sources = [], keys = []) {
  for (const source of sources) {
    if (Array.isArray(source)) {
      return source;
    }
    if (!source || typeof source !== "object") {
      continue;
    }
    const direct = readMessagingLooseList(source, keys);
    if (direct.length) {
      return direct;
    }
    for (const key of keys) {
      const nested = source[key];
      if (nested && typeof nested === "object") {
        const nestedList = readMessagingLooseList(nested, [
          "items",
          "entries",
          "events",
          "rules",
          "links",
          "assets",
          "policies",
        ]);
        if (nestedList.length) {
          return nestedList;
        }
      }
    }
  }
  return [];
}

function readMessagingServerSettingsValue(sources = [], keys = []) {
  for (const source of sources) {
    if (!source || typeof source !== "object" || Array.isArray(source)) {
      continue;
    }
    for (const key of keys) {
      const value = source[key];
      if (
        value === true ||
        value === false ||
        Number.isFinite(Number(value)) ||
        normalizeString(value)
      ) {
        return value;
      }
    }
  }
  return "";
}

function messagingServerSettingsFlag(value, fallback = "Not set") {
  if (value === true) return "Enabled";
  if (value === false) return "Disabled";
  return messagingServerSettingsValue(value, fallback);
}

function messagingServerSettingsDisplayValue(value, fallback = "Not set") {
  if (value === true) return "Enabled";
  if (value === false) return "Disabled";
  return normalizeString(value) || fallback;
}

function renderMessagingServerSettingsFieldGrid(entries = [], emptyLabel = "") {
  const fields = entries.filter((entry) => normalizeString(entry?.label));
  if (!fields.length) {
    return `<div class="shared-messaging-empty">${escapeHtml(emptyLabel || "No fields were returned for this workspace area.")}</div>`;
  }
  return `<div class="shared-messaging-settings-grid">${fields
    .map(
      ({ label, value, fallback = "Not set" }) =>
        `<div><strong>${escapeHtml(label)}</strong><span>${escapeHtml(messagingServerSettingsDisplayValue(value, fallback))}</span></div>`,
    )
    .join("")}</div>`;
}

function renderMessagingServerSettingsActionRow(actions = []) {
  const buttons = actions
    .filter((action) => normalizeString(action?.route) && normalizeString(action?.label))
    .map(
      (action, index) =>
        `<button class="shared-feed-chip${index === 0 ? " shared-feed-chip--primary" : ""}" type="button" data-action="navigate" data-route="${escapeHtml(action.route)}">${escapeHtml(action.label)}</button>`,
    )
    .join("");
  return buttons;
}

function messagingServerSettingsBooleanValue(sources = [], keys = [], fallback = false) {
  const value = readMessagingServerSettingsValue(sources, keys);
  return value === "" ? fallback : parseBoolean(value, fallback);
}

function renderMessagingServerSettingsToggle({
  name,
  label,
  description,
  checked = false,
  disabled = false,
}) {
  return `<label class="shared-messaging-server-settings-toggle">
    <input type="checkbox" name="${escapeHtml(name)}" value="true"${checkedAttr(checked)}${disabledAttr(disabled)} />
    <span>
      <strong>${escapeHtml(label)}</strong>
      <small>${escapeHtml(description)}</small>
    </span>
  </label>`;
}

function renderMessagingServerSettingsChannelSelect({
  name,
  label,
  channels,
  value,
  disabled = false,
  noneLabel = "No room selected",
}) {
  const selectedValue = normalizeString(value);
  const roomOptions = (Array.isArray(channels) ? channels : [])
    .map((channel) => {
      const channelId = normalizeString(
        channel.conversationId || channel.id || channel.raw?.conversationId,
      );
      if (!channelId) {
        return "";
      }
      const title = normalizeString(channel.title || channel.name) || channelId;
      return `<option value="${escapeHtml(channelId)}"${selectedAttr(channelId === selectedValue)}>${escapeHtml(title)}</option>`;
    })
    .filter(Boolean)
    .join("");
  return `<label>
    <span>${escapeHtml(label)}</span>
    <select name="${escapeHtml(name)}"${disabledAttr(disabled)}>
      <option value=""${selectedAttr(!selectedValue)}>${escapeHtml(noneLabel)}</option>
      ${roomOptions}
    </select>
  </label>`;
}

const MESSAGING_SERVER_SECURITY_POLICY_CONTROLS = [
  {
    key: "requireTrustedDeviceForAdminActions",
    label: "Trusted device for admin actions",
    description: "Workspace management and moderation changes require a trusted device.",
  },
  {
    key: "requireTrustedDeviceForSensitiveChannels",
    label: "Trusted device for sensitive rooms",
    description: "Sensitive-room posting requires a trusted device on the account.",
  },
  {
    key: "requireE2eeForSensitiveChannels",
    label: "E2EE for sensitive rooms",
    description: "Sensitive rooms must be encrypted before members can post.",
  },
  {
    key: "requireMfaForAdminActions",
    label: "MFA for admin actions",
    description: "Unavailable until MFA enforcement signals are enabled.",
    requiresMfaSignal: true,
  },
  {
    key: "requireMfaForSensitiveChannels",
    label: "MFA for sensitive rooms",
    description: "Unavailable until MFA enforcement signals are enabled.",
    requiresMfaSignal: true,
  },
];

function renderMessagingServerSecurityPolicyForm({
  subroute,
  policy,
  canManage,
  policyState,
}) {
  const current = normalizeMessagingServerSecurityPolicy(policy || {});
  const saving = policyState?.saving === true;
  const disabled = saving || !canManage;
  const activeCount = MESSAGING_SERVER_SECURITY_POLICY_CONTROLS.filter(
    (control) => current[control.key] === true,
  ).length;
  const mfaLocked = !current.mfaSignalAvailable;
  const updatedLabel = current.updatedAt
    ? messagingRoomTimestampLabel(current.updatedAt, "Updated")
    : "Not updated";
  return `<div class="shared-messaging-server-security-panel">
    <div class="shared-messaging-server-security-summary">
      <div><strong>${escapeHtml(formatCount(activeCount))}</strong><span>active</span></div>
      <div><strong>${escapeHtml(current.requireE2eeForSensitiveChannels ? "On" : "Off")}</strong><span>E2EE</span></div>
      <div><strong>${escapeHtml(current.mfaSignalAvailable ? "Ready" : "Unavailable")}</strong><span>MFA</span></div>
      <div><strong>${escapeHtml(updatedLabel)}</strong><span>status</span></div>
    </div>
    <form class="shared-messaging-server-security-form" data-route-form="messaging-server-security-policy-update">
      <input type="hidden" name="scopeType" value="${escapeHtml(subroute.scopeType)}" />
      <input type="hidden" name="scopeId" value="${escapeHtml(subroute.scopeId)}" />
      <div class="shared-messaging-server-security-list">
        ${MESSAGING_SERVER_SECURITY_POLICY_CONTROLS.map((control) => {
          const controlDisabled =
            disabled || (control.requiresMfaSignal && mfaLocked);
          return `<label class="shared-messaging-server-security-toggle${controlDisabled ? " is-disabled" : ""}">
            <input type="checkbox" name="${escapeHtml(control.key)}" value="true"${checkedAttr(current[control.key] === true)}${disabledAttr(controlDisabled)} />
            <span>
              <strong>${escapeHtml(control.label)}</strong>
              <small>${escapeHtml(control.description)}</small>
            </span>
            <em>${escapeHtml(current[control.key] === true ? "On" : "Off")}</em>
          </label>`;
        }).join("")}
      </div>
      <div class="shared-messaging-server-settings-form__footer">
        <span>${escapeHtml(
          saving
            ? "Saving security policy..."
            : canManage
              ? "Trusted-device and E2EE changes apply to protected workspace actions."
              : "You need workspace management access to change security policy.",
        )}</span>
        <button class="shared-feed-chip shared-feed-chip--primary" type="submit"${disabledAttr(disabled)}>${saving ? "Saving..." : "Save policy"}</button>
      </div>
    </form>
  </div>`;
}

