function mergeMessagingServerInviteRows(embeddedInvites = [], serverInvites) {
  const loadedInvites =
    Array.isArray(serverInvites?.items) &&
    serverInvites.items.length
      ? serverInvites.items
      : [];
  const rows = [
    ...loadedInvites.map(normalizeMessagingServerInvite),
    ...embeddedInvites.map(normalizeMessagingServerInvite),
  ];
  const seen = new Set();
  return rows.filter((invite) => {
    const key =
      invite.inviteeUserId ||
      invite.inviteId ||
      normalizeString(invite.title).toLowerCase();
    if (!key || seen.has(key)) {
      return false;
    }
    seen.add(key);
    return true;
  });
}

function renderMessagingServerCategorySelectOptions(
  categories = [],
  selectedCategoryId = "",
) {
  const normalizedSelected = normalizeString(selectedCategoryId);
  return [
    `<option value=""${selectedAttr(!normalizedSelected)}>Uncategorized</option>`,
    ...categories
      .map((category) => {
        const categoryId = messagingDirectoryCategoryId(category);
        if (!categoryId) {
          return "";
        }
        return `<option value="${escapeHtml(categoryId)}"${selectedAttr(categoryId === normalizedSelected)}>${escapeHtml(messagingDirectoryCategoryTitle(category))}</option>`;
      })
      .filter(Boolean),
  ].join("");
}

function renderMessagingServerPositionOptions(count, selectedPosition = 0) {
  const safeCount = Math.max(1, Number(count) || 1);
  const selected = Math.max(0, Number(selectedPosition) || 0);
  return Array.from({ length: safeCount }, (_, index) => {
    const label = index === 0 ? "Top" : `Position ${index + 1}`;
    return `<option value="${escapeHtml(String(index))}"${selectedAttr(index === selected)}>${escapeHtml(label)}</option>`;
  }).join("");
}

function renderMessagingServerRoomTypeOptions(selectedRoomType = "") {
  const normalized = normalizeString(selectedRoomType).toLowerCase();
  return MESSAGING_DIRECTORY_ROOM_TYPE_OPTIONS.map(
    (option) =>
      `<option value="${escapeHtml(option.value)}"${selectedAttr((normalized || "public_within_scope") === option.value)}>${escapeHtml(option.label)}</option>`,
  ).join("");
}

