function renderMessagingMessageReactions(message, { conversationId = "" } = {}) {
  if (!message?.messageId || message.isDeleted) {
    return "";
  }
  const reactionMap = new Map(
    (message.reactions || [])
      .filter((reaction) => normalizeString(reaction.emoji))
      .map((reaction) => [normalizeString(reaction.emoji), reaction]),
  );
  const emojis = Array.from(
    new Set([
      ...MESSAGING_QUICK_REACTIONS,
      ...Array.from(reactionMap.keys()).filter(
        (emoji) => !MESSAGING_QUICK_REACTIONS.includes(emoji),
      ),
    ]),
  );
  const pendingKey = state.pages.messaging.conversation.reactionPendingKey;
  return `<div class="shared-message-reactions" aria-label="Message reactions">${emojis
    .map((emoji) => {
      const reaction = reactionMap.get(emoji) || {
        emoji,
        count: 0,
        reactedByMe: false,
      };
      const count = Math.max(0, Number(reaction.count) || 0);
      const reactedByMe = reaction.reactedByMe === true;
      const pending =
        pendingKey === messagingReactionPendingKey(message.messageId, emoji);
      return `<button class="shared-message-reaction${reactedByMe ? " is-active" : ""}" type="button" data-action="messaging-message-reaction" data-conversation-id="${escapeHtml(conversationId || message.conversationId)}" data-message-id="${escapeHtml(message.messageId)}" data-emoji="${escapeHtml(emoji)}" data-reacted="${reactedByMe ? "true" : "false"}"${disabledAttr(pending)} aria-pressed="${reactedByMe ? "true" : "false"}" aria-label="${escapeHtml(`${reactedByMe ? "Remove" : "Add"} ${emoji} reaction`)}"><strong>${escapeHtml(emoji)}</strong>${count ? `<span>${escapeHtml(formatCount(count))}</span>` : ""}</button>`;
    })
    .join("")}</div>`;
}

function renderMessagingMessageActions(
  message,
  { conversationId = "", isSelf = false } = {},
) {
  if (!message?.messageId || message.isDeleted) {
    return "";
  }
  const currentUserId = currentMessagingUserId();
  const canReply = canReplyMessagingMessageInWeb(message);
  const canEdit = canEditMessagingMessageInWeb(message, currentUserId);
  const canDelete = isSelf && canDeleteMessagingMessageInWeb(message, currentUserId);
  const canReport =
    !isSelf && canReportMessagingMessageInWeb(message, currentUserId);
  if (!canReply && !canEdit && !canDelete && !canReport) {
    return "";
  }
  const pendingKey = state.pages.messaging.conversation.messageActionPendingKey;
  return `<div class="shared-message-actions" aria-label="Message actions">
    ${
      canReply
        ? `<button class="shared-message-action" type="button" data-action="messaging-message-reply" data-conversation-id="${escapeHtml(conversationId || message.conversationId)}" data-message-id="${escapeHtml(message.messageId)}" aria-label="Reply to message">${renderIcon("reply")}<span>Reply</span></button>`
        : ""
    }
    ${
      isSelf && canEdit
        ? `<button class="shared-message-action" type="button" data-action="messaging-message-edit" data-conversation-id="${escapeHtml(conversationId || message.conversationId)}" data-message-id="${escapeHtml(message.messageId)}" aria-label="Edit message">${renderIcon("edit")}<span>Edit</span></button>`
        : ""
    }
    ${
      canDelete
        ? `<button class="shared-message-action shared-message-action--danger" type="button" data-action="messaging-message-delete" data-conversation-id="${escapeHtml(conversationId || message.conversationId)}" data-message-id="${escapeHtml(message.messageId)}"${disabledAttr(pendingKey === `delete:${message.messageId}`)} aria-label="Delete message">${renderIcon("trash")}<span>${pendingKey === `delete:${message.messageId}` ? "Deleting" : "Delete"}</span></button>`
        : ""
    }
    ${
      canReport
        ? `<button class="shared-message-action shared-message-action--warning" type="button" data-action="messaging-message-report" data-conversation-id="${escapeHtml(conversationId || message.conversationId)}" data-message-id="${escapeHtml(message.messageId)}"${disabledAttr(pendingKey === `report:${message.messageId}`)} aria-label="Report message">${renderIcon("flag")}<span>${pendingKey === `report:${message.messageId}` ? "Reporting" : "Report"}</span></button>`
        : ""
    }
  </div>`;
}

function renderMessagingSeenByStatus(message, { isSelf = false } = {}) {
  if (!isSelf || message?.isDeleted) {
    return "";
  }
  const currentUserId = currentMessagingUserId();
  const seenBy = (message.seenBy || [])
    .filter((viewer) => {
      const viewerId = normalizeString(viewer.userId);
      return !viewerId || viewerId !== currentUserId;
    })
    .filter(
      (viewer, index, items) =>
        index ===
        items.findIndex(
          (item) =>
            normalizeString(item.userId) === normalizeString(viewer.userId) &&
            normalizeString(item.displayName) ===
              normalizeString(viewer.displayName),
        ),
    );
  if (!seenBy.length) {
    return "";
  }
  const visible = seenBy.slice(0, 3);
  const extraCount = Math.max(0, seenBy.length - visible.length);
  const label = `Seen by ${seenBy
    .map((viewer) => normalizeString(viewer.displayName) || "Polis user")
    .slice(0, 4)
    .join(", ")}${seenBy.length > 4 ? ` and ${formatCount(seenBy.length - 4)} more` : ""}`;
  const latestSeenAt = seenBy.reduce((latest, viewer) => {
    const seenAt = Number(viewer.seenAt) || 0;
    return seenAt > latest ? seenAt : latest;
  }, 0);
  return `<div class="shared-message-seen" title="${escapeHtml(label)}" aria-label="${escapeHtml(label)}">
    <span>${escapeHtml(latestSeenAt ? `Seen ${formatAbsoluteDateTime(latestSeenAt)}` : "Seen")}</span>
    <div class="shared-message-seen__avatars" aria-hidden="true">
      ${visible
        .map((viewer) => {
          const displayName =
            normalizeString(viewer.displayName) ||
            normalizeString(viewer.username) ||
            "Polis user";
          const avatarUrl = normalizeUrl(viewer.avatarUrl);
          return `<span class="shared-message-seen__avatar">
            ${avatarUrl ? `<img src="${escapeHtml(avatarUrl)}" alt="" loading="lazy" />` : `<strong>${escapeHtml(messagingWorkspaceInitial(displayName))}</strong>`}
          </span>`;
        })
        .join("")}
      ${extraCount ? `<span class="shared-message-seen__avatar shared-message-seen__avatar--more">+${escapeHtml(formatCount(extraCount))}</span>` : ""}
    </div>
  </div>`;
}

function renderMessagingReplyPreviewBlock(replyTo = null) {
  const replyPreview = normalizeMessagingReplyPreview(replyTo);
  if (!replyPreview) {
    return "";
  }
  const senderLabel = messagingReplySenderLabel(replyPreview);
  const textLabel = messagingReplyTextLabel(replyPreview);
  return `<button class="shared-message-reply-preview" type="button" data-action="messaging-message-reply-jump" data-message-id="${escapeHtml(replyPreview.messageId)}" aria-label="${escapeHtml(`Jump to ${senderLabel}'s message`)}">
    <span>${renderIcon("reply")}</span>
    <strong>${escapeHtml(senderLabel)}</strong>
    <small>${escapeHtml(textLabel)}</small>
  </button>`;
}

function renderMessagingMessageReportModal(conversationState) {
  const messageId = normalizeString(conversationState?.reportingMessageId);
  if (!messageId) {
    return "";
  }
  const message = (conversationState.messages || []).find(
    (item) => item.messageId === messageId,
  );
  if (!message || !canReportMessagingMessageInWeb(message, currentMessagingUserId())) {
    return "";
  }
  const conversationId = normalizeString(conversationState.item?.conversationId);
  const pending =
    conversationState.messageActionPendingKey === `report:${messageId}`;
  const senderLabel =
    normalizeString(message.senderDisplayName) ||
    normalizeString(message.senderUsername) ||
    "Polis user";
  const excerpt =
    normalizeString(message.text) ||
    (message.attachments?.length ? "Attachment message" : "Message");
  const sentLabel = message.createdAt
    ? formatAbsoluteDateTime(message.createdAt)
    : "Recent message";
  const reasonMarkup = MESSAGING_REPORT_REASON_OPTIONS.map(
    ([value, label, detail], index) => `<label class="shared-messaging-report-modal__reason">
      <input type="radio" name="reasonCode" value="${escapeHtml(value)}"${index === 0 ? " checked" : ""}${disabledAttr(pending)} />
      <span>
        <strong>${escapeHtml(label)}</strong>
        <small>${escapeHtml(detail)}</small>
      </span>
    </label>`,
  ).join("");
  return `<div class="shared-messaging-report-modal" role="presentation">
    <button class="shared-messaging-report-modal__backdrop" type="button" data-action="messaging-message-report-cancel" aria-label="Close report dialog"></button>
    <form class="shared-messaging-report-modal__dialog" data-route-form="messaging-message-report" role="dialog" aria-modal="true" aria-labelledby="messaging-report-title" tabindex="-1">
      <input type="hidden" name="conversationId" value="${escapeHtml(conversationId)}" />
      <input type="hidden" name="messageId" value="${escapeHtml(messageId)}" />
      <header>
        <span>${renderIcon("flag")}</span>
        <div>
          <p>Safety review</p>
          <h3 id="messaging-report-title">Report message</h3>
        </div>
      </header>
      <div class="shared-messaging-report-modal__excerpt">
        <strong>${escapeHtml(senderLabel)}</strong>
        <small>${escapeHtml(sentLabel)}</small>
        <p>${escapeHtml(excerpt)}</p>
      </div>
      <fieldset class="shared-messaging-report-modal__reasons">
        <legend>Reason</legend>
        ${reasonMarkup}
      </fieldset>
      <label class="shared-messaging-report-modal__details">
        <span>Details <small>optional</small></span>
        <textarea name="details" rows="4" maxlength="1000" placeholder="Add context for the safety team."${disabledAttr(pending)}></textarea>
      </label>
      <div class="shared-messaging-report-modal__actions">
        <button class="shared-feed-chip" type="button" data-action="messaging-message-report-cancel"${disabledAttr(pending)}>Cancel</button>
        <button class="shared-feed-chip shared-feed-chip--primary" type="submit"${disabledAttr(pending)}>${renderIcon("flag")} <span>${escapeHtml(pending ? "Sending..." : "Send report")}</span></button>
      </div>
    </form>
  </div>`;
}

function shortMessagingDeviceId(deviceId) {
  const normalized = normalizeString(deviceId);
  if (normalized.length <= 14) {
    return normalized;
  }
  return `${normalized.slice(0, 8)}...${normalized.slice(-4)}`;
}

function messagingTrustedDeviceItems() {
  const devices = state.pages.messaging.devices;
  return (Array.isArray(devices.items) ? devices.items : []).filter((device) => {
    const revokedAt = normalizeString(
      device?.revokedAt || device?.raw?.revokedAt || device?.raw?.revoked_at,
    );
    return !revokedAt;
  });
}

function messagingRecoveryBackupLabel(recovery = state.pages.messaging.recovery) {
  const status = recovery.status && typeof recovery.status === "object"
    ? recovery.status
    : {};
  const rawStatus = normalizeString(
    status.status || status.state || status.health || status.phase,
  );
  if (rawStatus) {
    return rawStatus
      .split(/[_-]+/g)
      .filter(Boolean)
      .map((part) => `${part.slice(0, 1).toUpperCase()}${part.slice(1)}`)
      .join(" ");
  }
  if (Number(status.backupVersion) > 0 || recovery.bundle) {
    return "Backup available";
  }
  if (recovery.loaded) {
    return "Not enrolled";
  }
  return "Not checked";
}

function messagingRecoveryBackupDetail(recovery = state.pages.messaging.recovery) {
  const status = recovery.status && typeof recovery.status === "object"
    ? recovery.status
    : {};
  const updatedAt =
    Number(
      status.backupUpdatedAt ||
        status.updatedAt ||
        status.verifiedAt ||
        status.createdAt,
    ) || null;
  if (updatedAt) {
    return `Updated ${formatAbsoluteDateTime(updatedAt)}`;
  }
  if (recovery.error) {
    return recovery.error;
  }
  if (recovery.localCode) {
    return "Local recovery key is saved in this browser.";
  }
  return recovery.loaded
    ? "Use recovery to prepare encrypted history on this browser."
    : "Open recovery to check encrypted history backup.";
}

function renderMessagingSecureStatusItem({
  icon = "shield",
  label,
  value,
  detail,
} = {}) {
  return `<div class="shared-messaging-secure-handoff__status-item" role="listitem">
    <span class="shared-messaging-secure-handoff__status-icon">${renderIcon(icon)}</span>
    <span>
      <small>${escapeHtml(label)}</small>
      <strong>${escapeHtml(value)}</strong>
      <em>${escapeHtml(detail)}</em>
    </span>
  </div>`;
}

function renderMessagingSecureHandoff({ stacked = false, conversation = null } = {}) {
  const messaging = state.pages.messaging;
  const recovery = messaging.recovery;
  const currentDeviceId = normalizeString(messaging.device.currentDeviceId);
  const trustedDevices = messagingTrustedDeviceItems();
  const currentDeviceListed = Boolean(
    currentDeviceId &&
      trustedDevices.some(
        (device) => normalizeString(device.deviceId) === currentDeviceId,
      ),
  );
  const trustedDeviceCount = trustedDevices.length;
  const trustedDeviceValue = messaging.devices.loaded
    ? `${formatCount(trustedDeviceCount)} trusted ${trustedDeviceCount === 1 ? "device" : "devices"}`
    : "Check trusted devices";
  const trustedDeviceDetail = messaging.devices.error
    ? messaging.devices.error
    : messaging.devices.loaded
      ? currentDeviceListed
        ? "This browser is listed as a trusted device."
        : "Link this browser from another trusted device."
      : "Open trusted devices to verify this browser.";
  const recoveryValue = recovery.localCode
    ? "Local key saved"
    : messagingRecoveryBackupLabel(recovery);
  const deviceValue = currentDeviceId ? "Browser device ready" : "Device not ready";
  const deviceDetail = currentDeviceId
    ? `Current device ${shortMessagingDeviceId(currentDeviceId)}`
    : "Open trusted devices to register this browser.";
  const conversationLabel = normalizeString(conversation?.title)
    ? ` in ${conversation.title}`
    : "";
  const className = `shared-messaging-secure-handoff${stacked ? " shared-messaging-secure-handoff--stacked" : ""}`;
  return `<section class="${className}" aria-label="Encrypted conversation options">
    <div class="shared-messaging-secure-handoff__icon">${renderIcon("lock")}</div>
    <div class="shared-messaging-secure-handoff__body">
      <div class="shared-messaging-secure-handoff__copy">
        <strong>Trust this browser to reply${escapeHtml(conversationLabel)}</strong>
        <p>Encrypted sending stays locked until this web session has a trusted message key. Restore encrypted history or approve this browser from another trusted device.</p>
      </div>
      <div class="shared-messaging-secure-handoff__status" role="list">
        ${renderMessagingSecureStatusItem({
          icon: "dashboard",
          label: "This browser",
          value: deviceValue,
          detail: deviceDetail,
        })}
        ${renderMessagingSecureStatusItem({
          icon: "shield",
          label: "Trusted devices",
          value: trustedDeviceValue,
          detail: trustedDeviceDetail,
        })}
        ${renderMessagingSecureStatusItem({
          icon: "lock",
          label: "Recovery",
          value: recoveryValue,
          detail: messagingRecoveryBackupDetail(recovery),
        })}
      </div>
      <div class="shared-messaging-secure-handoff__actions">
        <button class="shared-feed-chip shared-feed-chip--primary" type="button" data-action="navigate" data-route="/messages/recovery/restore">Restore key</button>
        <button class="shared-feed-chip" type="button" data-action="navigate" data-route="/messages/devices/link">Link browser</button>
        <button class="shared-feed-chip" type="button" data-action="navigate" data-route="/messages/devices">Trusted devices</button>
      </div>
    </div>
  </section>`;
}

function renderMessagingRoomContextPanel({
  subroute,
  conversation,
  directory,
  roomMembers,
}) {
  if (!subroute?.scopeType || !subroute?.scopeId || !conversation) {
    return "";
  }
  const raw = conversation.raw || {};
  const categoryId = normalizeString(
    raw.categoryId || raw.category?.categoryId || raw.category?.id,
  );
  const category = findMessagingDirectoryCategory(directory, categoryId);
  const categoryLabel =
    normalizeString(category?.name || category?.title || raw.categoryName) ||
    "Uncategorized";
  const members = Array.isArray(roomMembers?.items) ? roomMembers.items : [];
  const memberCount =
    Number(raw.memberCount || conversation.participantCount) || members.length;
  const activityLabel = conversation.updatedAt
    ? messagingConversationTimeLabel(conversation.updatedAt)
    : "No activity yet";
  const unreadLabel = conversation.unreadCount
    ? `${formatCount(conversation.unreadCount)} unread`
    : "All caught up";
  const canManage = conversation.canManage === true || raw.canManage === true;
  const chips = [
    messagingConversationKindLabel(conversation),
    categoryLabel,
    conversation.isEncrypted ? "Encrypted" : "Standard",
    canManage ? "Manager access" : "Member view",
  ].filter(Boolean);
  return `<aside class="shared-messaging-room-context" aria-label="Room details">
    <section class="shared-messaging-room-context__hero">
      ${renderMessagingWorkspaceAvatar({
        label: conversation.title,
        imageUrl: conversation.avatarUrl,
        icon: "messages",
        className: "shared-messaging-avatar--server-card",
      })}
      <div>
        <p>${escapeHtml(messagingRoomSettingValue(subroute.scopeType, "Workspace"))}</p>
        <h3>${escapeHtml(messagingConversationDisplayTitle(conversation, currentMessagingUserId()))}</h3>
        <span>${escapeHtml(messagingConversationDisplaySubtitle(conversation, currentMessagingUserId()))}</span>
      </div>
      <div class="shared-messaging-room-chip-cloud">${chips
        .map((chip) => `<span>${escapeHtml(chip)}</span>`)
        .join("")}</div>
    </section>
    <section class="shared-messaging-room-context__metrics">
      <div><strong>${escapeHtml(formatCount(memberCount))}</strong><span>members</span></div>
      <div><strong>${escapeHtml(unreadLabel)}</strong><span>status</span></div>
      <div><strong>${escapeHtml(activityLabel)}</strong><span>activity</span></div>
    </section>
    <section class="shared-messaging-room-context__actions">
      <button class="shared-feed-chip shared-feed-chip--primary" type="button" data-action="navigate" data-route="${escapeHtml(buildMessagingRoomRoute(subroute.scopeType, subroute.scopeId, subroute.conversationId, "/settings"))}">${renderIcon("settings")}<span>Details</span></button>
      <button class="shared-feed-chip" type="button" data-action="navigate" data-route="${escapeHtml(buildMessagingRoomRoute(subroute.scopeType, subroute.scopeId, subroute.conversationId, "/settings/permissions"))}">${renderIcon("team")}<span>Room access</span></button>
      <button class="shared-feed-chip" type="button" data-action="navigate" data-route="${escapeHtml(buildMessagingServerRoute(subroute.scopeType, subroute.scopeId, "/members"))}">${renderIcon("candidate")}<span>Members</span></button>
      <button class="shared-feed-chip" type="button" data-action="refresh-current-route">Refresh</button>
    </section>
    <section class="shared-messaging-room-context__members">
      <div class="shared-messaging-room-context__section-header">
        <h3>Room access</h3>
        <span>${escapeHtml(roomMembers?.loading && !roomMembers?.loaded ? "Loading" : `${formatCount(members.length)} listed`)}</span>
      </div>
      ${roomMembers?.error ? `<div class="shared-page__error">${escapeHtml(roomMembers.error)}</div>` : ""}
      <div class="shared-messaging-room-context__member-list">${
        members.length
          ? members
              .slice(0, 6)
              .map((member) => {
                const roleSummary =
                  member.roles.map(messagingMemberRoleLabel).filter(Boolean).join(", ") ||
                  member.username ||
                  member.userId ||
                  "Room member";
                return `<div class="shared-messaging-room-context__member">
                  ${renderMessagingWorkspaceAvatar({
                    label: member.effectiveName,
                    imageUrl: member.avatarUrl,
                  })}
                  <span>
                    <strong>${escapeHtml(member.effectiveName)}</strong>
                    <small>${escapeHtml(roleSummary)}</small>
                  </span>
                </div>`;
              })
              .join("")
          : `<div class="shared-messaging-empty">${escapeHtml(roomMembers?.loading ? "Loading room members..." : "No room members returned yet.")}</div>`
      }</div>
    </section>
  </aside>`;
}

function messagingMessageDate(value) {
  if (!value) {
    return null;
  }
  const date = new Date(value);
  return Number.isNaN(date.getTime()) ? null : date;
}

function messagingMessageDateKey(value) {
  const date = messagingMessageDate(value);
  if (!date) {
    return "";
  }
  return [
    date.getFullYear(),
    String(date.getMonth() + 1).padStart(2, "0"),
    String(date.getDate()).padStart(2, "0"),
  ].join("-");
}

function messagingMessageDayLabel(value) {
  const date = messagingMessageDate(value);
  if (!date) {
    return "";
  }
  const startOfDay = (input) =>
    new Date(input.getFullYear(), input.getMonth(), input.getDate()).getTime();
  const today = startOfDay(new Date());
  const target = startOfDay(date);
  if (target === today) {
    return "Today";
  }
  if (target === today - 24 * 60 * 60 * 1000) {
    return "Yesterday";
  }
  const options = {
    month: "short",
    day: "numeric",
    ...(date.getFullYear() !== new Date().getFullYear() ? { year: "numeric" } : {}),
  };
  return date.toLocaleDateString(undefined, options);
}

function renderMessagingDaySeparator(message) {
  const label = messagingMessageDayLabel(message?.createdAt);
  if (!label) {
    return "";
  }
  return `<div class="shared-message-day" role="separator" aria-label="${escapeHtml(label)}"><span>${escapeHtml(label)}</span></div>`;
}

function renderMessagingThreadMessage(
  message,
  { isSelf, compact, conversationId = "" } = {},
) {
  const type = normalizeString(message.type || "text").toLowerCase();
  if (type === "system") {
    const systemText = normalizeString(message.text);
    if (!systemText) {
      return "";
    }
    return `<article class="shared-message-system" data-message-id="${escapeHtml(message.messageId)}"><span>${escapeHtml(systemText)}</span></article>`;
  }
  const label = normalizeString(message.senderDisplayName) || "Polis user";
  const statusLabel = messagingMessageStatusLabel(message, isSelf);
  const timestampLabel = message.createdAt
    ? formatAbsoluteDateTime(message.createdAt)
    : "";
  const statePills = [
    statusLabel,
    !statusLabel && message.isEdited ? "Edited" : "",
    message.isEncrypted ? "Encrypted" : "",
  ]
    .filter(Boolean)
    .map(
      (labelText) =>
        `<span>${labelText === "Encrypted" ? renderIcon("lock") : ""}${escapeHtml(labelText)}</span>`,
    )
    .join("");
  return `<article class="shared-message${isSelf ? " is-self" : ""}${compact ? " is-compact" : ""}${message.isDeleted ? " is-deleted" : ""}" data-message-id="${escapeHtml(message.messageId)}">
    ${
      !isSelf && !compact
        ? renderMessagingWorkspaceAvatar({
            label,
            imageUrl: message.senderAvatarUrl,
            className: "shared-messaging-avatar--message",
          })
        : '<span class="shared-message__avatar-spacer"></span>'
    }
    <div class="shared-message__bubble">
      ${
        compact
          ? ""
          : `<div class="shared-message__meta">
              <span>${escapeHtml(label)}</span>
              ${timestampLabel ? `<time datetime="${escapeHtml(new Date(message.createdAt).toISOString())}">${escapeHtml(timestampLabel)}</time>` : ""}
            </div>`
      }
      ${renderMessagingReplyPreviewBlock(message.replyTo)}
      ${renderMessagingMessageBody(message)}
      ${renderMessagingMessageAttachments(message)}
      ${statePills ? `<div class="shared-message__footer">${statePills}</div>` : ""}
      ${renderMessagingSeenByStatus(message, { isSelf })}
      ${renderMessagingMessageActions(message, { conversationId, isSelf })}
      ${renderMessagingMessageReactions(message, { conversationId })}
    </div>
  </article>`;
}

function messagingConversationIsGroup(conversation = {}) {
  const kind = normalizeString(conversation.kind).toLowerCase();
  const raw = conversation.raw || {};
  return (
    kind === "group" ||
    raw.isGroup === true ||
    raw.group === true ||
    Number(conversation.participantCount) > 2
  );
}

function messagingGroupCanManage(conversation = {}, currentUserId = "") {
  if (!messagingConversationIsGroup(conversation)) {
    return false;
  }
  const raw = conversation.raw || {};
  if (conversation.isReadOnly || raw.isReadOnly === true || raw.readOnly === true) {
    return false;
  }
  if (
    conversation.canManage ||
    conversation.canManageMembers ||
    raw.canManage === true ||
    raw.canManageMembers === true ||
    raw.canManageGroup === true
  ) {
    return true;
  }
  const normalizedCurrentUserId = normalizeString(currentUserId);
  const participant = (conversation.participants || []).find(
    (item) => normalizeString(item.userId) === normalizedCurrentUserId,
  );
  const role = normalizeString(
    participant?.role ||
      participant?.raw?.role ||
      participant?.raw?.memberRole ||
      participant?.raw?.groupRole ||
      participant?.raw?.membershipRole,
  ).toLowerCase();
  return ["owner", "admin", "manager", "moderator"].includes(role);
}

function messagingConversationIsRoom(conversation = {}) {
  const kind = normalizeString(conversation.kind).toLowerCase();
  return kind === "room" || Boolean(conversation.scopeType && conversation.scopeId);
}

function messagingRoomPermissionAllowed(conversation = {}, key = "") {
  const normalizedKey = normalizeString(key);
  if (!normalizedKey) {
    return true;
  }
  const permissions =
    conversation?.roomPermissions &&
    typeof conversation.roomPermissions === "object" &&
    !Array.isArray(conversation.roomPermissions)
      ? conversation.roomPermissions
      : {};
  return permissions[normalizedKey] !== false;
}

function messagingMissionScopeForConversation(conversation = {}) {
  if (!messagingConversationIsRoom(conversation)) {
    return null;
  }
  const scopeType = normalizeString(conversation.scopeType).toLowerCase();
  const scopeId = normalizeString(conversation.scopeId);
  if (!scopeId) {
    return null;
  }
  if (scopeType === "candidate" || scopeType === "campaign") {
    return { scopeType: "candidate", scopeId };
  }
  if (scopeType === "coalition") {
    return { scopeType: "coalition", scopeId };
  }
  return null;
}

function messagingCanUseMissionCommands(conversation = {}) {
  return Boolean(
    messagingMissionScopeForConversation(conversation) &&
      messagingRoomPermissionAllowed(conversation, "useMissionCommands"),
  );
}

function parseMessagingMissionCommand(text) {
  const trimmed = normalizeString(text);
  if (!trimmed.startsWith("/")) {
    return null;
  }
  const [commandPart = ""] = trimmed.split(/\s+/u);
  const command = commandPart.toLowerCase();
  if (!MESSAGING_MISSION_COMMANDS.some((entry) => entry.command === command)) {
    return null;
  }
  const body = trimmed.slice(commandPart.length).trim();
  const priorityMatch = MESSAGING_MISSION_PRIORITY_PATTERN.exec(body);
  const priority = normalizeString(priorityMatch?.[1]).toLowerCase();
  const withoutPriority = body.replace(
    MESSAGING_MISSION_PRIORITY_PATTERN,
    " ",
  );
  MESSAGING_MISSION_PLAIN_MENTION_PATTERN.lastIndex = 0;
  const mentions = [];
  let match = MESSAGING_MISSION_PLAIN_MENTION_PATTERN.exec(withoutPriority);
  while (match) {
    const value = normalizeString(match[2]);
    if (value) {
      const normalized = value.toLowerCase();
      mentions.push(
        normalized === "all" || normalized === "everyone"
          ? { assignee: "all", targetMode: "role_fanout" }
          : { assignee: value, targetMode: "role_claim" },
      );
    }
    match = MESSAGING_MISSION_PLAIN_MENTION_PATTERN.exec(withoutPriority);
  }
  const title = withoutPriority
    .replace(MESSAGING_MISSION_PLAIN_MENTION_PATTERN, " ")
    .replace(/\s+/gu, " ")
    .trim();
  const fallback = mentions[0] || null;
  return {
    command,
    title,
    priority: priority || "",
    fallbackAssignee: fallback?.assignee || "",
    fallbackTargetMode: fallback?.targetMode || "",
  };
}

function messagingMissionTargetFromMentions(mentions = []) {
  for (const mention of normalizeMessagingMentionPayloadsForSend(mentions)) {
    if (mention.type === "user" && mention.userId) {
      return { assignee: mention.userId, targetMode: "user" };
    }
    if (mention.type === "role" && mention.roleId) {
      return { assignee: mention.roleId, targetMode: "role_claim" };
    }
    if (mention.type === "everyone") {
      return { assignee: "all", targetMode: "role_fanout" };
    }
  }
  return null;
}

function messagingMissionTargetFromCommand(command = {}) {
  const assignee = normalizeString(command.fallbackAssignee);
  const targetMode = normalizeString(command.fallbackTargetMode);
  return assignee && targetMode ? { assignee, targetMode } : null;
}

function messagingMissionTargetFromReply(replyTo = null) {
  const senderId = normalizeString(replyTo?.senderId);
  return senderId ? { assignee: senderId, targetMode: "user" } : null;
}

function messagingMissionTitleFromText(value) {
  const normalized = normalizeString(value).replace(/\s+/gu, " ");
  if (!normalized) {
    return "";
  }
  return normalized.length <= 88
    ? normalized
    : `${normalized.slice(0, 87).trimEnd()}...`;
}

function messagingMissionDefaultAssignee() {
  return currentMessagingUserId() || normalizeString(state.auth.user?.username);
}

function openMessagingMissionDraftFromCommand(command, { text = "", mentions = [] } = {}) {
  const conversationState = state.pages.messaging.conversation;
  const conversation = conversationState.item;
  const scope = messagingMissionScopeForConversation(conversation);
  if (!scope) {
    conversationState.error =
      "Missions can be created from campaign or coalition rooms.";
    showToast(conversationState.error);
    scheduleRender();
    return false;
  }
  if (!messagingRoomPermissionAllowed(conversation, "useMissionCommands")) {
    conversationState.error = "Mission commands are disabled in this room.";
    showToast(conversationState.error);
    scheduleRender();
    return false;
  }
  const target =
    messagingMissionTargetFromMentions(mentions) ||
    messagingMissionTargetFromCommand(command) ||
    messagingMissionTargetFromReply(conversationState.pendingReply) ||
    { assignee: messagingMissionDefaultAssignee(), targetMode: "user" };
  const pendingReply = normalizeMessagingReplyPreview(
    conversationState.pendingReply,
  );
  const sourceExcerpt = pendingReply?.isDeleted
    ? ""
    : normalizeString(pendingReply?.text) || normalizeString(text);
  conversationState.missionDraft = createMessagingMissionDraftState({
    open: true,
    command: normalizeString(command.command),
    title:
      normalizeString(command.title) ||
      messagingMissionTitleFromText(sourceExcerpt) ||
      "Follow up",
    description:
      pendingReply && sourceExcerpt
        ? `From chat: ${sourceExcerpt}`
        : "",
    priority: normalizeString(command.priority).toLowerCase() || "normal",
    assignee: normalizeString(target.assignee),
    targetMode: normalizeString(target.targetMode) || "user",
    sourceExcerpt,
  });
  conversationState.draft = "";
  conversationState.mention = createMessagingComposerMentionState();
  conversationState.missionCommand = createMessagingMissionCommandState();
  conversationState.error = "";
  scheduleRender();
  return true;
}

function closeMessagingMissionDraft() {
  const conversationState = state.pages.messaging.conversation;
  conversationState.missionDraft = createMessagingMissionDraftState();
  conversationState.error = "";
  scheduleRender();
  focusMessagingComposerSoon();
}

function isMessagingMentionBodyChar(character) {
  return MESSAGING_MENTION_USERNAME_PATTERN.test(normalizeString(character));
}

function findActiveMessagingMentionQuery(text, cursor) {
  const source = String(text || "");
  const offset = Number(cursor);
  if (!Number.isFinite(offset) || offset < 0 || offset > source.length) {
    return null;
  }
  let atIndex = offset - 1;
  while (atIndex >= 0 && isMessagingMentionBodyChar(source[atIndex])) {
    atIndex -= 1;
  }
  if (atIndex < 0 || source[atIndex] !== "@") {
    return null;
  }
  if (atIndex > 0 && isMessagingMentionBodyChar(source[atIndex - 1])) {
    return null;
  }
  let end = offset;
  while (end < source.length && isMessagingMentionBodyChar(source[end])) {
    end += 1;
  }
  return {
    start: atIndex,
    end,
    query: source.slice(atIndex + 1, offset),
  };
}

function messagingMentionUsernameCandidate(raw = {}) {
  const values = [
    raw.username,
    raw.handle,
    raw.displayName,
    raw.effectiveName,
    raw.name,
    raw.userId,
    raw.id,
  ];
  for (const value of values) {
    const normalized = normalizeString(value).replace(/^@/u, "");
    if (MESSAGING_MENTION_USERNAME_PATTERN.test(normalized)) {
      return normalized;
    }
  }
  return "";
}

function messagingMentionSuggestionKey(suggestion = {}) {
  const type = normalizeString(suggestion.type).toLowerCase();
  if (type === "role") {
    return `role:${normalizeString(suggestion.roleId)}`;
  }
  if (type === "everyone") {
    return "everyone";
  }
  const userId = normalizeString(suggestion.userId);
  if (userId) {
    return `user:${userId}`;
  }
  const username = normalizeString(suggestion.username).toLowerCase();
  return username ? `username:${username}` : "";
}

function messagingMentionCandidatesForConversation(conversation = null) {
  const targetConversation =
    conversation || state.pages.messaging.conversation.item;
  if (!targetConversation) {
    return [];
  }
  const currentUserId = currentMessagingUserId();
  const candidates = [];
  const seen = new Set();
  const addCandidate = (candidate) => {
    const username = normalizeString(candidate.username).replace(/^@/u, "");
    const type = normalizeString(candidate.type || "user").toLowerCase();
    if (!username || !type) {
      return;
    }
    const normalized = {
      ...candidate,
      type,
      username,
      displayName:
        normalizeString(candidate.displayName || candidate.label || candidate.name) ||
        username,
    };
    const key = messagingMentionSuggestionKey(normalized);
    if (!key || seen.has(key)) {
      return;
    }
    seen.add(key);
    candidates.push(normalized);
  };

  if (
    messagingConversationIsGroup(targetConversation) &&
    messagingGroupCanManage(targetConversation, currentUserId)
  ) {
    addCandidate({
      type: "everyone",
      username: "everyone",
      displayName: "Everyone",
      subtitle: "Notify this group",
    });
  }

  if (messagingConversationIsRoom(targetConversation)) {
    const scopeType = normalizeString(targetConversation.scopeType).toLowerCase();
    const scopeId = normalizeString(targetConversation.scopeId);
    (state.pages.messaging.serverRoles.items || []).forEach((role) => {
      if (
        !role?.roleId ||
        !role.mentionable ||
        role.isEveryone ||
        role.raw?.isHidden === true ||
        (scopeType && normalizeString(role.scopeType).toLowerCase() !== scopeType) ||
        (scopeId && normalizeString(role.scopeId) !== scopeId)
      ) {
        return;
      }
      const roleName = normalizeString(role.name);
      if (!roleName) {
        return;
      }
      addCandidate({
        type: "role",
        username: roleName,
        displayName: roleName,
        roleId: role.roleId,
        color: normalizeString(role.color),
        subtitle: "Access group",
      });
    });
  }

  const addUser = (raw) => {
    const person = normalizeMessagingGroupPerson(raw);
    const userId = normalizeString(person.userId);
    if (!userId || userId === currentUserId) {
      return;
    }
    const username = messagingMentionUsernameCandidate(person);
    if (!username) {
      return;
    }
    addCandidate({
      type: "user",
      username,
      userId,
      displayName:
        normalizeString(person.displayName || person.effectiveName) || username,
      avatarUrl: normalizeUrl(person.avatarUrl),
      subtitle: person.isFriend ? "Friend" : "Member",
    });
  };
  (targetConversation.participants || []).forEach(addUser);
  (targetConversation.members || []).forEach(addUser);
  if (messagingConversationIsRoom(targetConversation)) {
    (state.pages.messaging.serverMembers.items || []).forEach(addUser);
  }

  return candidates;
}

function messagingMentionSuggestionsForQuery(conversation, query) {
  const normalizedQuery = normalizeString(query).toLowerCase();
  return messagingMentionCandidatesForConversation(conversation)
    .filter((candidate) => {
      if (!normalizedQuery) {
        return true;
      }
      const haystacks = [
        candidate.username,
        candidate.displayName,
        candidate.subtitle,
      ]
        .map((entry) => normalizeString(entry).toLowerCase())
        .filter(Boolean);
      return haystacks.some((entry) => entry.includes(normalizedQuery));
    })
    .slice(0, 8);
}

function normalizeMessagingMentionPayloadsForSend(mentions = []) {
  if (!Array.isArray(mentions)) {
    return [];
  }
  const seen = new Set();
  return mentions
    .map((mention) => {
      const source =
        mention && typeof mention === "object" && !Array.isArray(mention)
          ? mention
          : {};
      const type = normalizeString(source.type || "user").toLowerCase();
      const username = normalizeString(source.username).replace(/^@/u, "");
      const start = Math.max(0, Number(source.start) || 0);
      const length = Math.max(0, Number(source.length) || 0);
      if (!username || !length || !["user", "role", "everyone"].includes(type)) {
        return null;
      }
      const payload = { type, username, start, length };
      if (type === "user") {
        const userId = normalizeString(source.userId);
        if (!userId) return null;
        payload.userId = userId;
      }
      if (type === "role") {
        const roleId = normalizeString(source.roleId);
        if (!roleId) return null;
        payload.roleId = roleId;
      }
      const key = `${payload.start}:${payload.length}:${messagingMentionSuggestionKey(payload)}`;
      if (seen.has(key)) {
        return null;
      }
      seen.add(key);
      return payload;
    })
    .filter(Boolean);
}

function messagingMentionPayloadFromSuggestion(suggestion, { start, length }) {
  return normalizeMessagingMentionPayloadsForSend([
    {
      type: suggestion.type,
      username: suggestion.username,
      userId: suggestion.userId,
      roleId: suggestion.roleId,
      start,
      length,
    },
  ])[0] || null;
}

function messagingAppliedMentionsFromMessage(message = {}) {
  const text = normalizeString(message.text);
  return normalizeMessagingMentionPayloadsForSend(
    (message.mentions || []).map((mention) => {
      const start = Math.max(0, Number(mention.start) || 0);
      const length =
        Math.max(0, Number(mention.length) || 0) ||
        Math.max(0, Number(mention.end) - start);
      return {
        type: mention.type,
        username: mention.username,
        userId: mention.userId,
        roleId: mention.roleId,
        start,
        length,
      };
    }),
  ).filter((mention) => {
    const mentionText = `@${mention.username}`;
    return text.slice(mention.start, mention.start + mention.length) === mentionText;
  });
}

function reconcileMessagingAppliedMentions(previousText, nextText, mentions = []) {
  const previous = String(previousText || "");
  const next = String(nextText || "");
  if (!Array.isArray(mentions) || !mentions.length) {
    return [];
  }
  let prefixLength = 0;
  while (
    prefixLength < previous.length &&
    prefixLength < next.length &&
    previous[prefixLength] === next[prefixLength]
  ) {
    prefixLength += 1;
  }
  let suffixLength = 0;
  while (
    suffixLength + prefixLength < previous.length &&
    suffixLength + prefixLength < next.length &&
    previous[previous.length - 1 - suffixLength] ===
      next[next.length - 1 - suffixLength]
  ) {
    suffixLength += 1;
  }
  const previousChangeEnd = previous.length - suffixLength;
  const delta = next.length - previous.length;
  return normalizeMessagingMentionPayloadsForSend(
    mentions
      .map((mention) => {
        const start = Math.max(0, Number(mention.start) || 0);
        const length = Math.max(0, Number(mention.length) || 0);
        const end = start + length;
        let nextStart = start;
        if (previousChangeEnd <= start) {
          nextStart = start + delta;
        } else if (prefixLength >= end) {
          nextStart = start;
        } else {
          return null;
        }
        return {
          ...mention,
          start: Math.max(0, nextStart),
          length,
        };
      })
      .filter(Boolean),
  ).filter((mention) => {
    const mentionText = `@${mention.username}`;
    return next.slice(mention.start, mention.start + mention.length) === mentionText;
  });
}

function messagingMentionCandidateByUsername(conversation, username) {
  const normalizedUsername = normalizeString(username).replace(/^@/u, "").toLowerCase();
  if (!normalizedUsername) {
    return null;
  }
  return (
    messagingMentionCandidatesForConversation(conversation).find(
      (candidate) =>
        normalizeString(candidate.username).replace(/^@/u, "").toLowerCase() ===
        normalizedUsername,
    ) || null
  );
}

function buildMessagingMentionsFromText(text, conversation = null) {
  const source = normalizeString(text);
  const conversationState = state.pages.messaging.conversation;
  const mentions = [];
  const addMention = (mention) => {
    const normalized = normalizeMessagingMentionPayloadsForSend([mention])[0];
    if (!normalized) {
      return;
    }
    const mentionText = `@${normalized.username}`;
    if (
      source.slice(normalized.start, normalized.start + normalized.length) !==
      mentionText
    ) {
      return;
    }
    mentions.push(normalized);
  };

  (conversationState.mention?.appliedMentions || []).forEach(addMention);
  MESSAGING_MENTION_SCAN_PATTERN.lastIndex = 0;
  let match = MESSAGING_MENTION_SCAN_PATTERN.exec(source);
  while (match) {
    const prefix = match[1] || "";
    const username = match[2] || "";
    const start = match.index + prefix.length;
    const candidate = messagingMentionCandidateByUsername(conversation, username);
    if (candidate) {
      addMention(
        messagingMentionPayloadFromSuggestion(candidate, {
          start,
          length: username.length + 1,
        }),
      );
    }
    match = MESSAGING_MENTION_SCAN_PATTERN.exec(source);
  }
  return normalizeMessagingMentionPayloadsForSend(mentions);
}

function renderMessagingMentionSuggestionAvatar(suggestion) {
  const type = normalizeString(suggestion.type);
  if (suggestion.avatarUrl) {
    return `<img src="${escapeHtml(suggestion.avatarUrl)}" alt="" loading="lazy" />`;
  }
  if (type === "role") {
    const color = normalizeString(suggestion.color) || "#8f96a3";
    return `<span style="--mention-color:${escapeHtml(color)}">${renderIcon("shield")}</span>`;
  }
  if (type === "everyone") {
    return `<span>${renderIcon("bell")}</span>`;
  }
  return `<span>${renderIcon("profile")}</span>`;
}

function renderMessagingComposerMentionMenu(mentionState = {}) {
  const active = mentionState.active;
  const suggestions = Array.isArray(mentionState.suggestions)
    ? mentionState.suggestions
    : [];
  const selectedIndex = Math.max(0, Number(mentionState.selectedIndex) || 0);
  if (!active) {
    return '<div class="shared-messaging-mention-menu" data-messaging-mention-menu hidden></div>';
  }
  const body = suggestions.length
    ? suggestions
        .map((suggestion, index) => {
          const selected = index === Math.min(selectedIndex, suggestions.length - 1);
          const handle = `@${normalizeString(suggestion.username)}`;
          const subtitle = normalizeString(suggestion.subtitle);
          return `<button class="shared-messaging-mention-option${selected ? " is-selected" : ""}" type="button" role="option" aria-selected="${selected ? "true" : "false"}" data-action="messaging-mention-apply" data-mention-index="${escapeHtml(String(index))}">
            <span class="shared-messaging-mention-option__avatar">${renderMessagingMentionSuggestionAvatar(suggestion)}</span>
            <span class="shared-messaging-mention-option__body">
              <strong>${escapeHtml(suggestion.displayName || handle)}</strong>
              <small>${escapeHtml(subtitle ? `${handle} - ${subtitle}` : handle)}</small>
            </span>
          </button>`;
        })
        .join("")
    : '<div class="shared-messaging-mention-empty">No matching people or roles</div>';
  return `<div class="shared-messaging-mention-menu" data-messaging-mention-menu role="listbox" aria-label="Mention suggestions">${body}</div>`;
}

function syncMessagingMentionMenuDom() {
  const menu = root?.querySelector("[data-messaging-mention-menu]");
  if (!menu) {
    return;
  }
  menu.outerHTML = renderMessagingComposerMentionMenu(
    state.pages.messaging.conversation.mention,
  );
}

function updateMessagingComposerMentionState(input) {
  const conversationState = state.pages.messaging.conversation;
  const mentionState =
    conversationState.mention || createMessagingComposerMentionState();
  conversationState.mention = mentionState;
  const active = findActiveMessagingMentionQuery(
    input?.value || "",
    input?.selectionStart ?? input?.value?.length ?? 0,
  );
  if (!active) {
    mentionState.active = null;
    mentionState.suggestions = [];
    mentionState.selectedIndex = 0;
    syncMessagingMentionMenuDom();
    return;
  }
  mentionState.active = active;
  mentionState.suggestions = messagingMentionSuggestionsForQuery(
    conversationState.item,
    active.query,
  );
  mentionState.selectedIndex = Math.min(
    Math.max(0, Number(mentionState.selectedIndex) || 0),
    Math.max(0, mentionState.suggestions.length - 1),
  );
  syncMessagingMentionMenuDom();
}

function findActiveMessagingMissionCommand(text, cursor, conversation = null) {
  if (!messagingCanUseMissionCommands(conversation)) {
    return null;
  }
  const source = String(text || "");
  const offset = Number(cursor);
  if (!Number.isFinite(offset) || offset < 0 || offset > source.length) {
    return null;
  }
  const typed = source.slice(0, offset);
  if (!typed.startsWith("/") || /\s/u.test(typed)) {
    return null;
  }
  let end = offset;
  while (end < source.length && !/\s/u.test(source[end])) {
    end += 1;
  }
  return { start: 0, end, query: typed.toLowerCase() };
}

function messagingMissionCommandSuggestions(query) {
  const normalized = normalizeString(query).toLowerCase();
  return MESSAGING_MISSION_COMMANDS.filter((entry) =>
    entry.command.startsWith(normalized || "/"),
  );
}

function renderMessagingMissionCommandMenu(commandState = {}) {
  const active = commandState.active;
  const suggestions = Array.isArray(commandState.suggestions)
    ? commandState.suggestions
    : [];
  const selectedIndex = Math.max(0, Number(commandState.selectedIndex) || 0);
  if (!active || !suggestions.length) {
    return '<div class="shared-messaging-command-menu" data-messaging-command-menu hidden></div>';
  }
  const body = suggestions
    .map((suggestion, index) => {
      const selected = index === Math.min(selectedIndex, suggestions.length - 1);
      return `<button class="shared-messaging-command-option${selected ? " is-selected" : ""}" type="button" role="option" aria-selected="${selected ? "true" : "false"}" data-action="messaging-command-apply" data-command-index="${escapeHtml(String(index))}">
        <span class="shared-messaging-command-option__icon">${renderIcon("mission")}</span>
        <span class="shared-messaging-command-option__body">
          <strong>${escapeHtml(suggestion.title)}</strong>
          <small>${escapeHtml(suggestion.subtitle)}</small>
        </span>
      </button>`;
    })
    .join("");
  return `<div class="shared-messaging-command-menu" data-messaging-command-menu role="listbox" aria-label="Mission command suggestions">${body}</div>`;
}

function syncMessagingMissionCommandMenuDom() {
  const menu = root?.querySelector("[data-messaging-command-menu]");
  if (!menu) {
    return;
  }
  menu.outerHTML = renderMessagingMissionCommandMenu(
    state.pages.messaging.conversation.missionCommand,
  );
}

function updateMessagingMissionCommandState(input) {
  const conversationState = state.pages.messaging.conversation;
  const commandState =
    conversationState.missionCommand || createMessagingMissionCommandState();
  conversationState.missionCommand = commandState;
  if (conversationState.missionDraft?.open) {
    commandState.active = null;
    commandState.suggestions = [];
    commandState.selectedIndex = 0;
    syncMessagingMissionCommandMenuDom();
    return;
  }
  const active = findActiveMessagingMissionCommand(
    input?.value || "",
    input?.selectionStart ?? input?.value?.length ?? 0,
    conversationState.item,
  );
  if (!active) {
    commandState.active = null;
    commandState.suggestions = [];
    commandState.selectedIndex = 0;
    syncMessagingMissionCommandMenuDom();
    return;
  }
  commandState.active = active;
  commandState.suggestions = messagingMissionCommandSuggestions(active.query);
  commandState.selectedIndex = Math.min(
    Math.max(0, Number(commandState.selectedIndex) || 0),
    Math.max(0, commandState.suggestions.length - 1),
  );
  syncMessagingMissionCommandMenuDom();
}

function closeMessagingMissionCommandMenu() {
  const conversationState = state.pages.messaging.conversation;
  conversationState.missionCommand = createMessagingMissionCommandState();
  syncMessagingMissionCommandMenuDom();
}

function applyMessagingMissionCommandSuggestion(index = 0) {
  const conversationState = state.pages.messaging.conversation;
  const commandState =
    conversationState.missionCommand || createMessagingMissionCommandState();
  const active = commandState.active;
  const suggestions = commandState.suggestions || [];
  const suggestion = suggestions[Math.max(0, Number(index) || 0)];
  const input = root?.querySelector(
    '[data-route-form="messaging-send"] textarea[name="text"]',
  );
  if (!active || !suggestion || !input) {
    closeMessagingMissionCommandMenu();
    return;
  }
  const previousText = input.value || "";
  const replacement = `${suggestion.command} `;
  const nextText = `${replacement}${previousText.slice(active.end)}`;
  input.value = nextText;
  conversationState.draft = nextText;
  conversationState.mention = createMessagingComposerMentionState();
  conversationState.missionCommand = createMessagingMissionCommandState();
  syncMessagingMentionMenuDom();
  syncMessagingMissionCommandMenuDom();
  try {
    input.focus();
    input.setSelectionRange(replacement.length, replacement.length);
  } catch {
    // Best effort after DOM insertion.
  }
}

function closeMessagingComposerMentionMenu() {
  const conversationState = state.pages.messaging.conversation;
  conversationState.mention = {
    ...(conversationState.mention || createMessagingComposerMentionState()),
    active: null,
    suggestions: [],
    selectedIndex: 0,
  };
  syncMessagingMentionMenuDom();
}

function applyMessagingMentionSuggestion(index = 0) {
  const conversationState = state.pages.messaging.conversation;
  const mentionState =
    conversationState.mention || createMessagingComposerMentionState();
  const active = mentionState.active;
  const suggestions = mentionState.suggestions || [];
  const suggestion = suggestions[Math.max(0, Number(index) || 0)];
  const input = root?.querySelector(
    '[data-route-form="messaging-send"] textarea[name="text"]',
  );
  if (!active || !suggestion || !input) {
    closeMessagingComposerMentionMenu();
    return;
  }
  const previousText = input.value || "";
  const mentionText = `@${suggestion.username}`;
  const replacement = `${mentionText} `;
  const nextText = `${previousText.slice(0, active.start)}${replacement}${previousText.slice(active.end)}`;
  const nextCursor = active.start + replacement.length;
  input.value = nextText;
  conversationState.mention.appliedMentions = reconcileMessagingAppliedMentions(
    conversationState.draft,
    nextText,
    conversationState.mention.appliedMentions,
  ).filter((mention) => {
    const start = Number(mention.start) || 0;
    const end = start + (Number(mention.length) || 0);
    return end <= active.start || start >= active.start + replacement.length;
  });
  const payload = messagingMentionPayloadFromSuggestion(suggestion, {
    start: active.start,
    length: mentionText.length,
  });
  if (payload) {
    conversationState.mention.appliedMentions = [
      ...conversationState.mention.appliedMentions,
      payload,
    ];
  }
  conversationState.draft = nextText;
  conversationState.mention.active = null;
  conversationState.mention.suggestions = [];
  conversationState.mention.selectedIndex = 0;
  syncMessagingMentionMenuDom();
  try {
    input.focus();
    input.setSelectionRange(nextCursor, nextCursor);
  } catch {
    // Best effort after DOM insertion.
  }
}

function normalizeMessagingGroupPerson(raw = {}) {
  const source = raw && typeof raw === "object" ? raw : {};
  const nestedRaw =
    source.raw && typeof source.raw === "object" && !Array.isArray(source.raw)
      ? source.raw
      : {};
  const userId = normalizeString(
    source.userId || nestedRaw.userId || nestedRaw.id || source.id,
  );
  const username = normalizeString(
    source.username || source.handle || nestedRaw.username || nestedRaw.handle,
  ).replace(/^@/u, "");
  const displayName = normalizeString(
    source.displayName ||
      source.effectiveName ||
      source.name ||
      nestedRaw.displayName ||
      nestedRaw.effectiveName ||
      nestedRaw.name ||
      username ||
      userId,
  );
  const avatarUrl = normalizeUrl(
    source.avatarUrl ||
      source.imageUrl ||
      nestedRaw.avatarUrl ||
      nestedRaw.imageUrl,
  );
  const roles = (
    Array.isArray(source.roles)
      ? source.roles
      : Array.isArray(nestedRaw.roles)
        ? nestedRaw.roles
        : [
            source.role ||
              source.memberRole ||
              source.groupRole ||
              nestedRaw.role ||
              nestedRaw.memberRole ||
              nestedRaw.groupRole,
          ]
  ).filter(Boolean);
  const sourceTags = Array.isArray(source.sourceTags)
    ? source.sourceTags
    : Array.isArray(nestedRaw.sourceTags)
      ? nestedRaw.sourceTags
      : [];
  const isFriend =
    source.isFriend === true ||
    source.friend === true ||
    nestedRaw.isFriend === true ||
    nestedRaw.friend === true ||
    sourceTags.some((tag) => normalizeString(tag).toLowerCase() === "friend");
  const normalizedTags = [
    ...sourceTags.map((tag) => normalizeString(tag)).filter(Boolean),
    ...(isFriend ? ["friend"] : []),
  ];
  return {
    userId,
    username,
    displayName,
    effectiveName: displayName || username || userId || "Polis user",
    avatarUrl,
    roles,
    sourceTags: [...new Set(normalizedTags)],
    isFriend,
    raw: source,
  };
}

function messagingGroupPersonKey(person = {}) {
  const userId = normalizeString(person.userId);
  if (userId) return `user:${userId}`;
  const username = normalizeString(person.username).replace(/^@/u, "");
  return username ? `username:${username.toLowerCase()}` : "";
}

function messagingGroupPeople(conversation, membersState) {
  const peopleByKey = new Map();
  const addPerson = (raw) => {
    const person = normalizeMessagingGroupPerson(raw);
    const key = messagingGroupPersonKey(person);
    if (!key) return;
    const existing = peopleByKey.get(key);
    if (existing) {
      peopleByKey.set(key, {
        ...existing,
        ...person,
        roles: person.roles.length ? person.roles : existing.roles,
        sourceTags: [...new Set([...existing.sourceTags, ...person.sourceTags])],
      });
      return;
    }
    peopleByKey.set(key, person);
  };
  (conversation?.participants || []).forEach(addPerson);
  (membersState?.items || []).forEach(addPerson);
  return [...peopleByKey.values()];
}

function messagingGroupExistingPeopleKeys(conversation, membersState) {
  return new Set(
    messagingGroupPeople(conversation, membersState)
      .map(messagingGroupPersonKey)
      .filter(Boolean),
  );
}

function messagingGroupPeopleCandidates(conversation, membersState, peopleState) {
  const existingKeys = messagingGroupExistingPeopleKeys(conversation, membersState);
  const friendItems = (peopleState.friends.items || []).filter(
    (candidate) => !existingKeys.has(messagingComposeCandidateKey(candidate)),
  );
  const friendKeys = new Set(
    friendItems.map(messagingComposeCandidateKey).filter(Boolean),
  );
  const searchItems = (peopleState.search.items || []).filter((candidate) => {
    const key = messagingComposeCandidateKey(candidate);
    return key && !existingKeys.has(key) && !friendKeys.has(key);
  });
  const query = normalizeString(peopleState.query).toLowerCase();
  if (query.length >= 3) {
    return [
      ...friendItems.filter(
        (candidate) =>
          normalizeString(candidate.displayName).toLowerCase().includes(query) ||
          normalizeString(candidate.username).toLowerCase().includes(query),
      ),
      ...searchItems,
    ];
  }
  return friendItems;
}

function renderMessagingGroupPersonRow(
  person,
  {
    currentUserId = "",
    canManage = false,
    pendingKey = "",
    conversationId = "",
  } = {},
) {
  const userId = normalizeString(person.userId);
  const username = normalizeString(person.username).replace(/^@/u, "");
  const isCurrentUser = userId && userId === normalizeString(currentUserId);
  const personKey = messagingGroupPersonKey(person);
  const removePending = pendingKey === `remove:${userId}`;
  const roleLabels = (person.roles || []).map(messagingMemberRoleLabel).filter(Boolean);
  const handle = username ? `@${username}` : userId;
  const meta = [
    isCurrentUser ? "You" : "",
    roleLabels.join(", "),
    handle,
  ].filter(Boolean).join(" - ") || "Group member";
  const tags = [
    ...(person.sourceTags || []).map((tag) => humanizeLabel(tag) || tag),
    ...(removePending ? ["Removing"] : []),
  ]
    .map((tag) => normalizeString(tag))
    .filter(Boolean)
    .slice(0, 3);
  const profileRoute = userId ? `/profile/${encodeURIComponent(userId)}` : "";
  return `<article class="shared-messaging-person-row${removePending ? " is-pending" : ""}">
    ${renderMessagingWorkspaceAvatar({
      label: person.effectiveName,
      imageUrl: person.avatarUrl,
      icon: "profile",
    })}
    <div class="shared-messaging-person-row__main">
      <strong>${escapeHtml(person.effectiveName)}</strong>
      <span>${escapeHtml(meta)}</span>
      ${
        tags.length
          ? `<div class="shared-messaging-people-tags">${tags
              .map((tag) => `<span>${escapeHtml(tag)}</span>`)
              .join("")}</div>`
          : ""
      }
    </div>
    <div class="shared-messaging-person-row__actions">
      ${
        !isCurrentUser && (userId || username)
          ? `<button class="shared-feed-chip" type="button" data-action="messaging-group-person-message" data-user-id="${escapeHtml(userId)}" data-username="${escapeHtml(username)}">Message</button>`
          : ""
      }
      ${
        profileRoute
          ? `<button class="shared-feed-chip" type="button" data-action="navigate" data-route="${escapeHtml(profileRoute)}">Profile</button>`
          : ""
      }
      ${
        canManage && !isCurrentUser && userId
          ? `<button class="shared-feed-chip" type="button" data-action="messaging-group-person-remove" data-conversation-id="${escapeHtml(conversationId)}" data-user-id="${escapeHtml(userId)}" data-person-key="${escapeHtml(personKey)}"${disabledAttr(Boolean(pendingKey))}>${removePending ? "Removing..." : "Remove"}</button>`
          : ""
      }
    </div>
  </article>`;
}

function renderMessagingGroupPeopleBucket(
  title,
  people,
  renderOptions,
  emptyLabel = "",
) {
  return `<section class="shared-messaging-people-section">
    <div class="shared-messaging-people-section__header">
      <h3>${escapeHtml(title)}</h3>
      <span>${escapeHtml(formatCount(people.length))}</span>
    </div>
    <div class="shared-messaging-people-list">${
      people.length
        ? people.map((person) => renderMessagingGroupPersonRow(person, renderOptions)).join("")
        : `<div class="shared-messaging-empty">${escapeHtml(emptyLabel || `No ${title.toLowerCase()} listed.`)}</div>`
    }</div>
  </section>`;
}

function renderMessagingGroupPeopleCandidates(
  conversation,
  membersState,
  peopleState,
  canManage,
) {
  if (!canManage) {
    return '<div class="shared-messaging-people-note">Only group managers can add or remove people.</div>';
  }
  const pendingKey = normalizeString(peopleState.actionPendingKey);
  const candidates = messagingGroupPeopleCandidates(
    conversation,
    membersState,
    peopleState,
  );
  const loading = peopleState.friends.loading || peopleState.search.loading;
  const error =
    normalizeString(peopleState.error) ||
    normalizeString(peopleState.friends.error) ||
    normalizeString(peopleState.search.error);
  const candidateMarkup = candidates.length
    ? candidates
        .map((candidate) => {
          const key = messagingComposeCandidateKey(candidate);
          const pending = pendingKey === `add:${key}`;
          const blocked = candidate.blockedByPrivacy === true;
          const title =
            normalizeString(candidate.displayName) ||
            normalizeString(candidate.username) ||
            normalizeString(candidate.userId) ||
            "Polis user";
          return `<article class="shared-messaging-people-candidate${blocked ? " is-blocked" : ""}${pending ? " is-pending" : ""}">
            ${renderMessagingWorkspaceAvatar({
              label: title,
              imageUrl: candidate.avatarUrl,
              icon: "profile",
            })}
            <div>
              <strong>${escapeHtml(title)}</strong>
              <span>${escapeHtml(messagingComposeCandidateSubtitle(candidate))}</span>
            </div>
            <button class="shared-feed-chip shared-feed-chip--primary" type="button" data-action="messaging-group-person-add" data-conversation-id="${escapeHtml(conversation.conversationId)}" data-candidate-key="${escapeHtml(key)}"${disabledAttr(Boolean(pendingKey) || blocked || !key)}>${pending ? "Adding..." : "Add"}</button>
          </article>`;
        })
        .join("")
    : `<div class="shared-messaging-empty">${escapeHtml(
        normalizeString(peopleState.query).length >= 3
          ? "No matching people found."
          : "Friend suggestions will appear here.",
      )}</div>`;
  return `<div class="shared-messaging-people-add">
    <label class="shared-messaging-people-search">
      <span>Find people</span>
      <div>
        ${renderIcon("search")}
        <input name="query" data-messaging-group-people-field="query" value="${escapeHtml(peopleState.query || "")}" placeholder="Name or username" autocomplete="off"${disabledAttr(Boolean(pendingKey))} />
        ${
          peopleState.query
            ? `<button type="button" data-action="messaging-group-people-clear-search" aria-label="Clear search"${disabledAttr(Boolean(pendingKey))}>${renderIcon("close")}</button>`
            : ""
        }
      </div>
    </label>
    <div class="shared-messaging-people-candidates">
      ${candidateMarkup}
      ${loading ? '<div class="shared-messaging-compose-status">Searching...</div>' : ""}
      ${error ? `<div class="shared-page__error">${escapeHtml(error)}</div>` : ""}
    </div>
    <details class="shared-messaging-people-exact">
      <summary>Add exact username or user ID</summary>
      <form class="shared-messaging-people-exact-form" data-route-form="messaging-group-member-add">
        <input type="hidden" name="conversationId" value="${escapeHtml(conversation.conversationId)}" />
        <label><span>Username</span><input name="username" placeholder="@username"${disabledAttr(Boolean(pendingKey))} autocomplete="off" /></label>
        <label><span>User ID</span><input name="userId" placeholder="user_..."${disabledAttr(Boolean(pendingKey))} autocomplete="off" /></label>
        <button class="shared-feed-chip shared-feed-chip--primary" type="submit"${disabledAttr(Boolean(pendingKey))}>Add person</button>
      </form>
    </details>
  </div>`;
}

function renderMessagingGroupPeoplePanel({
  conversation,
  membersState,
  peopleState,
  subroute,
}) {
  const conversationId = normalizeString(subroute?.conversationId);
  if (!conversation) {
    return renderMessagingWorkspacePanel({
      title: "People",
      subtitle: "Group conversation members",
      body: '<div class="shared-page__loading">Loading group people...</div>',
    });
  }
  const currentUserId = currentMessagingUserId();
  const displayTitle = messagingConversationDisplayTitle(
    conversation,
    currentUserId,
  );
  const chatRoute = `/messages/conversations/${encodeURIComponent(conversationId)}`;
  if (!messagingConversationIsGroup(conversation)) {
    return renderMessagingWorkspacePanel({
      title: "People",
      subtitle: displayTitle,
      actions: `<button class="shared-feed-chip" type="button" data-action="navigate" data-route="${escapeHtml(chatRoute)}">Back to chat</button>`,
      body: '<div class="shared-messaging-empty">People management is available for group conversations.</div>',
    });
  }
  const canManage = messagingGroupCanManage(conversation, currentUserId);
  const people = messagingGroupPeople(conversation, membersState);
  const you = people.filter(
    (person) => normalizeString(person.userId) === currentUserId,
  );
  const friends = people.filter(
    (person) =>
      normalizeString(person.userId) !== currentUserId && person.isFriend,
  );
  const others = people.filter(
    (person) =>
      normalizeString(person.userId) !== currentUserId && !person.isFriend,
  );
  const memberCount = Math.max(
    Number(conversation.participantCount) || 0,
    people.length,
  );
  const pendingKey = normalizeString(membersState.actionPendingKey);
  const renderOptions = {
    currentUserId,
    canManage,
    pendingKey,
    conversationId,
  };
  return renderMessagingWorkspacePanel({
    title: "People",
    subtitle: displayTitle,
    actions: `<button class="shared-feed-chip" type="button" data-action="navigate" data-route="${escapeHtml(chatRoute)}">Back to chat</button>`,
    className: "shared-messaging-panel--people",
    body: `<div class="shared-messaging-people-panel">
      <section class="shared-messaging-people-hero">
        ${renderMessagingWorkspaceAvatar({
          label: displayTitle,
          imageUrl: conversation.avatarUrl,
          icon: "team",
        })}
        <div class="shared-messaging-people-hero__main">
          <p>${escapeHtml(canManage ? "Manager access" : "Member view")}</p>
          <h3>${escapeHtml(displayTitle)}</h3>
          <span>${escapeHtml(`${formatCount(memberCount)} people in this group`)}</span>
        </div>
        <div class="shared-messaging-people-metrics">
          <div><strong>${escapeHtml(formatCount(you.length + friends.length + others.length))}</strong><span>Loaded</span></div>
          <div><strong>${escapeHtml(formatCount(friends.length))}</strong><span>Friends</span></div>
          <div><strong>${escapeHtml(canManage ? "Manage" : "View")}</strong><span>Access</span></div>
        </div>
      </section>
      ${membersState.error ? `<div class="shared-page__error">${escapeHtml(membersState.error)}</div>` : ""}
      ${membersState.loading && !membersState.loaded ? '<div class="shared-page__loading">Loading members...</div>' : ""}
      <div class="shared-messaging-people-layout">
        <div class="shared-messaging-people-roster">
          ${renderMessagingGroupPeopleBucket("You", you, renderOptions, "Your account was not included in the loaded member list.")}
          ${renderMessagingGroupPeopleBucket("Friends", friends, renderOptions, "No friends are listed in this group yet.")}
          ${renderMessagingGroupPeopleBucket("Others", others, renderOptions, "No other people are listed.")}
        </div>
        ${renderMessagingGroupPeopleCandidates(
          conversation,
          membersState,
          peopleState,
          canManage,
        )}
      </div>
    </div>`,
  });
}

function renderMessagingWorkspaceThread({
  conversation,
  messages = [],
  subroute,
  roomActions = false,
  directory = null,
  roomMembers = null,
}) {
  if (!conversation) {
    return renderMessagingWorkspacePanel({
      title: "Select a conversation",
      subtitle: "Open a direct message, group, or campaign room from the list.",
      body: '<div class="shared-messaging-empty">Your active thread will appear here.</div>',
      className: "shared-messaging-panel--thread",
    });
  }
  const currentUserId = normalizeString(state.auth.user?.userId);
  const displayTitle = messagingConversationDisplayTitle(
    conversation,
    currentUserId,
  );
  const displaySubtitle = messagingConversationDisplaySubtitle(
    conversation,
    currentUserId,
  );
  const displayAvatar = messagingConversationDisplayAvatar(
    conversation,
    currentUserId,
  );
  const kindLabel = messagingConversationKindLabel(conversation);
  const participantCount = Number(conversation.participantCount) || 0;
  const conversationState = state.pages.messaging.conversation;
  const messageMarkup = messages.length
    ? messages
        .map((message, index) => {
          const previous = messages[index - 1];
          const self = normalizeString(message.senderUserId) === currentUserId;
          const dateChanged =
            messagingMessageDateKey(message.createdAt) &&
            messagingMessageDateKey(message.createdAt) !==
              messagingMessageDateKey(previous?.createdAt);
          const compact =
            previous &&
            !dateChanged &&
            normalizeString(previous.senderUserId) ===
              normalizeString(message.senderUserId) &&
            Number(message.createdAt || 0) - Number(previous.createdAt || 0) <
              5 * 60 * 1000;
          return `${dateChanged ? renderMessagingDaySeparator(message) : ""}${renderMessagingThreadMessage(message, {
            isSelf: self,
            compact,
            conversationId: conversation.conversationId,
          })}`;
        })
        .join("")
    : '<div class="shared-messaging-empty shared-messaging-empty--thread">No messages in this thread yet.</div>';
  const typingLabel = conversationState.typingParticipants.length
    ? normalizeString(conversationState.typingParticipants[0].label)
    : "";
  const roomActionMarkup =
    roomActions && subroute?.scopeType && subroute?.scopeId && subroute?.conversationId
      ? `<button class="shared-feed-chip" data-action="navigate" data-route="${escapeHtml(buildMessagingRoomRoute(subroute.scopeType, subroute.scopeId, subroute.conversationId, "/settings"))}">${renderIcon("settings")}<span>Details</span></button>
         <button class="shared-feed-chip" data-action="navigate" data-route="${escapeHtml(buildMessagingRoomRoute(subroute.scopeType, subroute.scopeId, subroute.conversationId, "/settings/permissions"))}">${renderIcon("team")}<span>Room access</span></button>`
      : "";
  const groupActionMarkup =
    !roomActions &&
    messagingConversationIsGroup(conversation) &&
    conversation.conversationId
      ? `<button class="shared-feed-chip" data-action="navigate" data-route="/messages/conversations/${escapeHtml(encodeURIComponent(conversation.conversationId))}/people">${renderIcon("team")}<span>People</span></button>`
      : "";
  const headerActionMarkup = [roomActionMarkup, groupActionMarkup]
    .filter(Boolean)
    .join("");
  const threadReturnRoute =
    roomActions && subroute?.scopeType && subroute?.scopeId
      ? buildMessagingServerRoute(subroute.scopeType, subroute.scopeId)
      : "/messages";
  const threadReturnLabel = roomActions ? "Rooms" : "Inbox";
  const composerDisabled =
    conversationState.sending || conversationState.uploadingAttachment;
  const draftValue = normalizeString(conversationState.draft);
  const editingMessageId = normalizeString(conversationState.editingMessageId);
  const editingMessage = editingMessageId
    ? conversationState.messages.find(
        (message) => message.messageId === editingMessageId,
      )
    : null;
  const pendingReply = normalizeMessagingReplyPreview(
    conversationState.pendingReply,
  );
  const attachmentDraft =
    conversationState.attachmentDraft || createMessagingAttachmentDraft();
  const hasAttachmentDraft = Boolean(
    isMessagingAttachmentFile(attachmentDraft.file) ||
    normalizeString(attachmentDraft.url) ||
      normalizeString(attachmentDraft.fileName) ||
      normalizeString(attachmentDraft.mimeType),
  );
  const showAttachmentEditor =
    !editingMessageId &&
    (conversationState.attachmentEditorOpen || hasAttachmentDraft);
  const composerModeLabel = editingMessageId
    ? "Editing message"
    : pendingReply
      ? "Replying to message"
      : "Ready to send";
  const composerModeIcon = editingMessageId
    ? "edit"
    : pendingReply
      ? "reply"
      : "check";
  const composerTools = `<button type="button" class="shared-messaging-composer__tool${showAttachmentEditor ? " is-active" : ""}" data-action="messaging-attachment-toggle" aria-label="Attach media" aria-pressed="${showAttachmentEditor ? "true" : "false"}" title="Attach media"${disabledAttr(composerDisabled || Boolean(editingMessageId))}>${renderIcon("file")}</button>
       <span class="shared-messaging-composer__tool is-status" role="img" aria-label="${escapeHtml(composerModeLabel)}" title="${escapeHtml(composerModeLabel)}">${renderIcon(composerModeIcon)}</span>`;
  const attachmentEditorMarkup = showAttachmentEditor
    ? renderMessagingComposerAttachmentEditor(
        conversationState,
        composerDisabled,
      )
    : "";
  const mentionMenuMarkup = renderMessagingComposerMentionMenu(
    conversationState.mention,
  );
  const missionDraftOpen =
    !editingMessageId && conversationState.missionDraft?.open === true;
  const missionCommandMenuMarkup = renderMessagingMissionCommandMenu(
    conversationState.missionCommand,
  );
  const missionDraftMarkup = missionDraftOpen
    ? renderMessagingComposerMissionDraft(conversationState, conversation)
    : "";
  const editBannerMarkup = editingMessageId
    ? `<div class="shared-messaging-edit-banner">
        <span>${renderIcon("edit")}</span>
        <div>
          <strong>Editing message</strong>
          <small>${escapeHtml(editingMessage?.createdAt ? formatAbsoluteDateTime(editingMessage.createdAt) : "Unsaved changes stay in this composer.")}</small>
        </div>
        <button class="shared-feed-chip" type="button" data-action="messaging-message-edit-cancel"${disabledAttr(composerDisabled)}>Cancel</button>
      </div>`
    : "";
  const replyBannerMarkup =
    !editingMessageId && pendingReply
      ? `<div class="shared-messaging-reply-banner">
        <span>${renderIcon("reply")}</span>
        <div>
          <strong>Replying to ${escapeHtml(messagingReplySenderLabel(pendingReply))}</strong>
          <small>${escapeHtml(messagingReplyTextLabel(pendingReply))}</small>
        </div>
        <button class="shared-feed-chip" type="button" data-action="messaging-message-reply-cancel"${disabledAttr(composerDisabled)}>Cancel</button>
      </div>`
      : "";
  const composerPlaceholder = editingMessageId
    ? "Edit message"
    : pendingReply
      ? "Reply in thread"
      : `Message ${displayTitle}`;
  const sendButtonLabel = conversationState.uploadingAttachment
    ? "Uploading"
    : conversationState.sending
      ? editingMessageId
        ? "Saving"
        : "Sending"
      : editingMessageId
        ? "Save"
        : pendingReply
          ? "Reply"
          : "Send";
  const composerMarkup = conversation.isEncrypted
    ? renderMessagingSecureHandoff({ conversation })
    : `<form class="shared-messaging-composer" data-route-form="messaging-send">
      <input type="hidden" name="conversationId" value="${escapeHtml(conversation.conversationId)}" />
      ${replyBannerMarkup}
      ${
        missionDraftOpen
          ? missionDraftMarkup
          : `${editBannerMarkup}
      ${attachmentEditorMarkup}
      ${missionCommandMenuMarkup}
      ${mentionMenuMarkup}
      <div class="shared-messaging-composer__tools">
        ${composerTools}
      </div>
      <label class="shared-messaging-composer__input">
        <span class="shared-sr-only">Message</span>
        <textarea name="text" rows="1" placeholder="${escapeHtml(composerPlaceholder)}">${escapeHtml(draftValue)}</textarea>
      </label>
      <button class="shared-feed-chip shared-feed-chip--primary shared-messaging-composer__send" type="submit"${disabledAttr(composerDisabled)} aria-label="${escapeHtml(editingMessageId ? "Save edited message" : pendingReply ? "Send reply" : "Send message")}">${renderIcon(editingMessageId ? "check" : pendingReply ? "reply" : "send")}<span>${escapeHtml(sendButtonLabel)}</span></button>`
      }
    </form>`;
  const threadMarkup = `<article class="shared-messaging-panel shared-messaging-panel--thread">
    <div class="shared-messaging-thread-header">
      <button class="shared-messaging-thread-header__mobile-back" data-action="navigate" data-route="${escapeHtml(threadReturnRoute)}">${renderIcon("messages")}<span>${escapeHtml(threadReturnLabel)}</span></button>
      <div class="shared-messaging-thread-header__identity">
        ${renderMessagingWorkspaceAvatar({
          label: displayTitle,
          imageUrl: displayAvatar,
        })}
        <div>
          <p>${escapeHtml(kindLabel)}</p>
          <h2>${escapeHtml(displayTitle)}</h2>
          <span>${escapeHtml(displaySubtitle || "No recent messages.")}</span>
        </div>
      </div>
      <div class="shared-messaging-thread-header__meta">
        ${participantCount > 1 ? `<span>${escapeHtml(`${formatCount(participantCount)} people`)}</span>` : ""}
        ${conversation.unreadCount ? `<span>${escapeHtml(`${formatCount(conversation.unreadCount)} unread`)}</span>` : ""}
        ${conversation.isEncrypted ? `<span>${renderIcon("lock")}${escapeHtml("Encrypted")}</span>` : ""}
      </div>
      ${headerActionMarkup ? `<div class="shared-messaging-thread-header__actions">${headerActionMarkup}</div>` : ""}
    </div>
    ${conversationState.error ? `<div class="shared-page__error shared-messaging-thread-error">${escapeHtml(conversationState.error)}</div>` : ""}
    <div class="shared-message-list">${conversationState.loading && !conversationState.loaded ? '<div class="shared-page__loading">Loading messages...</div>' : messageMarkup}</div>
    ${typingLabel ? `<div class="shared-messaging-typing">${escapeHtml(`${typingLabel} is typing...`)}</div>` : ""}
    ${composerMarkup}
    ${renderMessagingMessageReportModal(conversationState)}
  </article>`;
  if (!roomActions) {
    return threadMarkup;
  }
  return `<div class="shared-messaging-thread-layout">
    ${threadMarkup}
    ${renderMessagingRoomContextPanel({
      subroute,
      conversation,
      directory,
      roomMembers,
    })}
  </div>`;
}

function renderMessagingWorkspaceShell({
  subroute,
  sidebarTitle,
  sidebarSubtitle = "",
  sidebarActions = "",
  sidebarBody = "",
  mainBody = "",
}) {
  const normalizedMainBody = normalizeString(mainBody);
  const workspaceClassName = `${normalizedMainBody.includes(
    "shared-messaging-panel--thread",
  )
    ? " shared-messaging-workspace--thread-active"
    : ""}${normalizedMainBody.includes("shared-messaging-server-settings-stack") ? " shared-messaging-workspace--settings-focus" : ""}${
    normalizedMainBody.includes("shared-messaging-role-panel") ||
    normalizedMainBody.includes("shared-messaging-role-detail")
      ? " shared-messaging-workspace--access-focus"
      : ""
  }${
    normalizedMainBody.includes("shared-messaging-moderation-panel") ||
    normalizedMainBody.includes("shared-messaging-ban-panel")
      ? " shared-messaging-workspace--safety-focus"
      : ""
  }${
    normalizedMainBody.includes("shared-messaging-workflow-panel")
      ? " shared-messaging-workspace--automation-focus"
      : ""
  }${
    normalizedMainBody.includes("shared-messaging-permissions")
      ? " shared-messaging-workspace--room-access-focus"
      : ""
  }${
    normalizedMainBody.includes("shared-messaging-inbox-home")
      ? " shared-messaging-workspace--inbox-home"
      : ""
  }`;
  return `<div class="shared-messaging-workspace${workspaceClassName}">
    ${renderMessagingWorkspaceRail(subroute)}
    <aside class="shared-messaging-sidebar">
      <div class="shared-messaging-sidebar__top">
        <div>
          <h1>${escapeHtml(sidebarTitle)}</h1>
          ${sidebarSubtitle ? `<p>${escapeHtml(sidebarSubtitle)}</p>` : ""}
        </div>
        ${renderMessagingWorkspaceStatus()}
      </div>
      ${sidebarActions}
      ${renderMessagingWorkspaceSidebarSummary(subroute)}
      ${sidebarBody}
    </aside>
    <main class="shared-messaging-main">${mainBody}</main>
  </div>`;
}

function renderMessagingPage() {
  if (window.__POLIS_LEGACY_MESSAGING_RENDERER__ === true) {
    return renderMessagingPageLegacy();
  }
  const messaging = state.pages.messaging;
  const inbox = messaging.inbox;
  const requests = messaging.requests;
  const conversation = messaging.conversation;
  const settings = messaging.settings || {};
  const subroute = parseMessagingSubroute();
  const currentServer = findMessagingServer(
    subroute.scopeType,
    subroute.scopeId,
  );
  const directory = messaging.serverDirectory.item;
  const serverSettings = messaging.serverSettings.item;
  const serverRoles = messaging.serverRoles;
  const serverMembers = messaging.serverMembers;
  const serverBans = messaging.serverBans;
  const serverModeration = messaging.serverModeration;
  const serverAutomod = messaging.serverAutomod;
  const serverWorkflows = messaging.serverWorkflows;
  const serverAudit = messaging.serverAudit;
  const serverAssets = messaging.serverAssets;
  const serverInvites = messaging.serverInvites;
  const serverSecurityPolicy = messaging.serverSecurityPolicy;
  const roomMembers = messaging.roomMembers;
  const roomInviteLinks = messaging.roomInviteLinks;
  const roomPins = messaging.roomPins;
  const permissionBundle = messaging.permissionTarget.bundle || {};
  const permissionTarget =
    permissionBundle.target && typeof permissionBundle.target === "object"
      ? permissionBundle.target
      : {};
  const activeConversationId =
    normalizeString(subroute.conversationId) ||
    normalizeString(conversation.item?.conversationId);
  const inboxRows = renderMessagingWorkspaceRows(
    inbox.items || [],
    activeConversationId,
    (conversation) =>
      `/messages/conversations/${encodeURIComponent(conversation.conversationId)}`,
    "No inbox conversations",
    {
      body: "Recent direct and group chats will appear here.",
      actions: "",
      className: "shared-messaging-empty-state--compact shared-messaging-empty-state--sidebar",
    },
  );
  const channelRows = renderMessagingWorkspaceChannelRows(
    directory,
    subroute,
    activeConversationId,
  );
  const activeRoomConversation =
    subroute.conversationId && subroute.scopeType && subroute.scopeId
      ? mergeMessagingRoomConversation(conversation.item, directory, subroute)
      : conversation.item;
  const miniNav = renderMessagingWorkspaceMiniNav(subroute.view);

  let workspaceMarkup = "";
  if (subroute.view === "requests") {
    workspaceMarkup = renderMessagingWorkspaceShell({
      subroute,
      sidebarTitle: "Requests",
      sidebarSubtitle: "Invites and message requests",
      sidebarActions: miniNav,
      sidebarBody: inboxRows,
      mainBody: renderMessagingWorkspacePanel({
        title: "Review requests",
        subtitle: "Accept workspace invites or refuse unwanted conversations.",
        body: renderMessagingWorkspaceRequests(requests.items || []),
      }),
    });
  } else if (subroute.view === "compose") {
    workspaceMarkup = renderMessagingWorkspaceShell({
      subroute,
      sidebarTitle: "Compose",
      sidebarSubtitle: "Start a direct message",
      sidebarActions: miniNav,
      sidebarBody: inboxRows,
      mainBody: renderMessagingComposePanel(messaging),
    });
  } else if (subroute.view === "conversation") {
    workspaceMarkup = renderMessagingWorkspaceShell({
      subroute,
      sidebarTitle: "Inbox",
      sidebarSubtitle: "Private and group conversations",
      sidebarActions: miniNav,
      sidebarBody: inboxRows,
      mainBody: renderMessagingWorkspaceThread({
        conversation: conversation.item,
        messages: conversation.messages,
        subroute,
      }),
    });
  } else if (subroute.view === "conversation-people") {
    workspaceMarkup = renderMessagingWorkspaceShell({
      subroute,
      sidebarTitle: "People",
      sidebarSubtitle: "Group conversation members",
      sidebarActions: miniNav,
      sidebarBody: inboxRows,
      mainBody: renderMessagingGroupPeoplePanel({
        conversation: conversation.item,
        membersState: roomMembers,
        peopleState: messagingGroupPeopleState(),
        subroute,
      }),
    });
  } else if (subroute.view === "server-room") {
    workspaceMarkup = renderMessagingWorkspaceShell({
      subroute,
      sidebarTitle: currentServer?.title || "Rooms",
      sidebarSubtitle: currentServer?.scopeBadge || "Campaign workspace",
      sidebarActions: renderMessagingWorkspaceServerTools(subroute, "server"),
      sidebarBody: channelRows,
      mainBody: renderMessagingWorkspaceThread({
        conversation: activeRoomConversation,
        messages: conversation.messages,
        subroute,
        roomActions: true,
        directory,
        roomMembers,
      }),
    });
  } else if (subroute.view === "settings") {
    workspaceMarkup = renderMessagingWorkspaceShell({
      subroute,
      sidebarTitle: "Settings",
      sidebarSubtitle: "Messaging privacy and security",
      sidebarActions: renderMessagingWorkspaceMiniNav("settings"),
      sidebarBody: renderMessagingWorkspaceSettingsNav("settings"),
      mainBody: renderMessagingWorkspacePanel({
        title: "Messaging privacy",
        subtitle: "DM requests, read receipts, devices, and recovery controls.",
        body: renderMessagingAccountSettings(settings, messaging),
      }),
    });
  } else if (subroute.view === "devices") {
    workspaceMarkup = renderMessagingWorkspaceShell({
      subroute,
      sidebarTitle: "Devices",
      sidebarSubtitle: "Trusted messaging devices",
      sidebarActions: renderMessagingWorkspaceMiniNav("settings"),
      sidebarBody: renderMessagingWorkspaceSettingsNav("devices"),
      mainBody: renderMessagingWorkspacePanel({
        title: "Trusted devices",
        subtitle:
          messaging.device.error ||
          `Current device: ${messaging.device.currentDeviceId || "unavailable"}`,
        actions:
          '<button class="shared-feed-chip shared-feed-chip--primary" data-action="navigate" data-route="/messages/devices/link">Link new device</button>',
        body: `<div class="shared-messaging-card-list">${(messaging.devices.items || [])
          .map(
            (device) =>
              `<article class="shared-messaging-device">
                ${renderMessagingWorkspaceAvatar({ label: device.deviceLabel, icon: "dashboard" })}
                <div>
                  <p>${escapeHtml(device.platform || "device")}${device.lastSeenAt ? ` | ${escapeHtml(formatAbsoluteDateTime(device.lastSeenAt))}` : ""}</p>
                  <h3>${escapeHtml(device.deviceLabel || "Device")}</h3>
                  <span>${escapeHtml(device.deviceId || "")}</span>
                </div>
                ${
                  device.deviceId &&
                  device.deviceId !== messaging.device.currentDeviceId
                    ? `<button class="shared-feed-chip" data-action="messaging-device-revoke" data-device-id="${escapeHtml(device.deviceId)}">Revoke</button>`
                    : ""
                }
              </article>`,
          )
          .join("") || '<div class="shared-messaging-empty">No trusted devices found.</div>'}</div>`,
      }),
    });
  } else if (subroute.view === "device-link") {
    const link = messaging.deviceLink.link;
    workspaceMarkup = renderMessagingWorkspaceShell({
      subroute,
      sidebarTitle: "Device link",
      sidebarSubtitle: "Approve browser or app devices",
      sidebarActions: renderMessagingWorkspaceMiniNav("settings"),
      sidebarBody: renderMessagingWorkspaceSettingsNav("device-link"),
      mainBody: renderMessagingWorkspacePanel({
        title: "Link a trusted device",
        subtitle: link?.linkCode
          ? `Link code: ${link.linkCode}`
          : "Start a device link flow or approve a code from another device.",
        body: `<div class="shared-messaging-settings-grid">
            <div><strong>Status</strong><span>${escapeHtml(normalizeString(link?.status) || "idle")}</span></div>
            <div><strong>Expires</strong><span>${escapeHtml(link?.expiresAt ? formatAbsoluteDateTime(link.expiresAt) : "Not started")}</span></div>
            <div><strong>Target device</strong><span>${escapeHtml(link?.targetDeviceId || "None")}</span></div>
          </div>
          <div class="shared-card__actions">
            <button class="shared-feed-chip shared-feed-chip--primary" data-action="messaging-device-link-start"${messaging.deviceLink.pending ? " disabled" : ""}>${messaging.deviceLink.pending ? "Working..." : "Start link"}</button>
            ${link?.linkId ? `<button class="shared-feed-chip" data-action="messaging-device-link-refresh" data-link-id="${escapeHtml(link.linkId)}">Refresh</button>` : ""}
            ${link?.linkId && link?.linkCode && link?.targetDeviceId ? '<button class="shared-feed-chip" data-action="messaging-device-link-approve">Approve</button>' : ""}
          </div>
          <form class="shared-form shared-form--inline shared-messaging-form" data-route-form="messaging-device-link-lookup">
            <input name="linkCode" value="${escapeHtml(messaging.deviceLink.lookupCode || "")}" placeholder="Link code" />
            <button class="shared-feed-chip shared-feed-chip--primary" type="submit"${messaging.deviceLink.pending ? " disabled" : ""}>Lookup</button>
          </form>
          ${messaging.deviceLink.error ? `<div class="shared-page__error">${escapeHtml(messaging.deviceLink.error)}</div>` : ""}`,
      }),
    });
  } else if (
    subroute.view === "recovery" ||
    subroute.view === "recovery-restore"
  ) {
    const recoveryStatus = normalizeString(
      messaging.recovery.status?.status ||
        (messaging.recovery.status?.backupVersion ? "Configured" : ""),
    );
    workspaceMarkup = renderMessagingWorkspaceShell({
      subroute,
      sidebarTitle: "Recovery",
      sidebarSubtitle: "Conversation key backup",
      sidebarActions: renderMessagingWorkspaceMiniNav("settings"),
      sidebarBody: renderMessagingWorkspaceSettingsNav("recovery"),
      mainBody: renderMessagingWorkspacePanel({
        title: "Recovery status",
        subtitle: recoveryStatus || "Not enrolled",
        body: `<div class="shared-messaging-settings-grid">
            <div><strong>Local code</strong><span>${escapeHtml(messaging.recovery.localCode || "No local code stored")}</span></div>
            <div><strong>Backup</strong><span>${escapeHtml(recoveryStatus || "Not enrolled")}</span></div>
          </div>
          <div class="shared-card__actions">
            <button class="shared-feed-chip shared-feed-chip--primary" data-action="messaging-recovery-enroll">${messaging.recovery.actionPending ? "Working..." : "Enroll"}</button>
            <button class="shared-feed-chip" data-action="messaging-recovery-rotate">Rotate</button>
            <button class="shared-feed-chip" data-action="messaging-recovery-verify">Verify</button>
          </div>
          <form class="shared-form shared-form--inline shared-messaging-form" data-route-form="messaging-recovery-restore">
            <input name="recoveryCode" placeholder="Recovery code" />
            <button class="shared-feed-chip shared-feed-chip--primary" type="submit"${messaging.recovery.actionPending ? " disabled" : ""}>Restore</button>
          </form>
          ${messaging.recovery.error ? `<div class="shared-page__error">${escapeHtml(messaging.recovery.error)}</div>` : ""}`,
      }),
    });
  } else if (subroute.view === "security") {
    workspaceMarkup = renderMessagingWorkspaceShell({
      subroute,
      sidebarTitle: "Security",
      sidebarSubtitle: "Messaging activity",
      sidebarActions: renderMessagingWorkspaceMiniNav("settings"),
      sidebarBody: renderMessagingWorkspaceSettingsNav("security"),
      mainBody: renderMessagingWorkspacePanel({
        title: "Security activity",
        subtitle: "Device, recovery, and messaging security events.",
        body: `<div class="shared-messaging-card-list">${(messaging.security.items || [])
          .map(
            (item) =>
              `<article class="shared-messaging-device">
                ${renderMessagingWorkspaceAvatar({ label: item.type || item.title, icon: "bell" })}
                <div><p>${item.createdAt ? escapeHtml(formatAbsoluteDateTime(item.createdAt)) : "Event"}</p><h3>${escapeHtml(item.type || item.title || "Security event")}</h3><span>${escapeHtml(item.description || item.deviceLabel || "")}</span></div>
              </article>`,
          )
          .join("") || '<div class="shared-messaging-empty">No security activity yet.</div>'}</div>`,
      }),
    });
  } else if (subroute.view === "server") {
    const categories = Array.isArray(directory?.categories)
      ? directory.categories
      : [];
    const channels = Array.isArray(directory?.channels)
      ? directory.channels
      : [];
    const canManageDirectory =
      currentServer?.canManage === true || directory?.canManage === true;
    const scopeLabel = messagingServerScopeLabel(subroute, currentServer);
    const roomGroups = categories
      .map((category) => {
        const categoryId = messagingDirectoryCategoryId(category);
        const items = channels.filter(
          (item) => messagingDirectoryChannelCategoryId(item) === categoryId,
        );
        if (!items.length) return "";
        return `<section class="shared-messaging-room-group">
          <div class="shared-messaging-room-group__header">
            <div>
              <h3>${escapeHtml(messagingDirectoryCategoryTitle(category))}</h3>
              <p>${escapeHtml(normalizeString(category.description || category.subtitle) || `${formatCount(items.length)} room${items.length === 1 ? "" : "s"}`)}</p>
            </div>
            ${
              canManageDirectory
                ? `<button class="shared-feed-chip" data-action="navigate" data-route="${escapeHtml(buildMessagingCategoryPermissionRoute(subroute.scopeType, subroute.scopeId, categoryId))}">Access</button>`
                : ""
            }
          </div>
          ${renderMessagingWorkspaceRows(items, "", (item) =>
            buildMessagingRoomRoute(
              subroute.scopeType,
              subroute.scopeId,
              item.conversationId,
            ),
          )}
        </section>`;
      })
      .join("");
    const uncategorized = channels.filter(
      (item) => !messagingDirectoryChannelCategoryId(item),
    );
    const uncategorizedGroup = uncategorized.length
      ? `<section class="shared-messaging-room-group"><h3>Rooms</h3>${renderMessagingWorkspaceRows(
          uncategorized,
          "",
          (item) =>
            buildMessagingRoomRoute(
              subroute.scopeType,
              subroute.scopeId,
              item.conversationId,
            ),
        )}</section>`
      : "";
    const directoryBody =
      roomGroups || uncategorizedGroup
        ? `<div class="shared-messaging-room-directory">${roomGroups}${uncategorizedGroup}</div>`
        : `<div class="shared-messaging-empty">No rooms are available yet.${canManageDirectory ? " Create the first room below." : ""}</div>`;
    const commandPanel = canManageDirectory
      ? renderMessagingServerDirectoryCommandPanel({
          subroute,
          directory,
          currentServer,
          settingsState: messaging.serverSettings,
        })
      : "";
    workspaceMarkup = renderMessagingWorkspaceShell({
      subroute,
      sidebarTitle: currentServer?.title || "Workspace",
      sidebarSubtitle: scopeLabel,
      sidebarActions: renderMessagingWorkspaceServerTools(subroute, "server"),
      sidebarBody: channelRows,
      mainBody: renderMessagingWorkspacePanel({
        title: currentServer?.title || "Rooms",
        subtitle: canManageDirectory
          ? `Manage ${scopeLabel.toLowerCase()} rooms, categories, access groups, people, and safety review from the browser.`
          : `Open ${scopeLabel.toLowerCase()} rooms available to your role.`,
        actions: canManageDirectory
          ? `<button class="shared-feed-chip shared-feed-chip--primary" data-action="navigate" data-route="${escapeHtml(buildMessagingServerRoute(subroute.scopeType, subroute.scopeId, "/settings/channels"))}">Manage directory</button>`
          : "",
        body: `${commandPanel}${directoryBody}`,
      }),
    });
  } else if (
    subroute.view === "server-settings" ||
    subroute.view === "server-settings-section"
  ) {
    const selectedSection = normalizeString(subroute.sectionId);
    const selectedSectionDisplay = messagingServerSettingsItemPresentation({
      id: selectedSection,
    });
    workspaceMarkup = renderMessagingWorkspaceShell({
      subroute,
      sidebarTitle: currentServer?.title || "Workspace settings",
      sidebarSubtitle: "Preferences and member entry controls",
      sidebarActions: renderMessagingWorkspaceServerTools(
        subroute,
        messagingServerSettingsSidebarKey(selectedSection),
      ),
      sidebarBody: channelRows,
      mainBody: renderMessagingWorkspacePanel({
        title:
          serverSettings?.server?.title ||
          currentServer?.title ||
          "Workspace settings",
        subtitle: selectedSection
          ? `${selectedSectionDisplay.title} area`
          : "Overview and workspace preferences.",
        body: renderMessagingServerSettingsBody({
          subroute,
          serverSettings,
          currentServer,
          directory,
          settingsState: messaging.serverSettings,
          serverAudit,
          serverAssets,
          serverInvites,
          serverSecurityPolicy,
        }),
      }),
    });
  } else if (subroute.view === "server-roles") {
    workspaceMarkup = renderMessagingWorkspaceShell({
      subroute,
      sidebarTitle: currentServer?.title || "Access groups",
      sidebarSubtitle: "People and room access",
      sidebarActions: renderMessagingWorkspaceServerTools(
        subroute,
        "server-roles",
      ),
      sidebarBody: channelRows,
      mainBody: renderMessagingWorkspacePanel({
        title: "Access groups",
        subtitle:
          "Create groups, review room access defaults, and manage assignments.",
        body: renderMessagingRolesPanel(subroute, serverRoles),
      }),
    });
  } else if (subroute.view === "server-members") {
    workspaceMarkup = renderMessagingWorkspaceShell({
      subroute,
      sidebarTitle: currentServer?.title || "People",
      sidebarSubtitle: "Members and access",
      sidebarActions: renderMessagingWorkspaceServerTools(
        subroute,
        "server-members",
      ),
      sidebarBody: channelRows,
      mainBody: renderMessagingWorkspacePanel({
        title: "People",
        subtitle: "Review access groups, names, and safety context.",
        body: renderMessagingServerMembersPanel(subroute, serverMembers),
      }),
    });
  } else if (subroute.view === "server-moderation") {
    workspaceMarkup = renderMessagingWorkspaceShell({
      subroute,
      sidebarTitle: currentServer?.title || "Safety review",
      sidebarSubtitle: "Reports and held messages",
      sidebarActions: renderMessagingWorkspaceServerTools(
        subroute,
        "server-moderation",
      ),
      sidebarBody: channelRows,
      mainBody: renderMessagingWorkspacePanel({
        title: "Safety review",
        subtitle:
          normalizeString(serverModeration.status) === "open"
            ? "Review reports and held messages that need a decision."
            : `${messagingModerationStatusLabel(serverModeration.status)} moderation history.`,
        actions: `<button class="shared-feed-chip" type="button" data-action="refresh-current-route">Refresh</button>`,
        body: renderMessagingModerationPanel(
          subroute,
          serverModeration,
          serverAutomod,
        ),
      }),
    });
  } else if (subroute.view === "server-workflows") {
    workspaceMarkup = renderMessagingWorkspaceShell({
      subroute,
      sidebarTitle: currentServer?.title || "Automations",
      sidebarSubtitle: "Triggers and handoffs",
      sidebarActions: renderMessagingWorkspaceServerTools(
        subroute,
        "server-workflows",
      ),
      sidebarBody: channelRows,
      mainBody: renderMessagingWorkspacePanel({
        title: "Room automations",
        subtitle:
          "Route reports, joins, schedules, room notices, and external handoffs without manual follow-up.",
        actions: `<button class="shared-feed-chip" type="button" data-action="refresh-current-route">Refresh</button>`,
        body: renderMessagingWorkflowsPanel(subroute, serverWorkflows),
      }),
    });
  } else if (subroute.view === "server-role") {
    const selectedRole = serverRoles.selected;
    workspaceMarkup = renderMessagingWorkspaceShell({
      subroute,
      sidebarTitle: currentServer?.title || "Access group",
      sidebarSubtitle: "People and room access",
      sidebarActions: renderMessagingWorkspaceServerTools(
        subroute,
        "server-roles",
      ),
      sidebarBody: channelRows,
      mainBody: renderMessagingWorkspacePanel({
        title: selectedRole?.name || "Access group",
        subtitle: selectedRole?.mentionable
          ? "Can be mentioned in room messages"
          : "Access group details",
        body: renderMessagingRoleDetailPanel(subroute, serverRoles),
      }),
    });
  } else if (subroute.view === "server-member") {
    const member = serverMembers.detail?.member;
    workspaceMarkup = renderMessagingWorkspaceShell({
      subroute,
      sidebarTitle: currentServer?.title || "Member detail",
      sidebarSubtitle: "Roster profile",
      sidebarActions: renderMessagingWorkspaceServerTools(
        subroute,
        "server-members",
      ),
      sidebarBody: channelRows,
      mainBody: renderMessagingWorkspacePanel({
        title: member?.effectiveName || "Member",
        subtitle:
          member?.roles?.map(messagingMemberRoleLabel).filter(Boolean).join(", ") ||
          "No explicit roles",
        actions: `<button class="shared-feed-chip" type="button" data-action="navigate" data-route="${escapeHtml(buildMessagingServerRoute(subroute.scopeType, subroute.scopeId, "/members"))}">All members</button>`,
        body: renderMessagingServerMemberPanel(subroute, serverMembers),
      }),
    });
  } else if (subroute.view === "server-bans") {
    workspaceMarkup = renderMessagingWorkspaceShell({
      subroute,
      sidebarTitle: currentServer?.title || "Blocked access",
      sidebarSubtitle: "Restrictions and restores",
      sidebarActions: renderMessagingWorkspaceServerTools(
        subroute,
        "server-bans",
      ),
      sidebarBody: channelRows,
      mainBody: renderMessagingWorkspacePanel({
        title: "Blocked access",
        subtitle: "Review restricted members and restore access with clear context.",
        actions: `<button class="shared-feed-chip" type="button" data-action="refresh-current-route">Refresh</button>`,
        body: renderMessagingBansPanel(subroute, serverBans),
      }),
    });
  } else if (
    subroute.view === "room-settings" ||
    subroute.view === "room-settings-notifications" ||
    subroute.view === "room-settings-pins" ||
    subroute.view === "room-settings-invites" ||
    subroute.view === "room-settings-integrations" ||
    subroute.view === "room-settings-section"
  ) {
    const roomSettingsConfig = messagingRoomSettingsConfig(subroute);
    workspaceMarkup = renderMessagingWorkspaceShell({
      subroute,
      sidebarTitle: currentServer?.title || "Room settings",
      sidebarSubtitle: activeRoomConversation?.title || "Room",
      sidebarActions: renderMessagingWorkspaceServerTools(subroute, "server"),
      sidebarBody: channelRows,
      mainBody: renderMessagingWorkspacePanel({
        title:
          roomSettingsConfig.title === "Room settings"
            ? activeRoomConversation?.title || roomSettingsConfig.title
            : roomSettingsConfig.title,
        subtitle:
          roomSettingsConfig.title === "Room settings"
            ? activeRoomConversation?.subtitle || roomSettingsConfig.subtitle
            : `${activeRoomConversation?.title || "Room"} | ${roomSettingsConfig.subtitle}`,
        actions: `<button class="shared-feed-chip" type="button" data-action="navigate" data-route="${escapeHtml(buildMessagingRoomRoute(subroute.scopeType, subroute.scopeId, subroute.conversationId))}">Open room</button>
          <button class="shared-feed-chip" type="button" data-action="navigate" data-route="${escapeHtml(buildMessagingRoomRoute(subroute.scopeType, subroute.scopeId, subroute.conversationId, "/settings/permissions"))}">Room access</button>`,
        body: renderMessagingRoomSettingsBody(
          subroute,
          activeRoomConversation,
          directory,
          roomMembers,
          roomInviteLinks,
          roomPins,
          conversation.messages,
        ),
      }),
    });
  } else if (
    subroute.view === "room-permissions" ||
    subroute.view === "room-permission-role" ||
    subroute.view === "category-permissions" ||
    subroute.view === "category-permission-role"
  ) {
    const permissionsTitle = messagingPermissionTargetTitle(
      subroute,
      activeRoomConversation,
      directory,
    );
    workspaceMarkup = renderMessagingWorkspaceShell({
      subroute,
      sidebarTitle: currentServer?.title || "Room access",
      sidebarSubtitle: permissionsTitle,
      sidebarActions: renderMessagingWorkspaceServerTools(subroute, "server"),
      sidebarBody: channelRows,
      mainBody: renderMessagingPermissionPanel({
        subroute,
        permissionTarget,
        conversation: activeRoomConversation,
        directory,
        roles: permissionBundle.roles || [],
        permissionsState: messaging.permissionTarget,
      }),
    });
  } else if (subroute.view === "unsupported") {
    workspaceMarkup = renderMessagingWorkspaceShell({
      subroute,
      sidebarTitle: "Messages",
      sidebarSubtitle: "Route unavailable",
      sidebarActions: miniNav,
      sidebarBody: inboxRows,
      mainBody: renderMessagingWorkspacePanel({
        title: "Choose a messaging workspace",
        subtitle:
          "This route does not match a known messaging workspace.",
        body: '<div class="shared-messaging-empty">Use the inbox, requests, compose, privacy, or workspace routes.</div>',
      }),
    });
  } else {
    workspaceMarkup = renderMessagingWorkspaceShell({
      subroute,
      sidebarTitle: "Messages",
      sidebarSubtitle: "Inbox and private chats",
      sidebarActions: miniNav,
      sidebarBody: inboxRows,
      mainBody: renderMessagingInboxHomePanel({
        inbox,
        requests,
        servers: messaging.servers,
        messaging,
      }),
    });
  }

  const errorMarkup = [
    messaging.error,
    messaging.serverDirectory.error,
    messaging.serverSettings.error,
    messaging.serverRoles.error,
    messaging.serverMembers.error,
    messaging.serverBans.error,
    messaging.serverModeration.error,
    messaging.serverAutomod.error,
    messaging.serverWorkflows.error,
    messaging.roomMembers.error,
    messaging.permissionTarget.error,
  ]
    .filter(Boolean)
    .map(
      (error) =>
        `<div class="shared-page__error">${escapeHtml(error)}</div>`,
    )
    .join("");

  return `<section class="shared-page shared-messaging-page">
    ${renderTopChrome()}
    <div class="shared-page__content shared-messaging-page__content">
      ${errorMarkup}
      ${messaging.loading ? '<div class="shared-page__loading">Loading messaging...</div>' : ""}
      ${workspaceMarkup}
    </div>
  </section>`;
}

function renderAuthRouteModeControls(activeMode) {
  const returnTo = encodeURIComponent(authRouteReturnPath());
  const controls = [
    ["login", "Sign in", `/auth?returnTo=${returnTo}`],
    ["signup", "Create account", `/auth/signup/email?returnTo=${returnTo}`],
    ["reset", "Reset password", `/auth/forgot-password?returnTo=${returnTo}`],
  ];
  return `<div class="shared-auth-route-tabs">
    ${controls
      .map(
        ([mode, label, route]) =>
          `<button class="shared-feed-chip${activeMode === mode ? " shared-feed-chip--primary" : ""}" type="button" data-action="navigate" data-route="${escapeHtml(route)}">${escapeHtml(label)}</button>`,
      )
      .join("")}
  </div>`;
}

function renderAuthRouteStatus(resource) {
  if (!resource) {
    return "";
  }
  return `${resource.error ? `<div class="shared-auth-modal__status shared-auth-modal__status--error">${escapeHtml(resource.error)}</div>` : ""}${resource.notice ? `<div class="shared-auth-modal__status shared-auth-modal__status--notice">${escapeHtml(resource.notice)}</div>` : ""}`;
}

function renderAuthRouteSignedIn() {
  const label =
    state.auth.user?.displayName ||
    state.auth.user?.email ||
    state.auth.user?.username ||
    "your account";
  const returnTo = authRouteReturnPath();
  return `<div class="shared-auth-route-signed-in">
    <span class="shared-settings-eyebrow">Polis account</span>
    <h2>Signed in</h2>
    <p>${escapeHtml(`You are signed in as ${label}.`)}</p>
    <div class="shared-auth-route-actions">
      <button class="shared-feed-chip shared-feed-chip--primary" type="button" data-action="navigate" data-route="${escapeHtml(returnTo)}">Continue</button>
      <button class="shared-feed-chip" type="button" data-action="navigate" data-route="/profile">Profile</button>
      <button class="shared-feed-chip" type="button" data-action="logout">Log out</button>
    </div>
  </div>`;
}

function renderAuthRouteLogin(auth, capabilities) {
  if (!capabilities.password) {
    return `<div class="shared-auth-modal__fallback">
      <p>Password sign-in is not available for this web client right now.</p>
      ${capabilities.hosted ? `<button class="shared-feed-chip shared-feed-chip--primary" type="button" data-action="auth-route-hosted-login"${disabledAttr(auth.pending)}>Continue in browser</button>` : ""}
    </div>`;
  }
  return `<form class="shared-auth-modal__form" data-route-form="auth-route-login">
    <label>
      <span>Username or email</span>
      <input name="identifier" autocomplete="username" value="${escapeHtml(auth.fields.identifier)}" placeholder="you@example.com" />
    </label>
    <label>
      <span>Password</span>
      <input name="password" type="password" autocomplete="current-password" value="${escapeHtml(auth.fields.password)}" placeholder="Password" />
    </label>
    <div class="shared-auth-route-actions">
      <button class="shared-feed-chip shared-feed-chip--primary" type="submit"${disabledAttr(auth.pending)}>${auth.pending ? "Signing in..." : "Sign in"}</button>
      ${capabilities.hosted ? `<button class="shared-feed-chip" type="button" data-action="auth-route-hosted-login"${disabledAttr(auth.pending)}>Use browser sign-in</button>` : ""}
      <button class="shared-feed-chip" type="button" data-action="navigate" data-route="/auth/forgot-password?returnTo=${escapeHtml(encodeURIComponent(authRouteReturnPath()))}">Forgot password</button>
    </div>
  </form>`;
}

function renderAuthRouteSignup(auth, capabilities) {
  if (!capabilities.direct) {
    return `<div class="shared-auth-modal__fallback">
      <p>Direct sign-up is not available for this web client right now.</p>
      ${capabilities.hosted ? `<button class="shared-feed-chip shared-feed-chip--primary" type="button" data-action="auth-route-hosted-signup"${disabledAttr(auth.pending)}>Use browser sign-up</button>` : ""}
    </div>`;
  }
  return `<form class="shared-auth-modal__form" data-route-form="auth-route-signup">
    <label>
      <span>Email</span>
      <input name="email" type="email" autocomplete="email" value="${escapeHtml(auth.fields.email)}" placeholder="you@example.com" />
    </label>
    <label>
      <span>Password</span>
      <input name="password" type="password" autocomplete="new-password" value="${escapeHtml(auth.fields.signupPassword)}" placeholder="Use at least 8 characters" />
    </label>
    <label>
      <span>Confirm password</span>
      <input name="confirmPassword" type="password" autocomplete="new-password" value="${escapeHtml(auth.fields.confirmPassword)}" placeholder="Confirm password" />
    </label>
    <div class="shared-auth-route-actions">
      <button class="shared-feed-chip shared-feed-chip--primary" type="submit"${disabledAttr(auth.pending)}>${auth.pending ? "Creating..." : "Create account"}</button>
      ${capabilities.hosted ? `<button class="shared-feed-chip" type="button" data-action="auth-route-hosted-signup"${disabledAttr(auth.pending)}>Use browser sign-up</button>` : ""}
    </div>
  </form>`;
}

function renderAuthRouteConfirm(auth) {
  const awaiting = auth.awaitingConfirmation || {};
  const destination =
    awaiting.deliveryDestination || awaiting.email || "your email";
  const needsCredentials = !awaiting.username || !awaiting.password;
  return `<div class="shared-auth-modal__confirm-copy">
      <p>${escapeHtml(`Enter the verification code sent to ${destination}.`)}</p>
    </div>
    <form class="shared-auth-modal__form" data-route-form="auth-route-confirm">
      ${
        needsCredentials
          ? `<label>
              <span>Email or username</span>
              <input name="identifier" autocomplete="username" value="${escapeHtml(auth.fields.identifier || auth.fields.email)}" placeholder="you@example.com" />
            </label>
            <label>
              <span>Password</span>
              <input name="password" type="password" autocomplete="current-password" value="${escapeHtml(auth.fields.password)}" placeholder="Password" />
            </label>`
          : ""
      }
      <label>
        <span>6-digit code</span>
        <input name="code" inputmode="numeric" autocomplete="one-time-code" value="${escapeHtml(auth.fields.code)}" placeholder="123456" />
      </label>
      <div class="shared-auth-route-actions">
        <button class="shared-feed-chip shared-feed-chip--primary" type="submit"${disabledAttr(auth.pending)}>${auth.pending ? "Confirming..." : "Confirm account"}</button>
        <button class="shared-feed-chip" type="button" data-action="auth-route-resend-code"${disabledAttr(auth.pending || !awaiting.username)}>Resend code</button>
      </div>
    </form>`;
}

function renderAuthRoutePasswordReset(mode) {
  const reset = settingsAccountSecurity().reset;
  const confirming = mode === "reset-confirm";
  return `<div class="shared-auth-route-reset">
    ${renderAuthRouteStatus(reset)}
    ${
      confirming
        ? `<form class="shared-auth-modal__form" data-route-form="settings-password-reset-confirm">
            <label>
              <span>Email or username</span>
              <input name="identifier" autocomplete="username" value="${escapeHtml(reset.username || reset.identifier || "")}" placeholder="you@example.com" />
            </label>
            <label>
              <span>Reset code</span>
              <input name="code" inputmode="numeric" autocomplete="one-time-code" placeholder="123456" />
            </label>
            <label>
              <span>New password</span>
              <input name="password" type="password" autocomplete="new-password" placeholder="Use at least 8 characters" />
            </label>
            <div class="shared-auth-route-actions">
              <button class="shared-feed-chip shared-feed-chip--primary" type="submit"${disabledAttr(reset.confirming)}>${reset.confirming ? "Updating..." : "Update password"}</button>
              <button class="shared-feed-chip" type="button" data-action="navigate" data-route="/auth">Sign in</button>
            </div>
          </form>`
        : `<form class="shared-auth-modal__form" data-route-form="settings-password-reset-request">
            <label>
              <span>Email or username</span>
              <input name="identifier" autocomplete="username" value="${escapeHtml(defaultSettingsSecurityIdentifier())}" placeholder="you@example.com" />
            </label>
            <div class="shared-auth-route-actions">
              <button class="shared-feed-chip shared-feed-chip--primary" type="submit"${disabledAttr(reset.requesting)}>${reset.requesting ? "Sending..." : "Send reset code"}</button>
              <button class="shared-feed-chip" type="button" data-action="navigate" data-route="/auth/forgot-password/confirm?returnTo=${escapeHtml(encodeURIComponent(authRouteReturnPath()))}">I have a code</button>
            </div>
          </form>`
    }
  </div>`;
}

function renderAuthRoutePage() {
  const mode = authRouteModeFromPath();
  const auth = routeAuthState();
  const capabilities = getSharedFeedAuthCapabilities(state.auth.config);
  let body = "";
  if (state.auth.session) {
    body = renderAuthRouteSignedIn();
  } else if (mode === "signup") {
    body = `${renderAuthRouteModeControls("signup")} ${renderAuthRouteStatus(auth)} ${renderAuthRouteSignup(auth, capabilities)}`;
  } else if (mode === "confirm") {
    body = `${renderAuthRouteModeControls("signup")} ${renderAuthRouteStatus(auth)} ${renderAuthRouteConfirm(auth)}`;
  } else if (mode === "reset" || mode === "reset-confirm") {
    body = `${renderAuthRouteModeControls("reset")} ${renderAuthRoutePasswordReset(mode)}`;
  } else {
    body = `${renderAuthRouteModeControls("login")} ${renderAuthRouteStatus(auth)} ${renderAuthRouteLogin(auth, capabilities)}`;
  }
  return `<section class="shared-page shared-auth-route-page">
    ${renderTopChrome()}
    <div class="shared-page__content shared-auth-route-content">
      <section class="shared-auth-route-hero">
        <span class="shared-settings-eyebrow">Polis account</span>
        <h1>${escapeHtml(mode === "signup" ? "Create your account" : mode === "confirm" ? "Confirm your account" : mode === "reset" || mode === "reset-confirm" ? "Reset your password" : "Sign in to Polis")}</h1>
        <p>Use your Polis account to open the feed, messages, coalitions, campaign dashboards, settings, and creator tools from the browser.</p>
      </section>
      <section class="shared-auth-route-panel">
        ${body}
      </section>
    </div>
  </section>`;
}

