function renderSettingsPublishingForm() {
  const resource = state.pages.settings.publishing;
  const audienceGroups = state.pages.settings.audienceGroups;
  const publishing = resource.item || defaultPublishingDefaults();
  const preferences = publishing.postReviewPreferences;
  const selectedGroupIds = new Set(publishing.defaultAudienceGroupIds);
  const knownGroupIds = new Set(audienceGroups.items.map((group) => group.groupId));
  const missingGroupIds = publishing.defaultAudienceGroupIds.filter(
    (groupId) => groupId && !knownGroupIds.has(groupId),
  );
  const audienceGroupControl = audienceGroups.items.length
    ? `<div class="shared-settings-audience-choices">
        ${audienceGroups.items
          .map(
            (group) => `<label class="shared-settings-audience-choice">
              <input type="checkbox" name="defaultAudienceGroupIds" value="${escapeHtml(group.groupId)}"${checkedAttr(selectedGroupIds.has(group.groupId))} />
              <span>
                <strong>${escapeHtml(group.name)}</strong>
                <small>${escapeHtml(`${formatCount(group.memberUserIds.length)} member ID${group.memberUserIds.length === 1 ? "" : "s"}`)}</small>
              </span>
            </label>`,
          )
          .join("")}
        ${missingGroupIds
          .map(
            (groupId) =>
              `<input type="hidden" name="defaultAudienceGroupIds" value="${escapeHtml(groupId)}" />`,
          )
          .join("")}
        ${
          missingGroupIds.length
            ? `<div class="shared-settings-empty">${escapeHtml(`${formatCount(missingGroupIds.length)} saved group ID${missingGroupIds.length === 1 ? "" : "s"} no longer appears in your audience groups.`)}</div>`
            : ""
        }
      </div>`
    : `<label>
        <span>Default audience group IDs</span>
        <input name="defaultAudienceGroupIds" value="${escapeHtml(publishing.defaultAudienceGroupIds.join(", "))}" placeholder="Only used for custom visibility" />
      </label>`;
  return `<form class="shared-settings-form" data-route-form="settings-publishing">
    <div class="shared-settings-form-grid">
      <label>
        <span>Default visibility</span>
        <select name="defaultPostVisibility">
          ${["public", "followers", "private", "custom"]
            .map(
              (value) => `<option value="${escapeHtml(value)}"${
                publishing.defaultPostVisibility === value ? " selected" : ""
              }>${escapeHtml(humanizeLabel(value))}</option>`,
            )
            .join("")}
        </select>
      </label>
      <div class="shared-settings-field">
        <span>Custom visibility groups</span>
        ${audienceGroupControl}
      </div>
    </div>
    ${renderSettingsResourceStatus(audienceGroups, "audience groups")}
    <div class="shared-settings-inline-note">
      <span>Custom post visibility uses your private audience groups.</span>
      <button class="shared-feed-chip" type="button" data-action="navigate" data-route="/settings/audience-groups">Manage groups</button>
    </div>
    <div class="shared-settings-check-grid">
      <label class="shared-settings-toggle"><input type="checkbox" checked disabled /><span>Branding overlay on published media</span></label>
      <label class="shared-settings-toggle"><input type="checkbox" name="allowComments" value="true"${checkedAttr(preferences.allowComments)} /><span>Allow comments by default</span></label>
      <label class="shared-settings-toggle"><input type="checkbox" name="allowReuseContent" value="true"${checkedAttr(preferences.allowReuseContent)} /><span>Allow reuse by default</span></label>
      <label class="shared-settings-toggle"><input type="checkbox" name="aiGeneratedContent" value="true"${checkedAttr(preferences.aiGeneratedContent)} /><span>Mark AI-generated content</span></label>
      <label class="shared-settings-toggle"><input type="checkbox" name="saveToDevice" value="true"${checkedAttr(preferences.saveToDevice)} /><span>Save reviewed posts to this device</span></label>
      <label class="shared-settings-toggle"><input type="checkbox" checked disabled /><span>Save posts with watermark</span></label>
    </div>
    ${renderSettingsResourceStatus(resource, "publishing defaults")}
    <div class="shared-settings-form-actions">
      <button class="shared-feed-chip shared-feed-chip--primary" type="submit"${disabledAttr(resource.saving)}>Save publishing defaults</button>
    </div>
  </form>`;
}

