function voterProfileDisplayName(profile) {
  return (
    normalizeString(profile?.fullName) ||
    normalizeString(profile?.displayName) ||
    normalizeString(profile?.username) ||
    "Your voter profile"
  );
}

function voterProfileHandle(profile) {
  const username = normalizeString(profile?.username);
  return username ? `@${username.replace(/^@/u, "")}` : "No username yet";
}

function voterProfileInitials(profile) {
  const name = voterProfileDisplayName(profile);
  const parts = name.split(/\s+/u).filter(Boolean);
  return (
    parts
      .slice(0, 2)
      .map((part) => part.slice(0, 1).toUpperCase())
      .join("") || "P"
  );
}

function voterProfileAddress(profile) {
  const parts = [
    profile?.addressLine1,
    profile?.addressLine2,
    [profile?.city, profile?.locationStateId, profile?.postalCode]
      .filter(Boolean)
      .join(", "),
  ]
    .map(normalizeString)
    .filter(Boolean);
  return parts.join(" - ");
}

function voterProfileCompletion(profile, districts) {
  const checks = [
    voterProfileDisplayName(profile) !== "Your voter profile",
    Boolean(normalizeString(profile?.email)),
    Boolean(normalizeString(profile?.phone)),
    Boolean(normalizeString(profile?.politicalAffiliation)),
    Boolean(voterProfileAddress(profile)),
    Boolean(
      normalizeString(profile?.locationDistrictId) ||
        normalizeString(districts?.jurisdictions?.federal?.congressionalDistrictId),
    ),
  ];
  return Math.round((checks.filter(Boolean).length / checks.length) * 100);
}

function renderVoterProfileMetric(label, value, copy) {
  return `<article class="shared-voter-profile-metric">
    <strong>${escapeHtml(value)}</strong>
    <span>${escapeHtml(label)}</span>
    <p>${escapeHtml(copy)}</p>
  </article>`;
}

function renderVoterProfileBadge(label, value, tone = "") {
  return `<span class="shared-voter-profile-badge${tone ? ` is-${escapeHtml(tone)}` : ""}">
    <strong>${escapeHtml(label)}</strong>
    <em>${escapeHtml(value)}</em>
  </span>`;
}

function renderVoterProfileHero(profile, districts) {
  const completion = voterProfileCompletion(profile, districts);
  const address = voterProfileAddress(profile);
  const districtId =
    normalizeString(districts?.jurisdictions?.federal?.congressionalDistrictId) ||
    normalizeString(profile?.locationDistrictId) ||
    normalizeString(profile?.manualCongressionalDistrictId);
  return `<section class="shared-voter-profile-hero">
    <div class="shared-voter-profile-id">
      <div class="shared-voter-profile-avatar">
        ${
          profile?.avatarUrl
            ? `<img src="${escapeHtml(profile.avatarUrl)}" alt="" loading="lazy" />`
            : `<span>${escapeHtml(voterProfileInitials(profile))}</span>`
        }
      </div>
      <div>
        <span class="shared-settings-eyebrow">Voter profile</span>
        <h2>${escapeHtml(voterProfileDisplayName(profile))}</h2>
        <p>${escapeHtml(voterProfileHandle(profile))}</p>
      </div>
    </div>
    <div class="shared-voter-profile-badges">
      ${renderVoterProfileBadge("Readiness", `${completion}%`, completion >= 80 ? "good" : "attention")}
      ${renderVoterProfileBadge("District", districtId || "Missing", districtId ? "good" : "attention")}
      ${renderVoterProfileBadge("GPS", profile?.gpsEnabled === true ? "On" : "Off")}
    </div>
    <div class="shared-voter-profile-address">
      <strong>${escapeHtml(address || "No home location saved")}</strong>
      <span>${escapeHtml(
        districtId
          ? "Home location is ready for district-aware features."
          : "Add a home location so Polis can resolve districts and ballot context.",
      )}</span>
    </div>
  </section>`;
}

