function renderAddressChangeAttachmentList(resource) {
  const pending = Boolean(resource.actionPendingKey);
  if (!resource.attachments.length) {
    return '<div class="shared-address-change-empty">Attach proof only when the direct save path cannot verify the correction.</div>';
  }
  return `<div class="shared-address-change-attachments">
    ${resource.attachments
      .map((attachment) => {
        const id = attachment.attachmentId || attachment.fileName;
        const meta = [
          attachment.type ? humanizeLabel(attachment.type) : "",
          formatComposerFileSize(attachment.sizeBytes),
        ]
          .filter(Boolean)
          .join(" - ");
        return `<article class="shared-address-change-attachment">
          <div>
            <strong>${escapeHtml(attachment.fileName || attachment.key || "Evidence file")}</strong>
            <span>${escapeHtml(meta || attachment.contentType || "Attached")}</span>
          </div>
          <button class="shared-feed-chip" type="button" data-action="settings-address-change-attachment-remove" data-attachment-id="${escapeHtml(id)}"${disabledAttr(pending)}>Remove</button>
        </article>`;
      })
      .join("")}
  </div>`;
}

function renderAddressChangeRequestCard(request) {
  const address = formatAddressChangeAddress(request.requestedAddress);
  const created = request.createdAt
    ? formatAbsoluteDateTime(request.createdAt)
    : request.updatedAt
      ? formatAbsoluteDateTime(request.updatedAt)
      : "";
  const secondary = [
    request.resolutionStatus ? `Resolution: ${humanizeLabel(request.resolutionStatus)}` : "",
    request.attachments.length
      ? `${formatCount(request.attachments.length)} evidence file${request.attachments.length === 1 ? "" : "s"}`
      : "",
  ]
    .filter(Boolean)
    .join(" - ");
  return `<article class="shared-address-change-request">
    <div class="shared-address-change-request__top">
      ${renderSettingsStatusPill(humanizeLabel(request.status), addressChangeStatusTone(request.status))}
      <span>${escapeHtml(created || "Submitted")}</span>
    </div>
    <h3>${escapeHtml(address || "Requested address")}</h3>
    ${request.message ? `<p>${escapeHtml(request.message)}</p>` : ""}
    ${secondary ? `<small>${escapeHtml(secondary)}</small>` : ""}
    ${request.decisionReason ? `<small>${escapeHtml(`Decision: ${request.decisionReason}`)}</small>` : ""}
  </article>`;
}

function renderAddressChangeHistory(resource) {
  if (resource.loading && !resource.loaded) {
    return '<div class="shared-settings-empty">Loading request history...</div>';
  }
  if (resource.error) {
    return `<div class="shared-settings-empty">${escapeHtml(resource.error)}</div>`;
  }
  if (!resource.items.length) {
    return '<div class="shared-settings-empty">No home-location review requests have been submitted from this account yet.</div>';
  }
  return `<div class="shared-address-change-history">
    ${resource.items.map(renderAddressChangeRequestCard).join("")}
    ${
      resource.nextCursor
        ? `<button class="shared-feed-chip" type="button" data-action="settings-address-change-load-more"${disabledAttr(resource.loadingMore)}>${resource.loadingMore ? "Loading..." : "Load more"}</button>`
        : ""
    }
  </div>`;
}

