    if (filters.view !== "admin") {
      navigateTo(buildMissionsRoute({ ...filters, view: "admin" }));
      return;
    }
    list.createOpen = !list.createOpen;
    if (!list.createOpen) {
      list.createDraft = null;
    }
    scheduleRender();
    return;
